	inline bool IsTrainerClanMemberField(const char* field)
	{
		return !strncmp(field, "_fed_id:", strlen("_fed_id:"));
	}

	inline bool IsClanEventField(const char* field)
	{
		return !strncmp(field, "_event_", strlen("_event_"));
	}

	inline std::string EventIdFromClanEventField(const char* fieldStr)
	{
		std::string field(fieldStr);
		return std::string(field.begin() + strlen("_event_"), field.end() - strlen("_score"));
	}

	inline std::string ClanEventFieldFromEventId(const char* eventId)
	{
		return std::string("_event_") + eventId + "_score";
	}

	inline bool IsClanEvent2Field(const char* field)
	{
		return !strncmp(field, "_event2_", strlen("_event2_"));
	}

	inline std::string EventIdFromClanEvent2Field(const char* fieldStr)
	{
		std::string field(fieldStr);
		return std::string(field.begin() + strlen("_event2_"), field.end() - strlen("_score"));
	}

	inline std::string ClanEvent2FieldFromEventId(const char* eventId)
	{
		return std::string("_event2_") + eventId + "_score";
	}

	std::string RotateString(const std::string& str, int shift)
	{
		auto shiftRange = [](char c, int shift, char min, char max) -> char
		{
			if (c < min || c > max) return c;
			auto diff = max - min + 1;
			if (shift < 0)
				shift = shift % diff + diff;
			return (c + shift - min) % diff + min;
		};

		auto ret = str;
		for (auto& c : ret)
		{
			c = shiftRange(c, shift, '0', '9');
			c = shiftRange(c, shift, 'a', 'z');
			c = shiftRange(c, shift, 'A', 'Z');
		}
		return ret;
	};

	bool CheckAlias(const std::string& alias, bool shifted = false)
	{
		if (alias.size() < 3)
			return false;

		int s = shifted ? 2 : 4;
		for (int i = 0; i < (int)alias.length() - 1; i++)
		{
			char c(alias.at(i));
			if (c >= 'a')
				c = c + 11 - 'a';
			else if (c >= 'A')
				c = c + 11 - 'A';
			else if (c > '0')
				c = c + 1 - '0';
			s += c;
		}

		s &= 7;
		if (shifted)
			s += 8;

		if (s > 9)
			s += ('a' - 10);
		else
			s += '0';

		return alias[alias.length() - 1] == s;
	}

	enum class ERedBossLeaderboardType
	{
		Global,
		Diamond_League,
		Gold_League,
		Silver_League,
		Bronze_League,
#ifdef RED_BOSS_CLAN_LEADERBOARD
		Clan,
#endif // RED_BOSS_CLAN_LEADERBOARD
		_count
	};

	// --- we have only 4 leagues for red boss, map them from pvp
	ERedBossLeaderboardType PvpLeagueToRedBossLeague(int league)	// --- 1 highest, 10 lowst
	{
		if (!league)
			league = 10;
		league = glf::Clamp(league, 1, 10);

		static const ERedBossLeaderboardType mapping[]{ ERedBossLeaderboardType::Diamond_League,
			ERedBossLeaderboardType::Gold_League, ERedBossLeaderboardType::Gold_League, ERedBossLeaderboardType::Gold_League,
			ERedBossLeaderboardType::Silver_League, ERedBossLeaderboardType::Silver_League, ERedBossLeaderboardType::Silver_League,
			ERedBossLeaderboardType::Bronze_League, ERedBossLeaderboardType::Bronze_League, ERedBossLeaderboardType::Bronze_League };

		return mapping[league - 1];
	}

	inline std::string RedBossLeaderboardType(ERedBossLeaderboardType type)
	{
		static const std::string s_type[]{
			"global",
			"diamond",
			"gold",
			"silver",
			"bronze",
		};

		return s_type[(int)type];
	}

	inline std::string RedBossLeaderboardName(const std::string& eventId, ERedBossLeaderboardType type)
	{
		return std::string("demon_") + RedBossLeaderboardType(type) + std::string("_") + eventId;
	}

