void GameServerFedManager::GiveAdsRewardTest(GSClient* client, Json::Value& rewardInfo)
{
	Json::Value items;
	items[rewardInfo["name"].asString()] = rewardInfo["qty"];

	Json::Value entry;
	entry["items"] = items;
	entry["source"] = "ads";
	entry["type"] = "inventory_delivery";

	Json::Value entryAds;
	entryAds[std::string("pending_transactions.ads_") + std::to_string(GetLocalTime())] = entry;// entry;

	std::unique_ptr<ProfileOperation> operation(new ProfileOperation);
	operation->client_id = client->m_clientId;
	operation->for_credential = client->m_credential;
	operation->owner_credential = client->m_credential;
	operation->operation = E_ProfileOperation::EPO_SAVE_ADS_REWARD_PENDING_TRANSACTION;
	operation->data = nullptr;

	GameServerFedManager::Instance()->ScriptSetSeshatProfileField(entryAds, std::move(operation));
}

bool GameServerFedManager::SendShopDailyAds(GSClient* client, int shopDailyCount, unsigned int cooldownEnd)
{
	NetworkMessageW shopDailyAdsMsg;
	shopDailyAdsMsg.addGameMessageType(TCPMSG_SERVER_SEND_SHOP_DAILY_ADS);

	shopDailyAdsMsg.addInt(shopDailyCount);
	shopDailyAdsMsg.addUInt(cooldownEnd);

	shopDailyAdsMsg.packMessage(client->m_Crypto);

	if (shopDailyAdsMsg.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: SendShopDailyAds packet memory overflow\n");
		return false;
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)shopDailyAdsMsg.getMessageBody(), shopDailyAdsMsg.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendforgeSquadmatesPacks send message failed\n");
		return false;
	}

	return true;
}

void  GameServerFedManager::GiveShopDailyAdsReward(GSClient* client)
{
	Json::Value data = client->GetHestiaConfig()->GetAdsConfig()["shop_daily"];
	auto cnt = client->m_seshatProfile->GetShopDailyAdsCount();
	std::string reward = "";

	if (cnt == data["max_round"].asInt() * 5) // last ads of the day
	{
		reward = data.get("milestone_reward_end", "").asString();
		client->m_seshatProfile->SetShopDailyCoolDown(true, data["cooldown_time"].asInt64());
	}
	else if (cnt > 0 && cnt % 5 == 0) // last milestone of a round
	{
		reward = data.get("milestone_reward_end", "").asString();
		client->m_seshatProfile->SetShopDailyCoolDown(false, data["cooldown_time"].asInt64());
	}
	else // normal milestone
	{
		reward = data.get("milestone_reward_normal", "").asString();
	}

	if (reward.empty()) return;

	GetGachaData()->GiveStuff(client, reward.c_str(), 1);
	client->m_seshatProfile->AddNotificationFromServer("ads_reward", reward.c_str(), 1, ENM_CATEGORY | ENM_INFO);
	client->m_seshatProfile->SetLastAdsWatchedTime(GetLocalTime());
}

