bool GameServerFedManager::LoadMissionsData()
{
	auto missionsData = std::make_unique<AHMissionsData>();
	bool bRet = missionsData->LoadData();

	if (!bRet)
	{
		MP_LOG(DBG_WARN, "Failed loading missions data!\n");
		return false;
	}
	else
	{
		m_missionsData = std::move(missionsData);
	}

	return bRet;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::LoadCoopEventsData()
{
	auto coopEventsData = std::make_unique<AHEventsData>();
	bool bRet = coopEventsData->LoadData();

	if (!bRet)
	{
		MP_LOG(DBG_WARN, "Failed loading coop events data!\n");
		return false;
	}
	else
	{
		m_eventsData = std::move(coopEventsData);
	}

	return bRet;
}

