//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::LoadCheatersList(const char* filename, char* &buff, charPSetT* &cheaters)
{
	delete[] buff;
	delete cheaters;

	buff = GSReadFile(filename);
	if (!buff)
	{
		MP_LOG(DBG_WARN, "GameServerFedManager - LoadCheatersList (%s) failed, ignoring\n", filename);
		return true;
	}

	cheaters = new charPSetT(charLessCmp());

	char* c = buff;
	while (c && *c)
	{
		char* d = strpbrk(c, "\r\n");
		if (d)
			*d = 0;
		cheaters->insert(c);
		if (d)
		{
			c = d + 1;
			c += strspn(c, "\r\n");
		}
		else
		{
			c = d;
		}
	}

	return true;
}

