//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::LoadLeaderboardExpiry()
{
	auto data = GSReadJsonFile("leaderboard_expiry.json");

	m_eloLadderExpiryData.clear();
	for (const auto& entry : data["leaderboard_expiry"])
	{
		time_t expiry = 0;
		SemEvent::parse_time(entry["expiry"].asCString(), expiry);
		if (!expiry)
		{
			MP_LOG(DBG_WARN, "GameServerFedManager - LoadLeaderboardExpiry failed to parse leaderboard expiry at index %u!\n", m_eloLadderExpiryData.size());
			return false;
		}
		auto eloSettings = StrToEloSettings(entry["settings"].asCString());

		auto pvpSettings = entry["pvp_settings"].asString();
		if (pvpSettings.empty())
			pvpSettings = "1";

		auto skmSettings = entry["skm_settings"].asString();
		if (skmSettings.empty())
			skmSettings = "1";

		auto pvpWeekHours = entry["pvp_week_hours"].isNull() ? 1 : entry["pvp_week_hours"].asInt();
		bool comingSoon = entry["coming_soon"].asBool();
		auto clanLb = entry["clan_lb"].asString();
		bool decay = entry["decay"].asBool();

		m_eloLadderExpiryData.emplace_back(expiry, entry["id"].asCString(), eloSettings, pvpSettings.c_str(), pvpWeekHours, comingSoon, clanLb.c_str(), decay, skmSettings.c_str());
	}

	// --- sort by expiry date
	std::sort(m_eloLadderExpiryData.begin(), m_eloLadderExpiryData.end());

	m_nextLadderCheck = GetCurrentLadderExpiry() + 5;

	m_nextPVPWeekCheck = GetLadderPvpWeek().second + 5;	// --- update mp week expiry time

	// --- update the current ladder id in the elo ladder
	SetEloLadderProps(StringHash(GetCurrentLadderId()), GetCurrentLadderSettings());

	// --- send the new current leaderboard data to any connected clients
	for (auto& clientEntry : m_gsClientsList)
	{
		auto client = clientEntry.second;
		if (!client || !client->m_isReadyForCommunication)
			continue;

		ServerSendLadderProps(client);
		ServerSendLadderExpiry(client);
		ServerSendPVPData(client);
	}

	return true;
}

