//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::LoadUuids()
{
	Json::Value data = GSReadJsonFile("uuids.json");
	bool ret = !data.empty();
	if (ret)
	{
		MP_LOG(DBG_INFO, "GameServerFedManager LoadUuids %s\n", data.toCompactString().c_str());
		const auto& c_prev = m_uuids;
		const auto& c_next = data;
		if (c_prev["mm_id"] != c_next["mm_id"])
		{
			// --- force a reconnection to the MM server
			HandleMMDisconnect(comms::Connection_error::GAMEOVER, 13);
		}
		if (c_prev["clanserver_id"] != c_next["clanserver_id"])
		{
			if (m_clanServerManager)
				m_clanServerManager->OnUuidChanged();
		}
		m_uuids = data;
	}

	auto& mm_id = m_uuids["mm_id"];
	if (mm_id.empty())
		mm_id = "mm_server";
	return ret;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::LoadRequiredDlcVersion()
{
	Json::Value data = GSReadJsonFile("required_dlc.json");
	bool ret = !data.empty();
	if (ret)
	{
		MP_LOG(DBG_INFO, "GameServerFedManager LoadRequiredDlcVersion %s\n", data.toCompactString().c_str());
		const auto& c_prev = m_requiredDlcVersion;
		const auto& c_next = data;
		auto broadcastChange = (c_prev["required_dlc_version"] != c_next["required_dlc_version"]);
		m_requiredDlcVersion = data;

		if (broadcastChange)
			BroadcastRequiredDlcVersion();
	}

	return ret;
}

