//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

Json::Value	GameServerFedManager::GetLoadingHints(GSClient* client) const
{
	Json::Value ret;
	ret["hints_param"] = m_loadingHintsJson["hints_param"];
	for (auto it = m_loadingHintsJson["hints"].begin(); it != m_loadingHintsJson["hints"].end(); ++it)
	{
		auto &arr = ret["hints"][it.memberName()] = Json::arrayValue;
		for (const auto& v : *it)
		{
			arr.append(v[client->m_language]);
		}
	}
	return ret;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

Json::Value	GameServerFedManager::GetChancesJson(GSClient* client) const
{
	Json::Value ret;

	const auto& platform = m_chancesJson["enable"]["platform"];
	if (!std::any_of(platform.begin(), platform.end(), [client](const Json::Value& p) { return client->m_clientId.find(p.asString()) != std::string::npos; }))
		return ret;

	auto items = client->GetHestiaConfig()->FindCreditsInCategory("gacha");
	for (auto item : items)
	{
		auto credit = client->GetHestiaConfig()->FindCredit(item);
		if (credit && m_chancesJson.isMember(credit->name))
		{
			ret[credit->name] = m_chancesJson[credit->name];
		}
	}

	const auto& sTranslations = m_chancesJson["translations"];
	auto& dTranslations = ret["translations"];

	for (auto it = sTranslations.begin(); it != sTranslations.end(); ++it)
	{
		dTranslations[it.memberName()] = (*it)[client->m_language];
	}
	return ret;
}

