	//load initial profile
	bRet = LoadInitialProfile();
	if (!bRet)
	{
		MP_LOG(DBG_WARN, "GameServerFedManager - Initial Profile Load Failed!\n");
		return false;
	}

	MP_LOG(DBG_INFO, "GameServerFedManager - Loaded Initial Profile!\n");

	bRet = LoadMultiplayerData();
	if (!bRet)
	{
		MP_LOG(DBG_WARN, "GameServerFedManager - MultiplayerData Load Failed!\n");
		return false;
	}

	MP_LOG(DBG_INFO, "GameServerFedManager - Loaded Multiplayer Data!\n");

	bRet = LoadRandomNames();
