//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::SendPingsToAllClients()
{
	if(OS_GetTime() - m_lastTimeSentKeepAlive > KEEP_ALIVE_TIMER)
	{
		m_lastTimeSentKeepAlive = OS_GetTime();
		auto crtTime = GetCrtUTCTimeSeconds();

		GSClientsIterator it;
		for (it = m_gsClientsList.begin(); it != m_gsClientsList.end(); ++it)
		{
			if(it->second->m_isReadyForCommunication)
			{
				ServerSendPingToClient(it->second, it->second->m_lastSentTs == 0 || it->second->m_lastSentTs < crtTime - PING_SEND_TS);
			}
		}
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::CheckAndHandIdlePlayers()
{
	std::vector< std::string > toRemove;

	GSClientsIterator it;
	for (it = m_gsClientsList.begin(); it != m_gsClientsList.end(); ++it)
	{
		int64_t maxConnectionTimeout = it->second->m_internalState == E_CLSTATE_SPECIAL_INTERRUPT ? m_serverSettings->GetSpecialInterruptMaxConnectionTimeout() : m_serverSettings->GetMaxConnectionTimeout();
		int64_t connectionIssuesTimeout = m_serverSettings->GetClientConnectionIssuesTimeout();

		if( ((it->second->m_lastTimeReceivedMessage != 0) && (OS_GetTime() - it->second->m_lastTimeReceivedMessage > maxConnectionTimeout))
			|| it->second->m_internalState == E_CLSTATE_TO_REMOVE)
		{
			//toRemove.push_back(it->first);
		}
		else if ( (it->second->m_lastTimeReceivedMessage != 0) 
			&& ( OS_GetTime() - it->second->m_lastTimeReceivedMessage > connectionIssuesTimeout ) 
			&& !it->second->m_profilePendingSave
			&& it->second->m_seshatProfile->IsProfileChanged())
		{
			//if connection has issues we save faster than disconnecting the player
			ScriptSetSeshatProfile(it->first, it->second);
		}
	}

	//remove the marked clients
	if (!toRemove.empty())
	{
		for (size_t i = 0; i < toRemove.size(); ++i)
		{
			MP_LOG(DBG_INFO, "Remove timeout player %s\n", toRemove[i].c_str());

			RemoveClient(toRemove[i]);
		}
	}
}

