void GameServerFedManager::UpdateAntiExploitationSystemExpiry()
{
	time_t now = GetLocalTime();
	for (const auto& entry : m_gsClientsList)
	{
		auto client = entry.second;
		if (client->m_seshatProfile->IsInvalid() || !client->GetHestiaConfig())
			continue;

		Json::Value profileDefL = client->m_seshatProfile->GetProfile()[SESHAT_DEFENDER_LEADERBOARD];
		int undefeatedStreak = profileDefL.get(SESHAT_LABEL_DEFENDER_LEADERBOARD_UNDEFEATED_STREAK, 0).asInt();
		int pendingELOAvoided = profileDefL.get(SESHAT_LABEL_DEFENDER_LEADERBOARD_PENDING_ELO_AVOIDED, 0).asInt();
		int pendingELOSucessDef = profileDefL.get(SESHAT_LABEL_DEFENDER_LEADERBOARD_PENDING_ELO_SUCCCESS_DEF, 0).asInt();
		
		if (undefeatedStreak != 0 || pendingELOAvoided != 0 || pendingELOSucessDef != 0)
		{
			if (!DefenderLeaderboard::Get()->IsAntiExploitationActive(client))
			{
				client->m_seshatProfile->ResetDefenderLeaderboardStreak(client);
				ServerSendUpdateDefenderLeaderboardStats(client);
			}
		}
	}
}

