//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UpdateTimedSave()
{
	std::vector< std::string > toRemove;

	auto ostime = OS_GetTime();
	auto now = GetServerTime();
	int64_t checkIncomingAttacksInterval = GetCheckIncomingAttacksInterval();

	GSClientsIterator it;
	for (it = m_gsClientsList.begin(); it != m_gsClientsList.end(); ++it)
	{
		if (it->second->m_profilePendingSave)
			continue;

		if (it->second->NeedsFullRefresh())
		{
			it->second->m_lastCheckedIncomingAttacks = ostime;
			it->second->SetNeedsFullRefresh(false);
			it->second->SetNeedsHalfRefresh(false);
			ScriptSetSeshatProfile(it->first, it->second, E_SSPRF_REQUEST_CONFIG);
		}
		else if (it->second->NeedsHalfRefresh())
		{
			it->second->m_lastCheckedIncomingAttacks = ostime;
			it->second->SetNeedsHalfRefresh(false);
			ScriptSetSeshatProfile(it->first, it->second);
		}
		else if (it->second->m_seshatProfile->IsProfileChanged()
				&& (ostime - it->second->m_lastTimeProfileSaved > (int64_t)m_serverSettings->GetSaveProgressInterval()))
		{
			it->second->m_lastCheckedIncomingAttacks = ostime;
			ScriptSetSeshatProfile(it->first, it->second);
		}
		else if (it->second->m_lastCheckedIncomingAttacks && ostime - it->second->m_lastCheckedIncomingAttacks > checkIncomingAttacksInterval)
		{
			MST_LOG("Update timed save for %s", it->second->m_credential.c_str());

			it->second->m_lastCheckedIncomingAttacks = ostime;
			Multiplayer::StartReadingProfileField(it->second->m_credential, it->second->m_credential, E_ProfileOperation::EPO_PROCESS_ATTACKS);
			StartGetingEloLadders(it->second);
			StartGetingMPLadders(it->second);
			StartGetingOutpostsLadders(it->second);
		}
		else if (it->second->m_nextConquestUpdate && it->second->m_nextConquestUpdate <= now)
		{
			it->second->m_multiplayer->RequestUpdateConquestMMKey(nullptr);
		}
		else if (it->second->m_nextConquestClaim && it->second->m_nextConquestClaim <= now)
		{
			ServerSendCurrentConquestClaimData(it->second);
		}
	}
}

