//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendEloLadder(const GSClient* client, StringHash ladderType, const char* ladder)
{
	NetworkMessageW ladderMsg;
	ladderMsg.addGameMessageType(TCPMSG_SERVER_SEND_ELO_LADDER);
	ladderMsg.addUInt(ladderType);
	
	bool added = false;
	int ladderSize = (int)strlen(ladder);
	if (ladderSize > 128)
	{
		int compressedSize = LZ4_compressHC((char*)ladder, (char*)m_tempBuffer.data(), ladderSize);
		if (compressedSize > 0 && compressedSize < ladderSize)
		{
			// --- ok and smaller -> send compressed
			// the compression worked so we add the compressed message
			ladderMsg.addByte(1);
			ladderMsg.addInt(ladderSize);
			ladderMsg.addBytesAndLen(m_tempBuffer.data(), compressedSize);

			added = true;
		}
	}

	if (!added)
	{
		ladderMsg.addByte(0);
		ladderMsg.addBytesAndLen((const byte*)ladder, ladderSize);
	}

	ladderMsg.packMessage(client->m_Crypto);

	if (ladderMsg.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendEloLadder packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)ladderMsg.getMessageBody(), ladderMsg.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendEloLadder send message failed\n");
		return false;
	}

	return true;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendDailyQuestsPatch(GSClient* client, const Json::Value& data)
{
	NetworkMessageW msg;
	msg.addGameMessageType(TCPMSG_SERVER_SEND_DAILY_QUESTS_PATCH);

	std::string txt = Json::FastWriter().write(data);

	// compress the text
	int size = (int)txt.length();
	if (size > (GetRecvBufferSize() - 2))
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendDailyQuestsPatch %s profile too large %d, resizing!!!\n", client->m_credential.c_str(), size);
		ResizeBuffers(size + 2);
	}

	int compressedSize = LZ4_compressHC(txt.c_str(), (char*)m_tempBuffer.data(), size);
	if ((compressedSize <= 0) || (compressedSize >= size))
	{
		msg.addByte(0);	// --- not compressed
		msg.addBytesAndLen((const byte*)txt.c_str(), (unsigned int)txt.length());
	}
	else
	{
		msg.addByte(1);	// --- compressed
		msg.addInt(size);
		msg.addBytesAndLen(m_tempBuffer.data(), compressedSize);
	}

	msg.packMessage(client->m_Crypto);

	if (msg.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendDailyQuestsPatch packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)msg.getMessageBody(), msg.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendDailyQuestsPatch send message failed\n");
		return false;
	}

	return true;
}

