void GameServerFedManager::ScriptRequestInitialData(const GSClient* client)
{
	std::map<std::string, std::string> customParams;
	customParams.insert(std::pair<std::string, std::string>("credential", client->m_credential));
	customParams.insert(std::pair<std::string, std::string>("access_token", client->GetAccessToken()));

	Json::Value jsonDevice;
	jsonDevice["id"] = client->m_deviceInfo.deviceId;
	jsonDevice["model"] = client->m_deviceInfo.model;
	jsonDevice["carrier"] = client->m_deviceInfo.carrier;
	jsonDevice["country"] = client->m_countryCode;
	jsonDevice["language"] = client->m_language;
	jsonDevice["firmware"] = client->m_deviceInfo.firmware;

	std::string resolution = "";
	if (client->m_deviceInfo.width != 0 && client->m_deviceInfo.height != 0)
		resolution = std::to_string(client->m_deviceInfo.width) + "x" + std::to_string(client->m_deviceInfo.height);
	jsonDevice["resolution"] = resolution;

	std::string device_str = Json::FastWriter().write(jsonDevice);
	customParams.insert(std::pair<std::string, std::string>("device_info", device_str));

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	void* userData = (void*)0;

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_INITIAL_DATA)->second, client->m_clientId, customParams, beneficiaries, callbackScriptInitialData, this, userData);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptInitialData(const SRequest& requestData)
{
	MP_LOG(DBG_INFO, "Callback get_initial_data code %s profile %s\n", requestData.m_code.c_str(), requestData.m_beneficiaires[0].c_str());
	
	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(credential);

	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "Initial data returned for non-existing user %s!\n", credential.c_str());
		return;
	}

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "Server request error on get_initial_data for %s, request error %d!\n", credential.c_str(), requestData.m_errorCode);
		callerObj->RemoveClient(credential);
		return;
	}

	Json::Value			jsonResponse;
	Json::Reader		reader;
	Json::FastWriter	writer;

	reader.parse(requestData.m_requestResponse, jsonResponse);

	int status = jsonResponse["status"].asUInt();

	if ( status != 200 )
	{
		MP_LOG(DBG_WARN, "Did not receive initial data for %s - status %d, reason %s !\n", credential.c_str(), status, jsonResponse["reason"].asCString());
		callerObj->RemoveClient(credential);
		return;
	}

	const auto& jsonSeshatValue = jsonResponse["seshat"];
	const auto& jsonHestiaValue = jsonResponse["hestia"];
	const char* seshatString = jsonSeshatValue.isNull() ? "" : jsonSeshatValue.asCString();
	const char* hestiaString = jsonHestiaValue.isNull() ? "" : jsonHestiaValue.asCString();
	int seshatStringSize = (int)strlen(seshatString);
	int hestiaStringSize = (int)strlen(hestiaString);

	if (seshatStringSize == 0 || hestiaStringSize == 0)
	{
		MP_LOG(DBG_WARN, "Initial data error for %s ! Return is success but seshat and hestia are not present!\n", credential.c_str());
		callerObj->RemoveClient(credential);
		return;
	}

	//seshat related -->
	Json::Value jsonSeshat(Json::nullValue);
	reader.parse(seshatString, seshatString + seshatStringSize + 1, jsonSeshat, false);
	client->m_seshatProfile->SetProfile(jsonSeshat);

	if (client->m_seshatProfile->IsBannedFromGame())
	{
		callerObj->ServerSendBannedMessage(credential, writer.write(jsonSeshat[SESHAT_BANNED_FROM]));
		return;
	}


	Json::Value jsonStats;
	client->m_seshatProfile->GetStatistics(jsonStats);
	client->m_seshatProfile->NormalizeInventory();

	//geo todo - are these needed?
	//// --- add new inventory field if it doesn't exist and populate it accordingly
	//m_hestiaConfigManager->UpdateInventoryFormat(client->m_seshatProfile, callerObj->m_armory, callerObj->m_rewardData);

	//// --- make sure the mission marked as unlocked by default are unlocked in the profile
	//callerObj->m_missionsData->ProcessDefaultUnlocks(client->m_seshatProfile);

	//// --- make sure the weapons marked as owned / equipped by default are marked accordingly in the profile
	//callerObj->m_weaponsData->ProcessDefaultUnlocks(client->m_seshatProfile);

	//// --- check for ecomm modifications (IAPs)
	//m_hestiaConfigManager->UpdateInventoryFromIAP(client->m_seshatProfile);

	//client->m_lastTimeProfileSaved = OS_GetTime();

	client->m_seshatProfile->SetCountryCode(client->m_countryCode.c_str());
	client->m_seshatProfile->SetLanguage(client->m_language.c_str());
	client->m_seshatProfile->SetDeviceId(client->m_deviceInfo.deviceId);

	//geo todo - what is this?
	// --- Viorel: maybe we should have an event fired when we recive the profile from seshat, because I need to alter it before sending it to client.  For now, I'll alter it here.
	client->m_seshatProfile->ProcessIncomingAttacks(true);

	callerObj->ServerSendProfileToPlayer(client->m_credential, client->m_seshatProfile);
	client->m_seshatProfile->FindNextOpponents();
	callerObj->ServerSendClanCommand(client, ClanCommand::ServerSendEnableClans, CLANS_ENABLED);
	//<-- seshat related



	//hestia related -->
	Json::Value jsonHestia(Json::nullValue);
	reader.parse(hestiaString, hestiaString + hestiaStringSize + 1, jsonHestia, false);
	client->SetGroupwareEvents(jsonHestia["groupware"]["events"]);

	HestiaConfigManager::HestiaSetConfigStatus config_status = callerObj->m_hestiaConfigManager->SetConfig(client, hestiaString, std::move(jsonHestia));
	if (config_status == HestiaConfigManager::HSCS_ERROR)
	{
		MP_LOG(DBG_CRIT, "Hestia config not valid for %s - removing client!\n", credential.c_str());
		callerObj->RemoveClient(credential);
		return;
	}

	callerObj->ScriptRequestEventsInfo(client);

	// --- send the config to the client
	callerObj->ServerSendConfigToPlayer(client);
	callerObj->ServerSendJsonToPlayer(client, E_LangJson::_All);
	client->m_seshatProfile->ClearVariablePresetsCache();

	// --- update variable prices
	auto var_price_changes = client->GetHestiaConfig()->UpdateInventoryVariableOffers(client, {});
	if (!var_price_changes.empty())
	{
		callerObj->ServerSendInventoryUpdate(client, "_variable_prices", std::move(var_price_changes));
	}

	//<-- hestia related

	//cache the access token
	const Json::Value& jsonAccessToken = jsonResponse.get("access_token", Json::nullValue);
	client->UpdateAccessTokenFromJson(jsonAccessToken);
}

