void GameServerFedManager::ScriptRequestFedId(GSClient* client)
{
	std::map<std::string, std::string> customParams;
	customParams["credential"] = client->m_credential;
	customParams["client_id"] = client->m_clientId;
	customParams["access_token"] = client->GetAccessToken();

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	void* userData = (void*)0;

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_ACCOUNT_INFO)->second, client->m_clientId, customParams, beneficiaries, callbackScriptRequestFedId, this, userData);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptRequestFedId(const SRequest& requestData)
{
	MP_LOG(DBG_INFO, "Callback get_account_info code %s profile %s\n", requestData.m_code.c_str(), requestData.m_beneficiaires[0].c_str());

	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(credential);

	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "Account info returned for non-existing user %s!\n", credential.c_str());
		return;
	}

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "Server request error on get_account_info for %s, request error %d!\n", credential.c_str(), requestData.m_errorCode);
		callerObj->RemoveClient(credential);
		return;
	}

	Json::Value			jsonResponse;
	Json::Reader		reader;
	Json::FastWriter	writer;

	reader.parse(requestData.m_requestResponse, jsonResponse);

	int status = jsonResponse["status"].asUInt();

	if (status != 200)
	{
		MP_LOG(DBG_WARN, "Did not receive account info for %s - status %d, reason %s !\n", credential.c_str(), status, jsonResponse["reason"].asCString());
		callerObj->RemoveClient(credential);
		return;
	}

	Json::Value			jsonAccountInfo;
	reader.parse(jsonResponse["account_info"].asString(), jsonAccountInfo);

	std::string account = jsonAccountInfo["account"].asString();
	if (account.empty())
	{
		MP_LOG(DBG_WARN, "Received empty account for %s\n", credential.c_str());
		return;
	}

	callerObj->SetClientFedId(client, account);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::CheckSevenDays(GSClient* client, std::string eventKey, bool bCheat)
{
	if (!bCheat)
	{
		if (client->m_sevenDaysPopupCheck[eventKey])
		{
			return;
		}
		else
		{
			client->m_sevenDaysPopupCheck[eventKey] = true;
		}
	}

	Json::Value data = client->GetHestiaConfig()->GlobalParameters()[eventKey];
	bool isSpecial = eventKey == SESHAT_LABEL_SEVEN_DAYS_SPECIAL;
	std::string rewardList = data["reward_list"].asString();
	auto hasRewardList = DailyManager::Get()->GetSevenDaysReward(0, rewardList);

	auto& profile = client->m_seshatProfile;
	time_t now = GetLocalTime();
	std::tm today = *localtime(&now);
	bool isNewDay = false;


	if (data.isNull() || hasRewardList.empty())
	{
		return;
	}

	if (rewardList != profile->GetSevenDaysRewardList(eventKey))
	{
		profile->ResetSevenDays(eventKey);
		profile->SetSevenDaysRewardList(eventKey, rewardList);

		if (!isSpecial)
		{
			if (profile->GetSevenDaysRefreshDate(eventKey) <= now)
			{
				auto duration = data["duration"].asInt();
				profile->SetSevenDaysRefreshDate(eventKey, now + 86400 * duration);
			}
		}
	}

	time_t lastClaimedDate = profile->GetSevenDaysClaimedRewardDate(eventKey);

	if (lastClaimedDate != 0)
	{
		std::tm lastClaimedTm = *localtime(&lastClaimedDate);
		if (today.tm_mday != lastClaimedTm.tm_mday || today.tm_mon != lastClaimedTm.tm_mon || today.tm_year != lastClaimedTm.tm_year)
		{
			isNewDay = true;
		}
	}
	else
	{
		profile->SetSevenDaysClaimableDay(eventKey, 1);
		if (profile->GetSevenDaysStartDate(eventKey) == 0)
		{
			profile->SetSevenDaysStartDate(eventKey);
		}
	}

	int claimableDays = profile->GetSevenDaysClaimableDay(eventKey);
	int claimedDays = profile->GetSevenDaysRewardClaimedDay(eventKey);

	if (isNewDay && (claimableDays == claimedDays))
	{
		profile->SetSevenDaysClaimableDay(eventKey, claimedDays + 1);
	}

	short isTodayRewardClaimed = 1 - (profile->GetSevenDaysClaimableDay(eventKey) - profile->GetSevenDaysRewardClaimedDay(eventKey));

	NetworkMessageW sevenDaysReward;
	sevenDaysReward.addGameMessageType(isSpecial ? TCPMSG_SERVER_NOTIFY_SEVEN_DAYS_SPECIAL : TCPMSG_SERVER_NOTIFY_SEVEN_DAYS_LOGIN);
	sevenDaysReward.addString((const unsigned char*)eventKey.c_str());
	sevenDaysReward.addShort(profile->GetSevenDaysRewardClaimedDay(eventKey));
	sevenDaysReward.addShort(profile->GetSevenDaysClaimableDay(eventKey));
	if (!isSpecial)
	{
		sevenDaysReward.addInt(profile->GetSevenDaysStartDate(eventKey));
	}
	else
	{
		sevenDaysReward.addByte(profile->GetSevenDaysPremium(eventKey));
	}
	sevenDaysReward.addShort(isTodayRewardClaimed);
	sevenDaysReward.addUInt((uint32_t)0);
	sevenDaysReward.packMessage(client->m_Crypto);

	if (sevenDaysReward.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: CheckSevenDays %s packet memory overflow\n", eventKey);
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)sevenDaysReward.getMessageBody(), sevenDaysReward.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: CheckSevenDays %s send message failed\n", eventKey);
	}

}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::CheckDailyLogin(GSClient* client, bool bCheat)
{
	DailyManager::Get()->UpdateCurrentMonth();

	client->m_seshatProfile->FixClaimedReward();

	bool newDay = false;
	if (client->m_seshatProfile->GetRewardsAvailable() != client->m_seshatProfile->GetRewardsClaimed())
	{ // if the player was eligible for a reward on his last login, but disconnected before claiming it. send it again now
		newDay = true;
	}
	else if (client->m_seshatProfile->GetRewardsDate() != 0)
	{
		time_t rewardsDate = client->m_seshatProfile->GetRewardsDate();
		std::tm lastDay = *localtime(&rewardsDate);

		time_t now = GetLocalTime();
		std::tm today = *localtime(&now);

		if ((today.tm_mon != lastDay.tm_mon) || (today.tm_year != lastDay.tm_year))
		{ // new month
			client->m_seshatProfile->SetRewardsClaimed(0);
			newDay = true;
		}
		else if (today.tm_mday != lastDay.tm_mday)
		{ // new day
			newDay = true;
		}
	}
	else
	{ // first login ever
		client->m_seshatProfile->SetRewardsClaimed(0);
		newDay = true;
	}

	if (newDay)
	{
		time_t now = GetLocalTime();
		std::tm today = *localtime(&now);
		if (!bCheat)
		{
			if (today.tm_mday < client->m_seshatProfile->GetRewardsClaimed())
			{
				client->m_seshatProfile->SetRewardsClaimed(0);
			}

			if (client->m_seshatProfile->GetRewardsClaimed() == 0)
			{
				client->m_seshatProfile->ResetClaimedReward();
			}

			client->m_seshatProfile->SetRewardsAvailable(client->m_seshatProfile->GetRewardsClaimed() + 1);
		}
		client->m_dailyRewardCheckTime = GetLocalTime();

		if (!DailyManager::Get()->HaveReward(client->m_seshatProfile->GetRewardsAvailable()))
		{ // no reward. this can happen if we have less rewards than days in a month - set the progress at the last available reward
			client->m_seshatProfile->SetRewardsAvailable(DailyManager::Get()->GetNumberRewards());
			client->m_seshatProfile->SetRewardsClaimed(DailyManager::Get()->GetNumberRewards());
		}
	}

	NetworkMessageW dailyRewards;
	dailyRewards.addGameMessageType(TCPMSG_SERVER_NOTIFY_DAILY_REWARDS);
	dailyRewards.addShort(client->m_seshatProfile->GetRewardsAvailable());
	dailyRewards.addShort(client->m_seshatProfile->GetRewardsClaimed());
	dailyRewards.addShort(DailyManager::Get()->GetCurrentMonth());
	dailyRewards.addUInt((uint32_t)0);
	dailyRewards.packMessage(client->m_Crypto);

	if (dailyRewards.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: CheckDailyLogin packet memory overflow\n");
	}
	bool bResult = ServerSendMessage(client->m_credential, (char*)dailyRewards.getMessageBody(), dailyRewards.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: CheckDailyLogin send message failed\n");
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::CheckDailyLoginV2(GSClient* client, bool bCheat)
{
	time_t now = GetLocalTime();

	bool pvpTutorialCompleted = client->m_seshatProfile->TutorialCompleted("tutorial_PVPUpgradePlayer");
	bool dailyV2NewUserLock = now < client->m_seshatProfile->GetDailyV2NewUserUnlock();

	if (!pvpTutorialCompleted || dailyV2NewUserLock)
		return;

	std::tm today;
	// only skip time on beta environment for testing
	if (GameServerFedManager::IsBetaEnvironment())
	{
		auto skipDay = client->m_seshatProfile->GetDaySkipReward();
		now += skipDay * 86400;
		today = *localtime(&now);
		DailyManager::Get()->UpdateCurrentMonthV2(today.tm_mon);
	}
	else
	{
		today = *localtime(&now);
		DailyManager::Get()->UpdateCurrentMonthV2();
	}
	
	bool newDay = false;
	
	if (client->m_seshatProfile->GetRewardsDateV2() != 0)
	{
		time_t rewardsDate = client->m_seshatProfile->GetRewardsDateV2();
		std::tm lastDay = *localtime(&rewardsDate);
		
		if ((today.tm_mon != lastDay.tm_mon) || (today.tm_year != lastDay.tm_year))
		{ // new month
			client->m_seshatProfile->SetRewardsClaimedV2(0);
			newDay = true;
		}
		else if (today.tm_mday != lastDay.tm_mday)
		{ // new day
			newDay = true;
		}
	}
	else
	{ // first login ever
		client->m_seshatProfile->SetRewardsClaimedV2(0);
		newDay = true;
	}

	if (newDay)
	{
		if (!bCheat)
		{
			if (today.tm_mday < client->m_seshatProfile->GetRewardsClaimedV2())
			{
				client->m_seshatProfile->SetRewardsClaimedV2(0);
			}

			if (client->m_seshatProfile->GetRewardsClaimedV2() == 0)
			{
				client->m_seshatProfile->ResetClaimedRewardV2();
				client->m_seshatProfile->SetRewardsUnlocked(0);
			}

			client->m_seshatProfile->SetRewardsClaimable(today.tm_mday);
		}
		client->m_dailyRewardCheckTime = GetLocalTime();
	}

	short isTodayClaim = client->m_seshatProfile->GetRewardsClaimable() - today.tm_mday; // < 0 - not claim, 1 - claimed

	NetworkMessageW dailyRewards;
	dailyRewards.addGameMessageType(TCPMSG_SERVER_NOTIFY_DAILY_REWARDS_V2);
	dailyRewards.addShort(client->m_seshatProfile->GetUnlockableReward());
	dailyRewards.addShort(client->m_seshatProfile->GetRewardsClaimedV2());
	dailyRewards.addShort(DailyManager::Get()->GetCurrentMonthV2());
	dailyRewards.addShort(isTodayClaim);
	// only sent this skip time on beta environment
	if (GameServerFedManager::IsBetaEnvironment())
	{
		dailyRewards.addShort(client->m_seshatProfile->GetDaySkipReward());
	}
	else
	{
		dailyRewards.addShort((int16_t)0);
	}
	dailyRewards.addUInt((uint32_t)0);
	dailyRewards.packMessage(client->m_Crypto);

	if (dailyRewards.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: CheckDailyLogin packet memory overflow\n");
	}
	bool bResult = ServerSendMessage(client->m_credential, (char*)dailyRewards.getMessageBody(), dailyRewards.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: CheckDailyLogin send message failed\n");
	}
}

