//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::SentPiggyBankConfig(GSClient* client)
{
	NetworkMessageW piggyBankConfig;
	piggyBankConfig.addGameMessageType(TCPMSG_SERVER_SEND_PIGGY_BANK_CONFIG);
	piggyBankConfig.addInt(client->m_piggyBank->GetInitialValue());
	piggyBankConfig.addInt(client->m_piggyBank->GetCappingValue());
	piggyBankConfig.addFloat(client->m_piggyBank->GetMultiplierValue());

	// sent extra rewards list config
	Json::Value extraRewardList = client->m_piggyBank->GetExtraRewardsList();
	piggyBankConfig.addInt(extraRewardList.size());
	if (!extraRewardList.isNull())
	{
		for (Json::Value reward : extraRewardList)
		{
			piggyBankConfig.addString((unsigned char*)reward["id"].asCString());
			piggyBankConfig.addInt(reward["value"].asInt());
		}

		piggyBankConfig.addInt(client->m_piggyBank->GetExtraRewardsRubiesThreshold());
		piggyBankConfig.addInt(client->m_piggyBank->GetExtraRewardsEventPurchaseLimit() - client->m_seshatProfile->GetPiggyBankPurchaseCountForExtraEvent());
		piggyBankConfig.addUInt((unsigned int)client->m_piggyBank->GetEventExtraRewardsEndTime());
	}

	piggyBankConfig.addInt(client->m_piggyBank->GetRubiesToAddForMission(StringHash("Multiplayer")));

	piggyBankConfig.packMessage(client->m_Crypto);

	if (piggyBankConfig.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: SentPiggyBankConfig packet memory overflow\n");
	}
	bool bResult = ServerSendMessage(client->m_credential, (char*)piggyBankConfig.getMessageBody(), piggyBankConfig.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: SentPiggyBankConfig send message failed\n");
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::AddAchievementProgress(const GSClient* client, const Json::Value& jStatistics)
{
	Json::Value jUpdate, jAchiev;
	for (auto jit = jStatistics.begin(), jite = jStatistics.end(); jit != jite; ++jit)
	{
		auto key = jit.memberName();

		double addProgress = (strstr(key, "mission.") == key) ? 1 : (*jit).asDouble();
		if (addProgress <= 0)
		{
			continue;
		}

		int achIdx = AchievementsManager::Get()->GetAchievementIndexFromType(Hash(key));
		if (achIdx < 0)
			continue;

		const Json::Value &achiev = AchievementsManager::Get()->GetAchievement(achIdx);
		if (achiev["flags"]["no_test_defense"].asBool() && IsPvpSelfTest(client))
			return;

		double progress = client->m_seshatProfile->GetAchievementProgress(achIdx);
		progress += addProgress;
		client->m_seshatProfile->SetAchievementProgress(achIdx, progress);
		jAchiev["type"] = achiev["type"].asUInt();
		jAchiev["progress"] = progress;
		jUpdate.append(jAchiev);
	}

	if (!jUpdate.empty())
	{
		ServerSendAchievementProgress(client, jUpdate);
	}
}

