double GameServerFedManager::GetAchievementProgress(const GSClient* client, hash_t hType)
{
	int achIdx = AchievementsManager::Get()->GetAchievementIndexFromType(hType);
	if (achIdx < 0)
		return 0;

	return client->m_seshatProfile->GetAchievementProgress(achIdx);
}

