void GameServerFedManager::AddAchievementProgress(const GSClient* client, hash_t hType, double addProgress)
{
	int achIdx = AchievementsManager::Get()->GetAchievementIndexFromType(hType);
	if (achIdx < 0 || addProgress <= 0)
		return;

	const Json::Value &achiev = AchievementsManager::Get()->GetAchievement(achIdx);
	if (achiev["flags"]["no_test_defense"].asBool() && IsPvpSelfTest(client))
		return;

	double progress = client->m_seshatProfile->GetAchievementProgress(achIdx);
	progress += addProgress;
	client->m_seshatProfile->SetAchievementProgress(achIdx, progress);

	Json::Value jUpdate, jAchiev;
	jAchiev["type"] = achiev["type"].asUInt();
	jAchiev["progress"] = progress;
	jUpdate.append(std::move(jAchiev));

	ServerSendAchievementProgress(client, jUpdate);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::SetAchievementProgress(const GSClient* client, hash_t hType, double progress)
{
	int achIdx = AchievementsManager::Get()->GetAchievementIndexFromType(hType);
	if (achIdx < 0)
		return false;

	double currentProgress = client->m_seshatProfile->GetAchievementProgress(achIdx);
	if (currentProgress >= progress)
	{
		return false;
	}

	const Json::Value &achiev = AchievementsManager::Get()->GetAchievement(achIdx);

	if (achiev["flags"]["no_test_defense"].asBool() && IsPvpSelfTest(client))
		return false;

	client->m_seshatProfile->SetAchievementProgress(achIdx, progress);

	Json::Value jUpdate, jAchiev;
	jAchiev["type"] = achiev["type"].asUInt();
	jAchiev["progress"] = progress;
	jUpdate.append(std::move(jAchiev));

	ServerSendAchievementProgress(client, jUpdate);

	return true;
}
