//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UnlockAllAchievements(const GSClient* client)
{
	Json::Value jUpdate;

	const Json::Value& jAchievements = AchievementsManager::Get()->GetAchievements();
	for (int achIdx = 0; achIdx < static_cast<int>(jAchievements.size()); achIdx++)
	{
		const Json::Value& jAchiev = jAchievements[achIdx];
		const Json::Value& jAchievMilestones = jAchiev["milestones"];
		const Json::Value& jLastMilestone = jAchievMilestones[jAchievMilestones.size() - 1];
		double lastMilestoneQty = jLastMilestone["qty"].asDouble();
		
		double progress = client->m_seshatProfile->GetAchievementProgress(achIdx);
		if (progress < lastMilestoneQty)
		{
			client->m_seshatProfile->SetAchievementProgress(achIdx, lastMilestoneQty);
			
			Json::Value jTempAchiev;
			jTempAchiev["type"] = jAchiev["type"].asUInt();
			jTempAchiev["progress"] = lastMilestoneQty;
			jUpdate.append(std::move(jTempAchiev));
		}
	}

	if (!jUpdate.empty())
	{
		ServerSendAchievementProgress(client, jUpdate);
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UnlockRandomAchievement(const GSClient* client)
{
	const Json::Value& jAchievements = AchievementsManager::Get()->GetAchievements();

	struct LockedAchData
	{
		int index;
		double quantity;
		unsigned int type;
	};
	std::vector<LockedAchData> lockedAchievements;
	lockedAchievements.reserve(jAchievements.size());
	
	for (int achIdx = 0; achIdx < static_cast<int>(jAchievements.size()); achIdx++)
	{
		double progress = client->m_seshatProfile->GetAchievementProgress(achIdx);

		const Json::Value &jAchiev = jAchievements[achIdx];
		for (const Json::Value &jMilestone : jAchiev["milestones"])
		{
			double milestoneQty = jMilestone["qty"].asDouble();
			if (progress < milestoneQty)
			{
				LockedAchData lockedAchData;
				lockedAchData.index = achIdx;
				lockedAchData.quantity = milestoneQty;
				lockedAchData.type = jAchiev["type"].asUInt();
				lockedAchievements.push_back(lockedAchData);
				break;
			}
		}
	}

	auto numLockedAch = lockedAchievements.size();
	if (numLockedAch > 0)
	{
		int indexToUnlock = rand() % numLockedAch;
		const LockedAchData& lockedAchData = lockedAchievements[indexToUnlock];

		client->m_seshatProfile->SetAchievementProgress(lockedAchData.index, lockedAchData.quantity);

		Json::Value jUpdate, jAchiev;
		jAchiev["type"] = lockedAchData.type;
		jAchiev["progress"] = lockedAchData.quantity;
		jUpdate.append(std::move(jAchiev));
		ServerSendAchievementProgress(client, jUpdate);
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::AccelerateAchievements(const GSClient* client)
{
	Json::Value jUpdate;

	const Json::Value& jAchievements = AchievementsManager::Get()->GetAchievements();
	for (int achIdx = 0; achIdx < static_cast<int>(jAchievements.size()); achIdx++)
	{
		double progress = client->m_seshatProfile->GetAchievementProgress(achIdx);

		const Json::Value& jAchiev = jAchievements[achIdx];
		for (const Json::Value &jMilestone : jAchiev["milestones"])
		{
			double targetQty = jMilestone["qty"].asDouble() - 1;
			if (progress < targetQty)
			{
				client->m_seshatProfile->SetAchievementProgress(achIdx, targetQty);

				Json::Value jTempAchiev;
				jTempAchiev["type"] = jAchiev["type"].asUInt();
				jTempAchiev["progress"] = targetQty;
				jUpdate.append(std::move(jTempAchiev));

				break;
			}
		}
	}

	if (!jUpdate.empty())
	{
		ServerSendAchievementProgress(client, jUpdate);
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ServerSendAchievementProgress(const GSClient* client, const Json::Value &jUpdate)
{
	NetworkMessageW msgAchievements;
	msgAchievements.addGameMessageType(TCPMSG_SERVER_ACHIEVEMENTS_UPDATE);
	msgAchievements.addString((const unsigned char*)Json::FastWriter().write(jUpdate).c_str());
	msgAchievements.packMessage(client->m_Crypto);

	if (msgAchievements.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendAchievementProgress packet memory overflow\n");
	}
	bool bResult = ServerSendMessage(client->m_credential, (char*)msgAchievements.getMessageBody(), msgAchievements.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendAchievementProgress send message failed\n");
	}
}

////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::IsAchievementCompleted(GSClient *client, int type, int tier)
{
	int achIdx = AchievementsManager::Get()->GetAchievementIndexFromType(type);
	double progress = client->m_seshatProfile->GetAchievementProgress(achIdx);
	int claimed = client->m_seshatProfile->GetAchievementClaimed(achIdx);
	if ((claimed & (1 << tier)) != 0)
		return true; // already claimed this tier

	const Json::Value &achiev = AchievementsManager::Get()->GetAchievement(achIdx);
	if (achiev["milestones"][tier]["qty"].asDouble() <= progress)
		return true; // you must construct additional progress

	return false;
}

////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ClaimAchievementReward(GSClient *client, int type, int tier)
{
	int achIdx = AchievementsManager::Get()->GetAchievementIndexFromType(type);
	double progress = client->m_seshatProfile->GetAchievementProgress(achIdx);
	int claimed = client->m_seshatProfile->GetAchievementClaimed(achIdx);
	if ((claimed & (1 << tier)) != 0)
		return; // already claimed this tier

	const Json::Value &achiev = AchievementsManager::Get()->GetAchievement(achIdx);
	if (achiev["milestones"][tier]["qty"].asDouble() > progress)
		return; // you must construct additional progress

	client->m_seshatProfile->StartTrackingInventoryChanges("reward:achievement");
	for (const Json::Value &jReward : achiev["milestones"][tier]["reward"])
	{
		const HestiaConfig::Credit* credit = client->GetHestiaConfig()->FindCredit(jReward["id"].asUInt());
		if (!credit)
			MP_LOG(DBG_CRIT, "GameServerFedManager: ClaimAchievementReward missing item with hash = %d\n", jReward["id"].asUInt());
		client->GetHestiaConfig()->ChangeCreditBalance(client, credit, jReward["qty"].asInt());
	}
	auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
	if (!inventory_changes.empty())
	{
		ServerSendInventoryUpdate(client, 0, std::move(inventory_changes));
	}

	claimed |= (1 << tier);
	client->m_seshatProfile->SetAchievementClaimed(achIdx, claimed);

	Json::Value jUpdate, jAchiev;
	jAchiev["type"] = achiev["type"].asUInt();
	jAchiev["claimed"] = claimed;
	jUpdate.append(std::move(jAchiev));
	ServerSendAchievementProgress(client, jUpdate);

	AddAchievementProgress(client, StringHash("claim.achievement"), 1);
}

