void GameServerFedManager::HandleEventCommand(GSClient* client, EventMessageCommand command, const std::string& eventId, int missionIndex, int chapterIndex)
{
	switch (command)
	{
		case EventMessageCommand::RestartCoopEvent:
		{
			GLF_ASSERTMSG(false, "Received EventMessageCommand::RestartCoopEvent which is no longer supported");
			MP_LOG(DBG_CRIT, "HandleEventCommand RestartEvent which is no longer supported %s coop == %s\n", client->m_credential.c_str(), eventId.c_str());

			//const ServerEvent *coop = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_COOP);
			//if (!coop)
			//{
			//	MP_LOG(DBG_CRIT, "HandleEventCommand RestartEvent %s coop == NULL\n", client->m_credential.c_str());
			//	break;
			//}

			//auto eventData = m_eventsData->GetCoopEventData(coop->GetPreset());

			//// --- change from Maria - reset the event to the beginning of the current chapter instead of the beginning of the first chapter
			//// --- v2 - if the user's event weapon doesn't meet the gating of the first mission in the current chapter, go one chapter back
			//const auto& milestones = coop->GetMilestones();
			//auto currentMilestone = client->m_seshatProfile->GetEventMilestone(coop->GetID());
			//if (currentMilestone > (short)milestones.size() - 1)
			//{
			//	currentMilestone = (short)milestones.size() - 1;
			//}
			//// --- if the current chapter is locked (currentMilestone == unlockedChapter), then go to previous milestone on restart
			//auto unlockedChapter = coop->GetUnlockedChapter();
			//if (unlockedChapter > -1 && currentMilestone == unlockedChapter)
			//	currentMilestone = unlockedChapter - 1;
			//auto currentMilestoneProgress = currentMilestone < 0 ? 0 : milestones[currentMilestone].targetValue;

			//// --- compute user's damage for the event weapon
			//auto eventWeapon = eventData.ForcedWeapon();
			//auto eventWeaponDamage = m_weaponsData->GetCurrentWeaponClassDamage(client, nullptr, eventWeapon);
			//// --- get the gating on the first mission of the chapter
			//auto requiredDamage = eventData.MissionRequirement(currentMilestoneProgress, "Damage");
			//if (eventWeaponDamage < requiredDamage)
			//{
			//	currentMilestone = std::max(-1, currentMilestone - 1);
			//	currentMilestoneProgress = currentMilestone < 0 ? 0 : milestones[currentMilestone].targetValue;
			//}

			//client->m_seshatProfile->ResetEventProgress(coop->GetID(), currentMilestone, currentMilestoneProgress);
			////client->m_seshatProfile->ResetEventProgress(coop->GetID());

			//ServerSendEventUpdate(client, coop->GetID());
			//ScriptRequestEventsInfo(client);

			//// --- update variable prices
			//auto var_price_changes = client->GetHestiaConfig()->UpdateInventoryVariablePrice(client);
			//if (!var_price_changes.empty())
			//{
			//	ServerSendInventoryUpdate(client, "_variable_prices", std::move(var_price_changes));
			//}

			break;
		}
		case EventMessageCommand::SkipCoopMission:
		{
			const SemEvent *coop = client->FindEvent(eventId);
			if (!coop)
			{
				MP_LOG(DBG_CRIT, "HandleEventCommand SkipMission %s coop == NULL for id %s\n", client->m_credential.c_str(), eventId.c_str());
				break;
			}

			// --- validate the received mission index is within the current progress
			auto maxProgress = client->m_seshatProfile->GetEventMaxProgress(eventId);
			if (missionIndex > maxProgress)
			{
				MP_LOG(DBG_CRIT, "HandleEventCommand SkipMission %s id %s sent mission index %d higher than max progress %d\n", client->m_credential.c_str(), eventId.c_str(), missionIndex, maxProgress);
				break;
			}

			// --- hack for coop event revamp - the progress is actually the current mission, so make it so
			// --- it won't go higher than max progress anyway due to the condition above
			auto progress = client->m_seshatProfile->GetEventProgress(eventId);
			client->m_seshatProfile->AddEventProgress(eventId, missionIndex - progress);

			// --- give mission rewards
			// --- create a fake mission uid for the first event mission from the first chapter
			// --- the actual mission doesn't matter, only the type, as for event missions the reward is based on the event progress
			MissionUid muid{ 0, m_missionsData->GetBlockIndex("Event"), 0 };
			auto eventData = GetAHEventsData()->GetCoopEventData(coop->GetPreset());
			auto weapon = eventData.ForcedWeapon(); // --- assume the mission was played using the event forced weapon
			int64_t xp = 0, sc = 0;
			MissionCompletedRewards(client, muid, Hash(weapon), false, eventId, nullptr, &xp, &sc);

			client->GetHestiaConfig()->ChangeCreditBalance(client, SESHAT_LABEL_XP, xp);
			client->GetHestiaConfig()->ChangeCreditBalance(client, "sc", sc);

			auto dropData = MissionDropChances(client, muid, eventId);
			DropMissionEndStuff(client, nullptr, 0, dropData);

			//MP_LOG(DBG_INFO, "HandleEventCommand SkipMission max progress before increase %d\n", client->m_seshatProfile->GetEventMaxProgress(coop->GetID()));

			// --- mark the mission as completed
			client->m_seshatProfile->AddEventScore(coop->GetID(), 1);
			client->m_seshatProfile->AddEventProgress(coop->GetID(), 1);
			ServerSendEventUpdate(client, coop->GetID());

			//MP_LOG(DBG_INFO, "HandleEventCommand SkipMission max progress after increase %d\n", client->m_seshatProfile->GetEventMaxProgress(coop->GetID()));

			// --- post new score only if ranked - newer coop events aren't ranked
			if (coop->IsRanked())
			{
				Json::Value jRankedScores(Json::arrayValue);
				jRankedScores[0u]["event_id"] = coop->GetID();
				jRankedScores[0u]["event_score"] = client->m_seshatProfile->GetEventScore(coop->GetID());
				ScriptPostEventRankedScore(client, jRankedScores);
			}

			break;
		}
		case EventMessageCommand::RefreshEvents:
		{
			ScriptRequestEventsInfo(client);
			break;
		}
		case EventMessageCommand::FinishCoopEvent:
		{
			const SemEvent *coop = client->FindEvent(eventId);
			if (!coop)
			{
				MP_LOG(DBG_CRIT, "HandleEventCommand FinishCoopEvent %s coop == NULL\n", client->m_credential.c_str());
				break;
			}
			client->m_seshatProfile->SetEventFinishedWithRank(eventId, 42); // --- because why not - just mark it as finished so it can get erased

			ScriptRequestEventsInfo(client);

			break;
		}
		case EventMessageCommand::SkipBountyMission:
		{
			const auto bountyEvent = client->FindEvent(eventId);
			if (!bountyEvent)
			{
				MP_LOG(DBG_CRIT, "HandleEventCommand SkipBountyMission %s bountyEvent == NULL\n", client->m_credential.c_str());
				break;
			}

			// --- compute missionIndex (the received one is within chapter chapterIndex)
			auto eventData = m_eventsData->GetBountyEventData(bountyEvent->GetPreset());
			auto chapterMissionCount = eventData.ChapterData(0).MissionCount();
			auto progressMissionIndex = missionIndex + chapterIndex * chapterMissionCount;

			// --- validate the received mission index is within the current progress
			auto maxProgress = client->m_seshatProfile->GetEventMaxProgress(eventId);
			if (progressMissionIndex > maxProgress)
			{
				MP_LOG(DBG_CRIT, "HandleEventCommand SkipMission %s id %s sent mission index %d higher than max progress %d\n", client->m_credential.c_str(), eventId.c_str(), missionIndex, maxProgress);
				break;
			}

			// --- the progress is actually the current mission, so make it so
			// --- it won't go higher than max progress anyway due to the condition above
			auto progress = client->m_seshatProfile->GetEventProgress(eventId);
			client->m_seshatProfile->AddEventProgress(eventId, progressMissionIndex - progress);

			// --- give mission rewards
			// --- leave an invalid MissionUid - should direct to the bounty rewards code path (based on the eventId and the current event progress)
			auto dropData = MissionDropChances(client, MissionUid(), eventId);
			DropMissionEndStuff(client, nullptr, 0, dropData);

			// --- mark the mission as rewarded
			if (!client->m_seshatProfile->GetBountyMissionRewarded(eventId, chapterIndex, missionIndex))
				client->m_seshatProfile->SetBountyMissionRewarded(eventId, chapterIndex, missionIndex);

			// --- mark the mission as completed
			client->m_seshatProfile->AddEventProgress(eventId, 1);
			ServerSendEventUpdate(client, eventId);

			break;
		}
		case EventMessageCommand::ResetBountyBombAnim:
		case EventMessageCommand::ResetBountyFragmentAnim:
		case EventMessageCommand::ResetBountyBossAnim:
		{
			const auto bountyEvent = client->FindEvent(eventId);
			if (!bountyEvent)
			{
				MP_LOG(DBG_CRIT, "HandleEventCommand %d %s bountyEvent == NULL\n", command, client->m_credential.c_str());
				break;
			}

			switch (command)
			{
			case EventMessageCommand::ResetBountyBombAnim:
				client->m_seshatProfile->ResetBountyBombAnim(eventId, chapterIndex);
				break;
			case EventMessageCommand::ResetBountyFragmentAnim:
				client->m_seshatProfile->ResetBountyMapFragmentAnim(eventId, chapterIndex);
				break;
			case EventMessageCommand::ResetBountyBossAnim:
				client->m_seshatProfile->ResetBountyBossAnim(eventId, chapterIndex);
				break;
			}

			break;
		}
		case EventMessageCommand::FinishBountyEvent:
		{
			auto bountyEvent = client->FindEvent(eventId);
			if (!bountyEvent)
			{
				MP_LOG(DBG_CRIT, "HandleEventCommand FinishBountyEvent %s bounty == NULL\n", client->m_credential.c_str());
				break;
			}
			client->m_seshatProfile->SetEventFinishedWithRank(eventId, 42); // --- because why not - just mark it as finished so it can get erased

			ScriptRequestEventsInfo(client);

			break;
		}
		case EventMessageCommand::SkipMiniopsMission:
		{
			const auto miniopsEvent = client->FindEvent(eventId);
			if (!miniopsEvent)
			{
				MP_LOG(DBG_CRIT, "HandleEventCommand SkipMiniopsMission %s miniopsEvent == NULL\n", client->m_credential.c_str());
				break;
			}

			// --- compute missionIndex (the received one is within chapter chapterIndex)
			auto eventData = m_eventsData->GetMiniopsEventData(miniopsEvent->GetPreset());

			// --- take energy
			const auto& energyData = eventData.PveEnergy();
			auto energyCreditHash = StringHash(energyData["id"].asCString());
			auto energyCost = energyData["qty"].asInt();
			auto energyCredit = client->GetHestiaConfig()->FindCredit(energyCreditHash);
			auto energyAmount = client->GetHestiaConfig()->GetCreditBalance(client, energyCredit);

			if (energyAmount < energyCost)
			{
				MP_LOG(DBG_CRIT, "HandleEventCommand SkipMiniopsMission %s wihtout enough energy\n", client->m_credential.c_str());
				break;
			}

			client->GetHestiaConfig()->ChangeCreditBalance(client, energyCredit, -energyCost);

			// --- give the event item for skip
			auto skipEventItemQty = eventData.SkipEventItemQty();
			client->GetHestiaConfig()->ChangeCreditBalance(client, eventData.EventItem(), skipEventItemQty);

			// --- TODO: what about MissionCompletedRewards?

			// --- give mission rewards
			// --- leave an invalid MissionUid - should direct to the miniops rewards code path (based on the eventId)
			auto dropData = MissionDropChances(client, MissionUid(), eventId);
			DropMissionEndStuff(client, nullptr, 0, dropData);

			ServerSendEventUpdate(client, eventId);

			break;
		}
		case EventMessageCommand::ResetEventStat:
		{
			// --- TODO: this is really bad... move params of command to a json...
			auto statId = StringHash(missionIndex);
			auto statValue = chapterIndex;
			if (statId == "unlock_notified")
				client->m_seshatProfile->ResetEventStat(eventId, "unlock_notified", statValue);
			else if (statId == "end_notified")
				client->m_seshatProfile->ResetEventStat(eventId, "end_notified", statValue);
			else if (statId == "collected")
				client->m_seshatProfile->ResetEventStat(eventId, "collected", statValue);
			else if (statId == "end_notified")
				client->m_seshatProfile->ResetEventStat(eventId, "end_notified", statValue);
			break;
		}
	}
}

