void GameServerFedManager::ScriptRequestSeshatProfile(GSClient* client)
{
	Json::Value jsonDevice;
	jsonDevice["id"]		= client->m_deviceInfo.deviceId;
	jsonDevice["model"]		= client->m_deviceInfo.model;
	jsonDevice["carrier"]	= client->m_deviceInfo.carrier;
	jsonDevice["country"]	= client->m_countryCode;
	jsonDevice["language"]	= client->m_language;

	std::map<std::string, std::string> customParams = {
		{ "access_token",	client->GetAccessToken() },
		{ "credential",		client->m_credential },
		{ "device_info",	Json::FastWriter().write(jsonDevice) },
		{ "etag_for",		SESHAT_ETAG_FOR },
	};

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	void* userData = (void*) 0;

	SetIAPPendingRequest(client, true);	// --- set it to true here, and to false when only when sending the profile to client
	
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_SESHAT_PROFILE)->second, client->m_clientId, customParams, beneficiaries, callbackScriptGetSeshatProfile, this, userData);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetSeshatProfile(const SRequest& requestData)
{
	//MP_LOG(DBG_INFO, "Callback get_profile code %s response %s\n", requestData.m_code.c_str(), requestData.m_requestResponse.c_str());
	MP_LOG(DBG_INFO, "Callback get_profile code %s profile %s\n", requestData.m_code.c_str(), requestData.m_beneficiaires[0].c_str());

	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);

	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(credential);

	if(client == NULL)
	{
		MP_LOG(DBG_INFO, "Profile returned for non-existing user %s!\n", credential.c_str());
		return;
	}

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "Server request error on get_profile for %s, request error %d!\n", credential.c_str(), requestData.m_errorCode);
		callerObj->RemoveClient(credential);
		return;
	}


	const size_t opCode		= (size_t)requestData.m_userData;
	bool flushProfile	= false; // --- will be set true if this step makes profile changes that affect the hestia config

	Json::Value json/*, jsonSeshatString*/;
	Json::Reader		reader;
	Json::FastWriter	writer;

	reader.parse(requestData.m_requestResponse, json);

	int status = json["status"].asUInt();

	MP_LOG_USER(credential.c_str(), "GameServerFedManager::callbackScriptGetSeshatProfile status %d\n", status);

	//if response status is not OK(200) and not "profile not found"(404) it means it's unknown error so return
	if( (status != 200) && (status != 404) )
	{
		MP_LOG(DBG_WARN, "Did not receive profile for %s - status %d, reason %s !\n", credential.c_str(), status, json["reason"].asCString());
		callerObj->RemoveClient(credential);
		return;
	}
	
	//jsonSeshatString = json.get("seshat", Json::nullValue);
	Json::Value nv(Json::nullValue);
	const Json::Value& jsonSeshatString = json.isMember("seshat") ? json["seshat"] : nv;

	Json::Value jsonSeshat(Json::nullValue);
	if (!jsonSeshatString.isNull())
	{
		std::string jsonSeshatStr = jsonSeshatString.asCString();

//		jsonSeshatStr = "\\ude0eabc\\ud800\\ud800\\udf00\\uDE0E0\\udeuabc";

		char* c = &jsonSeshatStr[0];
		char* e = c + jsonSeshatStr.length();

		auto isHexDigit  = [](char c) -> bool { return (c >= '0' && c <= '9') || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F'); };
		auto isHexDigit8 = [](char c) -> bool { return (c >= '8' && c <= '9') || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F'); };

		while (c < e)
		{
			char* c1 = strstr(c, "\\uD");
			c = strstr(c, "\\ud");
			if (!c && c1)
				c = c1;
			else if (c1 && c1 < c)
				c = c1;
			if (!c || c >= e)
				break;

			c++;
			c++;
			if (isHexDigit8(*c))	// --- found a surrogate character, check for validity
			{
				if (e - c < 4)	// --- string too short
				{
					*(c - 2) = '?';
					*(c - 1) = '?';
					flushProfile = true;
					continue;
				}

				unsigned s1;
				std::string n(c, c + 4);
				if (!isHexDigit(n[0]) || !isHexDigit(n[1]) || !isHexDigit(n[2]) || !isHexDigit(n[3]))
				{
					*(c - 2) = '?';
					*(c - 1) = '?';
					flushProfile = true;
					continue;
				}
				if (sscanf(n.c_str(), "%04x", &s1) < 1)
				{
					*(c - 2) = '?';
					*(c - 1) = '?';
					flushProfile = true;
					continue;
				}

				if (s1 >= 0xdc00 && s1 <= 0xdfff)	// --- unpaired second surrogate
				{
					memcpy(c, "fffd", 4);
					flushProfile = true;
					continue;
				}

				if (s1 >= 0xd800 && s1 <= 0xdbff)	// --- first surrogate, look for second
				{
					char* d = c + 4;
					if (e - d < 6)	// --- string too short
					{
						memcpy(c, "fffd", 4);
						flushProfile = true;
						continue;
					}

					if (d[0] != '\\' || d[1] != 'u')	// --- not followed by another unicode
					{
						memcpy(c, "fffd", 4);
						flushProfile = true;
						continue;
					}

					d += 2;
					unsigned s2;
					std::string n2(d, d + 4);
					if (!isHexDigit(n2[0]) || !isHexDigit(n2[1]) || !isHexDigit(n2[2]) || !isHexDigit(n2[3]))
					{
						memcpy(c, "fffd", 4);
						flushProfile = true;
						continue;
					}
					if (sscanf(n2.c_str(), "%04x", &s2) < 1)	// --- invalid unicode
					{
						memcpy(c, "fffd", 4);
						flushProfile = true;
						continue;
					}

					if (s2 < 0xdc00 || s2 > 0xdfff)	// --- not a second surrogate
					{
						memcpy(c, "fffd", 4);
						flushProfile = true;
						continue;
					}

					c = d;	// --- found it, skip it
				}
			}
		}

		reader.parse(jsonSeshatStr, jsonSeshat, false);
	}
	

	const auto& constProfile = (const Json::Value&)jsonSeshat;
	MP_LOG_USER(credential.c_str(), "GameServerFedManager::callbackScriptGetSeshatProfile stats %s\n", Json::FastWriter().write(constProfile[SESHAT_GAME_SAVE][SESHAT_LABEL_STATISTICS]).c_str());
	

	//cache the access token
	const Json::Value& jsonAccessToken = json.isMember("access_token") ? json["access_token"] : nv;
	client->UpdateAccessTokenFromJson(jsonAccessToken/*requestData.m_requestResponse*/);

	//init profile if needed
	if(jsonSeshat == Json::nullValue || jsonSeshat[SESHAT_GAME_SAVE].isNull() || jsonSeshat[SESHAT_GAME_SAVE].empty())
	{
		if(jsonSeshat != Json::nullValue)
		{
			//this is to add "install_verified" field in m_jsonProfile to be checked later. Otherwise it's not saved at first run. Init only adds data to game_save
			client->m_seshatProfile->SetProfile(jsonSeshat);
		}

		// --- get the fed id from the access token
		{
			Json::Value jToken;
			std::string fedid;
			auto ok = Json::Reader().parse(jsonAccessToken.asString(), jToken);
			if (ok)
			{
				fedid = jToken[SESHAT_FED_ID_LABEL].asString();
			}
			
			if (ok && !fedid.empty())
			{
				callerObj->SetClientFedId(client, fedid);
			}
			else
			{
				MP_LOG(DBG_CRIT, "callbackScriptGetSeshatProfile: could not get fedid from access token ok %d emtpy %d; credential = %s - requesting it separately\n", ok, fedid.empty(), credential.c_str());
				GameServerFedManager::Instance()->ScriptRequestFedId(client);
			}
		}

		//Init only adds data to game_save
		client->m_seshatProfile->InitProfile(callerObj->m_initial_profile, "NEW PROFILE");
		//client->m_seshatProfile->NormalizeInventory();

		flushProfile = true;
	}
	else
	{
		// --- save etags
		client->m_seshatProfile->SetEtags(json["etags"]);

		client->m_seshatProfile->SetProfile(jsonSeshat);

		callerObj->SetClientFedId(client, jsonSeshat[SESHAT_FED_ID_LABEL].asString());

		//Json::Value jsonStats;
		//client->m_seshatProfile->GetStatistics(jsonStats);
		//client->m_seshatProfile->NormalizeInventory();
		//MP_LOG(DBG_INFO, "--callbackScriptGetSeshatProfile %s, multiplayer statistics: %s", client->m_credential.c_str(), Json::FastWriter().write(jsonStats).c_str());
	}

	if (client->m_seshatProfile->UpdateProfileVersion())
	{
		//client->m_seshatProfile->NormalizeInventory();
		flushProfile = true;
	}

	if (!client->m_seshatProfile->UpdateClientProfileVersion())
	{
		Json::Value obj;
		obj["update"] = "mandatory";

		callerObj->ServerSendBannedMessage(client->m_credential, Json::FastWriter().write(obj));
		client->m_seshatProfile->SetSafeToSave(false);
		callerObj->RemoveClient(credential);
		return;
	}

	client->m_lastTimeProfileSaved = OS_GetTime();
	
	//update profile with country and language
	{
		const char* country = client->m_seshatProfile->GetCountryCode();
		if( country == NULL || client->m_countryCode != std::string(country) )
		{
			client->m_seshatProfile->SetCountryCode( client->m_countryCode.c_str() );
			flushProfile = true; // --- affects the hestia config, should flush profile right away and request the get_config request
		}
		const char* language = client->m_seshatProfile->GetLanguage();
		if( language == NULL || client->m_language != std::string(language) )
		{
			client->m_seshatProfile->SetLanguage( client->m_language.c_str() );
			flushProfile = true; // --- affects the hestia config, should flush profile right away and request the get_config request
		}
		auto clientId = client->m_seshatProfile->GetCurrentClientId();
		if (clientId.empty() || client->m_clientId != clientId)
		{
			client->m_seshatProfile->SetProfileSavedStatus(false);
			flushProfile = true; // --- affects the hestia config, should flush profile right away and request the get_config request
		}

		// no need for this - all profile versions updates are flushed
		//if (callerObj->m_RequestsManager->GetClientId() != client->m_seshatProfile->GetCurrentClientId())
		//{
		//	// profile should already be changed by UpdateProfileVersion
		//	// if nothing is changed in the profile, the "current_client_id" field will not be updated by seshat

		//	flushProfile = true; // --- affects the hestia config, should flush profile right away and request the get_config request
		//}

		std::string deviceId = client->m_seshatProfile->GetDeviceId();
		if( client->m_deviceInfo.deviceId != deviceId )
		{
			client->m_seshatProfile->SetDeviceId(client->m_deviceInfo.deviceId);
		}
		
	}

	//if ban struct present then send ban message and skip profile init
	if( client->m_seshatProfile->IsBannedFromGame())
	{
		callerObj->ServerSendBannedMessage(credential, writer.write(jsonSeshat[SESHAT_BANNED_FROM]));
		callerObj->SetIAPPendingRequest(client, false);
		return;
	}

	// --- get an alias if we don't have one assigned
	if (!client->m_seshatProfile->HasAlias())
		callerObj->ScriptGetAlias(client);

	callerObj->CheckDailyLoginV2(client);

	callerObj->CheckDailyLogin(client);
	callerObj->CheckComebackRewardTimestamp(client);

	// --- received both the profile and the config
	// --- check if we need to trigger another refresh caused by the cohort (basically the same path as a country change - flushProfile)
	if (client->GetHestiaConfig() &&
		!client->GetHestiaConfig()->GetCohort().empty() &&
		client->m_seshatProfile->GetCohort() != client->GetHestiaConfig()->GetCohort())
	{
		// --- so we received a valid cohort in the config which isn't in the profile
		// --- start a profile flush and wait for it to end in order to trigger another hestia refresh and send the data to the client
		client->m_seshatProfile->SetCohort(client->GetHestiaConfig()->GetCohort());
		flushProfile = true;
	}

	// --- if there was a config-changing operation, flush the profile and mark the initial hestia request as invalid
	if (flushProfile)
	{
		callerObj->ScriptSetSeshatProfile(credential, client, E_SSPRF_REQUEST_CONFIG);
		client->m_ignoreInitialHestiaRequest = true;
		client->m_hestiaRequestState = GSClient::CHRS_NONE;
		client->SetHestiaConfig(nullptr);
		client->m_seshatProfile->MarkSendToPlayer(true); // --- send the profile to the client when both hestia and seshat are available
		MP_LOG(DBG_INFO, "callbackScriptGetSeshatProfile: flush profile, ignore next hestia config\n");
		return; // --- don't do any more operations even if the hestia config has arrived (it should be ignored, as it's not correct)
	}

	//send profile to player
	// --- only if hestia config arrived first
	if (client->GetHestiaConfig())
	{
		callerObj->OnInitialDataRequestsComplete(client);

		// after receiving both seshat profile and hestia config, request event details from osiris
		callerObj->ScriptRequestEventsInfo(client);
	}
	else
	{
		client->m_seshatProfile->MarkSendToPlayer(true);
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

struct ProfileForOtherParams
{
	std::string credential;
	E_ProfileOperation reason;
	std::string custom_data;
};

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptRequestSeshatProfileForOther(GSClient* client, const std::string &credential, E_ProfileOperation reason, std::string custom_data)
{
	std::map<std::string, std::string> customParams;
	customParams["credential"] = credential;
	customParams["access_token"] = GetAccessToken(credential);
	customParams["include_fields"] = SeshatProfileManager::GetOpponentProfileFieldsForPVP();
	
	if (reason == E_ProfileOperation::EPO_DEFENSE_SUCCESSED
		|| reason == E_ProfileOperation::EPO_ATTACK_AVOIDED
		|| reason == E_ProfileOperation::EPO_DEFENSE_FAILED
		)
	{
		customParams["include_fields"] = SESHAT_DEFENDER_LEADERBOARD;
	}

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	auto ppo = new ProfileForOtherParams;
	ppo->credential = credential;
	ppo->reason = reason;
	ppo->custom_data = custom_data;

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_SESHAT_PROFILE)->second, client->m_clientId, customParams, beneficiaries, callbackScriptGetSeshatProfileForOther, this, ppo);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetSeshatProfileForOther(const SRequest& requestData)
{
	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(credential);

	std::unique_ptr<ProfileForOtherParams> req_params((ProfileForOtherParams*)requestData.m_userData);

	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "Profile get for other returned for non-existing user %s!\n", credential.c_str());
		return;
	}

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "Server request error on get_profile for other, request error %d!\n", requestData.m_errorCode);
		return;
	}

	Json::Value json/*, jsonSeshatString*/;
	Json::Reader		reader;

	reader.parse(requestData.m_requestResponse, json);

	int status = json["status"].asUInt();
	const Json::Value& jsonAccessToken = json.isMember("access_token") ? json["access_token"] : Json::nullValue;

	//if response status is not OK(200) and not "profile not found"(404) it means it's unknown error so return
	if ((status != 200))
	{
		MP_LOG(DBG_WARN, "Did not receive profile for other - status %d, reason %s !\n", status, json["reason"].asCString());
		return;
	}

	callerObj->UpdateAccessTokenFromJson(json["credential"].asString(), jsonAccessToken);

	reader.parse(json["seshat"].asString(), json);

	switch (req_params->reason)
	{
	case E_ProfileOperation::EPO_REQUEST_REVENGE:
		json["revenge"] = true;
		json["credential"] = req_params->credential;
		client->m_seshatProfile->SetRevengeOpponent(json);
		break;
	case E_ProfileOperation::EPO_DEFENSE_SUCCESSED:
	case E_ProfileOperation::EPO_ATTACK_AVOIDED:
	case E_ProfileOperation::EPO_DEFENSE_FAILED:
		DefenderLeaderboard::Get()->ProcessDefenderScoreUpdate(client, req_params->credential, json, req_params->reason);
		break;
	default:
		GLF_ASSERTMSG(false, "ScriptRequestSeshatProfileForOther: Uknown deci reason");
		break;

	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptRequestSeshatProfileForOtherForDisplay(GSClient* client, const std::string &credential)
{
	std::map<std::string, std::string> customParams;
	customParams["credential"] = credential;
	customParams["access_token"] = GetAccessToken(credential);
	customParams["include_fields"] = SeshatProfileManager::GetProfileFieldsForDisplay();

	Json::Value *userJson = new Json::Value;
	(*userJson)["credential"] = credential;

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_SESHAT_PROFILE)->second, client->m_clientId, customParams, beneficiaries, callbackScriptGetSeshatProfileForOtherForDisplay, this, userJson);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetSeshatProfileForOtherForDisplay(const SRequest& requestData)
{
	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(credential);

	std::unique_ptr<Json::Value> userJson((Json::Value*)requestData.m_userData);

	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "Profile get for other for display returned for non-existing user %s!\n", credential.c_str());
		return;
	}

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "Server request error on get_profile for other for display, request error %d!\n", requestData.m_errorCode);

		Json::Value json2;
		json2["credential"] = (*userJson)["credential"];
		json2[SESHAT_GAME_SAVE]["error"] = requestData.m_errorCode;
		callerObj->ServerSendProfileForOtherPlayer(client, std::move(json2));

		return;
	}

	Json::Value json;
	Json::Reader reader;

	reader.parse(requestData.m_requestResponse, json);

	int status = json["status"].asUInt();
	const Json::Value& jsonAccessToken = json.isMember("access_token") ? json["access_token"] : Json::nullValue;

	//if response status is not OK(200) and not "profile not found"(404) it means it's unknown error so return
	if ((status != 200))
	{
		MP_LOG(DBG_WARN, "Did not receive profile for other for display - status %d, reason %s !\n", status, json["reason"].asCString());

		Json::Value json2;
		json2["credential"] = (*userJson)["credential"];
		json2[SESHAT_GAME_SAVE]["error"] = status;
		callerObj->ServerSendProfileForOtherPlayer(client, std::move(json2));

		return;
	}

	reader.parse(json["seshat"].asString(), json);
	callerObj->UpdateAccessTokenFromJson(json["credential"].asString(), jsonAccessToken);

	json["credential"] = (*userJson)["credential"];

	if (!callerObj->IsEloRanked(json[SESHAT_LABEL_PVP_STATS]))
	{
		auto md = callerObj->GetMultiplayerData();
		int elo = json[SESHAT_LABEL_PVP_STATS][SESHAT_LABEL_SCRATCHPAD][SESHAT_LABEL_ELO].asInt();
		auto eloSettings = callerObj->GetCurrentLadderSettings();
		elo = glf::Clamp(elo, md->GetMinElo(eloSettings), md->GetResetElo(eloSettings));
		json[SESHAT_LABEL_PVP_STATS][SESHAT_LABEL_SCRATCHPAD][SESHAT_LABEL_ELO] = elo;
	}

	callerObj->ServerSendProfileForOtherPlayer(client, std::move(json));
}

