void GameServerFedManager::ScriptRequestSeshatProfileField(const std::string& fields, std::unique_ptr<ProfileOperation> operation)
{
	std::map<std::string, std::string> customParams;
	customParams["credential"] = operation->for_credential;
	customParams["access_token"] = GetAccessToken(operation->for_credential);
	customParams["include_fields"] = 
		std::string(fields) +														","
		"credential"																","
		SESHAT_CURRENT_CLIENT_ID													","
		SESHAT_LABEL_LEVEL															","
		SESHAT_GAME_SAVE "." SESHAT_LABEL_PRESTIGE "." SESHAT_LABEL_PRESTIGE_LEVEL	","
		SESHAT_GAME_SAVE "." SESHAT_LABEL_HALL_OF_FAME								","
		SESHAT_GAME_SAVE "." SESHAT_LABEL_GET_OSIRIS_INFO;

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(operation->owner_credential);

	auto data = new ScriptRequestSeshatProfileField_Data;
	data->client = operation->owner_credential;
	data->credential = operation->for_credential;
	data->field = fields;
	data->operation = std::move(operation);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_SESHAT_PROFILE)->second, "", customParams, beneficiaries, callbackScriptGetSeshatProfileField, this, data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetSeshatProfileField(const SRequest& requestData)
{
	std::unique_ptr<ScriptRequestSeshatProfileField_Data> data((ScriptRequestSeshatProfileField_Data*)requestData.m_userData);

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "Server request error on get_profile for other, request error %d!\n", requestData.m_errorCode);
		return;
	}

	Json::Value json;
	Json::Reader reader;

	reader.parse(requestData.m_requestResponse, json);

	int status = json["status"].asUInt();
	const Json::Value& jsonAccessToken = json.isMember("access_token") ? json["access_token"] : Json::nullValue;

	if ((status != 200))
	{
		MP_LOG(DBG_WARN, "Did not receive profile for ScriptRequestSeshatProfileField - status %d, reason %s !\n", status, json["reason"].asCString());
		return;
	}

	GameServerFedManager::Instance()->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);

	reader.parse(json["seshat"].asString(), json);
	Multiplayer::OnProfileFieldRead(std::move(data->operation), std::move(json));
}

