//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptSetSeshatProfileField(const Json::Value& obj, std::unique_ptr<ProfileOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "credential",			operation->for_credential },
		{ "profile_obj",		Json::FastWriter().write(obj) },
		{ "selector",			"" },
		{ "client_id",			operation->client_id },
		{ "use_impersonation",	Json::FastWriter().write(operation->useImpersonation) },
	};

	if (operation->useImpersonation)
	{
		customParams["access_token"] = GetAccessToken(operation->for_credential);
	}
	else
	{
		customParams["access_token"] = GetAccessToken("game");
	}


	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(operation->owner_credential);

	auto data = new ScriptSetSeshatProfileField_Data;
	data->client = operation->owner_credential;
	data->credential = operation->for_credential;
	data->operation = std::move(operation);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_SET_OTHER_SESHAT_PROFILE)->second, "", customParams, beneficiaries, callbackScriptSetSeshatProfileField, this, data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptSetSeshatProfileField(const SRequest& requestData)
{
	std::unique_ptr<ScriptSetSeshatProfileField_Data> data((ScriptSetSeshatProfileField_Data*)requestData.m_userData);

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "Server request error on set_profile for other, request error %d!\n", requestData.m_errorCode);
		return;
	}

	Json::Value json;
	Json::Reader reader;

	reader.parse(requestData.m_requestResponse, json);

	int status = json["status"].asUInt();

	if (data->operation->useImpersonation)
	{
		const Json::Value& jsonAccessToken = json.isMember("access_token") ? json["access_token"] : Json::nullValue;
		GameServerFedManager::Instance()->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);
	}
	//else
	//{
	//	GameServerFedManager::Instance()->UpdateAccessTokenFromJson("game", jsonAccessToken);
	//}

	if (status == 200)
	{
		if (data->operation->operation == E_ProfileOperation::EPO_ADD_RECRUIT)
		{
			// --- if the client is still online, mark in the profile that we increased the referral user's recruits counter
			GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
			const std::string& credential = requestData.m_beneficiaires[0];
			GSClient* client = callerObj->GetClient(credential);

			// --- player is online, update his referral user
			if (client)
			{
				client->m_seshatProfile->SetReferralUser("");
			}
		}
		if (data->operation->operation == E_ProfileOperation::EPO_SAVE_REDEEM_PENDING_TRANSACTION)
		{

			GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
			const std::string& credential = requestData.m_beneficiaires[0];
			GSClient* client = callerObj->GetClient(credential);
			if (client)
			{
				//Instance()->ScriptRequestSeshatECommInventory(client, 0, false);
				Instance()->QueueIAPPendingRequests(client, 0, false);
			}

		}
		// for testing only
		if (data->operation->operation == E_ProfileOperation::EPO_SAVE_ADS_REWARD_PENDING_TRANSACTION)
		{

			GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
			const std::string& credential = requestData.m_beneficiaires[0];
			GSClient* client = callerObj->GetClient(credential);
			if (client)
			{
				Instance()->QueueIAPPendingRequests(client, 0, false);
			}

		}
		// end: for testing only
	}
}

