void GameServerFedManager::ScriptRequestSeshatECommInventory(GSClient* client, hash_t transactionId, bool suppress_no_change_error)
{
	std::map<std::string, std::string> customParams;
	customParams["credential"] = client->m_credential;
	customParams["access_token"] = client->GetAccessToken();
//	customParams["path"] = SESHAT_LABEL_PENDING_TRANSACTIONS;	// --- was: "inventory";
	customParams["include_fields"] =
		SESHAT_LABEL_PENDING_TRANSACTIONS											","
		SESHAT_LABEL_ACTIVE_SUBSCRIPTIONS;

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	void* userData = new ecommUserData(transactionId, suppress_no_change_error);
	
	SetIAPPendingRequest(client, true);
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_SESHAT_PROFILE)->second, client->m_clientId, customParams, beneficiaries, callbackScriptGetSeshatECommInventory, this, userData);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetSeshatECommInventory(const SRequest& requestData)
{
	MP_LOG(DBG_INFO, "Callback get_profile ecomm inventory code %s response %s\n", requestData.m_code.c_str(), requestData.m_requestResponse.c_str());

	std::unique_ptr<ecommUserData> pUserData((ecommUserData*)requestData.m_userData);

	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(credential);

	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "Profile ecomm inventory returned for non-existing user %s!\n", credential.c_str());
		return;
	}

	callerObj->SetIAPPendingRequest(client, false);

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "Server request error on get_profile ecomm inventory for %s, request error %d!\n", credential.c_str(), requestData.m_errorCode);
		// --- send error to client - there should be something there... 
		callerObj->ServerSendInventoryUpdate(client, pUserData->transactionId, TRS_HttpRequestError);
		return;
	}

	Json::Value json/*, jsonSeshat*/;
	Json::Reader		reader;

	reader.parse(requestData.m_requestResponse, json);

	int status = json["status"].asUInt();

	//if response status is not OK(200) and not "profile not found"(404) it means it's unknown error so return
	if ((status != 200))
	{
		MP_LOG(DBG_WARN, "Did not receive profile ecomm inventory for %s - status %d, reason %s !\n", credential.c_str(), status, json["reason"].asCString());
		// --- send error to client - there should be something there...
		callerObj->ServerSendInventoryUpdate(client, pUserData->transactionId, TRS_HttpRequestStatusError);
		return;
	}

	//cache the access token
	//Json::Value jsonAccessToken = json.get("access_token", Json::nullValue);
	const Json::Value nv(Json::nullValue);
	const Json::Value& jsonAccessToken = json.isMember("access_token") ? json["access_token"] : nv;

	client->UpdateAccessTokenFromJson(jsonAccessToken);

	const Json::Value& jsonSeshatString = json.isMember("seshat") ? json["seshat"] : nv;
	//jsonSeshat = json.get("seshat", Json::nullValue);

	Json::Value jsonSeshat(Json::nullValue);
	if (!jsonSeshatString.isNull())
	{
		std::string jsonSeshatStr = jsonSeshatString.asCString();
		reader.parse(jsonSeshatStr, jsonSeshat, false);
	}

	if (jsonSeshat == Json::nullValue || jsonSeshat.empty())
	{
		MP_LOG(DBG_WARN, "Empty profile ecomm inventory for %s - status %d, reason %s !\n", credential.c_str(), status, json["reason"].asCString());
		// --- send error to client - there should be something there...
		callerObj->ServerSendInventoryUpdate(client, pUserData->transactionId, TRS_EmptyECommInventory);
		return;
	}

	// --- update the key in the profile
	client->m_seshatProfile->SetPendingKey(SESHAT_LABEL_PENDING_TRANSACTIONS, jsonSeshat[SESHAT_LABEL_PENDING_TRANSACTIONS]);
	client->m_seshatProfile->SetPendingKey(SESHAT_LABEL_ACTIVE_SUBSCRIPTIONS, jsonSeshat[SESHAT_LABEL_ACTIVE_SUBSCRIPTIONS]);

	// --- start tracking game inventory changes
	client->m_seshatProfile->StartTrackingInventoryChanges();

	// --- check for ecomm modifications (IAPs)
	callerObj->m_hestiaConfigManager->UpdateInventoryFromIAP(client);

	// --- get the game inventory changes
	Json::Value inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();

	// --- send them to the client
	if (pUserData->suppress_no_change_error &&
		((inventory_changes.isInt() && inventory_changes.asInt() == TRS_NoChange) ||
			inventory_changes.empty()))
	{
		inventory_changes = Json::Value::null;
		inventory_changes["action"] = "restore";
		inventory_changes["error"] = TRS_Ok;
		callerObj->ServerSendInventoryUpdate(client, pUserData->transactionId, std::move(inventory_changes));
	}
	else
	{
		callerObj->ServerSendInventoryUpdate(client, pUserData->transactionId, std::move(inventory_changes));
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptRequestHestiaConfig(GSClient* client, E_HESTIA_REQUEST_TYPE requestType)
{
	std::map<std::string, std::string> customParams;
	customParams.insert(std::pair<std::string, std::string>("credential", client->m_credential));
	customParams.insert(std::pair<std::string, std::string>("access_token", client->GetAccessToken()));
	
	Json::Value jsonDevice;
	jsonDevice["id"] = client->m_deviceInfo.deviceId;
	jsonDevice["model"] = client->m_deviceInfo.model;
	jsonDevice["carrier"] = client->m_deviceInfo.carrier;
	jsonDevice["country"] = client->m_countryCode;
	jsonDevice["language"] = client->m_language;

	std::string device_str = Json::FastWriter().write(jsonDevice);
	customParams.insert(std::pair<std::string, std::string>("device_info", device_str));

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	void* userData = (void*)requestType;

	client->m_hestiaRequestState = GSClient::CHRS_IN_PROGRESS;
	
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_HESTIA_CONFIG)->second, client->m_clientId, customParams, beneficiaries, callbackScriptGetHestiaConfig, this, userData);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetHestiaConfig(const SRequest& requestData)
{
	MP_LOG(DBG_INFO, "Callback get_config code %s for %s\n", requestData.m_code.c_str(), requestData.m_beneficiaires[0].c_str());

	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(credential);

	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "Hestia config returned for non-existing user %s!\n", credential.c_str());
		return;
	}

	E_HESTIA_REQUEST_TYPE requestType = (E_HESTIA_REQUEST_TYPE)(size_t)requestData.m_userData;

	if (requestType == E_HRT_INITIAL && client->m_ignoreInitialHestiaRequest)
	{
		MP_LOG(DBG_INFO, "Hestia config initial request ignored for user %s!\n", credential.c_str());
		return;
	}

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "Server request error on get_config for %s, request error %d!\n", credential.c_str(), requestData.m_errorCode);
		callerObj->RemoveClient(credential);
		return;
	}

	Json::Value json;
	Json::Reader reader;
	reader.parse(requestData.m_requestResponse, json, false);

	int status = json["status"].asUInt();

	MP_LOG_USER(credential.c_str(), "GameServerFedManager::callbackScriptGetHestiaConfig status %d\n", status);

	//if response status is not OK(200) means it's an unknown error so return
	if (status != 200)
	{
		MP_LOG(DBG_WARN, "Did not receive config for %s - status %d, reason %s !\n", credential.c_str(), status, json["reason"].asCString());

		// --- this still could mean the user had no profile at the time of the request
		// --- in this case, don't remove the client, there will be another hestia request made after the seshat profile is written
		if (status != 404)
		{
			callerObj->RemoveClient(credential);
		}
		return;
	}

	const auto& jsonHestiaValue = json["hestia"];
	const char* jsonHestiaString = jsonHestiaValue.isNull() ? "" : jsonHestiaValue.asCString();
	int jsonHestiaStringSize = (int)strlen(jsonHestiaString);
	Json::Value jsonHestia(Json::nullValue);
	if (jsonHestiaStringSize)
		reader.parse(jsonHestiaString, jsonHestiaString + jsonHestiaStringSize + 1, jsonHestia);

	// -- test hack - activate to use the local game parameters instead of the one from CRM
	/*
	Json::Value document = GSReadJsonFile("..\\..\\..\\data\\crm\\game_parameters.json");
	if (document.isNull())
		return;

	jsonHestia["game"] = document;
	auto jsonHestiaHackString = jsonHestia.toCompactString();
	jsonHestiaString = jsonHestiaHackString.c_str();
	*/
	// --- end test hack

	client->SetGroupwareEvents(jsonHestia["groupware"]["events"]);

	// --- Set client's config
	HestiaConfigManager::HestiaSetConfigStatus config_status = callerObj->m_hestiaConfigManager->SetConfig(client, jsonHestiaString, std::move(jsonHestia));
	if (config_status == HestiaConfigManager::HSCS_ERROR)
	{
		MP_LOG(DBG_CRIT, "Hestia config not valid for %s - removing client!\n", credential.c_str());
		callerObj->RemoveClient(credential);
		return;
	}

	if (client->m_seshatProfile && !client->m_seshatProfile->IsInvalid())
	{
		client->m_seshatProfile->CheckAndCleanUpOldSpinWheelData();
		// after receiving both seshat profile and hestia config, request event details from osiris
		callerObj->ScriptRequestEventsInfo(client);
		
		if (client->GetHestiaConfig())
		{
			auto sevenDaysStringKey = client->GetHestiaConfig()->GlobalParameters().getMemberNames();
			for (auto it : sevenDaysStringKey)
			{
				if (it.find("seven_days_") != it.npos)
				{
					callerObj->CheckSevenDays(client, it);
				}
			}	

#ifdef SKIRMISH_EVENT
			if (!client->GetHestiaConfig()->GlobalParameters()["skirmish_schedule"].empty() &&
				!GameServerFedManager::Instance()->m_skirmishScheduleData.isNull())
			{
				callerObj->ServerSendSkirmishSchedule(client, GameServerFedManager::Instance()->m_skirmishScheduleData);
				callerObj->SetSkirmishSeasonData(client->GetHestiaConfig()->GlobalParameters()["skirmish_schedule"]);
				// if we use skirmish schedule from crom
				client->m_seshatProfile->ResetMPTLESeason();
			}
#endif // SKIRMISH_EVENT
		}
	}

	// --- Mark the request state
	client->m_hestiaRequestState = GSClient::CHRS_WAIT_PROFILE;

	// --- Cache the access token
	//Json::Value jsonAccessToken = json.get("access_token", Json::nullValue);
	const Json::Value& jsonAccessToken = json["access_token"];

	client->UpdateAccessTokenFromJson(jsonAccessToken);
}

