namespace
{
struct ScriptSetSeshatProfileUserData
{
	unsigned int requestFlags;
	time_t profileChangeTime;

	std::map<std::string, std::vector<std::string>> batchNull;
};

}	// --- namespace

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptSetSeshatProfile(const std::string &credential, GSClient* client, unsigned int requestFlags)
{
	if(client == NULL)
	{
		MP_LOG(DBG_WARN, "Trying to update profile for non-existing client %s!\n", credential.c_str());
		return;
	}

	//MP_LOG(DBG_INFO, "Profile: %s", client->m_seshatProfile->GetProfile().toStyledString().c_str());

	if (client->m_seshatProfile->IsInvalid())
	{
		return;
	}

	if( client->m_seshatProfile->IsBannedFromGame() )
	{
		return;
	}

	if (!client->m_seshatProfile->IsSafeToSave())
	{
		return;
	}

	if( !client->m_seshatProfile->IsProfileChanged())
	{
		if( requestFlags & E_SSPRF_SEND_CONFIRMATION )
		{
			MP_LOG(DBG_INFO, "Sending profile saved for %s even though no save was done - profile is not changed\n", client->m_credential.c_str());
			ServerSendProfileSaved( client->m_credential );
		}
		MP_LOG(DBG_INFO, "Profile not changed for %s\n", client->m_credential.c_str());
		//no need to flush to Seshat, nothing changed since last time!

		if (requestFlags & E_SSPRF_REQUEST_CONFIG)
		{
			ScriptRequestHestiaConfig(client, E_HRT_REFRESH);
		}

		return;
	}

	Json::Value jsonStats;
	client->m_seshatProfile->GetStatistics(jsonStats);

	MP_LOG(DBG_INFO, "--ScriptSetSeshatProfile %s, statistics: %s", client->m_credential.c_str(), Json::FastWriter().write(jsonStats).c_str());


	std::map<std::string, std::string> customParams;
	customParams.insert(std::pair<std::string, std::string>("credential", credential));
	customParams.insert(std::pair<std::string, std::string>("access_token", client->GetAccessToken()));
	customParams["client_id"] = client->m_clientId;

	client->m_seshatProfile->CountSaveProfile();	// --- to be sure we have something changed

	Json::FastWriter jsonWriter;
	Json::Value profileToWrite;
	const Json::Value& profile = client->m_seshatProfile->GetProfile();
	profileToWrite[SESHAT_GAME_SAVE] = profile[SESHAT_GAME_SAVE];
	profileToWrite[SESHAT_LABEL_COUNTRY] = profile[SESHAT_LABEL_COUNTRY];
	profileToWrite[SESHAT_LABEL_LANGUAGE] = profile[SESHAT_LABEL_LANGUAGE];
	profileToWrite[SESHAT_LABEL_LEVEL] = profile[SESHAT_LABEL_STANDARD_INVENTORY][SESHAT_LABEL_LEVEL];
	profileToWrite[SESHAT_LABEL_TOTAL_PLAYTIME] = profile[SESHAT_GAME_SAVE][SESHAT_LABEL_STATISTICS][SESHAT_LABEL_STATISTICS_SP]["time.played"].asUInt();
	profileToWrite[SESHAT_LABEL_XP] = profile[SESHAT_LABEL_STANDARD_INVENTORY][SESHAT_LABEL_XP];
	profileToWrite[SESHAT_LABEL_STANDARD_INVENTORY] = profile[SESHAT_LABEL_STANDARD_INVENTORY];
	profileToWrite[SESHAT_RANDOM_ENGINE] = client->m_seshatProfile->SerializeRandomEngines();
	profileToWrite[SESHAT_LABEL_MP_DEFENSE_SQUAD] = profile[SESHAT_LABEL_MP_DEFENSE_SQUAD];
	profileToWrite[SESHAT_LABEL_BIRTHDATE] = profile[SESHAT_LABEL_BIRTHDATE];
	profileToWrite[SESHAT_LABEL_GENDER] = profile[SESHAT_LABEL_GENDER];
	profileToWrite[SESHAT_LABEL_CUSTOM_MATCHERS] = profile[SESHAT_LABEL_CUSTOM_MATCHERS];
	profileToWrite[SESHAT_LABEL_LOCATION] = profile[SESHAT_LABEL_LOCATION];
	profileToWrite[SESHAT_LABEL_OPPONENTS] = profile[SESHAT_LABEL_OPPONENTS];
	profileToWrite[SESHAT_GACHA_LABEL] = profile[SESHAT_GACHA_LABEL];
	profileToWrite[SESHAT_LABEL_UR_SEM_EVENTS] = profile[SESHAT_LABEL_UR_SEM_EVENTS];
	profileToWrite[SESHAT_LABEL_MP_STATS] = profile[SESHAT_LABEL_MP_STATS];
	profileToWrite[SESHAT_LABEL_MP_STATS_PENDING] = profile[SESHAT_LABEL_MP_STATS_PENDING];
	profileToWrite[SESHAT_LABEL_MP_HOF] = profile[SESHAT_LABEL_MP_HOF];
	profileToWrite[SESHAT_LABEL_CONQUEST_STATS] = profile[SESHAT_LABEL_CONQUEST_STATS];
	profileToWrite[SESHAT_USER_TAGS] = profile[SESHAT_USER_TAGS];
	profileToWrite[SESHAT_LABEL_MP_TLE_STATS] = profile[SESHAT_LABEL_MP_TLE_STATS];
	profileToWrite[SESHAT_LABEL_MP_TLE_STATS_PENDING] = profile[SESHAT_LABEL_MP_TLE_STATS_PENDING];


	//Quyen rem to fix the pvp trophy reset issue
	/*const Json::Value& pvpStats = client->m_seshatProfile->GetCachedPvpStatsJson();
	if (pvpStats.isMember(SESHAT_LABEL_LEAGUE_DATA) && pvpStats[SESHAT_LABEL_LEAGUE_DATA].isMember(SESHAT_LABEL_VERSION))
	{
		profileToWrite[SESHAT_LABEL_PVP_STATS][SESHAT_LABEL_LEAGUE_DATA][SESHAT_LABEL_VERSION] = pvpStats[SESHAT_LABEL_LEAGUE_DATA][SESHAT_LABEL_VERSION];
	}
	else
	{
		profileToWrite[SESHAT_LABEL_PVP_STATS][SESHAT_LABEL_LEAGUE_DATA][SESHAT_LABEL_VERSION] = LEAGUE_MATCHER_VERSION;
	}
	profileToWrite[SESHAT_LABEL_PVP_STATS][SESHAT_LABEL_PVP_TROPHIES] = pvpStats.isMember(SESHAT_LABEL_PVP_TROPHIES) ? pvpStats[SESHAT_LABEL_PVP_TROPHIES] : Json::arrayValue;*/

	if (!client->m_seshatProfile->GetActivePresetIdToSave().empty())
	{
		profileToWrite[SESHAT_GAME_SAVE][SESHAT_LABEL_LOADOUT][SESHAT_LABEL_LOADOUT_AVATAR_PRESET] = client->m_seshatProfile->GetActivePresetIdToSave();
	}

	const auto& clanOppList = client->m_seshatProfile->GetClanOppponentsList();

	auto& jFoundOpponents = profileToWrite[SESHAT_LABEL_OPPONENTS][SESHAT_LABEL_OPPONENTS_METADATA][SESHAT_LABEL_CLAN_OPPONENTS_FOUND];
	jFoundOpponents.clear();
	for (auto hash : clanOppList.foundOpponents())
		jFoundOpponents.append(hash.GetHash());
	auto& jUsedClans = profileToWrite[SESHAT_LABEL_OPPONENTS][SESHAT_LABEL_OPPONENTS_METADATA][SESHAT_LABEL_CLAN_OPPONENTS_CLANS];
	jUsedClans.clear();
	for (auto hash : clanOppList.usedClans())
		jUsedClans.append(hash.GetHash());

	if (profile.isMember(SESHAT_GACHA_COUNTERS))
		profileToWrite[SESHAT_GACHA_COUNTERS] = profile[SESHAT_GACHA_COUNTERS];

	Json::Value toWriteSquadmates;
	auto& squadmates = profileToWrite[SESHAT_GAME_SAVE][SESHAT_LABEL_SQUAD_MATES][SESHAT_LABEL_SQUAD_MATES_DETAILS];
	for (auto it = squadmates.begin(); it != squadmates.end(); ++it)
	{
		client->m_seshatProfile->RemoveCardControlExtraData(&*it);
		client->m_seshatProfile->ReduceCardControlExtraData(&*it);
		auto& squadmate = toWriteSquadmates[(*it)[SESHAT_LABEL_SQUAD_MATES_CREDIT].asString()][it.memberName()];
		squadmate = std::move(*it);
		squadmate.removeMember(SESHAT_LABEL_SQUAD_MATES_CREDIT);
	}
	profileToWrite[SESHAT_GAME_SAVE].removeMember(SESHAT_LABEL_SQUAD_MATES);

	// --- compress squadmates dict
	{
		const auto& cmpResult = SeshatProfileManager::CompressJson(toWriteSquadmates);
		auto& compressedSquadmates = profileToWrite[SESHAT_GAME_SAVE][SESHAT_LABEL_SAVE_SQUAD_MATES_CMP];
		compressedSquadmates["data"] = std::get<0>(cmpResult);
		compressedSquadmates["size"] = std::get<1>(cmpResult);
	}

	// Reduce squad ops data by replace mission name with misison ID
	auto& squadOpsData = profileToWrite[SESHAT_GAME_SAVE][SESHAT_LABEL_SQUAD_OPS];	
	client->m_seshatProfile->ReduceSquadOpsExtraData(squadOpsData);

	// --- compress squad ops dict
	{		
		const auto& sqOpsCmpResult = SeshatProfileManager::CompressJson(squadOpsData);
		auto& compressedSquadOps = profileToWrite[SESHAT_GAME_SAVE][SESHAT_LABEL_SQUAD_OPS_CMP];
		compressedSquadOps["data"] = std::get<0>(sqOpsCmpResult);
		compressedSquadOps["size"] = std::get<1>(sqOpsCmpResult);
		profileToWrite[SESHAT_GAME_SAVE].removeMember(SESHAT_LABEL_SQUAD_OPS);
	}

	const auto& clanData = client->m_seshatProfile->GetClanData();
	if (!clanData.isNull() && !clanData[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID].asString().empty())
	{
		profileToWrite[SESHAT_LABEL_CLAN]["id"] = clanData[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID];
	}
	else
	{
		profileToWrite[SESHAT_LABEL_CLAN] = Json::nullValue;
	}

	if (client->m_seshatProfile->mustResetProfile)
	{
		profileToWrite[SESHAT_LABEL_PVP_STATS] = Json::objectValue;
		profileToWrite[SESHAT_LABEL_MP_STATS] = Json::objectValue;
		profileToWrite[SESHAT_LABEL_MP_TLE_STATS] = Json::objectValue;
		client->m_seshatProfile->mustResetProfile = false;
	}

	// --- special crm matchers
	profileToWrite[SESHAT_LABEL_STANDARD_INVENTORY]["cash"] = profileToWrite[SESHAT_LABEL_STANDARD_INVENTORY]["hc"];
	profileToWrite[SESHAT_LABEL_STANDARD_INVENTORY]["coins"] = profileToWrite[SESHAT_LABEL_STANDARD_INVENTORY]["sc"];
	
	auto created = profile["created"].asString();
	time_t now = GetCrtUTCTimeSeconds();
	time_t utc_time = now;
	SemEvent::parse_time(created.c_str(), utc_time);
	int hours = (int)((now - utc_time) / 3600);
	profileToWrite[SESHAT_LABEL_CUSTOM_MATCHERS][SESHAT_LABEL_HOURS_SINCE_FIRST_LAUNCH] = hours;
	profileToWrite[SESHAT_GAME_SAVE][SESHAT_LABEL_NOW] = (int)now;
	profileToWrite[SESHAT_LABEL_CUSTOM_MATCHERS][SESHAT_LABEL_TOTAL_PLAYTIME] = profile[SESHAT_LABEL_CUSTOM_MATCHERS][SESHAT_LABEL_TOTAL_PLAYTIME].asTimeT() + (now - client->m_delayAdsTimestamp);
	
	MP_LOG_USER(credential.c_str(), "GameServerFedManager::ScriptSetSeshatProfile stats %s\n", Json::FastWriter().write(profile[SESHAT_GAME_SAVE][SESHAT_LABEL_STATISTICS]).c_str());

	auto* pUserData = new ScriptSetSeshatProfileUserData;
	pUserData->requestFlags = requestFlags;
	pUserData->profileChangeTime = client->m_seshatProfile->ProfileChangedTime();

	// --- remove processed pending transactions
	{
		auto& pending_transactions = client->m_seshatProfile->GetPendingKey(SESHAT_LABEL_PENDING_TRANSACTIONS);
		for (auto& key : pending_transactions.getMemberNames())
		{
			if (pending_transactions[key].isNull())
			{
				std::string transaction_to_remove = SESHAT_LABEL_PENDING_TRANSACTIONS ".";
				transaction_to_remove += key;
				profileToWrite[transaction_to_remove] = Json::nullValue;

				pUserData->batchNull[SESHAT_LABEL_PENDING_TRANSACTIONS].push_back(key);
			}
			else if (pending_transactions[key].get("processed", false).asBool())
			{
				std::string transaction_to_remove = SESHAT_LABEL_PENDING_TRANSACTIONS ".";
				transaction_to_remove += key;
				transaction_to_remove += ".processed";
				profileToWrite[transaction_to_remove] = true;

				pUserData->batchNull[SESHAT_LABEL_PENDING_TRANSACTIONS].push_back(key);
			}
		}
	}
	{
		auto& pending_attacks = client->m_seshatProfile->GetPendingKey(SESHAT_PENDING_ATTACKS);
		for (auto& key : pending_attacks.getMemberNames())
		{
			if (pending_attacks[key].isNull())
			{
				std::string transaction_to_remove = SESHAT_PENDING_ATTACKS ".";
				transaction_to_remove += key;
				profileToWrite[transaction_to_remove] = Json::nullValue;

				pUserData->batchNull[SESHAT_PENDING_ATTACKS].push_back(key);
			}
		}
	}

	std::string profileStr = jsonWriter.write(profileToWrite);
	customParams.insert(std::pair<std::string, std::string>("profile_obj", profileStr));
	
	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(credential);

	client->m_profilePendingSave = true;

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_SET_SESHAT_PROFILE)->second, client->m_clientId, customParams, beneficiaries, callbackScriptSetSeshatProfile, this, (void*)(pUserData));
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptSetSeshatProfile(const SRequest& requestData)
{
	std::unique_ptr<ScriptSetSeshatProfileUserData> pUserData((ScriptSetSeshatProfileUserData*)requestData.m_userData);

	MP_LOG(DBG_INFO, "Callback set_profile code %s response %s\n", requestData.m_code.c_str(), requestData.m_requestResponse.c_str());

	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	GSClient* client = callerObj->GetClient(requestData.m_beneficiaires[0]);
	const std::string& credential = requestData.m_beneficiaires[0];

	if(client == NULL)
	{
		MP_LOG(DBG_WARN, "callbackScriptSetSeshatProfile Profile %s for non-existing user %s!\n", requestData.m_errorCode > 0 ? "failed" : "set", credential.c_str());
		return;
	}

	client->m_profilePendingSave = false;

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "callbackScriptSetSeshatProfile Server request error on get_profile for %s, request error %d!\n", credential.c_str(), requestData.m_errorCode);
		return;
	}

	client->m_lastTimeProfileSaved = OS_GetTime();

	Json::Value			jsonResponse;
	Json::Reader		jsonReader;

	jsonReader.parse(requestData.m_requestResponse, jsonResponse);

	//jsonSaveStatus = jsonResponse.get("response", Json::nullValue);
	const Json::Value nv(Json::nullValue);
	const Json::Value& jsonSaveStatus = jsonResponse.isMember("reason") ? jsonResponse["reason"] : nv;

	if(jsonSaveStatus.isNull())
	{
		MP_LOG(DBG_WARN, "callbackScriptSetSeshatProfile Received invalid seshat response for %s\n", credential.c_str());
		return;
	}

	if( jsonSaveStatus.asString() == "OK" )
	{
		//Json::Value jsonAccessToken = jsonResponse.get("access_token", Json::nullValue);
		const Json::Value& jsonAccessToken = jsonResponse.isMember("access_token") ? jsonResponse["access_token"] : nv;
		client->UpdateAccessTokenFromJson(jsonAccessToken);

		size_t requestFlags = (size_t)pUserData->requestFlags;
		if( requestFlags & E_SSPRF_SEND_CONFIRMATION )
		{
			callerObj->ServerSendProfileSaved( client->m_credential );
		}

		// --- only reset profile saved status if no new changes were made in the mean time
		if (pUserData->profileChangeTime == client->m_seshatProfile->ProfileChangedTime())
		{
			client->m_seshatProfile->SetProfileSavedStatus(true);
		}

		for (const auto& key : pUserData->batchNull)
		{
			client->m_seshatProfile->RemoveKeysFromProfile(key.first, key.second);
		}
		//auto pending_transactions = client->m_seshatProfile->GetECommPendingTransactions();
		//client->m_seshatProfile->SetECommPendingTransactions(pending_transactions);

		if (requestFlags & E_SSPRF_REQUEST_CONFIG)
		{
			callerObj->ScriptRequestHestiaConfig(client, E_HRT_REFRESH);
		}

		if (client->m_seshatProfile->HasKeysToRemove())
		{
			callerObj->ScriptRequestRemoveKeysFromProfile(client);
		}
	}
	else
	{
		MP_LOG(DBG_CRIT, "callbackScriptSetSeshatProfile: Profile was not saved; credential = %s response = %s\n", credential.c_str(), requestData.m_requestResponse.c_str());
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptSetOtherSeshatProfile(const std::string &credential, const std::string& object, const Json::Value& extraData)
{
	std::map<std::string, std::string> customParams;
	customParams["credential"] = credential;
	customParams["profile_obj"] = object;
	customParams["selector"] = "";
	customParams["access_token"] = GetAccessToken(credential);
	customParams["use_impersonation"] = extraData.get("use_impersonation", false).asBool() ? "True" : "";

	auto client_id = extraData[SESHAT_CURRENT_CLIENT_ID].asString();
	auto pid = atoi(client_id.c_str());

	auto server_client_id = m_RequestsManager->GetClientId();
	auto server_pid = atoi(server_client_id.c_str());

	if (pid != server_pid)
		client_id = server_client_id;

	customParams["client_id"] = client_id;

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(credential);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_SET_OTHER_SESHAT_PROFILE)->second, "", customParams, beneficiaries, callbackScriptSetOtherSeshatProfile, this, nullptr);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptSetOtherSeshatProfile(const SRequest& requestData)
{
	const std::string& other_credential = requestData.m_beneficiaires[0];

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "Server request error on ScriptSetOtherSeshatProfile for %s, request error %d!\n", other_credential.c_str(), requestData.m_errorCode);
		return;
	}

	Json::Value json;
	Json::Reader reader;

	reader.parse(requestData.m_requestResponse, json);

	const Json::Value& jsonAccessToken = json.isMember("access_token") ? json["access_token"] : Json::nullValue;
	GameServerFedManager::Instance()->UpdateAccessTokenFromJson(other_credential, jsonAccessToken);
}

