void GameServerFedManager::ScriptRequestRemoveKeysFromProfile(GSClient* client)
{
	Json::Value* val = new Json::Value(client->m_seshatProfile->GetKeysToRemove());
	std::map<std::string, std::string> customParams;
	customParams["credential"] = client->m_credential;
	customParams["profile_obj"] = Json::FastWriter().write(*val);
	customParams["access_token"] = GetAccessToken(client->m_credential);
	customParams["operation"] = "batch_delete";
	customParams["client_id"] = client->m_clientId;

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CHANGE_OTHER_PROFILE)->second, "", customParams, beneficiaries, callbackScriptRequestRemoveKeysFromProfile, this, val);
	client->m_seshatProfile->ClearKeysToRemove();
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptRequestRemoveKeysFromProfile(const SRequest& requestData)
{
	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(requestData.m_beneficiaires[0]);
	std::unique_ptr<Json::Value> val((Json::Value*)requestData.m_userData);

	if (requestData.m_errorCode)
	{
		if (client)
			client->m_seshatProfile->AddKeysToRemove(*val);
		MP_LOG(DBG_WARN, "Server request error on ScriptRequestRemoveKeysFromProfile for %s, request error %d!\n", credential.c_str(), requestData.m_errorCode);
		return;
	}

	Json::Value json;
	Json::Reader reader;

	reader.parse(requestData.m_requestResponse, json);

	const Json::Value& jsonAccessToken = json.isMember("access_token") ? json["access_token"] : Json::nullValue;
	GameServerFedManager::Instance()->UpdateAccessTokenFromJson(credential, jsonAccessToken);

	if (json["status"].asInt() != 200)
	{
		if (client)
			client->m_seshatProfile->AddKeysToRemove(*val);

		MP_LOG(DBG_WARN, "Server request error on ScriptRequestRemoveKeysFromProfile for %s, request status %d!\n", credential.c_str(), json["status"].asInt());
		return;
	}
}

