void GameServerFedManager::ScriptRequestFilterMessage(GSClient* client, std::string message, const char* language, int chat)
{
	auto userData = new CustomFilterData{ chat, message };

	std::map<std::string, std::string> customParams;
	customParams["credential"] = client->m_credential;
	customParams["access_token"] = GetAccessToken(client->m_credential);	// --- if I uncomment this I get 403.  For some reason, the initial token does not contain `chat` scope
	customParams["client_id"] = client->m_clientId;
	customParams["message"] = std::move(message);
	customParams["language"] = language;

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	// --- TODO: maybe pass inventory_delta here and delay it to client?
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_FILTER_MESSAGE)->second, "", customParams, beneficiaries, callbackScriptRequestFilterMessage, this, userData);

}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptRequestFilterMessage(const SRequest& requestData)
{
	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(requestData.m_beneficiaires[0]);
	std::unique_ptr<CustomFilterData> chat((CustomFilterData*)requestData.m_userData);

	if (!client)
	{
		MP_LOG(DBG_WARN, "Server request ScriptRequestFilterMessage for %s: client vanished\n", credential.c_str());
		return;
	}

	if (requestData.m_errorCode)
	{
		MP_LOG(DBG_WARN, "Server request error on ScriptRequestFilterMessage for %s, request error %d!\n", credential.c_str(), requestData.m_errorCode);
		GameServerFedManager::Instance()->ServerSendChatMessage(client, chat->second, chat->first | ChatMessageFlags::RepFilterMesageNo, false);
		return;
	}

	Json::Value json;
	Json::Reader reader;

	reader.parse(requestData.m_requestResponse, json);

	const Json::Value& jsonAccessToken = json.isMember("access_token") ? json["access_token"] : Json::nullValue;
	GameServerFedManager::Instance()->UpdateAccessTokenFromJson(credential, jsonAccessToken);

	if (json["status"].asInt() != 200)
	{
		MP_LOG(DBG_WARN, "Server request error on ScriptRequestFilterMessage for %s, request status %d!\n", credential.c_str(), json["status"].asInt());
		GameServerFedManager::Instance()->ServerSendChatMessage(client, chat->second, chat->first | ChatMessageFlags::RepFilterMesageNo, false);
		return;
	}

	auto filter_data_str = json["filter_data"].asString();
	Json::Value filter_data;
	reader.parse(filter_data_str, filter_data);
	bool ok = !filter_data["matches"].asBool();
	chat->first |= (ok ? ChatMessageFlags::RepFilterMesageOk : ChatMessageFlags::RepFilterMesageNo);
	GameServerFedManager::Instance()->ServerSendChatMessage(client, chat->second, chat->first, false);
}

