void GameServerFedManager::ScriptRequestGiftMessage(const std::string& credential, const std::string& msgID)
{
	GSClient* client = GetClient(credential);
	if(client == NULL)
	{
		return;
	}
	client->m_customSettings->m_gifts[msgID] = Json::nullValue;
	std::map<std::string, Json::Value>::const_iterator cit = client->m_customSettings->m_gifts.find(msgID);

	std::map<std::string, std::string> customParams;
	customParams.insert(std::pair<std::string, std::string>("credential", credential));
	customParams.insert(std::pair<std::string, std::string>("msgid", msgID));
	customParams.insert(std::pair<std::string, std::string>("access_token", client->GetAccessToken()));

	std::vector<std::string> beneficiaries;

	beneficiaries.push_back(credential);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_GIFT_MESSAGE)->second, client->m_clientId, customParams, beneficiaries, callbackScriptRequestGiftMessage, this, (void*)cit->first.c_str());

	MP_LOG(DBG_INFO, "ScriptRequestGiftMessage: %s %s!\n", credential.c_str(), msgID.c_str());
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptRequestGiftMessage(const SRequest& requestData)
{
	if (requestData.m_errorCode)
	{
		return;
	}

	MP_LOG(DBG_INFO, "Callback code %s response %s\n", requestData.m_code.c_str(), requestData.m_requestResponse.c_str());

	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(requestData.m_beneficiaires[0]);

	if (client == NULL)
	{
		return;
	}

	std::string msgID = (char*)requestData.m_userData;

	Json::Value jsonResponse, jsonMessage;
	Json::Reader reader;

	reader.parse(requestData.m_requestResponse, jsonResponse);
	//cache the access token
	Json::Value jsonAccessToken = jsonResponse.get("access_token", Json::nullValue);
	client->UpdateAccessTokenFromJson(jsonAccessToken);

	jsonMessage = jsonResponse.get("message", Json::nullValue);
	if (jsonMessage.isNull())
	{
		MP_LOG(DBG_WARN, "Received invalid message from %s\n", credential.c_str());
		return;
	}

	reader.parse(jsonMessage.asString(), jsonMessage);
	if (jsonMessage["type"].asString() == "gift")
	{
		client->m_customSettings->m_gifts[msgID] = jsonMessage;

		callerObj->ScriptRequestDeleteGiftMessage(credential, msgID);
	}
	else if (jsonMessage["body"].asString() == "notification")
	{
		auto attachment = jsonMessage["attachment"].asString();

		// --- spelling fix in fedrex scripts, but treat old messages 
		if (attachment.empty() && !jsonMessage["attachement"].asString().empty())
		{
			MP_LOG(DBG_WARN, "Received malformed msgID(%s) of type notification from credential(%s) - deleting\n", msgID.c_str(), credential.c_str());
			callerObj->ScriptRequestDeleteGiftMessage(client->m_credential, msgID);
			return;
		}

		if (!attachment.empty())
		{
			callerObj->ProcessGenericHermesNotification(client, msgID, attachment);
		}
		else
		{
			MP_LOG(DBG_WARN, "Received msgID(%s) that is not of type notification from credential(%s) but with empty attachment!\n", msgID.c_str(), credential.c_str());
		}
	}
	else
	{
		MP_LOG(DBG_WARN, "Received msgID(%s) that is not of type gift from credential(%s)!\n", msgID.c_str(), credential.c_str());
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptRequestDeleteGiftMessage(const std::string& credential, const std::string& msgID)
{
	GSClient* client = GetClient(credential);
	if (!client)
		return;

	std::map<std::string, std::string> customParams =
	{
		{ "credential", credential },
		{ "msgid", msgID },
		{ "access_token", client->GetAccessToken() },
	};

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(credential);

	auto userData = new std::string(msgID);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_DELETE_GIFT_MESSAGE)->second, client->m_clientId, customParams, beneficiaries, callbackScriptRequestDeleteGiftMessage, this, (void*)userData);

	MP_LOG(DBG_INFO, "ScriptRequestDeleteGiftMessage: %s %s!\n", credential.c_str(), msgID.c_str());
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptRequestDeleteGiftMessage(const SRequest& requestData)
{
	if (requestData.m_errorCode)
		return;

	MP_LOG(DBG_INFO, "Callback code %s response %s\n", requestData.m_code.c_str(), requestData.m_requestResponse.c_str());

	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(credential);
	if (!client)
		return;

	//cache the access token
	client->UpdateAccessToken(requestData.m_requestResponse);

	std::unique_ptr<std::string> msgID((std::string*)requestData.m_userData);
	auto cit = client->m_customSettings->m_gifts.find(*msgID);
	if (cit != client->m_customSettings->m_gifts.end())
	{
		std::string body = cit->second["body"].asString();
		std::string gift_type = cit->second["gift_type"].asString();
		Json::Value gift;
		Json::Reader().parse(body, gift);

		//client->m_seshatProfile->StartTrackingInventoryChanges();
		callerObj->GiveGiftReward(credential, gift, gift_type);
		//Json::Value inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();

		client->m_customSettings->m_gifts.erase(cit);
		//client->m_seshatProfile->SetSP(client->m_seshatProfile->GetSP());
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::GiveGiftReward(const std::string& credential, const Json::Value& gift, const std::string& gift_type)
{
	GSClient* client = GetClient(credential);
	if (!client)
		return;

	client->m_seshatProfile->StartTrackingInventoryChanges("gift");

	Json::Value trackingGiftObj = Json::objectValue;
	trackingGiftObj["type"] = gift_type;
	Json::Value& trackingGift = trackingGiftObj["values"] = Json::arrayValue;
	const auto& gifts = gift["gifts"];

	auto processGift = [&](bool onlyReset)
	{
		for (const auto& gift : gifts)
		{
			std::string giftName = gift["name"].asCString();
			
			// --- determine if it's a set or add: set is prefixed with "reset_"
			static const std::string setPrefix = "reset_";
			auto creditName = giftName;
			bool reset = false;
			if (giftName.find(setPrefix) != std::string::npos)
			{
				creditName = giftName.substr(setPrefix.length(), giftName.length() - setPrefix.length());
				reset = true;
			}

			if ((reset && !onlyReset) ||
				(!reset && onlyReset))
				continue;

			int giftValue = 0;
			sscanf(gift["value"].asCString(), "%d", &giftValue);

			MP_LOG(DBG_INFO, "Gift=%s value=%d credential=%s\n", giftName.c_str(), giftValue, credential.c_str());

			Json::Value val(Json::objectValue);
			val["item"] = giftName;
			val["qty"] = giftValue;
			trackingGift.append(std::move(val));

			if (giftName == "reset_profile")
			{
				client->m_seshatProfile->InitProfile(m_initial_profile, "GIFT RESET PROFILE");
				// --- TODO: other stuff like refreshing hestia config, adding default unlocks, forcing the client to reconnect
			}
			else if (giftName == "reset_age")
			{
				client->m_seshatProfile->SetAge(-1, "");
			}
			else if (giftName == "reset_give_neutronium")
			{
				if (client->m_clanData)
					client->m_clanData->neutronium_data.consume_neutronium(client, giftValue, 1);
			}
			else if (giftName == "reset_give_elo")
			{
				int deltaElo = giftValue - client->m_seshatProfile->GetCachedPvpStats().elo;
				Multiplayer::StartReadingProfileField(client->m_credential, client->m_credential, E_ProfileOperation::EPO_ADD_ELO, deltaElo);
			}
			else if (giftName == "reset_give_winstreak")
			{
				int val = giftValue;
				if (val > 0)
					client->m_seshatProfile->SetPVPConsecutiveWins(val);
			}
			else if (giftName == "reset_skirmish_playtest")
			{
				int val = giftValue;
				client->m_seshatProfile->ResetSkirmishPlaytest();
			}
			else
			{
				// --- generic gift

				auto hestia = client->GetHestiaConfig();
				auto credit = hestia->FindCredit(Hash(creditName));
				if (!credit)
				{
					MP_LOG(DBG_WARN, "Invalid gift credit: Gift=%s value=%d credential=%s\n", giftName.c_str(), giftValue, credential.c_str());
					continue;
				}

				Json::Value extraData(Json::objectValue);
				extraData["gift"]["item"] = giftName;
				extraData["gift"]["qty"] = giftValue;

				if (reset)
				{
					auto resetCredit = credit;

					// --- give_unlimited credit actually represent offers - find the offer and reset the "unlimited_for" credit from it
					if (credit->categoryHash == "give_unlimited")
					{
						auto offer = hestia->FindOffer(credit->hash);
						if (offer)
						{
							auto it = std::find_if(offer->items.begin(), offer->items.end(), [hestia](const OfferItem& item)
							{
								auto itemCredit = hestia->FindCredit(StringHash(item.credit.c_str()));
								return itemCredit && itemCredit->categoryHash == "unlimited_for";
							});
							if (it != offer->items.end())
							{
								resetCredit = hestia->FindCredit(StringHash(it->credit.c_str()));
								extraData["track_changes"] = false;
							}
						}
					}

					hestia->SetCreditBalance(client, resetCredit, 0, extraData);
				}

				auto qty = hestia->GetCreditBalance(client, credit);
				if (credit->categoryHash == StringHash("consumable") && credit->unit_restore_time(client) == 0 && credit->max_qty(client) > 1 && qty + giftValue > credit->max_qty(client))	// --- try to go over capping
				{
					client->m_seshatProfile->SetBalanceCheat(credit->name, qty + giftValue);
				}
				else
				{
					hestia->ChangeCreditBalance(client, credit, giftValue, extraData);
				}
			}
		}
	};

	processGift(true);
	processGift(false);

	client->m_seshatProfile->AppendInventoryChanges(SESHAT_LABEL_CLIENT_INVENTORY_GIFT, trackingGiftObj);

	// --- get the game inventory changes
	Json::Value inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();

	if (!inventory_changes.empty())
	{
		auto transactionId = StringHash("gift");
		ServerSendInventoryUpdate(client, transactionId, std::move(inventory_changes));
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::GiveFriendGiftReward(const std::string& credential, const int giftQty, const std::string& gift_type)
{
	GSClient* client = GetClient(credential);
	if (!client)
		return;

	client->m_seshatProfile->StartTrackingInventoryChanges("gift_friend");

	Json::Value trackingGiftObj = Json::objectValue;
	trackingGiftObj["type"] = gift_type;
	trackingGiftObj["values"] = giftQty;
	
	auto hestia = client->GetHestiaConfig();
	auto credit = hestia->FindCredit(Hash(gift_type.c_str()));
	if (!credit)
	{
		MP_LOG(DBG_WARN, "Invalid gift credit: Gift=%s value=%d credential=%s\n", gift_type.c_str()/*"hc"*/, giftQty, credential.c_str());
		return;
	}

	hestia->ChangeCreditBalance(client, credit, giftQty);
	client->m_seshatProfile->AppendInventoryChanges(SESHAT_LABEL_CLIENT_INVENTORY_GIFT, trackingGiftObj);

	// --- get the game inventory changes
	Json::Value inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();

	if (!inventory_changes.empty())
	{
		auto transactionId = StringHash("gift");
		ServerSendInventoryUpdate(client, transactionId, std::move(inventory_changes));
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptSendHermesNotification(const std::string& clientId, const std::vector<std::string>& fedIds, const std::string& category, const std::string& info, unsigned int key, unsigned char mask, std::unique_ptr<ClanOperation> op)
{
	if (fedIds.empty())
		return;

	// --- compose to list
	Json::Value to;
	for (const auto& fedId : fedIds)
		to.append(fedId);
	
	// --- compose notification data
	Json::Value jData;
	jData["category"] = category;
	jData["info"] = info;
	jData["key"] = key;
	jData["mask"] = (unsigned int)mask;

	std::map<std::string, std::string> customParams = {
		{ "credentials",	Json::FastWriter().write(to) },
		{ "attachment",		Json::FastWriter().write(jData) },
	};

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_SEND_HERMES_NOTIFICATION)->second, clientId, customParams, {}, callbackScriptSendHermesNotification, this, op.release());
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptSendHermesNotification(const SRequest& requestData)
{
	std::unique_ptr<ClanOperation> op((ClanOperation*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptSendHermesNotification returned error %d - %s for %s", response["status"].asInt(), response["reason"].asCString(), response["ret"].asString().c_str());
		return;
	}

	if (!op)
		return;

	switch (op->operation)
	{
	case ECO_FIX_49:
	{
		auto& opdata = op->data;

		// --- data for the set field call
		opdata["field"] = OSIRIS_CLAN_ELO_FIELD;
		opdata["etag"] = op->clan_data->elo.etag();
		opdata["etag_for"] = OSIRIS_CLAN_ELO_FIELD;

		// --- data for the leaderboard post
		Json::Value new_data = op->clan_data->elo.data();
		new_data["fix_49"] = true;

		opdata["object"] = Json::FastWriter().write(new_data);

		MP_LOG(DBG_WARN, "ScriptSendHermesNotification - start fix 49 will write clan %s\n",
			op->clan_data ? op->clan_data->clan_id.c_str() : "none");

		GameServerFedManager::Instance()->ScriptClanSetField(std::move(op));

		break;
	}
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptSendHermesMessageToUsers(const std::string& clientId, const std::vector<ClanMember>& recipients, const Json::Value jData)
{
	if (recipients.empty())
		return;

	// --- compose to list
	Json::Value to;
	for (const auto& recipient : recipients)
		to.append(recipient.fed_id);

	std::map<std::string, std::string> customParams = {
		{ "credentials",	Json::FastWriter().write(to) },
		{ "attachment",		Json::FastWriter().write(jData) },
	};

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_SEND_HERMES_NOTIFICATION)->second, clientId, customParams, {}, callbackScriptSendHermesMessageToUsers, this, nullptr);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptSendHermesMessageToUsers(const SRequest& requestData)
{
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "callbackScriptSendHermesMessageToUsers returned error %d - %s for %s", response["status"].asInt(), response["reason"].asCString(), response["ret"].asString().c_str());
		return;
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptRequestEventsInfo(GSClient *client)
{
	for (const Json::Value &evt : client->m_seshatProfile->GetEvents())
	{
		if (client->m_EventContainer.AddGroupwareEvent(evt["event_id"].asString()))
		{
			ServerEvent &se = client->m_EventContainer.AddEmptyEvent(evt["event_id"].asString());
			se.SetCanErase();
			se.SetCanProgress(false);
		}
	}

	std::string strEvents = "";
	client->m_EventContainer.FillEmptyEventIDs(strEvents);

	if (strEvents.empty())
	{
		// --- send a message with empty data so that the client knows it has the data
		ServerSendEventsData(client, Json::arrayValue);

		// --- send the list of chapters that the client can delete based on progress information (this will be used against last played times held locally by each client)
		// --- this is done in the callback, but since we're no longer making the request in this (rare) case, do this here
		ServerSendDeletableChapters(client);
		
		//sync outpost data
		client->m_outpostEventRawLoad = true;
		if (client->FeatureUnlocked("outposts_unlocked"))
		{
			client->m_multiplayer->MarkAllOutpostsDirty();
			client->m_multiplayer->UpdateConquestStatus();
		}
	}
	else
	{
		std::map<std::string, std::string> customParams;
		customParams.insert(std::pair<std::string, std::string>("events", strEvents));

		std::vector<std::string> beneficiaries;
		beneficiaries.push_back(client->m_credential);

		m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_EVENTS_INFO)->second, client->m_clientId, customParams, beneficiaries, callbackScriptRequestEventsInfo, this);
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

static bool PatchRewards(GSClient* client, Json::Value& eventData, Json::Value& eventTemplate)
{
	bool ret = false;

	ServerEvent ev;
	ev.PartialParseData(eventData, eventTemplate);

	// --- patch relative tournament rewards
	for (auto& gift : eventData["tournament"]["awards"])
	{
		if (gift.isObject() && !gift.empty())
		{
			for (auto& value : gift["gifts"])
			{
				HestiaConfig::Price price(value["name"].asString(), value["value"].asInt());
				if (client->GetHestiaConfig()->ResolveRelativeCurrencyPrice(client, price))
				{
					ret = true;
					value["name"] = price.credit;
					value["value"] = price.qty;
				}
				if (ev.IsBoss())
				{
					ret = true;

					auto clan_members = client->m_clanData ? client->m_clanData->member_count() : client->m_seshatProfile->GetClanSize();

					value["value"] = price.qty * clan_members;
				}
			}
		}
	}

	const char* data = eventData["_template"].asCString();
	if (HestiaConfig::IsRelativeCurrency(data))
		return ret;

	// --- patch relative milestone rewards
	Json::Value &milestones = eventTemplate["milestones"]["value"];
	for (auto& milestone : milestones)
	{
		auto& awards = milestone["award"]["value"];
		for (auto& award : awards)
		{
			for (auto& value : award["value"])
			{
				HestiaConfig::Price price(value["id"].asString(), value["value"].asInt());
				if (client->GetHestiaConfig()->ResolveRelativeCurrencyPrice(client, price))
				{
					ret = true;
					value["id"] = price.credit;
					value["value"] = price.qty;
				}
			}
		}
	}

	if (ret)
		eventData["_template"] = Json::FastWriter().write(eventTemplate);

	return ret;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

static std::string format_time(time_t utc)
{
	struct tm* time = gmtime(&utc);

	time->tm_mon++;			// --- month is 0-based
	time->tm_year += 1900;	// --- year is 1900-based

	int size = snprintf(nullptr, 0, "%4d-%02d-%02d %02d:%02d:%02dZ", time->tm_year, time->tm_mon, time->tm_mday, time->tm_hour, time->tm_min, time->tm_sec);
	if (size <= 0)
		return "0";
	std::string ret(size, ' ');
	snprintf(&ret[0], size + 1, "%4d-%02d-%02d %02d:%02d:%02dZ", time->tm_year, time->tm_mon, time->tm_mday, time->tm_hour, time->tm_min, time->tm_sec);
	return ret;
}

void GameServerFedManager::callbackScriptRequestEventsInfo(const SRequest &requestData)
{
	if (requestData.m_errorCode || requestData.m_requestResponse.length() <= 0)
		return;

	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string &credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(credential);
	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "RequestEventsInfo returned for non-existing user %s!\n", credential.c_str());
		return;
	}

	if (client->m_seshatProfile->IsInvalid())
	{
		MP_LOG(DBG_INFO, "RequestEventsInfo returned with null Seshat profile %s!\n", credential.c_str());
		return;
	}

	if (!client->GetHestiaConfig())
	{
		MP_LOG(DBG_INFO, "RequestEventsInfo returned with empty Hestia config %s!\n", credential.c_str());
		return;
	}

	Json::Reader jsonReader;

	Json::Value eventsInfoResponse;
	bool parserSuccessful = jsonReader.parse(requestData.m_requestResponse, eventsInfoResponse);
	auto parserErrorMessages = jsonReader.getFormatedErrorMessages();
	if ( !parserSuccessful || !parserErrorMessages.empty() )
		MP_LOG(DBG_CRIT, "RequestEventsInfo %s json eventsInfoResponse %s\n%s", parserSuccessful ? "parsed with errors" : "failed to parse", credential.c_str(), parserErrorMessages.c_str());

	if (eventsInfoResponse["status"] != 200)
		return;

	bool changes = client->SetHash(Hash(eventsInfoResponse["events_info"].asString()));

	Json::Value jEvents1, jResponse;
	parserSuccessful = jsonReader.parse(eventsInfoResponse["events_info"].asString(), jEvents1);
	parserErrorMessages = jsonReader.getFormatedErrorMessages();
	if (!parserSuccessful || !parserErrorMessages.empty())
		MP_LOG(DBG_CRIT, "RequestEventsInfo %s json events_info %s\n%s", parserSuccessful ? "parsed with errors" : "failed to parse", credential.c_str(), parserErrorMessages.c_str());

	time_t now = GameServerFedManager::Instance()->GetLocalTime();

	// --- parse all events
	std::map<std::string, Json::Value> templates;
	Json::Value jEvents;
	Json::Value allEventIDs;
	for (auto& jEvent : jEvents1)
	{
		const auto &jID = jEvent["id"];
		if (!jID.isString())
			continue;
		auto id = jID.asCString();
		parserSuccessful = jsonReader.parse(jEvent["_template"].asCString(), templates[id]);
		parserErrorMessages = jsonReader.getFormatedErrorMessages();
		if (!parserSuccessful || !parserErrorMessages.empty())
			MP_LOG(DBG_CRIT, "RequestEventsInfo %s json _template %s\n%s", parserSuccessful ? "parsed with errors" : "failed to parse", credential.c_str(), parserErrorMessages.c_str());

		jEvents[id] = std::move(jEvent);
		allEventIDs.append(id);
	}	

	// --- test advertising bugs
	//static time_t beginning = now;
	//for (auto& jEvent : jEvents)
	//{
	//	jEvent["end_date"] = format_time(beginning + 60);
	//}

	// --- find user-relative (UR) event
	auto urit = std::find_if(jEvents.begin(), jEvents.end(), [&templates, client, now](const Json::Value& jEv)
	{
		auto id = jEv["id"].asCString();
		ServerEvent ev;
		ev.PartialParseData(jEv, templates[id]);
		if (ev.IsUserRelative())
		{
			auto& data = client->m_seshatProfile->GetUserRelativeEventData(id);
			if (data.isNull() || data["end"].asTimeT() > now)
				return true;
		}
		return false;
	});

	// --- if found, check it is seshat and replace start and end dates
	if (urit != jEvents.end())
	{
		auto id = (*urit)["id"].asCString();
		auto& data = client->m_seshatProfile->GetUserRelativeEventData(id);
		if (data.isNull())
		{
			ServerEvent ev;
			ev.PartialParseData((*urit), templates[id]);

			auto end = now + ev.GetUserRelativeDuration() * 60 * 60;	// --- duration is in hours, timestamp in seconds
			client->m_seshatProfile->SetUserRelativeEventData(id, now, end);

			(*urit)["start_date"] = format_time(now);
			(*urit)["end_date"] = format_time(end);
		}
		else
		{
			(*urit)["start_date"] = format_time(data["start"].asInt64());
			(*urit)["end_date"] = format_time(data["end"].asInt64());
		}
	}

	// --- remove coop & bounty events in some cases (details below)
	{
		auto urid = (urit != jEvents.end()) ? (*urit)["id"].asCString() : nullptr;

		ServerEvent urev;
		if (urid)
			urev.PartialParseData(*urit, templates[urid]);

		for (auto& jEv : jEvents)
		{
			auto id2 = jEv["id"].asString();
			if (urid && id2 == urid)
				continue;

			bool clear = client->m_seshatProfile->IsIgnoreEvent(id2.c_str());

			ServerEvent ev2;
			if (!clear)
			{
				ev2.PartialParseData(jEv, templates[id2]);
				clear =
					// --- have a UR coop and a non-UR coop - ignore the non-UR coop
					(urid && urev.IsCoop() && ev2.IsCoop()) || 
					// --- remove bounty events if we have an ongoing UR coop or the squad ops tutorial wasn't completed
					(ev2.IsBounty() && 
						((urid && urev.IsCoop()) || !client->m_seshatProfile->TutorialCompleted("tutorial_SquadOps")));
			}

			if (clear)
			{
				client->m_seshatProfile->SetIgnoreEvent(id2.c_str());
				jResponse["erase"].append(Json::Value(id2));
				jEv.clear();
				// --- TODO: is this neede din this situation?  uncomment if it is -- we are removing one of the events we just received, so we need to invalidate the cache, see below
				//client->SetHash(0);
			}
		}
	}

	// --- expired events clean-up
	std::vector<std::string> missing_coop_events;
	std::vector<std::string> missing_gh_events;
	std::vector<std::string> missing_miniops_events;
	{
		for (const auto& notification : client->m_seshatProfile->GetProfile()[SESHAT_GAME_SAVE][SESHAT_LABEL_NOTIFICATIONS])
		{
			if (notification[SESHAT_LABEL_NOTIFICATIONS_CATEGORY].asString() == "coopevent" &&
				notification[SESHAT_LABEL_NOTIFICATIONS_KEY].asInt() == 1)
			{
				auto id = notification[SESHAT_LABEL_NOTIFICATIONS_INFO].asString();
				if (!jEvents.isMember(id))
					missing_coop_events.push_back(std::move(id));
			}
			else if (notification[SESHAT_LABEL_NOTIFICATIONS_CATEGORY].asString() == "bounty:end")
			{
				auto id = notification[SESHAT_LABEL_NOTIFICATIONS_INFO].asString();
				if (!jEvents.isMember(id))
					missing_gh_events.push_back(std::move(id));
			}
			else if (notification[SESHAT_LABEL_NOTIFICATIONS_CATEGORY].asString() == "miniops:start")
			{
				auto id = notification[SESHAT_LABEL_NOTIFICATIONS_INFO].asString();
				if (!jEvents.isMember(id))
					missing_miniops_events.push_back(std::move(id));
			}
		}
	}

	auto findForcedWeapon = [client](const std::string& evtId) -> std::string
	{
		const auto& jParams = client->m_seshatProfile->GetProfile()[SESHAT_GAME_SAVE][SESHAT_LABEL_LOADOUT][SESHAT_LABEL_LOADOUT_PARAMS];
		auto it = std::find_if(jParams.begin(), jParams.end(), [&evtId](const Json::Value& v)
		{
			const auto& for_event = v["on_loan"]["for_event"];
			return for_event.isString() && for_event.asString() == evtId;
		});
		if (it == jParams.end())
			return "";

		return it.memberName();
	};

	auto cleanupCoopEvent = [client](const std::string& evtId, const std::string& forcedWeapon, bool cleanNotifications)
	{
		MP_LOG(DBG_WARN, "cleanupCoopEvent for %s event %s", client->m_credential.c_str(), evtId.c_str());
		if (!forcedWeapon.empty())
		{
			client->m_seshatProfile->SetItemLoanData(forcedWeapon.c_str(), Json::nullValue);
			client->m_seshatProfile->SetWeaponCamo(forcedWeapon.c_str(), nullptr);
		}
		if (cleanNotifications)
		{
			client->m_seshatProfile->DelNotification("coopevent", evtId, 0, ENM_CATEGORY | ENM_INFO);
		}
	};

	auto cleanupGhEvent = [client](const std::string& evtId, const std::string& forcedWeapon, bool cleanNotifications)
	{
		MP_LOG(DBG_WARN, "cleanupGhEvent for %s event %s", client->m_credential.c_str(), evtId.c_str());
		// --- remove the weapon
		if (!forcedWeapon.empty())
		{
			auto qty = client->GetHestiaConfig()->GetCreditBalance(client, StringHash(forcedWeapon.c_str()));
			if (qty <= 0)
			{
				client->m_seshatProfile->RemoveWeaponLoadoutData(forcedWeapon.c_str());

				// --- remove upgrades
				auto upgradeCredit = GameServerFedManager::Instance()->GetAHWeaponsData()->GetWeaponUpgradeCredit(forcedWeapon);
				client->GetHestiaConfig()->SetCreditBalance(client, upgradeCredit, 0);
			}
		}

		// --- remove the squadmates
		client->m_seshatProfile->RemoveLoanedSquadMates(evtId.c_str());

		if (cleanNotifications)
		{
			client->m_seshatProfile->DelNotification("bounty:end", evtId, 0, ENM_CATEGORY | ENM_INFO);
			client->m_seshatProfile->DelNotification("bounty:start", evtId, 0, ENM_CATEGORY | ENM_INFO);
		}
	};

	auto cleanupMiniopsEvent = [client](const std::string& evtId)
	{
		MP_LOG(DBG_WARN, "cleanupMiniopsEvent for %s event %s", client->m_credential.c_str(), evtId.c_str());
		//client->m_seshatProfile->DelNotification("miniops:end", evtId, 0, ENM_CATEGORY | ENM_INFO);
		client->m_seshatProfile->DelNotification("miniops:start", evtId, 0, ENM_CATEGORY | ENM_INFO);
	};

	for (const auto& evtId : missing_coop_events)
	{
		cleanupCoopEvent(evtId, findForcedWeapon(evtId), true);
	}

	for (const auto& evtId : missing_gh_events)
	{
		cleanupGhEvent(evtId, findForcedWeapon(evtId), true);
	}

	for (const auto& evtId : missing_miniops_events)
	{
		cleanupMiniopsEvent(evtId);
	}

	if (client->FeatureUnlocked("outposts_unlocked"))
	{
		client->m_outpostEventPreset = "Default";
		client->m_outpostEventExpiry = 0;
		//client->m_multiplayer->MarkAllOutpostsDirty();
		//client->m_multiplayer->UpdateConquestStatus();
	}

	for (Json::Value &jEvent : jEvents)
	{ // filter the events list

		if (jEvent.empty())
			continue;

		auto& templateData = templates[jEvent["id"].asCString()];
		PatchEventVersion(templateData);
		PatchRewards(client, jEvent, templateData);

		SemEvent* evt = client->AddEvent(jEvent, templateData, changes);
		
		//tuan.transy - change end date when hp is out
		if (evt->IsRedBoss())
		{
			BossEventData* redBossData = (BossEventData*)evt->GetRawDataPtr();
			auto redBossHp = redBossData ? redBossData->BossHealth() : GameServerFedManager::Instance()->GetAHEventsData()->GetBossEventData(evt->GetPreset()).BossHealth();
			auto redBossScore = GameServerFedManager::Instance()->m_adminClan[ClanEventFieldFromEventId(evt->GetID().c_str())].asDouble();
			auto timeStamptoZulu = [](time_t ts) -> std::string {
				std::ostringstream oss;
				std::tm* tm = std::gmtime(&ts); // Convert timestamp to UTC time
				oss << std::put_time(tm, "%Y-%m-%d %H:%M:%S") << "Z"; // Format the time
				return oss.str();
			};
			if (redBossScore >= redBossHp)
			{
				evt->SetEndDate(GameServerFedManager::Instance()->GetServerTime());
				auto endDate = timeStamptoZulu(evt->GetEndDate());
				jEvent["end_date"] = endDate;
				changes = true;
			}
		}
		//end
		// --- if the event is finished and was never joined, ignore it
		// --- basically this shouldn't happen, since we're only asking for events from hestia and from seshat
		// --- and hestia doesn't send us ended events
		// --- but it happened on beta that the end dates are different in hestia and osiris (in sem & osiris)
		// --- so just to be safe...
		if ((evt->GetEndDate() < now) && !client->m_seshatProfile->HasJoinedEvent(evt->GetID()))
			continue;

#ifdef SKIRMISH_EVENT
		if (evt->IsSkirmish() && !client->m_seshatProfile->TutorialCompleted("tutorial_ArenaGameplay"))
			continue;
#endif // SKIRMISH_EVENT

		if (evt->IsPiggyBankDefault())
		{
			client->m_piggyBank->LoadEventDefaultConfig(templateData["event_tuning"]);
		}
		if (evt->IsPiggyBankExtraRewards())
		{
			client->m_piggyBank->LoadEventExtraRewardsConfig(templateData["event_tuning"]);
			client->m_piggyBank->LoadEventExtraRewardsEndTime(evt->GetEndDate());
		}

		if (evt->IsCategory(EVENT_TYPE_SEASONAL_COLLECTION_CODEX))
		{
			client->m_collectionCodex->UpdateSeasonalBannerExpiry(evt);
		}

		// --- for coop & bounty events, only allow erase if they expired and the event is marked as finished
		bool isCoopEvent = evt->IsCoop();
		bool canEraseCoop = true;
		bool isBountyEvent = evt->IsBounty();
		bool canEraseBounty = true;
		bool isMiniopsEvent = evt->IsMiniops();
		bool canEraseMiniops = true;
		if (evt->IsOutposts())
		{
			//client->m_outpostEventId = evt->GetID();
			client->m_outpostEventPreset = evt->GetPreset();
			client->m_outpostEventExpiry = evt->GetEndDate();
		}
		if (evt->IsForge())
		{
			client->m_forgeEventPreset = evt->GetPreset();
			client->m_forgeEventExpiry = evt->GetEndDate();

			if(evt->GetEndDate() < now)
			{
				client->m_seshatProfile->ClearForgeRewardList();
				client->m_seshatProfile->SetForgeEventUsedXP(0);
				client->m_seshatProfile->SetForgeIgnite(false);
				client->GetHestiaConfig()->SetCreditBalance(client, "forge_premium_unlock", 0);
				client->GetHestiaConfig()->SetCreditBalance(client, "forge_predefined_unlock", 0);
				GameServerFedManager::Instance()->ActivateForgeRewardList(client, 0); //ForgeDataState::Init
			}

		}
		if (isCoopEvent)
		{
			auto maxMilestone = std::max((int)client->m_seshatProfile->GetEventMilestone(evt->GetID()), client->m_seshatProfile->GetEventMaxMilestone(evt->GetID()));
			canEraseCoop = client->m_seshatProfile->IsEventFinished(evt->GetID()) || // --- event marked as finished (the lose screen was shown)
				maxMilestone >= (int)evt->GetMilestones().size() - 1; // --- event won (won screen was shown)

			// --- if the event ended but can't be erased, add notification that popups up on the client and marks the event finished on the server when dismissed
			if (evt->GetCanErase() && evt->GetEndDate() < now && !canEraseCoop)
			{
				client->m_seshatProfile->StartTrackingInventoryChanges("notice:coop");
				client->m_seshatProfile->AddNotificationFromServer("coopevent", evt->GetID(), 1, ENM_CATEGORY | ENM_INFO | ENM_KEY);
				auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
				if (!inventory_changes.empty())
				{
					callerObj->ServerSendInventoryUpdate(client, 0, std::move(inventory_changes));
				}
			}
		}
		else if (isBountyEvent)
		{
			canEraseBounty = client->m_seshatProfile->IsEventFinished(evt->GetID()); // --- event marked as finished (the end screen was shown)
																					// --- if the event ended but can't be erased, add notification that popups up on the client and marks the event finished on the server when dismissed
			if (evt->GetCanErase() && evt->GetEndDate() < now && !canEraseBounty)
			{
				client->m_seshatProfile->StartTrackingInventoryChanges("notice:bounty");
				client->m_seshatProfile->AddNotificationFromServer("bounty:end", evt->GetID(), 0, ENM_CATEGORY | ENM_INFO);
				auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
				if (!inventory_changes.empty())
				{
					callerObj->ServerSendInventoryUpdate(client, 0, std::move(inventory_changes));
				}
			}
		}
		else if (evt->IsPvpMeta() && (evt->IsActive()))
		{
			client->m_pvpMeta->UpdateDefenseSquadOnFirstLoad();
			evt->SetCanErase();
		}
		else if (evt->IsEventShard() && (evt->IsActive()))
		{
			client->m_eventShard->LoadEventShardConfig();
		}
		//else if (isMiniopsEvent)
		//{
		//	// --- miniops events marked as finished as soon as they expire
		//	if (evt->GetCanErase() && evt->GetEndDate() < now)
		//	{
		//		client->m_seshatProfile->SetEventFinishedWithRank(evt->GetID(), 1);
		//	}
		//}

		// event ended, safe to filter it out if it's unranked or the rank reward was claimed, or there is no rank reward (0 score), except for boss events for which we also keep the ones with 0 score so we can show the popup telling you you won NOTHING
	/*	if ((evt->GetEndDate() < now) &&
			evt->IsOutposts() &&
			client->m_seshatProfile->IsEventFinished(evt->GetID()))
		{
			if (client->FeatureUnlocked("outposts_unlocked"))
			{
				client->m_outpostEventPreset = "Default";
				client->m_outpostEventExpiry = 0;
				client->m_multiplayer->MarkAllOutpostsDirty();
				client->m_multiplayer->UpdateConquestStatus();
			}
		}*/

		if (evt->GetCanErase() && 
			(evt->GetEndDate() < now) && 
			canEraseCoop &&
			canEraseBounty &&
			canEraseMiniops && 
			(!evt->IsRanked() || 
				client->m_seshatProfile->IsEventFinished(evt->GetID()) || 
				((client->m_seshatProfile->GetEventScore(evt->GetID()) <= 0) && !evt->IsBoss())))
		{
			MP_LOG(DBG_WARN, "callbackScriptRequestEventsInfo erased event %s for %s!\n", jEvent["id"].asCString(), client->m_credential.c_str());
			jResponse["erase"].append(jEvent["id"]);
			if (isCoopEvent)
			{
				auto eventData = callerObj->GetAHEventsData()->GetCoopEventData(evt->GetPreset());
				auto forcedWeapon = eventData.ForcedWeapon();
				if (forcedWeapon)
				{
					bool doCoopWeaponCleanup = true;
#if DELAY_CHECK_MTLE_ERASE > 0
					if (!eventData.Multipart().empty())
					{
						const time_t mtleCleanupAfter = evt->GetEndDate() + (time_t)DELAY_CHECK_MTLE_ERASE * 86400;
						if (now < mtleCleanupAfter)
							doCoopWeaponCleanup = false;
					}
#endif
					if (doCoopWeaponCleanup)
					{
					// --- if the event has a forced weapon and it's still on loan, remove it and the attached loan data
					client->m_seshatProfile->StartTrackingInventoryChanges("loan:coop");

					cleanupCoopEvent(evt->GetID(), forcedWeapon, false);

					// --- remove "Collector" craft parts from inventory
					// --- for multipart, only do this for the last part of a multipart
					bool shouldRemoveCollectorParts = true;
					if (!eventData.Multipart().empty())
					{
						auto multipartData = callerObj->GetAHEventsData()->GetMultipartEventData(eventData.Multipart());
						auto currentStage = multipartData.StageIndex(evt->GetPreset());
						shouldRemoveCollectorParts = currentStage == (multipartData.StageCount() - 1);
					}
					if (shouldRemoveCollectorParts)
					{
						auto collectorParts = callerObj->GetAHWeaponsData()->CraftPartsOfRarity(8); // Collector
						for (const auto& partId : collectorParts)
							client->GetHestiaConfig()->SetCreditBalance(client, partId, 0);
					}

					// --- for the ftue event:
					if (evt->IsUserRelative())
					{
						// --- remove the "invisible_1" item - crm campaigns rely on this to enable / disable the event battlepack and event redirects
						client->GetHestiaConfig()->SetCreditBalance(client, "invisible_1", 0);

						// --- mark the ftue tutorials as completed
						for (auto tuto : { "tutorial_CoopEventPartOne", "tutorial_CoopEventVictory", "tutorial_CoopEventPartTwo" })
							client->m_seshatProfile->UpdateTutorial(tuto, true);
					}

					// --- TODO: use seshat notifications in order to trigger the event lose screen, as the event isn't ranked and so isn't preserved for the popup to appear

					auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
					if (!inventory_changes.empty())
					{
						callerObj->ServerSendInventoryUpdate(client, 0, std::move(inventory_changes));
					}
					}
				}
			}
			else if (isBountyEvent)
			{
				client->m_seshatProfile->StartTrackingInventoryChanges("loan:bounty");

				auto eventData = callerObj->GetAHEventsData()->GetBountyEventData(evt->GetPreset());

				// --- remove the weapon
				auto weapon = eventData.ForcedWeapon();

				cleanupGhEvent(evt->GetID(), weapon, false);

				// --- remove currencies
				client->GetHestiaConfig()->SetCreditBalance(client, "bounty_token", 0);
				client->GetHestiaConfig()->SetCreditBalance(client, "bounty_star", 0);

				// --- remove squadops & chapter deplayed transactions
				for (int ci = 0; ci < eventData.ChapterCount(); ++ci)
				{
					auto missionIds = client->m_seshatProfile->SquadOpsMissions(SQUAD_OPS_BOUNTY_CHAPTER_INDEX + ci);
					for (auto missionId : missionIds)
					{
						client->m_seshatProfile->RemoveSquadOp(missionId);
					}

					auto chapterDtid = client->m_seshatProfile->GetBountyChapterDtid(evt->GetID(), ci);
					if (!chapterDtid.empty())
						client->m_seshatProfile->RemoveDelayedTransaction(chapterDtid);
				}

				auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
				if (!inventory_changes.empty())
				{
					callerObj->ServerSendInventoryUpdate(client, 0, std::move(inventory_changes));
				}
			}
			else if (isMiniopsEvent)
			{
				client->m_seshatProfile->StartTrackingInventoryChanges("cleanup:miniops");

				auto eventData = callerObj->GetAHEventsData()->GetMiniopsEventData(evt->GetPreset());

				// --- remove currency
				client->GetHestiaConfig()->SetCreditBalance(client, eventData.EventItem(), 0);

				auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
				if (!inventory_changes.empty())
				{
					callerObj->ServerSendInventoryUpdate(client, 0, std::move(inventory_changes));
				}
			}
			else if (evt->IsPiggyBankExtraRewards())
			{
				client->m_seshatProfile->UpdatePiggyBankPurchaseCountForExtraEvent(0);
				client->m_piggyBank->SetExtraRewardsEventActive(false);
				client->m_piggyBank->SendPiggyBankEventInfoToClient(client);
			}
		}
		else if (changes || 
			isCoopEvent || 
			(isBountyEvent && !client->m_seshatProfile->HasJoinedEvent(evt->GetID())))
		{
			jEvent["canProgress"] = evt->GetCanProgress();

			if (isCoopEvent)
			{
				auto eventData = callerObj->GetAHEventsData()->GetCoopEventData(evt->GetPreset());
				auto energyCreditHash = eventData.EnergyCredit(0);
				const auto energyCredit = client->GetHestiaConfig()->FindCredit(energyCreditHash);
				auto energyAmount = 2; // energyCredit->refill_qty(client); --- Requirement from Maria - don't give her the full refill; TODO: expose in data

				// --- replace milestone rewards based on dubious rules...
				evt->PatchCoopMilestoneRewards(jEvent, client->m_seshatProfile->GetEventMaxMilestone(jEvent["id"].asString()), energyCredit->name.c_str(), energyAmount);
			}
			else if (isBountyEvent)
			{
				// --- hack for live update of bounty bonus value
				auto bonusVal = client->m_seshatProfile->GetBountyBonus(evt->GetID(), "rpg_bounty_token");
				if (bonusVal >= 1 && bonusVal < 3)
				{
					client->m_seshatProfile->SetBountyBonus(evt->GetID(), "rpg_bounty_token", 3);	// --- even more hack
				}
			}
 			jResponse["add"].append(jEvent);
		}
	}

	if (allEventIDs.size())
		callerObj->CheckMultipleStageTleEventWeapon(client, allEventIDs);

#ifdef SKIRMISH_EVENT
	auto skirmishEvents = callerObj->FilterCustomSemEvent(client, EVENT_TYPE_SKIRMISH);

	if (skirmishEvents.size() > 1)
	{
		auto it = std::max_element(skirmishEvents.begin(), skirmishEvents.end(), [](const SemEvent* ev1, const SemEvent* ev2)
			{
				if (ev1->GetEndDate() < ev2->GetEndDate()) return true;
				if (ev1->GetEndDate() > ev2->GetEndDate()) return false;
				return ev1->GetCanErase() > ev2->GetCanErase();
			});

		const auto keep = (*it)->GetID();
		std::vector<std::string> skirmishEventIds;
		std::transform(skirmishEvents.begin(), skirmishEvents.end(), std::back_inserter(skirmishEventIds), [](const SemEvent* ev) { return ev->GetID(); });
		skirmishEventIds.erase(std::remove_if(skirmishEventIds.begin(), skirmishEventIds.end(), [&keep](const std::string& evId) { return evId == keep; }), skirmishEventIds.end());

		Json::Value newAdd;
		for (auto& v : jResponse["add"])
		{
			auto id = v["id"].asString();

			if (std::find_if(skirmishEventIds.begin(), skirmishEventIds.end(), [id](const std::string& evId) { return evId == id; }) == skirmishEventIds.end())
			{
				newAdd.append(std::move(v));
				if (client->FindEvent(id)->GetCategory() == EVENT_TYPE_SKIRMISH)
					client->AddUniqueCustomEvent(EVENT_TYPE_SKIRMISH, id);
			}
			else
			{
				//client->m_seshatProfile->SetIgnoreEvent(id.c_str());
				MP_LOG(DBG_WARN, "callbackScriptRequestEventsInfo erased event %s for %s because double skirmish!\n", id.c_str(), client->m_credential.c_str());
				
				// Check rewards before delete event
				if (client->m_seshatProfile->IsEventRewardsCheck(id, EVENT_TYPE_SKIRMISH))
				{
					jResponse["erase"].append(id);
					client->RemoveEvent(id);
				}
			}
		}

		jResponse["add"] = std::move(newAdd);
	}
#endif // SKIRMISH_EVENT

	// TrungND
	//auto redBossEvents = client->m_EventContainer.GetEventsOfType(EVENT_TYPE_RED_BOSS);
	auto redBossEvents = callerObj->FilterCustomSemEvent(client, EVENT_TYPE_RED_BOSS);

	if (redBossEvents.size() > 1)
	{
		auto it = std::max_element(redBossEvents.begin(), redBossEvents.end(), [](const SemEvent* ev1, const SemEvent* ev2)
			{
				if (ev1->GetEndDate() < ev2->GetEndDate()) return true;
				if (ev1->GetEndDate() > ev2->GetEndDate()) return false;
				return ev1->GetCanErase() > ev2->GetCanErase();
			});

		const auto keep = (*it)->GetID();
		std::vector<std::string> redBossEventIds;
		std::transform(redBossEvents.begin(), redBossEvents.end(), std::back_inserter(redBossEventIds), [](const SemEvent* ev) { return ev->GetID(); });
		redBossEventIds.erase(std::remove_if(redBossEventIds.begin(), redBossEventIds.end(), [&keep](const std::string& evId) { return evId == keep; }), redBossEventIds.end());

		Json::Value newAdd;
		for (auto& v : jResponse["add"])
		{
			auto id = v["id"].asString();
			
			if (std::find_if(redBossEventIds.begin(), redBossEventIds.end(), [id](const std::string& evId) { return evId == id; }) == redBossEventIds.end())
			{
				newAdd.append(std::move(v));
				if (client->FindEvent(id)->GetCategory() == EVENT_TYPE_RED_BOSS)
					client->AddUniqueCustomEvent(EVENT_TYPE_RED_BOSS, id);
			}
			else
			{
				//client->m_seshatProfile->SetIgnoreEvent(id.c_str());
				MP_LOG(DBG_WARN, "callbackScriptRequestEventsInfo erased event %s for %s because double red boss!\n", id.c_str(), client->m_credential.c_str());
				// Check rewards before delete event
				if (client->m_seshatProfile->IsEventRewardsCheck(id, EVENT_TYPE_RED_BOSS))
				{
					jResponse["erase"].append(id);
					client->RemoveEvent(id);
				}
			}
		}

		jResponse["add"] = std::move(newAdd);
	}

	auto redBossEvent = client->GetUniqueEvent(EVENT_TYPE_RED_BOSS);
	if (redBossEvent && redBossEvent->GetEndDate() > now)
	{
		std::uniform_int_distribution<size_t> rnd(0, 5 * 60);
		int randomDelay = (int)rnd(callerObj->m_rng);

		client->m_EventContainer.m_redOpsFinish = redBossEvent->GetEndDate() + randomDelay;
//		client->m_EventContainer.m_redOpsFinish = now + 60;	// --- DEBUG
	}

	// TrungND
	//auto survivalEvents = client->m_EventContainer.GetEventsOfType(EVENT_TYPE_SURVIVAL);
	auto survivalEvents = callerObj->FilterCustomSemEvent(client, EVENT_TYPE_SURVIVAL);

	if (survivalEvents.size() > 1)
	{
		auto it = std::max_element(survivalEvents.begin(), survivalEvents.end(), [](const SemEvent* ev1, const SemEvent* ev2)
			{
				if (ev1->GetEndDate() < ev2->GetEndDate()) return true;
				if (ev1->GetEndDate() > ev2->GetEndDate()) return false;
				return ev1->GetCanErase() > ev2->GetCanErase();
			});

		const auto keep = (*it)->GetID();
		std::vector<std::string> survivalEventIds;
		std::transform(survivalEvents.begin(), survivalEvents.end(), std::back_inserter(survivalEventIds), [](const SemEvent* ev) { return ev->GetID(); });
		survivalEventIds.erase(std::remove_if(survivalEventIds.begin(), survivalEventIds.end(), [&keep](const std::string& evId) { return evId == keep; }), survivalEventIds.end());

		Json::Value newAdd;
		for (auto& v : jResponse["add"])
		{
			auto id = v["id"].asString();

			if (std::find_if(survivalEventIds.begin(), survivalEventIds.end(), [id](const std::string& evId) { return evId == id; }) == survivalEventIds.end())
			{
				newAdd.append(std::move(v));
				if (client->FindEvent(id)->GetCategory() == EVENT_TYPE_SURVIVAL)
					client->AddUniqueCustomEvent(EVENT_TYPE_SURVIVAL, id);
			}
			else
			{
				//client->m_seshatProfile->SetIgnoreEvent(id.c_str());
				MP_LOG(DBG_WARN, "callbackScriptRequestEventsInfo erased event %s for %s because double survival!\n", id.c_str(), client->m_credential.c_str());
				jResponse["erase"].append(id);
				client->RemoveEvent(id);
			}
		}

		jResponse["add"] = std::move(newAdd);
	}

	//raw data loaded;
	client->m_outpostEventRawLoad = true;
	if (client->FeatureUnlocked("outposts_unlocked"))
	{
		client->m_multiplayer->MarkAllOutpostsDirty();
		client->m_multiplayer->UpdateConquestStatus();
	}
	// events that are empty at this point should be erased
	// --- TODO: here we should also run the cleanup for those events
	// --- i.e. for coop, we should remove any notifications, delayed transactions, loaned weapons
	// --- same for bounty: remove notifications, loaned stuff, delayed transactions - basically run the event cleanup code from above
	auto beforeEmpty = jResponse["erase"].size(); // --- for log
	client->GetEmptyEventIDs(jResponse["erase"]);
	auto it = jResponse["erase"].begin(); std::advance(it, beforeEmpty);
	for (auto ite = jResponse["erase"].end(); it != ite; ++it)
	{
		MP_LOG(DBG_WARN, "callbackScriptRequestEventsInfo erased event %s for %s because no category!\n", (*it).asString().c_str(), client->m_credential.c_str());
	}

	// --- also remove UNFINISHED events from other clans
	// --- leave the finished events since it means the client already received the reward for that event
	{
		for (const auto& ev : client->m_seshatProfile->GetEvents())
		{
			const auto& ev_clan_id = ev["clan"].asString();
			if (ev_clan_id.empty())
				continue;

			auto clientClanId = client->m_seshatProfile->GetClanData()[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID].asString();
			if (ev_clan_id != clientClanId &&
				!ev.isMember("event_finished"))
			{
				auto ev_id = ev["event_id"].asString();
				//jResponse["erase"].append(ev_id);
				if (client->m_seshatProfile->ResetClanEventOnKick(ev_id))	// --- don't remove the event, only partially reset it, keep the pools
				{
					auto ev_data = const_cast<const Json::Value&>(jEvents)[ev_id];
					if (!ev_data.isNull() && !ev_data.empty())
					{
						// --- we are removing one of the events we just received, so we need to invalidate the cache #8699898
						client->SetHash(0);
					}
				}

				if (!clientClanId.empty())
					client->m_seshatProfile->SetEventClanId(ev_id, clientClanId);
			}
		}
	}

	for (const Json::Value &jRemovableID : jResponse["erase"])
	{
		client->m_seshatProfile->RemoveEvent(jRemovableID.asString());
		client->RemoveEvent(jRemovableID.asString());

		MP_LOG(DBG_WARN, "callbackScriptRequestEventsInfo removed event %s for %s!\n", jRemovableID.asCString(), client->m_credential.c_str());

		// --- TODO: remove old elo events from pvp stats
	}

	callerObj->ServerSendEventsData(client, jResponse);

	// --- auto participate in vip, drone and bounty events; add new elo events in pvp stats
	Json::Value eventIDs;
	for (const Json::Value &jEventID : jResponse["add"])
	{
		auto eventID = jEventID["id"].asString();
		auto evt = client->FindEvent(eventID);
		if (evt && (evt->IsVip() || evt->IsElo() || evt->IsDroneOps() || evt->IsBounty() || evt->IsMiniops() || evt->IsForge() || evt->IsTopUp() || evt->IsDismiss() || evt->IsSurvival() || (evt->IsCoop() && evt->GetCanProgress()) || evt->IsPiggyBank()))
		{
			eventIDs.append(eventID);
		}
	}
	if (eventIDs.size())
		callerObj->ClientParticipateEvents(client, eventIDs);

	// --- I changed some rewards, I want to make sure the modified json is not used by mistake
	jResponse.clear();

	// --- ensure that joined boss events have the required squadops
	// --- for not-joined ones, the squad ops are added when the event is joined
	// --- should iterate, but for now just get using GetUniqueEvent(EVENT_TYPE_BOSS);
	auto bossEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_BOSS);
	if (bossEvent && client->m_seshatProfile->HasJoinedEvent(bossEvent->GetID()))
	{
		client->m_seshatProfile->StartTrackingInventoryChanges("boss:so");

		// --- then add the squad ops for the current chapter
		auto keyCredits = client->GetHestiaConfig()->FindCreditsInCategoryOrder("boss_event_key");
		for (auto chapter = 0; chapter < (int)keyCredits.size(); ++chapter)
		{
			auto sochapter = SQUAD_OPS_BOSS_CHAPTER_INDEX + chapter;
			callerObj->EnsureSquadOpsMissionsForChapter(client, sochapter, NewSquadOp::WithoutDelay);
		}

		auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
		if (!inventory_changes.empty())
		{
			callerObj->ServerSendInventoryUpdate(client, 0, std::move(inventory_changes));
		}
	}

	// --- in case there's a coop event and I'm participating, also send an update for the variable prices, in order to update the coop event skip mission cost
	auto coopEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_COOP);
	if (coopEvent && client->m_seshatProfile->HasJoinedEvent(coopEvent->GetID()))
	{
		// --- update variable prices
		auto var_price_changes = client->GetHestiaConfig()->UpdateInventoryVariableOffers(client, { "skip_event_mission", "coop_rush_chapter_config", "event_upgrade_config" });
		if (!var_price_changes.empty())
		{
			callerObj->ServerSendInventoryUpdate(client, "_variable_prices", std::move(var_price_changes));
		}
	}

	// --- in case there's a bounty event, update some variable prices
	auto bountyEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_BOUNTY);
	if (bountyEvent && client->m_seshatProfile->HasJoinedEvent(bountyEvent->GetID()))
	{
		// --- update variable prices
		auto var_price_changes = client->GetHestiaConfig()->UpdateInventoryVariableOffers(client, { "skip_bounty_mission", "event_upgrade_config", "bounty_shop_config", "bounty_shop_restock_config" });
		if (!var_price_changes.empty())
		{
			callerObj->ServerSendInventoryUpdate(client, "_variable_prices", std::move(var_price_changes));
		}
	}

	// --- in case there's a miniops event, update some variable prices
	auto miniopsEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_MINIOPS);
	if (miniopsEvent && client->m_seshatProfile->HasJoinedEvent(miniopsEvent->GetID()))
	{
		// --- update variable prices
		auto var_price_changes = client->GetHestiaConfig()->UpdateInventoryVariableOffers(client, { "miniops_shop_config", "miniops_shop_restock_config" });
		if (!var_price_changes.empty())
		{
			callerObj->ServerSendInventoryUpdate(client, "_variable_prices", std::move(var_price_changes));
		}
	}

	auto topupEvents = client->m_EventContainer.GetEventsOfType(EVENT_TYPE_TOPUP);
	if (topupEvents.empty())
	{
		client->m_seshatProfile->ResetEventTopupTransaction();
		client->m_seshatProfile->ResetEventTopupEcommEntry();
	}
	for(const auto& event : topupEvents)
	{
		if (client->m_seshatProfile->HasJoinedEvent(event->GetID()))
		{
			//add score from missing transactions
			auto score = client->m_seshatProfile->GetEventTopupScoreTransaction();
			if (score > 0)
			{
				Json::Value tmpStats(Json::nullValue);
				tmpStats["hc"] = score;
				tmpStats["topUp"] = true;
				tmpStats["entry_id"] = client->m_seshatProfile->GetEventTopupEcommEntry();
				client->m_seshatProfile->ResetEventTopupTransaction();
				client->m_seshatProfile->ResetEventTopupEcommEntry();
				antihackgs::GameServerFedManager::Instance()->UpdateEventScoresFromStatistics(client, tmpStats, 0, "", MissionUid());
				break;
			}
		}
	}

	auto survivalEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_SURVIVAL);
	if (survivalEvent)
	{
		client->GetHestiaConfig()->SetEventEnergyValues(client, EVENT_TYPE_SURVIVAL, "survival_energy", false);

		auto preset = survivalEvent->GetPreset();
		auto eventData = GameServerFedManager::Instance()->GetAHEventsData()->GetSurvivalEventData(preset);
		std::string tag = eventData.Event_Tag();

		client->m_seshatProfile->StartTrackingInventoryChanges("survival_sanity");
		client->m_seshatProfile->FixSurvivalOwnership(tag);
		auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
		if (!inventory_changes.empty())
			callerObj->ServerSendInventoryUpdate(client, "survival_sanity", std::move(inventory_changes));
	}

	auto piggyBankEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_PIGGY_BANK);
	if (piggyBankEvent)
	{
		client->m_piggyBank->SendPiggyBankEventInfoToClient(client);
	}

	// --- make sure the event participation conditions are up date
	callerObj->UpdateEventsMissionParams(client);

	// --- check clan boss event participation
	callerObj->CheckClanEventParticipation(client);

	// --- check global red boss event participation
	callerObj->CheckRedBossEventParticipation(client);

	// --- send the list of chapters that the client can delete based on progress information (this will be used against last played times held locally by each client)
	callerObj->ServerSendDeletableChapters(client);

#ifdef SKIRMISH_EVENT
	// --- check skirmish event participation
	callerObj->CheckSkirmishEventParticipation(client);
#endif // SKIRMISH_EVENT

	if (changes)
	{
		auto seasonalCollectionCodexEvents = client->m_EventContainerV2.GetEventsOfType(EVENT_TYPE_SEASONAL_COLLECTION_CODEX);
		client->m_collectionCodex->ValidateCollectionCodexProfile(seasonalCollectionCodexEvents);
	}
}

void GameServerFedManager::PatchEventVersion(Json::Value& templateData)
{
	if (templateData["event_tuning"].isMember("_event_version"))
		return;

	if (IsSemEventV2(templateData["category"].asString()))
	{
		templateData["event_tuning"]["_event_version"]["value"] = 2;
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
// TrungND
std::vector<SemEvent*> GameServerFedManager::FilterCustomSemEvent(GSClient* client, std::string eventType)
{
	auto events = client->GetEventsOfType(eventType);
	time_t now = GameServerFedManager::Instance()->GetLocalTime();

	std::vector<SemEvent*> results;
	std::vector<SemEvent*> customEvents;
	std::string matcher;
	auto userLevel = 0.0f;

	for (auto it : events)
	{
		if (it->IsCustomEvent())
		{
			if (it->GetEndDate() > now)
			{
				customEvents.push_back(it);
				matcher = it->GetEventMatcher();
			}
			else
			{
				results.push_back(it);
			}
		}
		else
		{
			results.push_back(it);
		}
	}

	// sort custom events base on level prefer (only not expired events), decrease order
	if (!customEvents.empty())
	{
		std::sort(customEvents.begin(), customEvents.end(), [](const SemEvent* ev1, const SemEvent* ev2)
			{
				return ev1->GetEventLevelPrefer() < ev2->GetEventLevelPrefer();
			});

		// get level prefer of matcher
		if (matcher == "level")
		{
			userLevel = (float)client->m_seshatProfile->GetLevel();
		}
		else if (matcher == "region")
		{
			userLevel = (float)client->m_seshatProfile->GetRegion();
		}
		else if (matcher == "spent")
		{
			userLevel = client->m_seshatProfile->GetTotalSpent();
		}
	}

	SemEvent* eventPrefer = nullptr;

	for (auto it : customEvents) {
		if (client->m_seshatProfile->HasJoinedEvent(it->GetID()))
		{
			eventPrefer = it;
			break;
		}
		else
		{
			if (userLevel >= it->GetEventLevelPrefer())
			{
				eventPrefer = it;
			}
		}
	}

	for (auto it : customEvents) {

		if (eventPrefer && it->GetID() != eventPrefer->GetID())
			it->SetCanErase();

		results.push_back(it);
	}

	return results;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptPostEventRankedScore(const GSClient *client, const Json::Value &jScores, bool autoRefreshLadder/*= false*/)
{
	Json::Value jsonRequest;

	jsonRequest["access_token"] = client->GetAccessToken();
	jsonRequest["credential"] = client->m_credential;
	jsonRequest["display_name"] = client->m_seshatProfile->GetDisplayName();
	jsonRequest["scores"] = jScores;

	for (auto& evInfo : jsonRequest["scores"])
	{
		const std::string& eventID = evInfo["event_id"].asString();
		const SemEvent* evOsiris = client->FindEvent(eventID);
		if (evOsiris && evOsiris->IsDroneOps())
		{
			evInfo["extraLeaderboard"] = evOsiris->GetAllTimeLeaderboardName();
		}
	}

	std::map<std::string, std::string> customParams;
	customParams.insert(std::pair<std::string, std::string>("event_scores", Json::FastWriter().write(jsonRequest))); // write all the necessary event info here

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_POST_EVENT_SCORE)->second, client->m_clientId, customParams, beneficiaries, callbackScriptPostEventRankedScore, this, (void*)autoRefreshLadder);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptPostEventRankedScore(const SRequest &_requestData)
{
	GameServerFedManager* callerObj = (GameServerFedManager*)(_requestData.m_callerObj);

	Json::Value response;
	Json::Reader().parse(_requestData.m_requestResponse, response);
	if (_requestData.m_errorCode || response["status"] != 200)
	{
		return;
	}

	const std::string &credential = _requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(credential);
	// --- TODO: shouldn't the profile be updated? In this case the client removal should wait for this callback?
	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "PostEventRankedScore returned for non-existing user %s!\n", credential.c_str());
		return;
	}

	if (_requestData.m_userData)
	{ // automatically refresh the leaderboard for the client
		Json::Value eventIDs(Json::arrayValue);
		for (const Json::Value &entry : response["event_scores"])
		{
			eventIDs.append(entry["event_id"]);
		}
		callerObj->ScriptRequestEventsLadder(client, eventIDs);
	}
	else for (const Json::Value &entry : response["event_scores"])
	{
		if (entry.isMember("error"))
		{
			MP_LOG(DBG_CRIT, "PostEventRankedScore failed for user %s and event %s - %s\n", credential.c_str(), entry["event_id"].asCString(), entry["error"].asCString());
		}
		else
		{
			const SemEvent *evt = client->FindEvent(entry["event_id"].asString());
			if (evt)
			{ // these events are revisited very often; refresh the leaderboard on each score update
				if ((evt->IsCoop() && evt->IsRanked()) || evt->IsDroneOps())
				{
					Json::Value eventIDs(Json::arrayValue);
					eventIDs[0u] = evt->GetID();
					callerObj->ScriptRequestEventsLadder(client, eventIDs);
				}
			}
		}
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptRequestEventsLadder(const GSClient *client, Json::Value &jEventIDs)
{
	Json::Value jClanIds(Json::objectValue);
	Json::Value jExtraLeaderboards(Json::objectValue);

	for (int i = 0; i < (int)jEventIDs.size(); ++i)
	{	// verify the validity of the request
		const SemEvent* evOsiris = client->FindEvent(jEventIDs[i].asString());
		if (!evOsiris || !evOsiris->IsRanked() || !client->m_seshatProfile->HasJoinedEvent(evOsiris->GetID()) || evOsiris->IsElo())
		{
			if (evOsiris && evOsiris->IsElo())
			{
				// --- ignore elo events ladder request, but also inhibit the error message
			}
			else if (evOsiris && evOsiris->IsBoss() && !client->m_seshatProfile->HasJoinedEvent(evOsiris->GetID()))
			{
				// --- the client sends ladder requests for clan events even if user is not in a clan (event not joined)
				// --- ignore them, but also inhibit the error message
			}
			else
			{
				MP_LOG(DBG_CRIT, "Client %s requested leaderboard for %s event %s\n!", client->m_credential.c_str(),
					(!evOsiris ? "missing" : (!evOsiris->IsRanked() ? "unranked" : "non-joined")),
					jEventIDs[i].asString().c_str());
			}
			// remove this event from the request
			jEventIDs[i] = jEventIDs[jEventIDs.size() - 1];
			jEventIDs.resize(jEventIDs.size() - 1);
			--i;
		}

		// --- add clan id for boss events
		if (evOsiris && evOsiris->IsBoss())
		{
			jClanIds[evOsiris->GetID()] = client->m_seshatProfile->GetEventClanId(evOsiris->GetID());
		}

		// --- Drone Ops events must also retrieve an additional, all-time leaderboard
		if (evOsiris && evOsiris->IsDroneOps())
		{
			jExtraLeaderboards[evOsiris->GetID()] = evOsiris->GetAllTimeLeaderboardName();
		}
	}

	if (jEventIDs.empty())
		return;

	Json::Value jFilters;
	jFilters["event_ids"] = jEventIDs;
	jFilters["top"] = DISPLAY_LADDER_TOP;
	jFilters["aroundUser"] = DISPLAY_LADDER_AROUND_USER;
	jFilters["clanIds"] = jClanIds;
	jFilters["extraLeaderboards"] = jExtraLeaderboards;

	std::map<std::string, std::string> customParams;
	customParams["credential"] = client->m_credential;
	customParams["filters"] = Json::FastWriter().write(jFilters);

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_EVENTS_LADDER)->second, client->m_clientId, customParams, beneficiaries, callbackScriptRequestEventsLadder, this);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptRequestEventsLadder(const SRequest &_requestData)
{
	GameServerFedManager* callerObj = (GameServerFedManager*)(_requestData.m_callerObj);

	Json::Value response;
	Json::Reader().parse(_requestData.m_requestResponse, response);
	if (_requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "events ladder script returned error %d - %s", response["status"].asInt(), response["reason"].asCString());
		return;
	}
	else
	{
		const std::string& credential = _requestData.m_beneficiaires[0];
		GSClient* client = callerObj->GetClient(credential);
		if (client == NULL)
		{
			MP_LOG(DBG_INFO, "RequestEventsLadder returned for non-existing user %s!\n", credential.c_str());
			return;
		}

		Json::Value &ladders = response["events_ladder"];
		Json::Value jFailures;
		for (auto eit = ladders.begin(); eit != ladders.end(); ++eit)
		{
			std::string eventID = eit.memberName();
			auto now = GameServerFedManager::Instance()->GetServerTime();
			auto evOsiris = client->FindEvent(eventID);
			auto& eventResponse = *eit;

			// --- for Drone Ops events extract the data for the additional all-time high score leadederboards and send them to client
			// --- this data can be valid even when the event leaderboard is still empty, so check it here
			if (evOsiris && evOsiris->IsDroneOps())
			{
				auto &extraData = eventResponse["extra"];
				for (const auto& topEntry : extraData["top"]["data"])
				{
					// --- MCFW-1516 - We should skip the scores <= 0 and display the first valid one.
					if (topEntry["score"].asInt() > 0)
					{
						extraData["top_player"] = topEntry;
						break;
					}
				}
				if (extraData["top"]["my_entry"].size())
				{
					extraData["my_rank"] = extraData["top"]["my_entry"]["rank"].asInt();
					extraData["my_score"] = extraData["top"]["my_entry"]["score"].asInt();
				}

				//// --- also temporary send the aroundUser leaderboard (if the user has a valid score) instead of the top leaderboard
				//// --- because the client displays only that :-/
				//auto& aroundUser = eventResponse["aroundUser"];
				//if (!aroundUser.empty() && eventResponse["score"].asInt() != EVENT_SCORE_INVALID)
				//{
				//	if (eventResponse["rank"].asInt() > 3)
				//	{
				//		eventResponse["top"] = std::move(aroundUser);
				//	}
				//	else
				//	{
				//		auto& top = eventResponse["top"];
				//		for (auto& entry : aroundUser)
				//			top.append(std::move(entry));
				//	}
				//}
			}

			if (eventResponse.isMember("error"))
			{	// cry in a corner
				MP_LOG(DBG_CRIT, "RequestEventsLadder for user %s and event %s returned error %s\n", credential.c_str(), eventID.c_str(), eventResponse["error"].asCString());
				if (client->m_seshatProfile->HasJoinedEvent(eventID) && client->m_seshatProfile->GetEventScore(eventID) > 0)
				{
					auto evOsiris = client->FindEvent(eventID);
					if (evOsiris && evOsiris->IsBoss()) // --- don't post for boss events, it's done automatically when increasing / decreasing the clan score
						continue;
					// post the score again; maybe it will work this time
					Json::Value jScore;
					jScore["event_id"] = eventID;
					jScore["event_score"] = client->m_seshatProfile->GetEventScore(eventID);
					jFailures.append(std::move(jScore));
				}
			}
			else
			{
				client->m_EventContainer.SetRank(eventID, eventResponse["rank"].asInt(), eventResponse["size"].asInt());

				// --- for boss events also send clan updates with the score
				if (evOsiris && evOsiris->IsBoss())
				{
					const auto& clanData = client->m_seshatProfile->GetClanData();
					if (clanData[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID] == client->m_seshatProfile->GetEventClanId(eventID))
					{
						auto clanScore = eventResponse["clan_score"].asDouble();
						client->m_EventContainer.SetClanScore(eventID, clanScore);

						Json::Value eventScores(Json::objectValue);
						eventScores[eventID.c_str()] = clanScore;
						Json::Value clanUpdate;
						clanUpdate["_events"] = eventScores;

						callerObj->ServerSendOwnClanToClient(client, clanUpdate);

						// --- update event scores in clien clan data
						if(client->m_clanData)
							client->m_clanData->update_event_scores(eventScores);
					}
				}

				// Survival Matcher - user just need to be on leaderboard will be counted as finished an event
				if (evOsiris && evOsiris->IsSurvival() && (evOsiris->GetEndDate() < now) && evOsiris->IsRanked())
				{
					int nb = client->m_seshatProfile->ReadCustomMatcher(SESHAT_LABEL_SURVIVAL_EVENT_FINISHED);
					client->m_seshatProfile->UpdateCustomMatcher(SESHAT_LABEL_SURVIVAL_EVENT_FINISHED, nb + 1);
				}
			}
		}
		callerObj->ServerRespondEventsLadder(client, Json::FastWriter().write(ladders).c_str());

		if (!jFailures.empty())
		{
			callerObj->ScriptPostEventRankedScore(client, jFailures);
		}
	}
}

