namespace
{
	struct GetMatchesParam
	{
		std::string name;
		int limit;
		bool hasGeolocation;
		std::string include;
		GameServerFedManager::OverrideT ovr;
		Json::Value customData;
		std::unique_ptr<ProfileOperation> operation;
	};
}	// --- namespace

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptRequestGetMatches(const GSClient* client, std::string name, int limit, const std::string& include, const OverrideT& ovr, Json::Value customData, bool location, const std::string& etag_for, std::unique_ptr<ProfileOperation> operation)
{
	std::map<std::string, std::string> customParams;
	customParams["credential"] = client->m_credential;
	customParams["access_token"] = client->GetAccessToken();
	customParams["limit"] = std::to_string(limit);
	customParams["include"] = include.empty() ? "None" : include;
	customParams["name"] = name;
	customParams["etag_for"] = etag_for;

	Json::Value j;
	for (const auto& it : ovr)
	{
		j[it.first] = it.second;
	}
	customParams["override"] = j.toStyledString();

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	GetMatchesParam* param = new GetMatchesParam;
	param->name = name;
	param->limit = limit;
	param->hasGeolocation = location;
	param->ovr = ovr;
	param->include = include;
	param->customData = std::move(customData);
	param->operation = std::move(operation);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_MATCHES)->second, client->m_clientId, customParams, beneficiaries, callbackScriptGetMatches, this, param);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetMatches(const SRequest& requestData)
{
	std::unique_ptr<GetMatchesParam> param((GetMatchesParam*)requestData.m_userData);

	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	const std::string& credential = requestData.m_beneficiaires[0];
	GSClient* client = callerObj->GetClient(credential);
	if (!client || !client->GetHestiaConfig() || client->m_seshatProfile->GetProfile().empty())
	{
		MP_LOG(DBG_WARN, "GameServerFedManager: ScriptRequestGetMatches received matches for partial client\n");
		return;
	}

	Json::Value response;
	Json::Reader reader;
	reader.parse(requestData.m_requestResponse, response);
	int status = response["status"].asInt();
	const Json::Value jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue; // --- copy because we reuse response below
	bool ok = reader.parse(response["profiles"].asString(), response);
	if (!ok)
	{
		status = 666;
		MP_LOG(DBG_INFO, "GameServerFedManager: ScriptRequestGetMatches json parse error %s\n", reader.getFormatedErrorMessages().c_str());
	}

	if (param->operation)
	{
		client->m_multiplayer->OnConquestMatchesFound(status, std::move(response), std::move(param->operation));
		return;
	}

	auto mmop = static_cast<EMatchmakingOperation>(param->customData["operation"].asInt());

	if (mmop == EMatchmakingOperation::E_FindPlayers)
	{
		client->m_seshatProfile->OnFoundPlayers(status, std::move(response), param->customData);
		return;
	}

	auto mmtype = static_cast<E_OpponentType>(param->customData["matchmaking"].asInt());
	auto what = static_cast<SeshatProfileManager::EF_FIND_OPPONENTS>(param->customData["what"].asInt());

	Json::Value profiles;
	if (status == 200)
	{
		profiles = client->m_seshatProfile->FilterOpponentProfiles(std::move(response), Hash(credential), mmtype);
	}
	else
	{
		MP_LOG(DBG_INFO, "GameServerFedManager: ScriptRequestGetMatches status %d\n", status);
	}

	client->UpdateAccessTokenFromJson(jsonAccessToken);
	switch (mmtype)
	{
	case E_OpponentType::ClanDomination:
		client->m_seshatProfile->SetClanOpponentsData(std::move(profiles));
		if (!profiles.isArray() || profiles.empty())
		{
			switch (what)
			{
			case SeshatProfileManager::EF_LEAGUE_ONLY:
				client->m_seshatProfile->SendReqFindOpponentClanDomination(SeshatProfileManager::EF_ANY, param->customData["clan_id"].asCString());
				break;

			default:
			case SeshatProfileManager::EF_ANY:
				client->m_seshatProfile->SendReqFindOpponentClanDomination(SeshatProfileManager::EF_LEAGUE_ONLY);
				break;
			}
		}
		break;

	case E_OpponentType::Miniops:
	case E_OpponentType::Pvp:
		client->m_seshatProfile->SetOpponentsData(std::move(profiles), param->hasGeolocation);

		if (!client->m_seshatProfile->GetOpponentsList().opponentsList.RequestPending && !client->m_seshatProfile->GetOpponentsList().opponentsList.NewOpponentsFound)
		{
			switch (what)
			{
			case SeshatProfileManager::EF_GEO_AND_GROUP:	
				if (!param->customData["group"].asString().empty())
				{
					if (param->customData["league"].asInt() == 1)
						client->m_seshatProfile->SendReqFindNextOpponent(SeshatProfileManager::EF_LEAGUE_AND_THIRD);
					else
						client->m_seshatProfile->SendReqFindNextOpponent(SeshatProfileManager::EF_LEAGUE_ONLY);
					return;
				}
				// --- nobreak

			case SeshatProfileManager::EF_LEAGUE_AND_THIRD:
				if (!param->customData["group"].asString().empty())
				{
					client->m_seshatProfile->SendReqFindNextOpponent(SeshatProfileManager::EF_LEAGUE_ONLY);
					return;
				}
				// --- nobreak

			case SeshatProfileManager::EF_LEAGUE_ONLY:
				if (client->m_seshatProfile->GetCachedPvpStats().GetLeague() > 2)
				{
					client->m_seshatProfile->SendReqFindNextOpponent(SeshatProfileManager::EF_HIGHER_LEAGUE_ONLY);
					return;
				}
				// --- nobreak

			case SeshatProfileManager::EF_HIGHER_LEAGUE_ONLY:
				if (client->m_seshatProfile->GetCachedPvpStats().GetLeague() < GameServerFedManager::Instance()->GetMultiplayerData()->GetLeagues(callerObj->GetCurrentLadderSettings()))
				{
					client->m_seshatProfile->SendReqFindNextOpponent(SeshatProfileManager::EF_LOWER_LEAGUE_ONLY);
					return;
				}
				// --- nobreak

			case SeshatProfileManager::EF_LOWER_LEAGUE_ONLY:
				client->m_seshatProfile->SendReqFindNextOpponent(SeshatProfileManager::EF_ANY);
				return;

			default:
				break;

			}

		}
	}
}

