void GameServerFedManager::ScriptRequestListFriends(const GSClient* client)
{
	std::map<std::string, std::string> customParams;
	customParams["credential"] = client->m_credential;
	customParams["access_token"] = client->GetAccessToken();

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_LIST_FRIENDS)->second, client->m_clientId, customParams, beneficiaries, callbackScriptListFriends, this, nullptr);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptListFriends(const SRequest& requestData)
{
	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	GSClient* client = callerObj->GetClient(requestData.m_beneficiaires[0]);
	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "RequestListFriends returned for non-existing user %s!\n", requestData.m_beneficiaires[0].c_str());
		return;
	}

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);
	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "list friends script returned error %d - %s", response["status"].asInt(), response["reason"].asCString());
		// --- TODO: what to do now?
		// --- 1) inform the client in order to inform the user; 2) retry (with exponential backkoff); 3) both
		return;
	}

	client->UpdateAccessTokenFromJson(response.get("access_token", Json::nullValue));

	// --- TODO: with response["friends"] -> parse status lines, keep resulted json, send relevant parts of it (compressed) to client
	//set the friends
	GameServerFedManager::Instance()->CreateFriendsGiftList(client, response["friends"]);
	
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
#define USER_STATUS_LINE_VERSION	3
#define HISTORY_DAY_NB				7

void GameServerFedManager::CreateFriendsGiftList(GSClient* client, Json::Value& friendList)
{
	const auto friendsStr = friendList.asCString();
	Json::Value jFriends;
	Json::Reader().parse(friendsStr, friendsStr + strlen(friendsStr), jFriends);

	Json::Value jFriendDataArray;
	int nbFriends = (int)jFriends.size();
	client->m_seshatProfile->SetFriendsNumber(nbFriends);

	for (int i = 0; i < (int)jFriends.size(); i++)
	{
		std::string statusLine = jFriends[i]["status_line"].asString();
		//char tm[7], td[7];
		//CEG TODO: logic must be dine for yesterday
		//std::string giftId = "claimed";
		int player_level = 1;
		int player_prestige_level = 1;
		if (statusLine.size())
		{
			if (statusLine.at(0) == 'y')
			{
				sscanf(statusLine.c_str() + 1, "%2d", &player_level);
				sscanf(statusLine.c_str() + 3, "%3d", &player_prestige_level);
			}
			else if (statusLine.at(0) == 'x')
				sscanf(statusLine.c_str() + 1, "%2d", &player_level);
			else
				sscanf(statusLine.c_str() + 1 + HISTORY_DAY_NB * 2, "%2d", &player_level);
		}

		//create the combined json (for each friend I have a gift list)
		auto& jFriend = jFriends[i];

		Json::Value jFriendData;
		jFriendData["name"] = std::move(jFriend["name"]);
		jFriendData["avatar"] = std::move(jFriend["avatar"]);
		jFriendData["fed_id"] = std::move(jFriend["fed_id"]);
		jFriendData["credential"] = std::move(jFriend["credential"]);
		jFriendData["credentials"] = std::move(jFriend["credentials"]);
		//jFriendData["gift_id"] = giftId; //CEG TODO: create gift list
		jFriendData["player_level"] = player_level; 
		jFriendData["player_prestige_level"] = player_prestige_level;

		jFriendDataArray.append(std::move(jFriendData));
	}
	//create the combined json
	GameServerFedManager::Instance()->ServerSendListConnectionToPlayer(client->m_credential, Json::FastWriter().write(jFriendDataArray).c_str());
}

