void GameServerFedManager::ScriptRequestUpdateStatusLine(const GSClient* client, const std::string& statusLine)
{
	std::map<std::string, std::string> customParams;
	customParams["credential"] = client->m_credential;
	customParams["access_token"] = client->GetAccessToken();
	customParams["status_line"] = statusLine;

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);
	
	//save status line
	m_playerStatusLine = statusLine;
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_UPDATE_STATUS_LINE)->second, client->m_clientId, customParams, beneficiaries, callbackScriptUpdateStatusLine, this, nullptr);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptUpdateStatusLine(const SRequest& requestData)
{
	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	GSClient* client = callerObj->GetClient(requestData.m_beneficiaires[0]);
	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "UpdateStatusLine returned for non-existing user %s!\n", requestData.m_beneficiaires[0].c_str());
		return;
	}

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);
	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "update status line script returned error %d - %s", response["status"].asInt(), response["reason"].asCString());
		// --- TODO: what to do now?
		// --- most likely retry with exponential backoff, as this is kind of important
		return;
	}

	client->UpdateAccessTokenFromJson(response.get("access_token", Json::nullValue));

	MP_LOG(DBG_INFO, "update status line script success for %s", requestData.m_beneficiaires[0].c_str());

	
	// --- test - also get the friends list
	GameServerFedManager::Instance()->ScriptRequestListFriends(client);
}

