void GameServerFedManager::ScriptRequestGetOsirisProfile(const GSClient* client, bool initialRequest)
{
	std::map<std::string, std::string> customParams;
	customParams["credential"] = client->m_credential;
	customParams["access_token"] = client->GetAccessToken();

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_OSIRIS_PROFILE)->second, client->m_clientId, customParams, beneficiaries, callbackScriptGetOsirisProfile, this, initialRequest ? reinterpret_cast<void *>(initialRequest) : nullptr);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetOsirisProfile(const SRequest& requestData)
{
	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	GSClient* client = callerObj->GetClient(requestData.m_beneficiaires[0]);
	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "GetOsirisProfile returned for non-existing user %s!\n", requestData.m_beneficiaires[0].c_str());
		return;
	}

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);
	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "get osiris profile script returned error %d - %s", response["status"].asInt(), response["reason"].asCString());
		// --- TODO: what to do now?
		// --- most likely retry with exponential backoff, as this is kind of important
		return;
	}

	client->UpdateAccessTokenFromJson(response.get("access_token", Json::nullValue));

	MP_LOG(DBG_INFO, "get osiris profile script success for %s", requestData.m_beneficiaires[0].c_str());

	Json::Value jOsirisProfile = response["profile"];
	
	auto osirisProfileStr = jOsirisProfile.asString();
	Json::Value jStatusLine;
	Json::Reader().parse(osirisProfileStr, jStatusLine);

	client->m_osirisGroups.clear();
	for (const auto& groupID : jStatusLine["groups"])
	{
		client->m_osirisGroups.push_back(groupID.asString());
	}

	std::string statusLineStr = jStatusLine["status_line"].asString();
	
	//status line - update
	//std::string status_line = "2;A;B;C;D;E;F;G";
	const auto& profileJson = client->m_seshatProfile->GetProfile();
	int xp = profileJson[SESHAT_LABEL_STANDARD_INVENTORY].get(SESHAT_LABEL_XP, 0).asInt();

	//GameServerFedManager::Instance()->UpdateUserStatusLineForToday(statusLineStr, true);
	if (client->GetHestiaConfig())
	{
		auto newLevel = client->GetHestiaConfig()->FindPlayerLevel(xp);
		GameServerFedManager::Instance()->UpdateUserStatusLineLevel(statusLineStr, newLevel, client->m_seshatProfile->GetPrestigeLevel());
	}
	GameServerFedManager::Instance()->ScriptRequestUpdateStatusLine(client, statusLineStr);

	if (requestData.m_userData)
	{
		//this is the first time that GetProfile was called for this client, perform some checks and initializaions, and send it to the client as well
		GameServerFedManager::Instance()->ProcessOsirisInfo(client, osirisProfileStr);
		GameServerFedManager::Instance()->ServerSendOsirisInfo(client, osirisProfileStr);
	}
}

void GameServerFedManager::ScriptRequestUpdateOsirisProfile(const GSClient* client, const std::string& name, const std::string& country, const std::string& language)
{
	std::map<std::string, std::string> customParams;
	customParams["credential"] = client->m_credential;
	customParams["access_token"] = client->GetAccessToken();
	if (name.length())
		customParams["name"] = name;
	customParams["country"] = country;
	customParams["language"] = language;

	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_UPDATE_OSIRIS_PROFILE)->second, client->m_clientId, customParams, beneficiaries, callbackScriptUpdateOsirisProfile, this, nullptr);
}

void GameServerFedManager::callbackScriptUpdateOsirisProfile(const SRequest & requestData)
{
	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	GSClient* client = callerObj->GetClient(requestData.m_beneficiaires[0]);
	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "UpdateOsirisProfile returned for non-existing user %s!\n", requestData.m_beneficiaires[0].c_str());
		return;
	}

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);
	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "update_osiris_profile script returned error %d - %s", response["status"].asInt(), response["reason"].asCString());
		GameServerFedManager::Instance()->ServerSendUpdateOsirisProfileConfirmation(client, false);
		return;
	}

	client->UpdateAccessTokenFromJson(response.get("access_token", Json::nullValue));

	GameServerFedManager::Instance()->ScriptRequestGetOsirisProfile(client);
	GameServerFedManager::Instance()->ServerSendUpdateOsirisProfileConfirmation(client, true);

	MP_LOG(DBG_INFO, "get_osiris_profile script success for %s", requestData.m_beneficiaires[0].c_str());
}

