namespace
{
	struct ScripAliasUserData
	{
		std::string credential;
		std::string alias;
	};

}	// --- namespace

void GameServerFedManager::ScriptRequestGetCredentialFromAlias(const GSClient* client, const std::string& alias)
{
	// --- TODO: validate datacenter / env, for now remove dc / pid letter
	MP_LOG(DBG_INFO, "ScriptRequestGetCredentialFromAlias start for alias %s!\n", alias.c_str());
	auto janusAlias = alias;

	auto ok = CheckAlias(janusAlias, false);
	if (!ok)
	{
		// delete friends from alias list
		client->m_seshatProfile->DeleteFriendAliasInList(alias.c_str());
		MP_LOG(DBG_CRIT, "TCPMSG_CLIENT_ADD_CONNECTION CheckAlias(friend_alias) not ok\n");
		return;
	}

	// --- remove dc/pid letter and checksum letter
	janusAlias = janusAlias.substr(1, janusAlias.length() - 2);
	janusAlias = RotateString(janusAlias, -2);

	std::map<std::string, std::string> customParams = {
		{ "alias",		janusAlias },
		{ "game",		"mcfw" },
		{ "client_id",	client->m_clientId },
	};
	
	auto* pUserData = new ScripAliasUserData;
	pUserData->credential = client->m_credential;
	pUserData->alias = alias;

	//auto userData = new std::string(client->m_credential);
	
	MP_LOG(DBG_INFO, "StartNewRequest callbackScriptGetCredentialFromAlias!\n");
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_LOOKUP_ALIAS)->second, client->m_clientId, customParams, {}, callbackScriptGetCredentialFromAlias, this, (void*)pUserData);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetCredentialFromAlias(const SRequest& requestData)
{
	MP_LOG(DBG_INFO, "callbackScriptGetCredentialFromAlias!\n");
	//std::unique_ptr<std::string> credential((std::string*)requestData.m_userData);
	std::unique_ptr<ScripAliasUserData> pUserData((ScripAliasUserData*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	auto client = serverMgr->GetClient(pUserData->credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		MP_LOG(DBG_WARN, "TCPMSG_CLIENT_ADD_CONNECTION callbackScriptGetCredentialFromAlias client is no longer connected\n");
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptGetCredentialFromAlias script returned error %d - %s for %s", response["status"].asInt(), response["reason"].asCString(), pUserData->credential.c_str());
		return;
	}

	// --- parse the response
	Json::Value alias;
	Json::Reader().parse(response["reply"].asCString(), alias);
	response = Json::nullValue; // --- to free the mem

	auto target_credential = alias["credential"].asString();

	if (client->m_seshatProfile->IsInvalid() || !client->GetHestiaConfig())
	{
		MP_LOG(DBG_INFO, "callbackScriptGetCredentialFromAlias error client->m_seshatProfile->IsInvalid() || !client->GetHestiaConfig()!\n");
		return;
	}

	MP_LOG(DBG_INFO, "TCPMSG_CLIENT_ADD_CONNECTION call ScriptRequestAddConnection %s %s \n", target_credential.c_str(), pUserData->alias.c_str());
	GameServerFedManager::Instance()->ScriptRequestAddConnection(client, target_credential, pUserData->alias);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptRequestAddConnection(const GSClient* client, const std::string& target_credential, const std::string& target_alias)
{
	MP_LOG(DBG_INFO, "ScriptRequestAddConnection start for target %s!\n", target_credential.c_str());
	std::map<std::string, std::string> customParams;
	if (target_credential.length())
		customParams["target_credential"] = target_credential;
	customParams["credential"] = client->m_credential;
	customParams["access_token"] = client->GetAccessToken();
	
	std::vector<std::string> beneficiaries;
	beneficiaries.push_back(client->m_credential);
	
	auto userData = new std::string(target_alias);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_ADD_CONNECTION)->second, client->m_clientId, customParams, beneficiaries, callbackScriptAddConnection, this, userData);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptAddConnection(const SRequest & requestData)
{
	MP_LOG(DBG_INFO, "callbackScriptAddConnection!\n");
	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	GSClient* client = callerObj->GetClient(requestData.m_beneficiaires[0]);
	std::unique_ptr<std::string> alias((std::string*)requestData.m_userData);
	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "add_connection returned for non-existing user %s!\n", requestData.m_beneficiaires[0].c_str());
		return;
	}

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);
	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "add_connection script returned error %d - %s", response["status"].asInt(), response["reason"].asCString());
		return;
	}


	callerObj->SetAchievementProgress(client, StringHash("invite_friend"), 1);
	client->m_seshatProfile->StartTrackingInventoryChanges();
	client->m_seshatProfile->BattlePassIncMilestone("invite_friend", 1);

	auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
	if (!inventory_changes.empty())
		callerObj->ServerSendInventoryUpdate(client, "battle_pass", std::move(inventory_changes));

	client->UpdateAccessTokenFromJson(response.get("access_token", Json::nullValue));
	MP_LOG(DBG_INFO, "add_connection script success for %s", requestData.m_beneficiaires[0].c_str());

	//delete friends from alias list
	client->m_seshatProfile->DeleteFriendAliasInList(alias->c_str());
	// --- 4 - start a request to update the friends list
	GameServerFedManager::Instance()->ScriptRequestListFriends(client);
}

