namespace
{

	struct ScriptEloLadder_Data
	{
		std::unique_ptr<LadderOperation> operation;
	};

}	// --- namespace

void GameServerFedManager::ScriptGetEloLadder(std::unique_ptr<LadderOperation> operation)
{
	operation->ladderId = (operation->operation == ELO_GET_EXPIRED_LADDER) ? GetLadderId(operation->post_timestamp) : GetCurrentLadderId();

	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->for_credential) },
		{ "credential",		operation->for_credential },
		{ "lb",				operation->ladderId },
	};

#ifdef RED_BOSS_CLAN_LEADERBOARD
	std::unique_ptr<ClanOperation> clanLeaderboardOp(new ClanOperation());
#endif // RED_BOSS_CLAN_LEADERBOARD

	// --- TODO
	//customParams["offset"] = "0";
	//customParams["limit"] = "50";

	switch (operation->operation)
	{
	case ELO_GET_EXPIRED_LADDER:
		customParams["limit"] = "1";
		customParams["type"] = "top";
		break;
	case ELO_GET_TIERED_GROUP:
		customParams["limit"] = "1";
		// --- nobreak

	case ELO_GET_TIERED:
		customParams["type"] = "me";
		GLF_ASSERTMSG(operation->tier, "ScriptGetEloLadder for tiered leaderboard without valid tier");
		customParams["tier"] = std::to_string(operation->tier);
		break;
	case ELO_GET_TOP:
		customParams["type"] = "top";
		customParams["limit"] = std::to_string(operation->limit);
		customParams["offset"] = std::to_string(operation->offset);
		break;
	case ELO_GET_TOP_PLAYERS:
		customParams["type"] = "top_players";
		customParams["limit"] = std::to_string(operation->limit);
		customParams["offset"] = std::to_string(operation->offset);
		break;
	case ELO_GET_FRIENDS:
		customParams["type"] = "friends";
		customParams["limit"] = std::to_string(100);
		break;
	case ELO_GET_RED_BOSS_GLOBAL:
		customParams["type"] = RedBossLeaderboardName(operation->eventId, ERedBossLeaderboardType::Global);
		customParams["limit"] = std::to_string(100);
		break;
	case ELO_GET_RED_BOSS_LEAGUE:
		customParams["type"] = RedBossLeaderboardName(operation->eventId, ERedBossLeaderboardType(operation->league));
		customParams["limit"] = std::to_string(100);
		break;
#ifdef RED_BOSS_CLAN_LEADERBOARD
	case ELO_GET_RED_BOSS_CLAN:
		clanLeaderboardOp->client_id = operation->client_id;
		clanLeaderboardOp->owner_credential = operation->owner_credential;
		clanLeaderboardOp->operation = ECO_GET_RED_BOSS_CLAN;
		clanLeaderboardOp->data["lb_name"] = RedBossClanLeaderboardName(operation->eventId);
		clanLeaderboardOp->data["eventId"] = operation->eventId;
		clanLeaderboardOp->data["sendToClient"] = operation->sendToClient;

		// Trung: function to get clan leaderboard entries
		ScriptGetRedBossClansLeaderboard(std::move(clanLeaderboardOp));
		return;
#endif // RED_BOSS_CLAN_LEADERBOARD

	default:
		GLF_ASSERTMSG(false, "Invalid operation %d for ScriptGetEloLadder", operation->operation);
		return;
	}

	MST_LOG("ScriptGetEloLadder for %s lb_id %s op %d tier %d", operation->for_credential.c_str(), GetCurrentLadderId(), operation->operation, operation->tier);

	auto data = new ScriptEloLadder_Data{ std::move(operation) };

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_ELO_LADDER)->second, data->operation->client_id, customParams, {}, callbackScriptGetEloLadder, this, data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetEloLadder(const SRequest& requestData)
{
	std::unique_ptr<ScriptEloLadder_Data> data((ScriptEloLadder_Data*)requestData.m_userData);

	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->for_credential);

	if (requestData.m_errorCode || response["status"].asInt() != 200)
	{
		MP_LOG(DBG_WARN, "ScriptGetEloLadder script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->for_credential.c_str());

		if (data->operation->operation == ELO_GET_EXPIRED_LADDER && 
			response["status"].asInt() == 404)
		{
			// --- if the leaderboard is no longer, use the current elo for reset
			response["reply"] = "{}";
		}
		else
		{
			// --- lost a top lb refresh
			if (data->operation->operation == ELO_GET_TOP ||
				data->operation->operation == ELO_GET_TOP_PLAYERS)
			{
				//serverMgr->m_topLeaderboard.get_fail(data->operation->cookie);
				serverMgr->m_eloLadder->on_get_error(std::move(data->operation));
			}

			return;
		}
	}

	StringHash ladderType;
	switch (data->operation->operation)
	{
	case ELO_GET_TOP: ladderType = StringHash("top"); break;
	case ELO_GET_TOP_PLAYERS: ladderType = StringHash("top_players"); break;
	case ELO_GET_FRIENDS: ladderType = StringHash("friends"); break;
	case ELO_GET_TIERED: ladderType = StringHash("me"); break;
	case ELO_GET_TIERED_GROUP: ladderType = 0; break;
	case ELO_GET_EXPIRED_LADDER: ladderType = 0; break;
	case ELO_GET_RED_BOSS_GLOBAL: ladderType = StringHash("red_boss_global"); break;
	case ELO_GET_RED_BOSS_LEAGUE: ladderType = StringHash("red_boss_league"); break;
#ifdef RED_BOSS_CLAN_LEADERBOARD
	case ELO_GET_RED_BOSS_CLAN: ladderType = StringHash("red_boss_clan"); break;
#endif // RED_BOSS_CLAN_LEADERBOARD

	default:
		MP_LOG(DBG_WARN, "ScriptGetEloLadder script op %d invalid for %s", data->operation->operation, data->operation->for_credential.c_str());
		return;
	}

	// --- parse the get reply
	Json::Value jReply;
	Json::Reader().parse(response["reply"].asCString(), jReply);

	if (!jReply.isObject())
	{
		MP_LOG(DBG_CRIT, "ScriptGetEloLadder script op %d returned error reply for %s", data->operation->operation, data->operation->for_credential.c_str());

		// --- lost a top lb refresh
		if (data->operation->operation == ELO_GET_TOP ||
			data->operation->operation == ELO_GET_TOP_PLAYERS)
		{
			//serverMgr->m_topLeaderboard.get_fail(data->operation->cookie);
			serverMgr->m_eloLadder->on_get_error(std::move(data->operation));
		}

		return;
	}

	// --- add the cookie
	jReply["cookie"] = data->operation->cookie;

	// achievement for top 10 in diamond league (top sniper)
	if (client && data->operation->operation == ELO_GET_TIERED)
	{
		auto myScore = jReply["my_entry"]["score"].asInt();
		auto myLeague = serverMgr->GetMultiplayerData()->FindLeague(serverMgr->GetEloSettingsForLadder(data->operation->ladderId), myScore);
		auto myRank = jReply["my_entry"]["rank"].asInt();
		if (myLeague == 1 && myRank <= 10)
		{
			GameServerFedManager::Instance()->SetAchievementProgress(client, StringHash("pvpTop10"), 1);
		}
	}

	// --- for friends and top ladders add the league
	// --- friends no longer used
	if (//data->operation->operation == ELO_GET_FRIENDS ||
		data->operation->operation == ELO_GET_TOP ||
		data->operation->operation == ELO_GET_TOP_PLAYERS)
	{
		//serverMgr->m_topLeaderboard.process_data(jReply);
		serverMgr->m_eloLadder->on_data(std::move(data->operation), std::move(jReply));

		return;
	}
	else if (data->operation->operation == ELO_GET_EXPIRED_LADDER)
	{
		if (!client)
			return;

		auto myRank = jReply["my_entry"]["rank"].asInt();
		auto myScore = jReply["my_entry"]["score"].asInt();
		if (!myScore)
			myScore = data->operation->score;	// --- use current score as fallback

		MP_LOG(DBG_WARN, "Performing season reset for user %s - lbScore %d used score %d current score %d\n",
			client->m_credential.c_str(), jReply["my_entry"]["score"].asInt(), myScore, data->operation->score);

		auto md = serverMgr->GetMultiplayerData();
		int elo = data->operation->score; // --- current score
		auto eloSettings = serverMgr->GetEloSettingsForLadder(data->operation->ladderId);
		auto maxElo = md->GetResetElo(eloSettings);
		// --- TODO: elo - should use the reset elo of the operation ladderId to compute the amount of diamond heads
		// --- and the reset elo of the current ladderId to compute the new elo...
		// --- fortunately for now they have the same value

		// --- award diamond heads
		int diff = myScore - maxElo; // --- this is the initial amount of diamond heads
		if (myScore > maxElo)
		{
			// --- set to no less than MaxElo on seazon end
			elo -= diff;
			if (elo < maxElo)
				elo = maxElo;
		}
		else
		{
			elo = 0; // --- do not change
		}

		// --- check for diamond points override
		auto dh = diff;
		auto league = md->FindLeague(eloSettings, myScore);
		const auto& jDiamondPoints = md->GetLeagueDiamondPoints(eloSettings, league);
		if (!jDiamondPoints.isNull() && jDiamondPoints.isInt())
			dh = jDiamondPoints.asInt();

		// --- check for "in hof at season end" reward
		bool inHof = false;
		auto seasonData = md->HofDataForSeason(StringHash(data->operation->ladderId.c_str()));
		if (seasonData)
		{
			MP_LOG(DBG_WARN, "Checking for hof reward during season reset for user %s - lbScore %d used score %d current score %d rank %d\n",
				client->m_credential.c_str(), jReply["my_entry"]["score"].asInt(), myScore, data->operation->score, myRank);

			// --- check hof entry conditions
			inHof = (myScore > seasonData->min_elo) && 
				(!seasonData->hof_places || (myRank < seasonData->hof_places));
			if (inHof)
			{
				dh += seasonData->hof_dp_reward;
			}
		}
		else
		{
			GLF_ASSERTMSG(false, "No season data found for ladder id %s for cred %s", data->operation->ladderId.c_str(), data->operation->for_credential.c_str());
			MP_LOG(DBG_CRIT, "No season data found for ladder id %s for cred %s", data->operation->ladderId.c_str(), data->operation->for_credential.c_str());
		}

		// --- award diamond points
		if (dh > 0)
		{
			client->m_seshatProfile->StartTrackingInventoryChanges("reset_leaderboard");
			client->m_seshatProfile->AddNotificationFromServer(inHof ? "end_of_season_reward_hof" : "end_of_season_reward", 
				data->operation->ladderId, dh, ENM_CATEGORY | ENM_INFO);
			auto changes = client->m_seshatProfile->StopTrackingInventoryChanges();
			if (!changes.empty())
				GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, "reset_leaderboard", std::move(changes));

			// --- update clan score and member score if necessary
			auto clan_id = client->m_seshatProfile->GetClanData()[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID].asString();
			if (!clan_id.empty())
			{
				//auto cop = std::unique_ptr<ClanOperation>(new ClanOperation);
				//cop->client_id = data->operation->client_id;
				//cop->for_credential = data->operation->for_credential;
				//cop->owner_credential = data->operation->owner_credential;
				//cop->data["score"] = myScore - elo;
				//cop->data["group_id"] = clan_id;
				//cop->data["operation"] = "dec";
				//cop->data["etag_for"] = CLAN_ETAG_FOR;
				//cop->operation = ECO_UPDATE_CLAN_SCORE;
				//GameServerFedManager::Instance()->ScriptClanUpdateScore(std::move(cop));
				
				auto cop = std::unique_ptr<ClanOperation>(new ClanOperation);
				cop->client_id = data->operation->client_id;
				cop->for_credential = data->operation->for_credential;
				cop->owner_credential = data->operation->owner_credential;
				cop->data["_score"] = elo;
				cop->data["group_id"] = clan_id;
				cop->operation = ECO_SET_CLAN_MEMBER_FIELD;
				GameServerFedManager::Instance()->ScriptClanSetMemberField(std::move(cop));
			}
		}

		// --- append hall of fame data in profile
		if (seasonData)
		{
			if (inHof)
			{
				client->m_seshatProfile->StartTrackingInventoryChanges("hall_of_fame_data");
				bool existing = client->m_seshatProfile->SetSeasonEndData(myScore, myRank, data->operation->ladderId);
				
				if (!existing && myRank <= seasonData->places)
				{
					client->m_seshatProfile->AddNotificationFromServer("hall_of_fame_reward", data->operation->ladderId, 0, ENM_CATEGORY | ENM_INFO);

					//update top 20 hof finish
					if (myRank <= 20)
					{
						GameServerFedManager::Instance()->SetAchievementProgress(client, StringHash("hof.top20"), 1);
					}
				}
				auto changes = client->m_seshatProfile->StopTrackingInventoryChanges();
				if (!changes.empty())
					GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, "hall_of_fame_data", std::move(changes));
			}
		}
		else
		{
			GLF_ASSERTMSG(false, "No season data found for ladder id %s for cred %s", data->operation->ladderId.c_str(), data->operation->for_credential.c_str());
			MP_LOG(DBG_CRIT, "No season data found for ladder id %s -- for cred %s", data->operation->ladderId.c_str(), data->operation->for_credential.c_str());
		}

		// --- update ts
		Multiplayer::SaveScratchpad(-1, 0, GameServerFedManager::Instance()->GetLocalTime(), elo, 0, data->operation->for_credential, data->operation->owner_credential, data->operation->client_id);
		if (elo)	// --- elo changed, update client
			Multiplayer::UpdateProfilePvpStats(client->m_credential, client->m_credential, client->m_seshatProfile->GetCachedPvpStatsJson(), client->m_clientId, Multiplayer::EUPPS_SendToClient);
	}
	else if (data->operation->operation == ELO_GET_RED_BOSS_GLOBAL)
	{
		if (client && ladderType)
		{
			if (data->operation->sendToClient)
				serverMgr->ServerSendEloLadder(client, ladderType, Json::FastWriter().write(jReply).c_str());
			client->m_seshatProfile->CheckRedOpsRewards(data->operation->eventId, ERedBossRewardType::GlobalLadder, jReply);
		}

		data->operation->operation = ELO_GET_RED_BOSS_LEAGUE;
		serverMgr->ScriptGetEloLadder(std::move(data->operation));
		return;
	}
	else if (data->operation->operation == ELO_GET_RED_BOSS_LEAGUE)
	{
		if (client && ladderType)
		{
			jReply["my_league"] = data->operation->league;
			if (data->operation->sendToClient)
				serverMgr->ServerSendEloLadder(client, ladderType, Json::FastWriter().write(jReply).c_str());
			client->m_seshatProfile->CheckRedOpsRewards(data->operation->eventId, ERedBossRewardType::LeagueLadder, jReply);
		}

#ifdef RED_BOSS_CLAN_LEADERBOARD
		// Trung: after get global and tier LB, we get clan LB
		data->operation->operation = ELO_GET_RED_BOSS_CLAN;
		serverMgr->ScriptGetEloLadder(std::move(data->operation));
		return;
#endif // RED_BOSS_CLAN_LEADERBOARD
	}

	else
	{
		const auto& group = jReply["division"].asString();
		Multiplayer::UpdateGroup(group, data->operation->for_credential, data->operation->owner_credential);

		if (client && ladderType)
		{
			serverMgr->ServerSendEloLadder(client, ladderType, Json::FastWriter().write(jReply).c_str());
		}
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptPostRedBossLadder(std::unique_ptr<LadderOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->for_credential) },
		{ "credential",		operation->for_credential },
		{ "score",			std::to_string(operation->large_score) },
		{ "display_name",	operation->display_name },
		{ "clan_name",		operation->clan_name },
		{ "lb",				GetCurrentLadderId() },
		{ "level",			std::to_string(operation->level) },
		{ "prestige",		std::to_string(operation->prestige) },
		{ "league",			std::to_string(operation->league) },
	};

	switch (operation->operation)
	{
	case ELO_POST_RED_BOSS_GLOBAL:
		customParams["type"] = RedBossLeaderboardName(operation->eventId, ERedBossLeaderboardType::Global);
		break;

	case ELO_POST_RED_BOSS_LEAGUE:
		customParams["type"] = RedBossLeaderboardName(operation->eventId, ERedBossLeaderboardType(operation->league));
		break;

	default:
		GLF_ASSERTMSG(false, "Invalid operation %d for ScriptPostRedBossLadder", operation->operation);
		return;
	}

	auto custom_data = new ScriptEloLadder_Data{ std::move(operation) };
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_POST_ELO_LADDER)->second, custom_data->operation->client_id, customParams, {}, callbackScriptPostRedBossLadder, this, custom_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptPostRedBossLadder(const SRequest& requestData)
{
	std::unique_ptr<ScriptEloLadder_Data> data((ScriptEloLadder_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptPostEloLadder script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->for_credential.c_str());
		return;
	}

	if (data->operation->operation == ELO_POST_RED_BOSS_GLOBAL)
	{
		data->operation->operation = ELO_POST_RED_BOSS_LEAGUE;
		serverMgr->ScriptPostRedBossLadder(std::move(data->operation));
		return;
	}
	else if (data->operation->operation == ELO_POST_RED_BOSS_LEAGUE)
	{
		data->operation->operation = ELO_GET_RED_BOSS_GLOBAL;
		serverMgr->ScriptGetEloLadder(std::move(data->operation));
		return;
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptPostEloLadder(std::unique_ptr<LadderOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->for_credential) },
		{ "credential",		operation->for_credential },
		{ "score",			std::to_string(operation->score) },
		{ "display_name",	operation->display_name },
		{ "clan_name",		operation->clan_name },
		{ "level",			std::to_string(operation->level) },
		{ "prestige",		std::to_string(operation->prestige) },
		{ "lb",				GetCurrentLadderId() },
		{ "hof",			std::to_string(operation->hofSeason) },
	};

	GLF_ASSERTMSG(operation->operation == ELO_POST, "Invalid operation %d for ScriptPostEloLadder", operation->operation);

	{
		auto tiered_data = new ScriptEloLadder_Data{ std::unique_ptr<LadderOperation>(new LadderOperation(*operation)) }; // --- copy operation
		tiered_data->operation->operation = ELO_POST_TIERED;

		// --- first post to tiered
		customParams["type"] = "me";
		if (operation->tier) // --- only send tier if one is set; otherwise it means I'm new to the lb and I let it assign me to a tier
			customParams["tier"] = std::to_string(operation->tier);

		m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_POST_ELO_LADDER)->second, tiered_data->operation->client_id, customParams, {}, callbackScriptPostEloLadder, this, tiered_data);
	}

	// --- then post to global leaderboard
	{
		auto global_data = new ScriptEloLadder_Data{ std::make_unique<LadderOperation>(*operation) };
		global_data->operation->operation = ELO_POST_GLOBAL;

		customParams["type"] = "top";
		customParams.erase("tier");
		m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_POST_ELO_LADDER)->second, global_data->operation->client_id, customParams, {}, callbackScriptPostEloLadder, this, global_data);
	}

	// --- then do any additional leaderboard operations required by the current lb model
	m_eloLadder->additional_post_op(std::move(operation), std::move(customParams));
}

