void GameServerFedManager::ScriptPostEloTopPlayersLadder(std::unique_ptr<LadderOperation> operation, std::map<std::string, std::string>&& customParams)
{
	auto top_players_data = new ScriptEloLadder_Data{ std::move(operation) };
	top_players_data->operation->operation = ELO_POST_TOP_PLAYERS;
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_POST_ELO_LADDER)->second, top_players_data->operation->client_id, customParams, {}, callbackScriptPostEloLadder, this, top_players_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptPostEloLadder(const SRequest& requestData)
{
	std::unique_ptr<ScriptEloLadder_Data> data((ScriptEloLadder_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptPostEloLadder script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->for_credential.c_str());
		return;
	}

	// --- so that we can check if the client is connected to this instance
	// --- when returning from a post, update the leaderboards if the client is connected
	auto client = serverMgr->GetClient(data->operation->for_credential);

	if (data->operation->operation == ELO_POST_TOP_PLAYERS)
	{
		serverMgr->m_eloLadder->on_post(client, std::move(data->operation));
	}
	else if (data->operation->operation == ELO_POST_GLOBAL)
	{
		serverMgr->m_eloLadder->on_post(client, std::move(data->operation));

		//// --- for global, we only do the get for connected clients
		//if (!client)
		//	return;

		//// --- after global post, update top
		//serverMgr->m_topLeaderboard.should_get_top(client, std::move(data->operation));
	}
	else if (data->operation->operation == ELO_POST_TIERED)
	{
		// --- parse the reply which should contain the new tier
		int new_tier = response["new_tier"].asInt();
		if (!new_tier)
		{
			// --- couldn't parse the reply for the tiered leaderboard post - the operation must have failed for some reason
			MP_LOG(DBG_CRIT, "ScriptPostEloLadder script op %d could not parse reply %s for tiered leaderboard post for %s", data->operation->operation, response["reply"].asCString(), data->operation->for_credential.c_str());
			return;
		}

//		GLF_ASSERT(data->operation->for_credential == data->operation->owner_credential);	// --- TODO: this fires because for_credential is fed_id while owner_credential is anonymous

		bool force_group = false;
		if (new_tier != data->operation->tier || 
			data->operation->post_timestamp) // --- first post in current leaderboard
		{
			MST_LOG("callbackScriptPostEloLadder tier changed or first time in leaderboard for %s old tier %d new tier %d", data->operation->for_credential.c_str(), data->operation->tier, new_tier);

			// --- the tier in the leaderboard changed as a result of the post -> update the olympus_tier in seshat
			force_group = true;
			Multiplayer::SaveScratchpad(new_tier, data->operation->post_timestamp, 0, 0, -1, data->operation->for_credential, data->operation->owner_credential, data->operation->client_id);

			if (data->operation->post_timestamp && client)
				Multiplayer::UpdateProfilePvpStats(client->m_credential, client->m_credential, client->m_seshatProfile->GetCachedPvpStatsJson(), client->m_clientId, Multiplayer::EUPPS_SendToClient);
		}

		// --- after a tiered post do a get for connected clients
		// --- TODO: to a get anyway with limit 1 for the group? only if the tier changed...
		if (!client && !force_group)
			return;

		data->operation->operation = client ? ELO_GET_TIERED : ELO_GET_TIERED_GROUP;
		data->operation->tier = new_tier;
		GameServerFedManager::Instance()->ScriptGetEloLadder(std::move(data->operation));
	}
	else
	{
		GLF_ASSERTMSG(false, "callbackScriptPostEloLadder with invalid operation %d", data->operation->operation);
	}
}

