void GameServerFedManager::ScriptGetMPLadder(std::unique_ptr<LadderOperation> operation)
{
	if(operation->ladderId.empty())
		operation->ladderId = GetCurrentLadderId();

	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->for_credential) },
		{ "credential",		operation->for_credential },
		{ "lb",				operation->ladderId },
	};

	switch (operation->operation)
	{
	case ELO_GET_MP_TIERED:
		customParams["type"] = "mp";
		GLF_ASSERTMSG(operation->tier, "ScriptGetMPLadder for tiered leaderboard without valid tier");
		customParams["tier"] = std::to_string(operation->tier);
		break;
	case ELO_GET_MP_TOP3:
	case ELO_GET_MP_TOP:
		customParams["type"] = "top_mp";
		customParams["limit"] = std::to_string(operation->limit);
		customParams["offset"] = std::to_string(operation->offset);
		break;
	case ELO_GET_MP_ARENA:
		customParams["type"] = "top_mp_arena";
		customParams["limit"] = std::to_string(operation->limit);
		customParams["offset"] = std::to_string(operation->offset);
		break;
	case ELO_GET_OUTPOSTS_TOP:
		customParams["type"] = "top_outposts";
		customParams["limit"] = std::to_string(operation->limit);
		customParams["offset"] = std::to_string(operation->offset);
		break;
	default:
		GLF_ASSERTMSG(false, "Invalid operation %d for ScriptGetPvPLadder", operation->operation);
		return;
	}

	MST_LOG("ScriptGetMPLadder for %s lb_id %s op %d tier %d", operation->for_credential.c_str(), operation->ladderId, operation->operation, operation->tier);

	auto data = new ScriptEloLadder_Data{ std::move(operation) };

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_ELO_LADDER)->second, data->operation->client_id, customParams, {}, callbackScriptGetMPLadder, this, data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetMPLadder(const SRequest& requestData)
{
	std::unique_ptr<ScriptEloLadder_Data> data((ScriptEloLadder_Data*)requestData.m_userData);

	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->for_credential);

	if (requestData.m_errorCode || response["status"].asInt() != 200)
	{
		MP_LOG(DBG_WARN, "ScriptGetMPLadder script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->for_credential.c_str());

		// --- lost a top lb refresh
		if (data->operation->operation == ELO_GET_MP_TOP)
		{
			serverMgr->m_mpTop->on_get_error(std::move(data->operation));
		}
		else if (data->operation->operation == ELO_GET_MP_ARENA)
		{
			serverMgr->m_mpArena->on_get_error(std::move(data->operation));
		}
		else if (data->operation->operation == ELO_GET_MP_TOP3)
		{
			auto lb = data->operation->ladderId;// --- need a copy because the std::move(data->operation) makes string.c_str invalid in map?
			serverMgr->GetMPTop3(lb).on_get_error(std::move(data->operation));
		}
		else if (data->operation->operation == ELO_GET_OUTPOSTS_TOP)
		{
			auto lb = data->operation->ladderId;// --- need a copy because the std::move(data->operation) makes string.c_str invalid in map?
			serverMgr->GetOutpostsTop(lb).on_get_error(std::move(data->operation));
		}

		return;
	}

	StringHash ladderType;
	switch (data->operation->operation)
	{
	case ELO_GET_MP_TIERED: ladderType = StringHash("mp"); break;
	case ELO_GET_MP_TOP: ladderType = StringHash("top_mp"); break;
	case ELO_GET_MP_ARENA: ladderType = StringHash("top_mp_arena"); break;
	case ELO_GET_MP_TOP3: break;
	case ELO_GET_OUTPOSTS_TOP: break;
	default:
		MP_LOG(DBG_WARN, "ScriptGetMPLadder script op %d invalid for %s", data->operation->operation, data->operation->for_credential.c_str());
		return;
	}

	// --- parse the get reply
	Json::Value jReply;
	Json::Reader().parse(response["reply"].asCString(), jReply);

	if (!jReply.isObject())
	{
		MP_LOG(DBG_CRIT, "ScriptGetMPLadder script op %d returned error reply for %s", data->operation->operation, data->operation->for_credential.c_str());

		// --- lost a top lb refresh
		switch(data->operation->operation)
		{
		case ELO_GET_MP_TOP:
			serverMgr->m_mpTop->on_get_error(std::move(data->operation));
			break;
		case ELO_GET_MP_ARENA:
			serverMgr->m_mpArena->on_get_error(std::move(data->operation));
			break;
		case ELO_GET_OUTPOSTS_TOP:
		{
			auto lb = data->operation->ladderId;// --- need a copy because the std::move(data->operation) makes string.c_str invalid in map?
			serverMgr->GetOutpostsTop(lb).on_get_error(std::move(data->operation));
			break;
		}
		case ELO_GET_MP_TOP3:
		{
			auto lb = data->operation->ladderId;// --- need a copy because the std::move(data->operation) makes string.c_str invalid in map?
			serverMgr->GetMPTop3(lb).on_get_error(std::move(data->operation));
			break;
		}
		}

		return;
	}

	// --- add the cookie
	jReply["cookie"] = data->operation->cookie;

	if (data->operation->operation == ELO_GET_MP_TOP)
	{	// top_mp
		serverMgr->m_mpTop->on_data(std::move(data->operation), std::move(jReply));
		return;
	}
	else if (data->operation->operation == ELO_GET_MP_TOP3)
	{
		auto lb = data->operation->ladderId;// --- need a copy because the std::move(data->operation) makes string.c_str invalid in map?
		serverMgr->GetMPTop3(lb).on_data(std::move(data->operation), std::move(jReply));
	}
	else if (data->operation->operation == ELO_GET_MP_ARENA)
	{	// top_mp_arena
		serverMgr->m_mpArena->on_data(std::move(data->operation), std::move(jReply));
		return;
	}
	else if (data->operation->operation == ELO_GET_OUTPOSTS_TOP)
	{	// top_outposts
		auto lb = data->operation->ladderId;// --- need a copy because the std::move(data->operation) makes string.c_str invalid in map?
		serverMgr->GetOutpostsTop(lb).on_data(std::move(data->operation), std::move(jReply));
		return;
	}
	else if(client && ladderType)
	{	// mp
		serverMgr->ServerSendEloLadder(client, ladderType, Json::FastWriter().write(jReply).c_str());
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptPostMPLadder(std::unique_ptr<LadderOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->for_credential) },
		{ "credential",		operation->for_credential },
		{ "score",			std::to_string(operation->score) },
		{ "display_name",	operation->display_name },
		//{ "clan_name",		operation->clan_name },
		//{ "level",			std::to_string(operation->level) },
		//{ "prestige",		std::to_string(operation->prestige) },
		{ "lb",				GetCurrentLadderId() },
		//{ "hof",			std::to_string(operation->hofSeason) },
	};

	GLF_ASSERTMSG(operation->operation == ELO_POST || operation->operation == ELO_POST_MP_ARENA || operation->operation == ELO_POST_OUTPOSTS_TOP, "Invalid operation %d for ScriptPostMPLadder", operation->operation);

	if (operation->operation == ELO_POST)
	{
		{
			auto tiered_data = new ScriptEloLadder_Data{ std::unique_ptr<LadderOperation>(new LadderOperation(*operation)) }; // --- copy operation
			tiered_data->operation->operation = ELO_POST_MP_TIERED;

			// --- first post to tiered
			customParams["type"] = "mp";
			if (operation->limit > 0)
				customParams["get"] = true;
			if (operation->tier) // --- only send tier if one is set; otherwise it means I'm new to the lb and I let it assign me to a tier
				customParams["tier"] = std::to_string(operation->tier);

			m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_POST_ELO_LADDER)->second, tiered_data->operation->client_id, customParams, {}, callbackScriptPostMPLadder, this, tiered_data);

			customParams.erase("tier");
		}

		// --- then post to top leaderboard
		{
			auto global_data = new ScriptEloLadder_Data{ std::make_unique<LadderOperation>(*operation) };
			global_data->operation->operation = ELO_POST_MP_TOP;

			customParams["type"] = "top_mp";
			if (operation->limit > 0)
			{
				customParams["get"] = true;
				customParams["limit"] = std::to_string(operation->limit);
				customParams["offset"] = std::to_string(operation->offset);
			}
			m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_POST_ELO_LADDER)->second, global_data->operation->client_id, customParams, {}, callbackScriptPostMPLadder, this, global_data);
		}
	}

	if(operation->operation == ELO_POST_MP_ARENA)
	{
		auto global_data = new ScriptEloLadder_Data{ std::make_unique<LadderOperation>(*operation) };
		global_data->operation->operation = ELO_POST_MP_ARENA;

		customParams["type"] = "top_mp_arena";
		if (operation->limit > 0)
		{
			customParams["get"] = true;
			customParams["limit"] = std::to_string(operation->limit);
			customParams["offset"] = std::to_string(operation->offset);
		}
		if (operation->level)
			customParams["level"] = std::to_string(operation->level);
		m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_POST_ELO_LADDER)->second, global_data->operation->client_id, customParams, {}, callbackScriptPostMPLadder, this, global_data);
	}

	if (operation->operation == ELO_POST_OUTPOSTS_TOP)
	{
		auto global_data = new ScriptEloLadder_Data{ std::make_unique<LadderOperation>(*operation) };
		global_data->operation->operation = ELO_POST_OUTPOSTS_TOP;
		global_data->operation->ladderId = GetCurrentLadderId();

		customParams["type"] = "top_outposts";
		if (operation->limit > 0)
		{
			customParams["get"] = true;
			customParams["limit"] = std::to_string(operation->limit);
			customParams["offset"] = std::to_string(operation->offset);
		}
		m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_POST_ELO_LADDER)->second, global_data->operation->client_id, customParams, {}, callbackScriptPostMPLadder, this, global_data);
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptPostMPLadder(const SRequest& requestData)
{
	std::unique_ptr<ScriptEloLadder_Data> data((ScriptEloLadder_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptPostMPLadder script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->for_credential.c_str());
		return;
	}

	// --- so that we can check if the client is connected to this instance
	// --- when returning from a post, update the leaderboards if the client is connected
	auto client = serverMgr->GetClient(data->operation->for_credential);

	// --- we also did a get after the post
	if (!response["get"].isNull())
	{
		StringHash ladderType;
		switch (data->operation->operation)
		{
		case ELO_POST_MP_TIERED: ladderType = StringHash("mp"); break;
		case ELO_POST_MP_TOP: ladderType = StringHash("top_mp"); break;
		case ELO_POST_MP_ARENA: ladderType = StringHash("top_mp_arena"); break;
		case ELO_POST_OUTPOSTS_TOP: break;
		default:
			MP_LOG(DBG_WARN, "ScriptPostMPLadder script op %d invalid for %s", data->operation->operation, data->operation->for_credential.c_str());
			return;
		}

		// --- parse the get reply
		Json::Value jReply;
		Json::Reader().parse(response["get"].asCString(), jReply);

		if (!jReply.isObject())
		{
			MP_LOG(DBG_CRIT, "ScriptPostMPLadder script op %d returned error reply for %s", data->operation->operation, data->operation->for_credential.c_str());
			return;
		}

		// --- add the cookie
		jReply["cookie"] = data->operation->cookie;

		if (data->operation->operation == ELO_POST_MP_TOP)
		{	// top_mp
			data->operation->operation = ELO_GET_MP_TOP;
			serverMgr->m_mpTop->on_data(std::move(data->operation), std::move(jReply));
			return;
		}
		else if (data->operation->operation == ELO_POST_MP_ARENA)
		{	// top_mp_arena
			data->operation->operation = ELO_GET_MP_ARENA;
			serverMgr->m_mpArena->on_data(std::move(data->operation), std::move(jReply));
			return;
		}
		else if (data->operation->operation == ELO_POST_OUTPOSTS_TOP)
		{	// top_outposts
			data->operation->operation = ELO_GET_OUTPOSTS_TOP;
			auto lb = data->operation->ladderId;// --- need a copy because the std::move(data->operation) makes string.c_str invalid in map?
			serverMgr->GetOutpostsTop(lb).on_data(std::move(data->operation), std::move(jReply));
			if(client)
				client->m_seshatProfile->SetOutpostsLb(lb);
			return;
		}
		else if (client && ladderType)
		{	// mp
			if (data->operation->operation == ELO_POST_MP_TIERED)
			{
				int new_tier = response["new_tier"].asInt();
				if (new_tier != data->operation->tier)
					client->m_seshatProfile->UpdateMPTier(new_tier);
			}

			serverMgr->ServerSendEloLadder(client, ladderType, Json::FastWriter().write(jReply).c_str());
		}
	}
	else
	{	// -- lets get the leaderboards
		if (data->operation->operation == ELO_POST_MP_TOP)
		{
			serverMgr->m_mpTop->on_post(client, std::move(data->operation));
		}
		else if (data->operation->operation == ELO_POST_MP_ARENA)
		{
			serverMgr->m_mpArena->on_post(client, std::move(data->operation));
		}
		else if (data->operation->operation == ELO_POST_OUTPOSTS_TOP)
		{
			auto lb = data->operation->ladderId;// --- need a copy because the std::move(data->operation) makes string.c_str invalid in map?
			serverMgr->GetOutpostsTop(lb).on_post(client, std::move(data->operation));
		}
		else if (data->operation->operation == ELO_POST_MP_TIERED)
		{
			// --- parse the reply which should contain the new tier
			int new_tier = response["new_tier"].asInt();
			if (!new_tier)
			{
				// --- couldn't parse the reply for the tiered leaderboard post - the operation must have failed for some reason
				MP_LOG(DBG_CRIT, "ScriptPostMPLadder script op %d could not parse reply %s for tiered leaderboard post for %s", data->operation->operation, response["reply"].asCString(), data->operation->for_credential.c_str());
				return;
			}

			// --- after a tiered post do a get for connected clients
			// --- TODO: to a get anyway with limit 1 for the group? only if the tier changed...
			if (!client)
				return;

			if (new_tier != data->operation->tier)
				client->m_seshatProfile->UpdateMPTier(new_tier);

			data->operation->operation = ELO_GET_MP_TIERED;
			data->operation->tier = new_tier;
			GameServerFedManager::Instance()->ScriptGetMPLadder(std::move(data->operation));
		}
		else
		{
			GLF_ASSERTMSG(false, "callbackScriptPostMPLadder with invalid operation %d", data->operation->operation);
		}
	}
}

