void GameServerFedManager::ScriptPostSkirmishLadder(std::unique_ptr<LadderOperation> operation, const std::string& eventId)
{
	GSClient* client = GetClient(operation->for_credential);

	if (client == NULL)
	{
		MP_LOG(DBG_INFO, "Received AH message from unknown client %s\n", operation->for_credential.c_str());
		return;
	}
	
	auto forEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_SKIRMISH);
	std::string ladderType;

	if (operation->operation == ELO_POST_MP_SKIRMISH_SEASON)
	{
		ladderType = SkirmishSeasonLeaderboardName(forEvent->GetSkirmishSeasonName());
	}
	else if (operation->operation == ELO_POST_MP_SKIRMISH)
	{
		ladderType = SkirmishLeaderboardName(forEvent->GetID());

		// If it the last week - no need to post week LB
		// comment out because forget to change UI side
		//if (forEvent->GetSkirmishCurrentWeek() == forEvent->GetSkirmishTotalWeeks())
			//return;
	}

	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->for_credential) },
		{ "credential",		operation->for_credential },
		{ "score",			std::to_string(operation->score) },
		{ "display_name",	operation->display_name },
		{ "lb",				GetCurrentLadderId() },
		{ "type",			ladderType }
	};
	
	GLF_ASSERTMSG(operation->operation == ELO_POST_MP_SKIRMISH || operation->operation == ELO_POST_MP_SKIRMISH_SEASON, "Invalid operation %d for ScriptPostSkirmishLadder", operation->operation);

	if (operation->limit > 0)
	{
		customParams["get"] = true;
		customParams["limit"] = std::to_string(operation->limit);
		customParams["offset"] = std::to_string(operation->offset);
	}

	if (operation->level)
		customParams["level"] = std::to_string(operation->level);

	operation->tier = GetPvpData()->GetSkirmishTierFromScore(GetCurrentLadderSkmSettings(), operation->score);

	auto custom_data = new ScriptEloLadder_Data{ std::move(operation) };

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_POST_ELO_LADDER)->second, custom_data->operation->client_id, customParams, {}, callbackScriptPostSkirmishLadder, this, custom_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptPostSkirmishLadder(const SRequest& requestData)
{
	std::unique_ptr<ScriptEloLadder_Data> data((ScriptEloLadder_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptPostSkirmishLadder script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->for_credential.c_str());
		return;
	}

	// --- so that we can check if the client is connected to this instance
	// --- when returning from a post, update the leaderboards if the client is connected
	auto client = serverMgr->GetClient(data->operation->for_credential);

	/*auto op1 = std::unique_ptr<LadderOperation>(new LadderOperation());
	op1->operation = ELO_GET_MP_SKIRMISH;
	op1->owner_credential = client->m_credential;
	op1->for_credential = client->m_credential;
	op1->client_id = client->m_clientId;
	op1->cookie = mgr_.GetLocalTime();
	op1->eventId = skirmishEvent->GetSkirmishSeason();

	mgr_.ScriptGetEloLadder(std::move(op1));*/

	// --- we also did a get after the post
	if (!response["get"].isNull())
	{
		StringHash ladderType;
		switch (data->operation->operation)
		{
		case ELO_POST_MP_SKIRMISH: ladderType = StringHash("skirmish_top_players"); break;
		default:
			MP_LOG(DBG_WARN, "ScriptPostMPLadder script op %d invalid for %s", data->operation->operation, data->operation->for_credential.c_str());
			return;
		}

		// --- parse the get reply
		Json::Value jReply;
		Json::Reader().parse(response["get"].asCString(), jReply);

		if (!jReply.isObject())
		{
			MP_LOG(DBG_CRIT, "ScriptPostMPLadder script op %d returned error reply for %s", data->operation->operation, data->operation->for_credential.c_str());
			return;
		}

		// --- add the cookie
		jReply["cookie"] = data->operation->cookie;

		serverMgr->ServerSendEloLadder(client, ladderType, Json::FastWriter().write(jReply).c_str());
	}
	else
	{	
		if (!client)
			return;
		
		client->m_seshatProfile->UpdateMPTLETier(data->operation->tier);

		auto skirmishEvents = client->m_EventContainer.GetEventsOfType(EVENT_TYPE_SKIRMISH);
		if (skirmishEvents.empty())
		{
			return;
		}
		
		for (auto skirmishEvent : skirmishEvents)
		{
			// GetCanProgress: only events found in hestia config are allowed to progress
			// IsActive: event is running
			if (!skirmishEvent->GetCanProgress() || !skirmishEvent->IsActive())
			{
				continue;
			}

			if (data->operation->operation == ELO_POST_MP_SKIRMISH)
			{
				data->operation->operation = ELO_GET_MP_SKIRMISH;
				data->operation->eventId = skirmishEvent->GetID();
			}
			else if (data->operation->operation == ELO_POST_MP_SKIRMISH_SEASON)
			{
				data->operation->operation = ELO_GET_MP_SKIRMISH_SEASON;
				data->operation->eventId = skirmishEvent->GetSkirmishSeasonName();
			}
				
			GameServerFedManager::Instance()->ScriptGetSkirmishLadder(std::move(data->operation));
		}
	}
}

