void GameServerFedManager::ScriptGetSkirmishLadder(std::unique_ptr<LadderOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->for_credential) },
		{ "credential",		operation->for_credential },
		{ "lb",				operation->ladderId },
	};

	switch (operation->operation)
	{
	case ELO_GET_MP_SKIRMISH:
		customParams["type"] = SkirmishLeaderboardName(operation->eventId);
		customParams["limit"] = std::to_string(100);
		break;
	case ELO_GET_MP_SKIRMISH_SEASON:
		customParams["type"] = SkirmishSeasonLeaderboardName(operation->eventId);
		customParams["limit"] = std::to_string(100);
		break;
	default:
		GLF_ASSERTMSG(false, "Invalid operation %d for ScriptGetSkirmishLadder", operation->operation);
		return;
	}

	MST_LOG("ScriptGetSkirmishLadder for %s eventId %s op %d", operation->for_credential.c_str(), operation->eventId, operation->operation);

	auto data = new ScriptEloLadder_Data{ std::move(operation) };

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_ELO_LADDER)->second, data->operation->client_id, customParams, {}, callbackScriptGetSkirmishLadder, this, data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetSkirmishLadder(const SRequest& requestData)
{
	std::unique_ptr<ScriptEloLadder_Data> data((ScriptEloLadder_Data*)requestData.m_userData);

	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->for_credential);

	if (requestData.m_errorCode || response["status"].asInt() != 200)
	{
		MP_LOG(DBG_WARN, "ScriptGetSkirmishLadder script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->for_credential.c_str());

		if (response["status"].asInt() == 404)
		{
			// --- if the leaderboard is not ready, use an empty for reset
			response["reply"] = "{}";
		}
		else
		{
			return;
		}
	}

	StringHash ladderType;
	switch (data->operation->operation)
	{
	case ELO_GET_MP_SKIRMISH: ladderType = StringHash("skirmish_top_players"); break;
	case ELO_GET_MP_SKIRMISH_SEASON: ladderType = StringHash("skirmish_top_players_season"); break;
	default:
		MP_LOG(DBG_WARN, "ScriptGetSkirmishLadder script op %d invalid for %s", data->operation->operation, data->operation->for_credential.c_str());
		return;
	}

	// --- parse the get reply
	Json::Value jReply;
	Json::Reader().parse(response["reply"].asCString(), jReply);

	if (!jReply.isObject())
	{
		MP_LOG(DBG_CRIT, "ScriptGetSkirmishLadder script op %d returned error reply for %s", data->operation->operation, data->operation->for_credential.c_str());

		return;
	}

	// --- add the cookie
	jReply["cookie"] = data->operation->cookie;

	if (data->operation->operation == ELO_GET_MP_SKIRMISH)
	{
		if (client && ladderType)
		{
			if (data->operation->sendToClient)
				serverMgr->ServerSendEloLadder(client, ladderType, Json::FastWriter().write(jReply).c_str());
			client->m_seshatProfile->CheckSkirmishStageRewards(data->operation->eventId, ESkirmishRewardType::Player, jReply);
		}
	}
	else if (data->operation->operation == ELO_GET_MP_SKIRMISH_SEASON)
	{
		if (client && ladderType)
		{
			if (data->operation->sendToClient)
				serverMgr->ServerSendEloLadder(client, ladderType, Json::FastWriter().write(jReply).c_str());
			client->m_seshatProfile->CheckSkirmishSeasonRewards(data->operation->eventId, ESkirmishRewardType::PlayerSeason, jReply);
		}
	}

	return;
}

