void GameServerFedManager::ScriptPostDefenderLadder(std::unique_ptr<LadderOperation> operation)
{	
	std::map<std::string, std::string> customParams = {
		{ "access_token",		GetAccessToken(operation->for_credential) },
		{ "credential",			operation->for_credential },
		{ "score",				std::to_string(operation->score) },
		{ "display_name",		operation->display_name },
		{ "level",			std::to_string(operation->level) },
		{ "prestige",		std::to_string(operation->prestige) },
		{ "lb",					GetCurrentLadderId() }
	};

	std::string leaderboardName = std::string(DEFENDER_LEADERBOARD_NAME) + operation->ladderId;

	switch (operation->operation)
	{
	case ELO_POST_DEFENDER:
		customParams["lb_name"] = leaderboardName;
		//customParams["limit"] = std::to_string(100);
		customParams["type"] = "me";
		customParams["get"] = true;
		break;
	default:
		GLF_ASSERTMSG(false, "Invalid operation %d for ScriptPostDefenderLadder", operation->operation);
		return;
	}

	MST_LOG("ScriptPostDefenderLadder for %s eventId %s op %d", operation->for_credential.c_str(), operation->eventId, operation->operation);

	auto data = new ScriptEloLadder_Data{ std::move(operation) };

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_POST_ELO_LADDER)->second, data->operation->client_id, customParams, {}, callbackScriptPostDefenderLadder, this, data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptPostDefenderLadder(const SRequest& requestData)
{
	std::unique_ptr<ScriptEloLadder_Data> data((ScriptEloLadder_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "callbackScriptPostDefenderLadder script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->for_credential.c_str());
		return;
	}

	// --- so that we can check if the client is connected to this instance
	// --- when returning from a post, update the leaderboards if the client is connected
	auto client = serverMgr->GetClient(data->operation->owner_credential);

	// --- we also did a get after the post
	if (!response["get"].isNull())
	{
		StringHash ladderType;
		switch (data->operation->operation)
		{
		case ELO_POST_DEFENDER: ladderType = StringHash(LADDER_TYPE_DEFENDER_ME);
			break;
		default:
			MP_LOG(DBG_WARN, "callbackScriptPostDefenderLadder script op %d invalid for %s", data->operation->operation, data->operation->owner_credential.c_str());
			return;
		}

		// --- parse the get reply
		Json::Value jReply;
		Json::Reader().parse(response["get"].asCString(), jReply);
		response = Json::nullValue; // --- to free the mem

		if (!jReply.isObject())
		{
			MP_LOG(DBG_CRIT, "callbackScriptPostDefenderLadder script op %d returned error reply for %s", data->operation->operation, data->operation->owner_credential.c_str());
			return;
		}

		// --- add the cookie
		jReply["cookie"] = data->operation->cookie;

		serverMgr->ServerSendEloLadder(client, ladderType, Json::FastWriter().write(jReply).c_str());
	}
	else
	{
		if (!client)
			return;
		// Do both get leaderboad me and hof
		data->operation->operation = ELO_GET_DEFENDER_ME;
		GameServerFedManager::Instance()->ScriptGetDefenderLadder(std::move(data->operation));
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptGetDefenderLadder(std::unique_ptr<LadderOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "lb",				operation->ladderId },
	};

	std::string leaderboardName = std::string(DEFENDER_LEADERBOARD_NAME) + operation->ladderId;
	customParams["lb_name"] = leaderboardName;
	switch (operation->operation)
	{
	case ELO_GET_DEFENDER_LAST_EXPIRED_SEASON:
		customParams["type"] = "me";
		customParams["limit"] = std::to_string(MAX_ENTRY_LB_ONLY_ME);
		break;
	case ELO_GET_DEFENDER_ME:
		customParams["type"] = "me";
		customParams["limit"] = std::to_string(MAX_ENTRY_LB_ME);
		break;
	case ELO_GET_DEFENDER_HOF:
		customParams["type"] = "top_players";
		customParams["limit"] = std::to_string(MAX_ENTRY_LB_HOF);
		break;
	default:
		GLF_ASSERTMSG(false, "Invalid operation %d for ScriptGetDefenderLadder", operation->operation);
		return;
	}

	MST_LOG("ScriptGetDefenderLadder for %s eventId %s op %d", operation->owner_credential.c_str(), operation->eventId, operation->operation);

	auto data = new ScriptEloLadder_Data{ std::move(operation) };

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_GET_ELO_LADDER)->second, data->operation->client_id, customParams, {}, callbackScriptGetDefenderLadder, this, data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetDefenderLadder(const SRequest& requestData)
{
	std::unique_ptr<ScriptEloLadder_Data> data((ScriptEloLadder_Data*)requestData.m_userData);

	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);

	if (requestData.m_errorCode || response["status"].asInt() != 200)
	{
		MP_LOG(DBG_WARN, "callbackScriptGetDefenderLadder script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->for_credential.c_str());

		if (response["status"].asInt() == 404)
		{
			// --- if the leaderboard is not ready, use an empty for reset
			response["reply"] = "{}";
		}
		else
		{
			return;
		}
	}
	
	StringHash ladderType;
	switch (data->operation->operation)
	{
	case ELO_GET_DEFENDER_LAST_EXPIRED_SEASON:
	case ELO_GET_DEFENDER_ME: ladderType = StringHash(LADDER_TYPE_DEFENDER_ME);
		break;
	case ELO_GET_DEFENDER_HOF: ladderType = StringHash(LADDER_TYPE_DEFENDER_HOF);
		break;
	default:
		MP_LOG(DBG_WARN, "callbackScriptGetDefenderLadder script op %d invalid for %s", data->operation->operation, data->operation->owner_credential.c_str());
		return;
	}

	// --- parse the get reply
	Json::Value jReply;
	Json::Reader().parse(response["reply"].asCString(), jReply);
	response = Json::nullValue; // --- to free the mem

	if (!jReply.isObject())
	{
		MP_LOG(DBG_CRIT, "callbackScriptGetDefenderLadder script op %d returned error reply for %s", data->operation->operation, data->operation->for_credential.c_str());

		return;
	}

	// --- add the cookie
	jReply["cookie"] = data->operation->cookie;

	if (data->operation->operation == ELO_GET_DEFENDER_ME || data->operation->operation == ELO_GET_DEFENDER_HOF)
	{
		if (client && ladderType)
		{
			if (data->operation->sendToClient)
				serverMgr->ServerSendEloLadder(client, ladderType, Json::FastWriter().write(jReply).c_str());
		}
	}
	if (data->operation->operation == ELO_GET_DEFENDER_LAST_EXPIRED_SEASON)
	{
		if (client)
		{
			auto ladderId = data->operation->ladderId;
			DefenderLeaderboard::Get()->CheckAndSendHOFRewards(client, jReply, ladderId);
		}
	}

	return;
}

