void GameServerFedManager::callbackScriptUserReferralCode(const SRequest& requestData)
{
	std::unique_ptr<std::string> credential((std::string*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(*credential, jsonAccessToken);

	auto client = serverMgr->GetClient(*credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptUseReferralCode script returned error %d - %s for %s", response["status"].asInt(), response["reason"].asCString(), credential->c_str());

		if (response["status"] == 409)
		{
			GameServerFedManager::Instance()->ServerSendAddReferralEnd(client->m_credential, antihackgs::E_OP_RECRUIT_CODE_ALREADY_HAVE_CONNECTION_PENDING);
		}
		else
		{
			// --- send ReferralRequestStatus error to client
			GameServerFedManager::Instance()->ServerSendAddReferralEnd(client->m_credential, antihackgs::E_OP_RECRUIT_CODE_ERROR);
			return;
		}
	}

	// --- parse the response
	Json::Value jData;
	Json::Reader().parse(response["reply"].asCString(), jData);
	response = Json::nullValue; // --- to free the mem

	// --- 1 - set the referral user in the profile (from jData['_account'] to SetReferralUser
	client->m_seshatProfile->SetReferralUser(jData["_account"].asCString());
	
	// --- 2 - award gift -> AddReferralReward
	auto award_gift = GameServerFedManager::Instance()->GetMultiplayerData()->AddReferralReward();;
	client->m_seshatProfile->StartTrackingInventoryChanges("reward:add_referral");
	for (const auto& gi : *award_gift)
	{
		auto qty = gi.qty;
		StringHash item = gi.id;

		client->GetHestiaConfig()->ChangeCreditBalance(client, item, qty);
	}
	// --- 3 - add ref gift notification and send it to the client
	client->m_seshatProfile->AddNotificationFromServer("add_referral", "gift_0", 0, ENM_CATEGORY | ENM_INFO);
	Json::Value changes = client->m_seshatProfile->StopTrackingInventoryChanges();
	if (!changes.empty())
		serverMgr->ServerSendInventoryUpdate(client, "add_referral", std::move(changes));

	GameServerFedManager::Instance()->ServerSendAddReferralEnd(client->m_credential, antihackgs::E_OP_RECRUIT_CODE_ADDED);

	// --- 4 - start a request to update the friends list
	GameServerFedManager::Instance()->ScriptRequestListFriends(client);
}

