void GameServerFedManager::callbackScriptGetTrainerClanFromAlias(const SRequest& requestData)
{
	std::unique_ptr<std::string> credential((std::string*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(*credential, jsonAccessToken);

	auto client = serverMgr->GetClient(*credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptGetTrainerClanFromAlias script returned error %d - %s for %s", response["status"].asInt(), response["reason"].asCString(), credential->c_str());

		if (response["status"] == 404)
		{
			// --- user not found
			Json::Value request;
			request["type"] = "membership_exception_apprentice";
			serverMgr->ServerSendRequestResult(client, request);
		}
		return;
	}

	// --- parse the response
	Json::Value seshat;
	Json::Reader().parse(response["seshat"].asCString(), seshat);
	response = Json::nullValue; // --- to free the mem

	if (seshat.isNull()
		|| seshat[SESHAT_LABEL_TRAINER_CLAN].isNull()
		|| seshat[SESHAT_LABEL_TRAINER_CLAN].asString().empty())
	{
		// --- user is not a trainer
		Json::Value request;
		request["type"] = "membership_exception_apprentice";
		serverMgr->ServerSendRequestResult(client, request);
		return;
	}

	// --- try to join clan
	Json::Value extraData;
	extraData["^level"] = std::to_string(client->GetHestiaConfig()->GetCreditBalance(client, SESHAT_LABEL_LEVEL));
	extraData["^prestige"] = std::to_string(client->m_seshatProfile->GetPrestigeLevel());
	extraData["^loadout"] = client->m_seshatProfile->GetAvatarModules().toCompactString();
	extraData["^last_online"] = std::to_string(GetCrtUTCTimeSeconds());
	extraData["group_id"] = seshat[SESHAT_LABEL_TRAINER_CLAN];

	client->m_seshatProfile->WriteTrainerClanData(seshat[SESHAT_LABEL_TRAINER_CLAN].asCString(), extraData);
}

