//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptLookupAliasMC5(const SRequest& requestData)
{
	std::unique_ptr<std::string> credential((std::string*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	auto client = serverMgr->GetClient(*credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptLookupAliasMC5 script returned error %d - %s for %s", response["status"].asInt(), response["reason"].asCString(), credential->c_str());
		return;
	}

	// --- parse the response
	Json::Value alias, seshat;
	Json::Reader().parse(response["reply"].asCString(), alias);
	Json::Reader().parse(response["seshat"].asCString(), seshat);
	response = Json::nullValue; // --- to free the mem

	auto mc5_credential = alias["credential"].asString();
	const auto& inventory = seshat["inventory"];

	if (client->m_seshatProfile->IsInvalid() || !client->GetHestiaConfig())
		return;

	auto mc5_items = client->GetHestiaConfig()->FindCreditsInCategory("mc5_gift");
	for (auto mc5_item : mc5_items)
	{
		auto credit = client->GetHestiaConfig()->FindCredit(mc5_item);
		if (!credit)	// --- unknown, ignore
			continue;

		// --- DEBUG
//		int old = client->GetHestiaConfig()->GetCreditBalance(client, mc5_item);
//		client->GetHestiaConfig()->SetCreditBalance(client, mc5_item, 1);
//		client->GetHestiaConfig()->SetCreditBalance(client, mc5_item, old);

		if (!inventory[credit->name].asInt())	// --- doesn't have it in mc5 profile
			continue;

		if (client->GetHestiaConfig()->GetCreditBalance(client, mc5_item) == inventory[credit->name].asInt())	// --- already have it
			continue;

		client->m_seshatProfile->StartTrackingInventoryChanges("mc5_gift");
		client->m_seshatProfile->AddNotificationFromServer("mc5_gift", std::to_string(mc5_item), 0, ENM_CATEGORY | ENM_INFO | ENM_KEY | ENM_UNIQUE_KEY);
		auto notification = client->m_seshatProfile->StopTrackingInventoryChanges();
		auto result = GameServerFedManager::Instance()->GetHestiaConfigManager()->ProcessTransaction(client, mc5_item, Json::Value::null);
		for (auto& j : notification[SESHAT_LABEL_NOTIFICATIONS])
		{
			result[SESHAT_LABEL_NOTIFICATIONS].append(std::move(j));
		}
		GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, mc5_item, std::move(result));
	}

}

