namespace
{

	struct ScriptClan_Data
	{
		std::unique_ptr<ClanOperation> operation;
	};

}	// --- namespace

void GameServerFedManager::ScriptClanCreate(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "name",			operation->data["name"].asString() },
		{ "description",	operation->data["desc"].asString() },
		{ "avatar",			operation->data["avatar"].asString() },
		{ "membership",		operation->data["membership"].asString() }, // open, owner_approved, (member_approved, private)
		//{ "score",			operation->data["score"].asString() },
		{ "member_limit",	std::to_string(DEFAULT_CLAN_MEMBER_LIMIT) },
		{ "etag_for",		operation->data["etag_for"].asString() },
		{ "_loc",			operation->data["_loc"].asString() },
		{ "recommendation_filter",			operation->data["_loc"].asString() },
		{ "_min_score",		operation->data["_min_score"].asString() },
		{ "_membership",	operation->data["_membership"].asString() },
		{ "_officers",		operation->data["_officers"].asString() },
		{ "_clanpower",		operation->data["_clanpower"].asString() },
		{ "recommendation_score",		operation->data["recommendation_score"].asString()  },
		{ "^score",			operation->data["score"].asString() },
		{ "^level",			operation->data["^level"].asString() },
		{ "^base_level",	operation->data["^base_level"].asString() },
		{ "^prestige",		operation->data["^prestige"].asString() },
		{ "^joinedAt",		std::to_string(GetCrtUTCTimeSeconds()) },
		{ "^last_online",	std::to_string(GetCrtUTCTimeSeconds()) },
	};

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(op_data->operation->operation == ECO_CREATE);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_CREATE)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanCreate, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanCreate(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected - the operation will be retried when the client connects again
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanCreate script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());

		// --- inform the client about the error
		int status = response["status"].asInt();
		auto error = ClanCreateUpdateStatus::Other;
		if (status == 1000) // --- clan  with same name already exists
		{
			error = ClanCreateUpdateStatus::NameTaken;
		}
		serverMgr->ServerSendCreateUpdateResult(client, error);
		
		// --- remove the pending clan creation
		client->m_seshatProfile->RemovePendingClanCreate();

		return;
	}

	// --- everything was ok - actually take the money
	{
		auto offerId = StringHash("clan_create");
		auto result = client->GetHestiaConfig()->ProcessTransaction(client, offerId);
		bool ok = !result.isInt() && !result.empty(); // --- TODO: take the code that does this out from ServerSendInventoryUpdate and make it function so that it can be used here as well
		serverMgr->ServerSendInventoryUpdate(client, offerId, std::move(result));
		if (!ok)
		{
			// --- for some reason the client no longer has money or something, don't create the clan

			// --- send back an error on clan create
			auto error = ClanCreateUpdateStatus::Other;
			serverMgr->ServerSendCreateUpdateResult(client, error);

			// --- remove the pending clan creation
			client->m_seshatProfile->RemovePendingClanCreate();

			return;
		}
	}

	// --- parse the clan data from the response
	Json::Value group;
	Json::Reader().parse(response["group"].asCString(), group);
	response = Json::nullValue; // --- to free the mem

	client->m_request_messages = true;

	GameServerFedManager::ProcessClanEntry(&group, client);

	// --- set the clan data in profile
	client->m_seshatProfile->StartTrackingInventoryChanges("clan:create");
	client->m_seshatProfile->SetClanData(group["id"], group["name"], group["avatar"]);
	Json::Value changes = client->m_seshatProfile->StopTrackingInventoryChanges();
	if (!changes.empty())
		serverMgr->ServerSendInventoryUpdate(client, 0, std::move(changes));

	// --- remove the pending clan creation
	client->m_seshatProfile->RemovePendingClanCreate();

	// --- send clan data to client
	serverMgr->ServerSendOwnClanToClient(client, group);

	// --- send an updated leaderboard to the clients if the new clan is potentially in the leaderboard
	int clanScore = client->m_clanData->elo.elo();
	data->operation->operation = ECO_CLANS_LEADERBOARD;
	data->operation->data.clear();
	data->operation->data["lb_name"] = serverMgr->GetCurrentClanLb();
	data->operation->data["client_lb_name"] = serverMgr->GetCurrentClientClanLb();

	serverMgr->StartGettingClansLeaderboard(std::move(data->operation), clanScore);

	// --- trigger a full refresh for the client (flush seshat, get hestia, get events); this is mainly to get clan events
	client->SetNeedsFullRefresh(true);

	serverMgr->ParseClanDataForCache(group);

	serverMgr->SetAchievementProgress(client, StringHash("clan.create"), 1);

	// -- Tracking Clan Actions
	tracking::ClanAction(client->m_fedCredential, group["id"].asString(), tracking::ClanActions::CreateClan, std::string(), tracking::PlayerRoles::Leader);
}

