//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptTrainerClanCreate(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected - the operation will be retried when the client connects again
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptTrainerClanCreate script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());

		// --- inform the client about the error
		int status = response["status"].asInt();

		// --- send result to client
		Json::Value request;
		request["type"] = "trainer_clan_create_failed";
		serverMgr->ServerSendRequestResult(client, request);

		return;
	}

	// --- parse the clan data from the response
	Json::Value group;
	Json::Reader().parse(response["group"].asCString(), group);
	response = Json::nullValue; // --- to free the mem

	GameServerFedManager::ProcessTrainerClanEntry(&group, client);

	// --- set the clan data in profile
	client->m_seshatProfile->StartTrackingInventoryChanges("trainer:clan:create");
	client->m_seshatProfile->SetTrainerClanData(group["id"]);
	if (data->operation->data["create"].asBool())
	{	// --- add notification informing the user he has become a trainer (or hermes message, but better not)
		client->m_seshatProfile->AddNotificationFromServer("trainer:clan:create", "", 0, ENM_CATEGORY);
	}
	Json::Value changes = client->m_seshatProfile->StopTrackingInventoryChanges();
	if (!changes.empty())
		serverMgr->ServerSendInventoryUpdate(client, 0, std::move(changes));

	// --- send clan data to client
	serverMgr->ServerSendOwnTrainerClanToClient(client, group);

	// --- trigger a full refresh for the client (flush seshat, get hestia, get events); this is mainly to get clan events
	// --- client->SetNeedsFullRefresh(true);

	// --- Tracking
	tracking::MentoringSystem(client->m_fedCredential.c_str(), 0, (int)client->GetHestiaConfig()->GetCreditBalance(client, "level"), tracking::MentoringActions::Graduated, group["id"].asString());
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptClanUpdate(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "group_id",		operation->data["group_id"].asString() },
		{ "name",			operation->data["name"].asString() },
		{ "avatar",			operation->data["avatar"].asString() },
		{ "membership",		operation->data["membership"].asString() }, // open, owner_approved, (member_approved, private)
		{ "etag_for",		operation->data["etag_for"].asString() },
		{ "_loc",			operation->data["_loc"].asString() },
		{ "recommendation_filter",			operation->data["_loc"].asString() },
		{ "_min_score",		operation->data["_min_score"].asString() },
		{ "_membership",	operation->data["_membership"].asString() },
		{ "_officers",		operation->data["_officers"].asString() },
	};

	if (operation->data["check_name"].asBool())
		customParams["check_name"] = "true";

	if(!operation->data["desc"].isNull())
		customParams["description"] = operation->data["desc"].asString();

	operation->data["request_timestamp"] = Json::Int64(std::time(nullptr));

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(op_data->operation->operation == ECO_UPDATE);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_UPDATE)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanUpdate, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanUpdate(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected - the operation will be retried when the client connects again
		return;
	}

	// --- TODO - to remove this after we find the issue with switching trainer<->default
	MP_LOG(DBG_WARN, "ScriptClanUpdate for_cred(%s)\n", client->m_fedCredential.c_str());

	bool check_name = data->operation->data["check_name"].asBool();
	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanUpdate script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());

		// --- inform the client about the error
		int status = response["status"].asInt();
		auto error = ClanCreateUpdateStatus::Other;
		if (status == 1000) // --- clan  with same name already exists
		{
			error = ClanCreateUpdateStatus::NameTaken;
		}
		serverMgr->ServerSendCreateUpdateResult(client, error);

		// --- remove the pending clan creation
		if(check_name)
			client->m_seshatProfile->RemovePendingClanRename();

		return;
	}

	// --- parse the clan data from the response
	Json::Value group;
	Json::Reader().parse(response["group"].asCString(), group);
	response = Json::nullValue; // --- to free the mem

	group["_request_timestamp"] = data->operation->data["request_timestamp"];
	
	if (check_name)
	{
		// --- everything was ok - actually take the money
		auto offerId = StringHash("clan_rename");
		auto result = client->GetHestiaConfig()->ProcessTransaction(client, offerId);
		bool ok = !result.isInt() && !result.empty(); // --- TODO: take the code that does this out from ServerSendInventoryUpdate and make it function so that it can be used here as well
		serverMgr->ServerSendInventoryUpdate(client, offerId, std::move(result));
		if (!ok)
		{
			// --- for some reason the client no longer has money or something, don't create the clan

			// --- send back an error on clan create
			auto error = ClanCreateUpdateStatus::Other;
			serverMgr->ServerSendCreateUpdateResult(client, error);

			// --- remove the pending clan creation
			client->m_seshatProfile->RemovePendingClanRename();

			return;
		}
	}

	GameServerFedManager::ProcessClanEntry(&group, client);

	// --- remove member info
	group["members"] = Json::Value::null;
	group["owner"] = Json::Value::null;

	// --- set the clan data in profile
	client->m_seshatProfile->StartTrackingInventoryChanges("clan:update");
	client->m_seshatProfile->SetClanData(group["id"], group["name"], group["avatar"]);
	Json::Value changes = client->m_seshatProfile->StopTrackingInventoryChanges();
	if (!changes.empty())
		GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(changes));

	// --- refresh for name or description change 
	if (check_name || !data->operation->data["desc"].isNull())
	{
		//refresh clan for client (s)
		auto postWallMessageForGroup = [&](const std::string& group_id, GameWallPostType postType)
		{
			std::unique_ptr<ClanOperation> opPostWallWar(new ClanOperation());
			opPostWallWar->operation = ECO_POST_WALL_GAME;
			opPostWallWar->client_id = client->m_clientId;
			opPostWallWar->data["group_id"] = group_id;
			auto& postData = opPostWallWar->data["post"];
			postData["type"] = static_cast<int>(postType);

			callerObj->ScriptClanPostWallGame(std::move(opPostWallWar));
		};
		postWallMessageForGroup(client->m_clanData->clan_id, GameWallPostType::ClanRefresh);
	}

	// --- remove the pending clan renaming
	if(check_name)
	{
		client->m_seshatProfile->RemovePendingClanRename();
		
		client->m_seshatProfile->StartTrackingInventoryChanges("clan:renameTs");
		client->m_seshatProfile->UpdateClanTs(SESHAT_LABEL_OSIRIS_INFO_CLAN_TS_RENAME, GameServerFedManager::Instance()->GetLocalTime());
		Json::Value profileData = client->m_seshatProfile->StopTrackingInventoryChanges();
		if (!profileData.empty())
			GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(profileData));

	}

	// --- send clan data to client
	serverMgr->ServerSendOwnClanToClient(client, group);

	serverMgr->ParseClanDataForCache(group);
}

