void GameServerFedManager::ScriptClanPromote(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "group_id",		operation->data["group_id"].asString() },
		{ "promote_owners",	operation->data["promote_owners"].asString() },
		{ "demote_owners",	operation->data["demote_owners"].asString() },
	};

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(op_data->operation->operation == ECO_PROMOTE);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_PROMOTE)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanPromote, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanPromote(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected - the operation will be retried when the client connects again
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanCreate script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());
		// --- TODO - inform the client about the error
		return;
	}

	Json::Value group;
	Json::Reader().parse(response["group"].asCString(), group);
	group["etags"] = std::move(response["etags"]);	// --- copy etags to group, will need them later

	// --- wall game post for promote
	if(!data->operation->data["name"].isNull())
	{
		std::unique_ptr<ClanOperation> opPostWallPromote(new ClanOperation());
		opPostWallPromote->operation = ECO_POST_WALL_GAME;
		opPostWallPromote->client_id = data->operation->client_id;
		opPostWallPromote->data["group_id"] = data->operation->data["group_id"];
		auto& postData = opPostWallPromote->data["post"];
		postData["type"] = static_cast<int>(GameWallPostType::MemberPromote);
		postData["params"]["NAME"] = data->operation->data["name"];
		postData["params"]["ID"] = data->operation->data["id"];

		serverMgr->ScriptClanPostWallGame(std::move(opPostWallPromote));
	}

	// --- if dethrone send last owner name
	if (!data->operation->data["dethrone_name"].isNull())
	{
		std::unique_ptr<ClanOperation> opPostWallPromote(new ClanOperation());
		opPostWallPromote->operation = ECO_POST_WALL_GAME;
		opPostWallPromote->client_id = data->operation->client_id;
		opPostWallPromote->data["group_id"] = data->operation->data["group_id"];
		auto& postData = opPostWallPromote->data["post"];
		postData["type"] = static_cast<int>(GameWallPostType::LeaderDethroned1);
		postData["params"]["NAME"] = data->operation->data["dethrone_name"];
		postData["params"]["ID"] = data->operation->data["dethrone_id"];

		serverMgr->ScriptClanPostWallGame(std::move(opPostWallPromote));

		// -- Tracking clan actions
		tracking::ClanAction(
			client->m_fedCredential,
			data->operation->data["group_id"].asString(),
			tracking::ClanActions::ChallengeInactiveLeader,
			data->operation->data["dethrone_id"].asString());
	}
	if (!data->operation->data["leader_name"].isNull())
	{
		std::unique_ptr<ClanOperation> opPostWallPromote(new ClanOperation());
		opPostWallPromote->operation = ECO_POST_WALL_GAME;
		opPostWallPromote->client_id = data->operation->client_id;
		opPostWallPromote->data["group_id"] = data->operation->data["group_id"];
		auto& postData = opPostWallPromote->data["post"];
		postData["type"] = static_cast<int>(GameWallPostType::LeaderDethroned2);
		postData["params"]["NAME"] = data->operation->data["leader_name"];
		postData["params"]["ID"] = data->operation->data["leader_id"];

		serverMgr->ScriptClanPostWallGame(std::move(opPostWallPromote));

		// -- Tracking clan actions
		tracking::ClanAction(
			client->m_fedCredential,
			data->operation->data["group_id"].asString(),
			tracking::ClanActions::PromoteToLeader,
			data->operation->data["leader_id"].asString(),
			tracking::PlayerRoles::Clan);
	}

	// --- send hermes message to new leader informing of promotion
	{
		Json::Value promote;
		Json::Reader().parse(data->operation->data["promote_owners"].asCString(), promote);
		std::string credential = promote[(Json::Value::UInt)0].asString();

		std::unique_ptr<ClanOperation> opHermesMessage(new ClanOperation(*data->operation.get()));
		opHermesMessage->operation = ECO_SEND_HERMES_MESSAGE_TO_USER;
		opHermesMessage->client_id = data->operation->client_id;
		opHermesMessage->for_credential = credential;
		opHermesMessage->data["from"] = group["name"];
		opHermesMessage->data["body"] = "promote";

		serverMgr->ScriptClanSendHermesMessageToUser(std::move(opHermesMessage));
	}

	// --- handle offiers promotion/demotion
	if (!data->operation->data["_promote_officer"].isNull())
	{
		client->m_clanData->officers.promote(client, data->operation->data["_promote_officer"].asString());
	}
	if (!data->operation->data["_demote_officer"].isNull())
	{
		client->m_clanData->officers.demote(client, data->operation->data["_demote_officer"].asString());
	}

	// --- send the old owner/new officer message that he should update his clan messages
	if (!data->operation->data["_send_demote"].isNull())
	{
		std::string credential = data->operation->data["_send_demote"].asString();

		std::unique_ptr<ClanOperation> opHermesMessage(new ClanOperation(*data->operation.get()));
		opHermesMessage->operation = ECO_SEND_HERMES_MESSAGE_TO_USER;
		opHermesMessage->client_id = data->operation->client_id;
		opHermesMessage->for_credential = credential;
		opHermesMessage->data["from"] = group["name"];
		opHermesMessage->data["body"] = "demote";

		serverMgr->ScriptClanSendHermesMessageToUser(std::move(opHermesMessage));

		// -- Tracking clan actions
		tracking::ClanAction(
			client->m_fedCredential,
			data->operation->data["group_id"].asString(),
			tracking::ClanActions::PromoteToLeader,
			credential,
			tracking::PlayerRoles::Leader);
	}

	// --- re-get clan to update members list
	std::unique_ptr<ClanOperation> clanGet(new ClanOperation(*data->operation.get()));
	clanGet->operation = ECO_GET_MY_CLAN;
	serverMgr->ScriptClanGet(std::move(clanGet));

	serverMgr->ParseClanDataForCache(group);
}

