//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptClanGet(std::unique_ptr<ClanOperation> operation)
{
	if (operation->data["group_id"].asString().empty())
	{
		MP_LOG(DBG_CRIT, "ScriptClanGet with empty group id op %d for %s", operation->operation, operation->owner_credential.c_str());
		return;
	}

	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "group_id",		operation->data["group_id"].asString() },
		{ "etag_for",		operation->data["etag_for"].asString() },
	};

	// --- brief -> don't get all members -> false by default
	if (operation->data.get("brief", false).asBool())
		customParams["brief"] = "y"; // --- non-empty string
	// --- get_opponent - also request and return opponent clan profile - true by default
	if (!operation->data.get("get_opponent", true).asBool())
		customParams["get_opponent"] = ""; // --- empty string

	operation->data["request_timestamp"] = Json::Int64(std::time(nullptr));

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(op_data->operation->operation == ECO_GET_MY_CLAN ||
		op_data->operation->operation == ECO_GET_OTHER_CLAN || 
		op_data->operation->operation == ECO_GET_OPPONENT_CLAN);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_SHOW)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanGet, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanGet(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanGet script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());
		// --- TODO: inform the client about the errors she should know about...

		auto status = response["status"].asInt();

		Json::Value response;
		response["id"] = data->operation->data["group_id"];
		response["error"] = static_cast<int>(status == 404 ? ClanRequestStatus::NotFound : ClanRequestStatus::Other);
		
		{
			if (data->operation->operation == ECO_GET_MY_CLAN)
			{
				// --- on 404 - clan not found - for "get my clan" requests, remove the clan data from the client's profile
				if (status == 404)
				{
					// --- update the clan data in profile
					client->m_seshatProfile->StartTrackingInventoryChanges("clan:disappeared");
					client->m_seshatProfile->RemoveClanData();
					client->GetHestiaConfig()->SetCreditBalance(client, StringHash("clan_cash"), 0);	// --- reset allied points / clan_cash when out of the clan
					client->GetHestiaConfig()->SetCreditBalance(client, StringHash("clan_insignia"), 0);	// --- reset clan_insignia / bagde when out of the clan
					client->m_seshatProfile->ResetAllClanBonus();										// --- reset any clan battlepass bonus if leaving clan
					Json::Value data = client->m_seshatProfile->StopTrackingInventoryChanges();
					if (!data.empty())
						GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(data));

					client->SetClanParticipations(Json::Value::null);

					// --- send clan data to client
					serverMgr->ServerSendOwnClanToClient(client, Json::Value::null);

					// --- reset client's clan data
					client->m_clanData.reset();
				}
				else
				{
					serverMgr->ServerSendOwnClanToClient(client, response);
				}
			}
			else if (data->operation->operation == ECO_GET_OTHER_CLAN)
			{
				serverMgr->ServerSendOtherClanToClient(client, response);
			}
			else if (data->operation->operation == ECO_GET_OPPONENT_CLAN)
			{
				if (status == 404)
				{
					// --- opponent clan no longer present - update the clan data and let the war update take over
					client->m_clanData->war.update_opponent_profile(Json::objectValue, "");
				}
				else
				{
					// --- some other error... :-/
				}
			}
			else
			{
				GLF_ASSERTMSG(false, "ScriptClanGet - unsupported operation %d", data->operation->operation);
			}
		}

		return;
	}

	// --- parse the clan data from the response
	Json::Value group;
	Json::Reader().parse(response["group"].asCString(), group);
	group["etags"] = std::move(response["etags"]);	// --- copy etags to group, will need them later
	Json::Value opponent_group_response = std::move(response["opponent_group"]);  // --- result of the request for the opponent group
	response = Json::nullValue; // --- to free the mem

	group["_request_timestamp"] = data->operation->data["request_timestamp"];

	// --- check if clan category is default
	if (group["category"].asString() != DEFAULT_CLAN)
	{	// --- we got something else here... not a default clan...
		if (data->operation->operation == ECO_GET_MY_CLAN
			&& group["category"].asString() == TRAINER_CLAN)
		{	// --- let's try the trainer clan
			data->operation->operation = ECO_GET_MY_TRAINER_CLAN;
			GameServerFedManager::Instance()->ScriptTrainerClanGet(std::move(data->operation));
		}

		// --- also check if this was set in profile
		if (client->m_seshatProfile->GetClanData()[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID] == group["id"])
		{	// --- remove
			client->m_seshatProfile->RemoveClanData();
		}
		return;
	}

	if (data->operation->operation == ECO_GET_MY_CLAN)
	{
		// --- check that I'm still a member of the clan
		bool stillMember = true;
		bool haveAllMembers = group["member_count"].asUInt() == group["members"].size();
		if (haveAllMembers)
		{
			auto credentialHash = StringHash(client->m_credential.c_str());
			const auto& members = group["members"];
			auto it = std::find_if(members.begin(), members.end(), [credentialHash](const Json::Value& member) { return credentialHash == StringHash(member["credential"].asCString()); });
			stillMember = it != members.end();
		}

		if (stillMember)
		{
			// --- at first get opperation we need to do some stuff
			if (data->operation->data["first_get"].asBool())
			{
				// --- wall
				std::unique_ptr<ClanOperation> wallOp(new ClanOperation(*data->operation.get()));
				wallOp->operation = ECO_VIEW_WALL;
				serverMgr->ScriptClanViewWall(std::move(wallOp));

				// --- requests (users want to join your clan)
				client->m_request_messages = true;
			}

			// --- check for new opponent group data
			if (!opponent_group_response.isNull())
			{
				if (opponent_group_response["status"] != 200)
				{
					// --- error retrieving opponent group
					MP_LOG(DBG_WARN, "ScriptClanGet script op %d for opponent clan returned error %d - %s for %s", 
						data->operation->operation, opponent_group_response["status"].asInt(), opponent_group_response["reason"].asCString(), data->operation->owner_credential.c_str());

					if (opponent_group_response["status"] == 404)
					{
						// --- opponent clan not found
						group[OSIRIS_CLAN_WAR_FIELD]["opponent_profile"] = Json::objectValue;
					}
					else
					{
						// --- some other error occured - disregard the request entirly
						// --- TODO: or maybe send a response with an error?
						//Json::Value response;
						//response["id"] = data->operation->data["group_id"];
						//response["error"] = static_cast<int>(ClanRequestStatus::Other);

						//serverMgr->ServerSendOwnClanToClient(client, response);

						return;
					}
				}
				else
				{
					Json::Value opponent_group;
					Json::Reader().parse(opponent_group_response["group"].asCString(), opponent_group);
					// --- TODO: also remove keys we're not interested in for an opponent
					GameServerFedManager::ProcessClanEntry(&opponent_group, nullptr, ProcessClanType::Opponent);
					group[OSIRIS_CLAN_WAR_FIELD]["opponent_profile"] = std::move(opponent_group);
					group["etags"]["opponent_profile"] = std::move(opponent_group_response["etags"]);
				}
			}

			GameServerFedManager::ProcessClanEntry(&group, client);

			// --- update the clan data in profile (checks for dirty)
			client->m_seshatProfile->StartTrackingInventoryChanges("clan:kick");
			client->m_seshatProfile->SetClanData(group["id"], group["name"], group["avatar"]);
			Json::Value trackingData = client->m_seshatProfile->StopTrackingInventoryChanges();
			if (!trackingData.empty())
				GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(trackingData));

			// --- send clan data to client
			serverMgr->ServerSendOwnClanToClient(client, group);

			// --- check clan events participation
			serverMgr->CheckClanEventParticipation(client);

			//if ads_rewards not processed
			if(client->UpdateClanAdsTranzactions())
				serverMgr->m_hestiaConfigManager->UpdateInventoryFromIAP(client);

			// --- check to fix clan score
			//if (!client->m_checkedClan)
			//{
			//	client->m_checkedClan = true;

			//	const auto& members = group["members"];
			//	auto clan_score = std::accumulate(members.begin(), members.end(), 0.0, [](double a, const Json::Value& m) -> double
			//	{
			//		return a + atof(m["_score"].asString().c_str());
			//	});

			//	std::unique_ptr<ClanOperation> operation(new ClanOperation);
			//	operation->client_id = client->m_clientId;
			//	operation->for_credential = client->m_credential;
			//	operation->owner_credential = client->m_credential;
			//	operation->clan_data = client->m_clanData;
			//	operation->data["clan_score"] = clan_score;

			//	serverMgr->ScriptIncCheckProfileCounter(std::move(operation));
			//}
		}
		else
		{
			// --- no longer a member
			// --- TODO: kick notification? something should have been sent on Hermes...

			// --- update the clan data in profile
			client->m_seshatProfile->StartTrackingInventoryChanges("clan:kick");
			client->m_seshatProfile->RemoveClanData();
			client->GetHestiaConfig()->SetCreditBalance(client, StringHash("clan_cash"), 0);	// --- reset allied points / clan_cash when out of the clan
			client->GetHestiaConfig()->SetCreditBalance(client, StringHash("clan_insignia"), 0);	// --- reset clan_insignia / bagde when out of the clan
			client->m_seshatProfile->ResetAllClanBonus();										// --- reset any clan battlepass bonus if leaving clan
			Json::Value data = client->m_seshatProfile->StopTrackingInventoryChanges();
			if (!data.empty())
				GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(data));

			// --- send clan data to client
			serverMgr->ServerSendOwnClanToClient(client, Json::Value::null);

			// --- reset client's clan data
			client->m_clanData.reset();

			// --- cache clan event participations in client
			client->SetClanParticipations(Json::Value::null);
		}

		if (data->operation->data.isMember("need_full_refresh"))
		{
			// --- trigger a full refresh for the client (flush seshat, get hestia, get events); this is mainly to get clan events
			client->SetNeedsFullRefresh(true);

			// --- this is expected to happen when `client` joins a clan
			// force a clan refresh through the clan server, don't wait for kairos, to notify clan members
			Json::Value post(Json::ValueType::objectValue);
			post["type"] = static_cast<int>(GameWallPostType::ClanRefresh);
			serverMgr->GetClanServerManager()->PostWall("game_post", group["id"].asString(), post);
		}
	}
	else if (data->operation->operation == ECO_GET_OTHER_CLAN)
	{
		GameServerFedManager::ProcessClanEntry(&group, nullptr, ProcessClanType::Other);

		// --- send clan data to client
		serverMgr->ServerSendOtherClanToClient(client, group);
	}
	else if (data->operation->operation == ECO_GET_OPPONENT_CLAN)
	{
		auto opponent_etag = group["etags"][OSIRIS_CLAN_WAR_FIELD].asString();

		GameServerFedManager::ProcessClanEntry(&group, nullptr, ProcessClanType::Opponent);

		client->m_clanData->war.update_opponent_profile(std::move(group), std::move(opponent_etag));

		client->m_clanData->war.send_update_to_client(client);

		return;
	}
	else
	{
		GLF_ASSERTMSG(false, "ScriptClanGet - unsupported operation %d", data->operation->operation);
	}

	serverMgr->ParseClanDataForCache(group);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptTrainerClanGet(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "group_id",		operation->data["group_id"].asString() },
		{ "etag_for",		operation->data["etag_for"].asString() },
	};

	// --- brief -> don't get all members -> false by default
	if (operation->data.get("brief", false).asBool())
		customParams["brief"] = "y"; // --- non-empty string

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(op_data->operation->operation == ECO_GET_MY_TRAINER_CLAN);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_TRAINER_CLAN_SHOW)->second, op_data->operation->client_id, customParams, {}, callbackScriptTrainerClanGet, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptTrainerClanGet(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptTrainerClanGet script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());
		// --- TODO: inform the client about the errors she should know about...

		auto status = response["status"].asInt();

		Json::Value response;
		response["id"] = data->operation->data["group_id"];
		response["error"] = static_cast<int>(status == 404 ? ClanRequestStatus::NotFound : ClanRequestStatus::Other);

		{
			if (data->operation->operation == ECO_GET_MY_TRAINER_CLAN)
			{
				// --- on 404 - clan not found - for "get my clan" requests, remove the clan data from the client's profile
				if (status == 404)
				{
					// --- update the clan data in profile
					client->m_seshatProfile->StartTrackingInventoryChanges("trainer:clan:disappeared");
					client->m_seshatProfile->RemoveTrainerClanData();
					Json::Value data = client->m_seshatProfile->StopTrackingInventoryChanges();
					if (!data.empty())
						GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(data));

					// --- send clan data to client
					serverMgr->ServerSendOwnTrainerClanToClient(client, Json::Value::null);

					// --- reset client's clan data
					client->m_trainerClan.reset();
				}
				else
				{
					serverMgr->ServerSendOwnTrainerClanToClient(client, response);
				}
			}
			else
			{
				GLF_ASSERTMSG(false, "ScriptTrainerClanGet - unsupported operation %d", data->operation->operation);
			}
		}

		return;
	}

	// --- parse the clan data from the response
	Json::Value group;
	Json::Reader().parse(response["group"].asCString(), group);
	group["etags"] = std::move(response["etags"]);	// --- copy etags to group, will need them later
	response = Json::nullValue; // --- to free the mem

	// --- check if clan category is trainer
	if (group["category"].asString() != TRAINER_CLAN)
	{	// --- we got something else here... not a trainer clan...
		if (data->operation->operation == ECO_GET_MY_TRAINER_CLAN	// --- was getting my clan
			&& group["category"].asString() == DEFAULT_CLAN)	// --- it was actually a default clan
		{	// --- let's try the default clan
			data->operation->operation = ECO_GET_MY_CLAN;
			data->operation->data["etag_for"] = CLAN_ETAG_FOR;
			GameServerFedManager::Instance()->ScriptClanGet(std::move(data->operation));

			// --- also check if this was set in profile
			if (client->m_seshatProfile->GetTrainerClanData() == group["id"])
			{	// --- remove
				client->m_seshatProfile->RemoveTrainerClanData();
			}
		}
		return;
	}

#ifdef DISABLE_TRAINER_CLAN
	return;
#endif // DISABLE_TRAINER_CLAN

	if (data->operation->operation == ECO_GET_MY_TRAINER_CLAN)
	{
		// --- check that I'm still a member of the clan
		bool stillMember = true;
		bool haveAllMembers = group["member_count"].asUInt() == group["members"].size();
		if (haveAllMembers)
		{
			auto credentialHash = StringHash(client->m_credential.c_str());
			const auto& members = group["members"];
			auto it = std::find_if(members.begin(), members.end(), [credentialHash](const Json::Value& member) { return credentialHash == StringHash(member["credential"].asCString()); });
			stillMember = it != members.end();
		}

		if (stillMember)
		{
			if (data->operation->data["first_get"].asBool())
			{
				client->m_give_mentorship_rewards = true;
			}

			GameServerFedManager::ProcessTrainerClanEntry(&group, client);

			// --- update the clan data in profile (checks for dirty)
			client->m_seshatProfile->StartTrackingInventoryChanges("trainer:clan:update");
			client->m_seshatProfile->SetTrainerClanData(group["id"]);
			Json::Value trackingData = client->m_seshatProfile->StopTrackingInventoryChanges();
			if (!trackingData.empty())
				GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(trackingData));

			// --- send clan data to client
			serverMgr->ServerSendOwnTrainerClanToClient(client, group);

			// --- Tracking
			if (data->operation->data.isMember("tracking:trainer:clan:join"))
			{
				auto trainerClan = client->m_trainerClan;
				std::string clanId = trainerClan->clan_id;
				int apprenticesCount = trainerClan->member_count() - 1;

				// -- for the apprentice that joined
				tracking::MentoringSystem(
					client->m_fedCredential.c_str(),
					apprenticesCount,
					(int)client->GetHestiaConfig()->GetCreditBalance(client, SESHAT_LABEL_LEVEL),
					tracking::MentoringActions::BecameApprentice,
					clanId
				);
				// -- for the trainer that was chosen
				tracking::MentoringSystem(
					trainerClan->ownerId.c_str(),
					apprenticesCount,
					trainerClan->get_member(StringHash(trainerClan->ownerId.c_str()))->level,
					apprenticesCount > 1 ? tracking::MentoringActions::AlreadyTrainer : tracking::MentoringActions::BecameTrainer,
					clanId
				);
			}
		}
		else
		{
			// --- no longer a member

			// --- update the clan data in profile
			client->m_seshatProfile->StartTrackingInventoryChanges("trainer:clan:kick");
			client->m_seshatProfile->RemoveTrainerClanData();
			Json::Value trackingData = client->m_seshatProfile->StopTrackingInventoryChanges();
			if (!trackingData.empty())
				GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(trackingData));

			// --- send clan data to client
			serverMgr->ServerSendOwnTrainerClanToClient(client, Json::Value::null);

			// --- reset client's clan data
			client->m_trainerClan.reset();
		}

		if (data->operation->data.isMember("need_full_refresh"))
		{
			// --- trigger a full refresh for the client (flush seshat, get hestia, get events); this is mainly to get clan events
			client->SetNeedsFullRefresh(true);
		}
	}
	else
	{
		GLF_ASSERTMSG(false, "ScriptTrainerClanGet - unsupported operation %d", data->operation->operation);
	}
}

