void GameServerFedManager::ScriptClanSearch(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "keyword",		operation->data["keyword"].asString() },
	};

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(op_data->operation->operation == ECO_SEARCH_CLAN);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_SEARCH_KEYWORD)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanSearch, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanSearch(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanSearch script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());
		// --- TODO: inform the client about the errors she should know about...
		return;
	}

	// --- parse the clan data from the response
	Json::Value groups;
	Json::Reader().parse(response["groups"].asCString(), groups);
	response = Json::nullValue; // --- to free the mem

	Json::Value result(Json::objectValue);
	result["cookie"] = data->operation->data["cookie"];
	auto& resGroups = result["groups"];

	// --- on the initial search (which has empty keywords) don't display clans that are full
	auto filterOutFullClans = data->operation->data["keyword"].asString().empty();
	for (auto& group : groups)
	{
		if ((filterOutFullClans &&
			group["member_count"].asInt() >= group["member_limit"].asInt()) || group["member_count"].asInt() < 1)
			continue;

		GameServerFedManager::ProcessSmallClanEntry(&group); // --- different filtering, leave only fields needed in search results

		serverMgr->ParseClanDataForCache(group);

		resGroups.append(std::move(group));
	}

	// --- send clan results to client
	serverMgr->ServerSendClanSearchResultsToClient(client, result);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptClansLeaderboard(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "name",			operation->data["lb_name"].asString() },
	};

	if (operation->operation == ECO_GET_DOMINATION_ZONE_LEADEBOARD)
	{
		customParams["for_entry_id"] = operation->data["group_id"].asString();
	}
	else if (operation->operation == ECO_CLANS_LEADERBOARD_OLD)
	{
		customParams["limit"] = operation->data["limit"].asString();
	}
	else if (operation->operation == ECO_FIX_49)
	{
		customParams["for_entry_id"] = operation->data["group_id"].asString();
		customParams["limit"] = "1";
	}

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(
		op_data->operation->operation == ECO_CLANS_LEADERBOARD ||
		op_data->operation->operation == ECO_CLANS_LEADERBOARD_OLD ||
		op_data->operation->operation == ECO_GET_DOMINATION_ZONE_LEADEBOARD ||
		op_data->operation->operation == ECO_FIX_49
	);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_LEADERBOARD)->second, op_data->operation->client_id, customParams, {}, callbackScriptClansLeaderboard, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClansLeaderboard(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	// --- reset flag in case the request was started from timer
	if (data->operation->data["time_update"].asBool())
	{
		if (data->operation->operation == ECO_CLANS_LEADERBOARD)
			serverMgr->ClansLeaderboard().SetTimeUpdateStarted(false);
		else if (data->operation->operation == ECO_CLANS_LEADERBOARD_OLD)
			serverMgr->ClansChampions().SetTimeUpdateStarted(false);
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClansLeaderboard script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());
		
		switch (data->operation->operation)
		{
		case ECO_CLANS_LEADERBOARD:
		{
			// --- retry again in CLANS_LEADERBOARD_CACHE_TIME time or when a forced refresh is made
			serverMgr->ClansLeaderboard().SetData(Json::Value());
			break;
		}
		case ECO_CLANS_LEADERBOARD_OLD:
		{
			break;
		}
		case ECO_GET_DOMINATION_ZONE_LEADEBOARD:
		{
			auto client = serverMgr->GetClient(data->operation->owner_credential);
			if (!client)
				break;

			if (!client->m_clanData ||
				client->m_clanData->clan_id != data->operation->clan_data->clan_id)
				break;

			auto zoneId = StringHash(data->operation->data["zone_name"].asCString());
			client->m_clanData->domination.update_zone_leaderboard(client, zoneId, Json::Value(), data->operation->data["request_ts"].asInt());

			break;
		}
		case ECO_FIX_49:
		{
			break;
		}
		}

		return;
	}

	// --- parse the clan data from the response
	Json::Value jReply;
	Json::Reader().parse(response["reply"].asCString(), jReply);
	response = Json::nullValue; // --- to free the mem

	switch (data->operation->operation)
	{
	case ECO_CLANS_LEADERBOARD:
	{
		// --- set global clans leaderboard data - this will send an update to all clients (including this one)
		jReply["id"] = data->operation->data["client_lb_name"];
		serverMgr->ClansLeaderboard().SetData(std::move(jReply));
		break;
	}
	case ECO_CLANS_LEADERBOARD_OLD:
	{
		jReply["id"] = data->operation->data["client_lb_name"];
		serverMgr->ClansChampions().SetData(std::move(jReply));
		break;
	}
	case ECO_GET_DOMINATION_ZONE_LEADEBOARD:
	{
		auto client = serverMgr->GetClient(data->operation->owner_credential);
		if (!client)
			break;

		if (!client->m_clanData ||
			client->m_clanData->clan_id != data->operation->clan_data->clan_id)
			break;

		auto zoneId = StringHash(data->operation->data["zone_name"].asCString());
		client->m_clanData->domination.update_zone_leaderboard(client, zoneId, std::move(jReply), data->operation->data["request_ts"].asInt());

		break;
	}
	case ECO_FIX_49:
	{
		auto rating = jReply["my_entry"]["score"].asInt();
		MP_LOG(DBG_WARN, "ScriptClansLeaderboard fix 49 - found old score %d for clan %s", rating, data->operation->data["group_id"].asString().c_str());

		// --- see about the rewards
		std::string lbId = "48";
		bool hasRewards = false;
		auto& clanSeasonRewardsData = GameServerFedManager::Instance()->GetMultiplayerData()->GetClanSeasonRewardsData(lbId);
		const auto& pid = GameServerFedManager::Instance()->GetPid();
		const auto& dc = GameServerFedManager::Instance()->GetDatacenter();
		for (const auto& bracket : clanSeasonRewardsData)
		{
			auto last_rating = bracket["last_rating"][pid][dc].asInt();
			if (rating < last_rating)
				continue;

			// --- construct member list
			std::vector<std::string> recipients;
			auto lbExpiry = GameServerFedManager::Instance()->GetLadderExpiry(lbId);
			std::for_each(data->operation->clan_data->members.begin(), data->operation->clan_data->members.end(),
				[&lbExpiry, &recipients](const ClanMember& member)
				{
					// --- member before season end
					if (member.joined_at <= lbExpiry)
						recipients.push_back(member.fed_id);
				});

			if (!recipients.empty())
			{
				MP_LOG(DBG_WARN, "Success: fix 49 for clan %s old score %d rewards using pid %s dc %s last rating %d\n",
					data->operation->clan_data->clan_id.c_str(), rating, pid.c_str(), dc.c_str(), last_rating);

				// --- send to other memebers
				auto client_id = data->operation->client_id;
				GameServerFedManager::Instance()->ScriptSendHermesNotification(
					client_id, recipients,
					"clan:season_reward", lbId, rating, ENM_CATEGORY | ENM_INFO | ENM_KEY, std::move(data->operation));

				hasRewards = true;
			}

			break;
		}

		if (!hasRewards)
		{
			auto& opdata = data->operation->data;

			// --- data for the set field call
			opdata["field"] = OSIRIS_CLAN_ELO_FIELD;
			opdata["etag"] = data->operation->clan_data->elo.etag();
			opdata["etag_for"] = OSIRIS_CLAN_ELO_FIELD;

			// --- data for the leaderboard post
			Json::Value new_data = data->operation->clan_data->elo.data();
			new_data["fix_49"] = true;

			opdata["object"] = Json::FastWriter().write(new_data);

			MP_LOG(DBG_WARN, "ScriptClansLeaderboard - no rewards fix 49 will write clan %s\n",
				data->operation->clan_data ? data->operation->clan_data->clan_id.c_str() : "none");

			GameServerFedManager::Instance()->ScriptClanSetField(std::move(data->operation));
		}

		break;
	}
	default:
		break;
	}
}

