	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_LEADERBOARD)->second, op_data->operation->client_id, customParams, {}, callbackScriptGetRedBossClansLeaderboard, this, op_data);
