//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGetRedBossClansLeaderboard(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptGetRedBossClansLeaderboard script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());

		return;
	}

	// --- parse the clan data from the response
	Json::Value jReply;
	Json::Reader().parse(response["reply"].asCString(), jReply);
	response = Json::nullValue; // --- to free the mem

	switch (data->operation->operation)
	{
		case ECO_GET_RED_BOSS_CLAN:
		{
			// send clan leaderboard data and check reward
			auto client = serverMgr->GetClient(data->operation->owner_credential);
			if (!client)
				break;

			// clan leaderboad
			jReply["id"] = data->operation->data["lb_name"];

			// check rewards
			client->m_seshatProfile->CheckRedOpsRewards(data->operation->data["eventId"].asString(), ERedBossRewardType::ClanLadder, jReply);

			// send data
			if (data->operation->data["sendToClient"].asBool())
			{
				serverMgr->ClansDemon().SetDemonClanData(true);
				serverMgr->ClansDemon().SetData(std::move(jReply));
			}
			
			break;
		}
		default:
			break;
	}
}

