void GameServerFedManager::ScriptClanSetMemberField(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->for_credential) },
		{ "credential",		operation->for_credential },
		{ "group_id",		operation->data["group_id"].asString() },
		{ "operation",		operation->data["operation"].asString() },
	};

	const auto& cData = const_cast<const Json::Value&>(operation->data);
	
	// --- copy all the fields starting with _
	for (auto it = cData.begin(); it != cData.end(); ++it)
	{
		auto memberName = it.memberName();
		if (*memberName == '_')
		{
			if ((*it).isString())
			{
				customParams[memberName] = (*it).asString();
			}
			else
			{
				customParams[memberName] = std::to_string((*it).asDouble());
			}
		}
	}

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(op_data->operation->operation == ECO_SET_CLAN_MEMBER_FIELD);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_SET_MEMBER_FIELD)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanSetMemberField, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanSetMemberField(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanSetMemberField script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());
		// --- TODO: the score will become unsynced - find a way to fix it at some point...
		return;
	}

	// --- for level change, wall post to inform the others the clan power has changed
	if (data->operation->data.isMember("_level"))
	{
		std::unique_ptr<ClanOperation> opPostWallWar(new ClanOperation());
		opPostWallWar->operation = ECO_POST_WALL_GAME;
		opPostWallWar->client_id = data->operation->client_id;
		opPostWallWar->data["group_id"] = data->operation->data["group_id"];

		auto& postData = opPostWallWar->data["post"];
		postData["type"] = static_cast<int>(GameWallPostType::MemberLevelUp);
		postData["params"]["LEVEL"] = data->operation->data["_level"];

		serverMgr->ScriptClanPostWallGame(std::move(opPostWallWar));
	}
	if (data->operation->data.isMember("_base_level"))
	{
		std::unique_ptr<ClanOperation> opPostWallWar(new ClanOperation());
		opPostWallWar->operation = ECO_POST_WALL_GAME;
		opPostWallWar->client_id = data->operation->client_id;
		opPostWallWar->data["group_id"] = data->operation->data["group_id"];

		auto& postData = opPostWallWar->data["post"];
		postData["type"] = static_cast<int>(GameWallPostType::MemberBaseLevelUp);
		postData["params"]["LEVEL"] = data->operation->data["_base_level"];

		serverMgr->ScriptClanPostWallGame(std::move(opPostWallWar));
	}
	else if (data->operation->data.isMember("_officer_ts"))
	{
		const auto& operation = data->operation->data["operation"];
		if (operation.empty() || operation.asString() == "update")
		{	// --- promotion

			if (!data->operation->data["name"].isNull())
			{	// --- wall post
				std::unique_ptr<ClanOperation> opPostWall(new ClanOperation());
				opPostWall->operation = ECO_POST_WALL_GAME;
				opPostWall->client_id = data->operation->client_id;
				opPostWall->data["group_id"] = data->operation->data["group_id"];

				auto& postData = opPostWall->data["post"];
				postData["type"] = static_cast<int>(GameWallPostType::MemberPromoteToOfficer);
				postData["params"]["NAME"] = data->operation->data["name"];
				postData["params"]["ID"] = data->operation->for_credential;

				// -- Tracking clan actions
				tracking::ClanAction(
					data->operation->owner_credential,
					data->operation->data["group_id"].asString(),
					tracking::ClanActions::PromoteToOfficer, 
					data->operation->for_credential);

				serverMgr->ScriptClanPostWallGame(std::move(opPostWall));

				// --- send hermes message to new officer informing of promotion
				{
					std::unique_ptr<ClanOperation> opHermesMessage(new ClanOperation(*data->operation.get()));
					opHermesMessage->operation = ECO_SEND_HERMES_MESSAGE_TO_USER;
					opHermesMessage->client_id = data->operation->client_id;
					opHermesMessage->data["from"] = data->operation->clan_data->name;
					opHermesMessage->data["body"] = "officer_promote";

					serverMgr->ScriptClanSendHermesMessageToUser(std::move(opHermesMessage));
				}
			}
		}
		else if (operation.asString() == "delete")
		{	// --- demotion

			if (!data->operation->data["name"].isNull())
			{	// --- wall post
				std::unique_ptr<ClanOperation> opPostWall(new ClanOperation());
				opPostWall->operation = ECO_POST_WALL_GAME;
				opPostWall->client_id = data->operation->client_id;
				opPostWall->data["group_id"] = data->operation->data["group_id"];

				auto& postData = opPostWall->data["post"];
				postData["type"] = static_cast<int>(GameWallPostType::MemberDemotedFromOfficer);
				postData["params"]["NAME"] = data->operation->data["name"];
				postData["params"]["ID"] = data->operation->for_credential;

				// -- Tracking clan actions
				tracking::ClanAction(
					data->operation->owner_credential,
					data->operation->data["group_id"].asString(),
					tracking::ClanActions::DemoteFromOfficer,
					data->operation->for_credential);

				serverMgr->ScriptClanPostWallGame(std::move(opPostWall));

				// --- send hermes message to old officer informing of demotion
				{
					std::unique_ptr<ClanOperation> opHermesMessage(new ClanOperation(*data->operation.get()));
					opHermesMessage->operation = ECO_SEND_HERMES_MESSAGE_TO_USER;
					opHermesMessage->client_id = data->operation->client_id;
					opHermesMessage->data["from"] = data->operation->clan_data->name;
					opHermesMessage->data["body"] = "officer_demote";

					serverMgr->ScriptClanSendHermesMessageToUser(std::move(opHermesMessage));
				}
			}
		}
	}

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (data->operation->data.isMember("_join_level"))
	{
		serverMgr->AddAchievementProgress(client, StringHash("trainer.appr_helped_50"), 1);
	}

	if (data->operation->data.isMember("boss_score"))
	{
		auto ev = client->FindEvent(data->operation->data["boss_eventId"].asString());
		if (ev && ev->IsBoss())
		{
			auto eventData = serverMgr->GetAHEventsData()->GetBossEventData(ev->GetPreset());
			client->m_seshatProfile->BattlePassIncMilestone("clan.boss_damage_" + eventData.Difficulty(), data->operation->data["score"].asInt64());

			client->m_seshatProfile->AddQuestProgress("damage_raid_boss", data->operation->data["score"].asInt64());
		}
	}

	if (data->operation->data.isMember("_joinedAt"))
	{
		std::unique_ptr<ClanOperation> operation(new ClanOperation());
		operation->client_id = client->m_clientId;
		operation->for_credential = client->m_credential;
		operation->owner_credential = client->m_credential;
		operation->operation = ECO_GET_MY_CLAN;

		operation->data["group_id"] = data->operation->data["group_id"];
		operation->data["etag_for"] = CLAN_ETAG_FOR;

		serverMgr->ScriptClanGet(std::move(operation));
	}

	//auto localClient = (data->operation->owner_credential == data->operation->for_credential);
	//if (!localClient)
	//	return;
}

