namespace
{
	struct RedBossIncScore_Data
	{
		std::string credential;
		std::string eventId;
		double score;
		std::unique_ptr<LadderOperation> ladderOperation;
	};
}

void GameServerFedManager::ScriptRedBossIncEventScore(const GSClient* client, const std::string& eventId, double score)
{
	if (m_adminClan.isNull())
	{
		MP_LOG(DBG_CRIT, "ScriptRedBossIncEventScore - we don't have admin clan!  event %s client %s",
			eventId.c_str(), client->m_credential.c_str());
		return;
	}

	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(client->m_credential) },
		{ "credential",		client->m_credential },
		{ "group_id",		m_adminClan["id"].asString() },
		{ "field",			ClanEventFieldFromEventId(eventId.c_str()) },
		{ "object",			std::to_string((int64_t)score) },
	};

	MP_LOG(DBG_WARN, "ScriptRedBossIncEventScore - starting script for %s group %s field %s object %s",
		customParams["credential"].c_str(), customParams["group_id"].c_str(), customParams["field"].c_str(), customParams["object"].c_str());

	auto op1 = std::unique_ptr<LadderOperation>(new LadderOperation());
	op1->operation = ELO_POST_RED_BOSS_GLOBAL;
	op1->owner_credential = client->m_credential;
	op1->for_credential = client->m_credential;
	op1->client_id = client->m_clientId;
	op1->cookie = GetLocalTime();
	op1->eventId = eventId;
	op1->large_score = client->m_seshatProfile->GetEventScore(eventId);
	//op1->league = (int)PvpLeagueToRedBossLeague(client->m_seshatProfile->GetCachedPvpStats().GetLeague());
	op1->league = (int)PvpLeagueToRedBossLeague(client->m_seshatProfile->GetEventPvpLeague(eventId));
	op1->clan_name = client->m_clanData ? client->m_clanData->name : "";
#ifdef RED_BOSS_CLAN_LEADERBOARD
	op1->clanId = client->m_clanData ? client->m_clanData->clan_id : "";
#endif // RED_BOSS_CLAN_LEADERBOARD
	op1->level = (int)client->GetHestiaConfig()->GetCreditBalance(client, "level");
	op1->prestige = client->m_seshatProfile->GetProfile()[SESHAT_GAME_SAVE][SESHAT_LABEL_PRESTIGE][SESHAT_LABEL_PRESTIGE_LEVEL].asInt();
	op1->display_name = client->m_seshatProfile->GetDisplayName();

	auto customData = new RedBossIncScore_Data{
		client->m_credential,
		eventId,
		score,
		std::move(op1),
	};

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_INC_DEC_FIELD)->second, client->m_clientId, customParams, {}, callbackScriptRedBossIncEventScore, this, customData);

}

