void GameServerFedManager::ScriptClanIncEventScore(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->for_credential) },
		{ "credential",		operation->for_credential },
		{ "group_id",		operation->data["group_id"].asString() },
		{ "field",			ClanEventFieldFromEventId(operation->data["event_id"].asCString()) },
		{ "object",			std::to_string(operation->data["score"].asInt64()) },
	};

	MP_LOG(DBG_WARN, "ScriptClanIncEventScore - starting script op %d for %s group %s field %s object %s", 
		operation->operation, customParams["credential"].c_str(), customParams["group_id"].c_str(), customParams["field"].c_str(), customParams["object"].c_str());
	
	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(op_data->operation->operation == ECO_INC_CLAN_EVENT_SCORE);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_INC_DEC_FIELD)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanIncEventScore, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanIncEventScore(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->for_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanIncEventScore script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());
		// --- TODO: the score will become unsynced - find a way to fix it at some point...

		// --- TODO: call the participate API if the field doesn't exist or something - apparently returns 400
		return;
	}

	Json::Value group;
	Json::Reader().parse(response["group"].asCString(), group);

	serverMgr->ParseClanDataForCache(group);

	auto localClient = (data->operation->owner_credential == data->operation->for_credential);
	if (!localClient)
		return;

	// --- for local clients send clan updates (in this case event scores)
	{
		Json::Value update;
		Json::Value eventScores;
		for (auto it = group.begin(); it != group.end(); ++it)
		{
			auto memberName = it.memberName();
			if (IsClanEventField(memberName))
			{
				eventScores[EventIdFromClanEventField(memberName)] = *it;
			}
		}
		update["_events"] = eventScores;
		serverMgr->ServerSendOwnClanToClient(client, update);

		if(client->m_clanData)
		{
			// --- update event scores in clien clan data
			client->m_clanData->eventScore = eventScores;

			auto eventId = data->operation->data["event_id"].asString();
			const SemEvent* evOsiris = client->FindEvent(eventId);
			if (evOsiris
				&& evOsiris->IsBoss())
			{
				auto myDamage = data->operation->data["score"].asDouble();

				// --- check if boss event and check if just killed the boss and send a wall post
				//if (!client->m_seshatProfile->IsEventFinished(eventId)
				//	&& !client->m_seshatProfile->IsEventFirstRunFinished(eventId))
				{
					auto clanScore = client->m_clanData->get_clan_score(eventId);
					auto eventData = serverMgr->GetAHEventsData()->GetBossEventData(evOsiris->GetPreset());
					auto firstRunDamage = client->m_clanData->neutronium_data.get_clan_boss_health(eventId);
					bool secondRun = firstRunDamage != 0;
					auto bossHealth = secondRun ? eventData.Boss2Health() : eventData.BossHealth();
					clanScore -= firstRunDamage;
					if (clanScore >= bossHealth
						&& clanScore - myDamage < bossHealth)
					{
						if (!secondRun)
						{
							// --- set cooldown
							client->m_clanData->bossVotes.set_cooldown(client, eventId);
						}

						// --- boss defeated wall post
						std::unique_ptr<ClanOperation> opPostWallDefeated(new ClanOperation());
						opPostWallDefeated->client_id = data->operation->client_id;
						opPostWallDefeated->data["group_id"] = client->m_clanData->clan_id;
						opPostWallDefeated->operation = ECO_POST_WALL_GAME;
						auto& postData = opPostWallDefeated->data["post"];
						postData["type"] = static_cast<int>(GameWallPostType::ClanBossDefeated);
						postData["hardcore"] = secondRun;
						postData["event_id"] = eventId;
						postData["params"]["CLAN_BOSS"] = evOsiris->GetBossName();
						GameServerFedManager::Instance()->ScriptClanPostWallGame(std::move(opPostWallDefeated));
					}
				}

				// --- achievement for dealing damage to a boss in hardcore mode
				if (client->m_seshatProfile->IsEventFirstRunFinished(eventId)
					&& !client->m_seshatProfile->IsEventFinished(eventId)
					&& myDamage > 0)
				{
					serverMgr->SetAchievementProgress(client, StringHash("clan_ops.hardcore"), 1);
				}
			}
		}

		// --- also, start a new get ladder op for the clans event
		Json::Value eventIDs(Json::arrayValue);
		eventIDs[0u] = data->operation->data["event_id"];
		serverMgr->ScriptRequestEventsLadder(client, eventIDs);
	}
}

