	GLF_ASSERT(op_data->operation->operation == ECO_INC_DEC_CLAN_WAR_CASH);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_INC_DEC_FIELD)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanIncWarCash, this, op_data);
