//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanIncWarCash(const SRequest & requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "UpdateAdminOsirisProfile script op %d returned error %d - %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString());
		return;
	}

	// --- parse the clan data from the response
	Json::Value clan;
	Json::Reader().parse(response["group"].asCString(), clan);

	// --- update war cash data
	data->operation->clan_data->war_cash.update_field(clan);

	// ---send update to client
	auto client = GameServerFedManager::Instance()->GetClient(data->operation->for_credential);
	if (client && client->m_clanData == data->operation->clan_data)
		data->operation->clan_data->war.send_update_to_client(client);

	// --- tracking clan resource gained
	tracking::ClanWarResourceGained(
		data->operation->owner_credential,
		data->operation->data["group_id"].asString(),
		data->operation->data["score"].asInt()
	);

	// --- broadcast the change
	data->operation->operation = ECO_POST_WALL_GAME;
	auto& postData = data->operation->data["post"];
	postData["type"] = static_cast<int>(GameWallPostType::WarCashChance);

	serverMgr->ScriptClanPostWallGame(std::move(data->operation));
}

