//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanInvite(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (data->operation->data["officer"].isNull())
	{	// --- dont update token if officer impersonated clan leader
		const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
		serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);
	}
	else
	{	// --- restore request owner (was impersonating clan leader)
		data->operation->owner_credential = data->operation->data["officer"].asCString();
	}

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected - the operation will be retried when the client connects again
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanInvite script op %d returned error %d - %s for %s and %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str(), data->operation->for_credential.c_str());
		// --- TODO: inform the client about the errors she should know about...

		// --- apparently 409 is MembershipException, which can mean "user already in clan" or "member limit reached" - should maybe trigger a refresh of the clan props
		if (response["status"] == 409)
		{
			// --- send exception message to client
			Json::Value request;
			if (data->operation->owner_credential == data->operation->for_credential || data->operation->for_credential == "me")
			{
				request["type"] = "membership_exception";
			}
			else
			{
				request["type"] = "membership_exception_leader";
				request["remove_request_id"] = data->operation->data["request_id"];
			}
			serverMgr->ServerSendRequestResult(client, request);

			// --- update clan data
			std::unique_ptr<ClanOperation> getClanOp(new ClanOperation(*data->operation.get()));
			getClanOp->operation = ECO_GET_OTHER_CLAN;
			getClanOp->data["etag_for"] = CLAN_ETAG_FOR;
			serverMgr->ScriptClanGet(std::move(getClanOp));
		}
		return;
	}

	Json::Value request;
	Json::Reader().parse(response["request"].asCString(), request);

	// --- TODO - maybe this shouldn't be updated for everyone (ex: when approving a request to join your clan, etc)
	// --- TODO - and maybe check if someone is joining/leaving to spam/flood
	// --- TODO - use this information on the client, display it on invite buttons and such
	// --- for any invite/join operation update invite timestamp
	client->m_seshatProfile->StartTrackingInventoryChanges("clan:inviteTS");
	client->m_seshatProfile->UpdateClanTs(SESHAT_LABEL_OSIRIS_INFO_CLAN_TS_INVITE, GameServerFedManager::Instance()->GetLocalTime());
	Json::Value profileData = client->m_seshatProfile->StopTrackingInventoryChanges();
	if (!profileData.empty())
		GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(profileData));

	// --- if join operation (on open membership clan)
	if (request.isNull() && (data->operation->owner_credential == data->operation->for_credential || data->operation->for_credential == "me"))
	{
		// --- set new clan id
		client->m_seshatProfile->StartTrackingInventoryChanges("clan:join");
		client->m_seshatProfile->SetClanData(data->operation->data["group_id"], "", "");
		Json::Value profileData = client->m_seshatProfile->StopTrackingInventoryChanges();
		if (!profileData.empty())
			GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(profileData));

		// --- get new clan data
		std::unique_ptr<ClanOperation> getClanOp(new ClanOperation(*data->operation.get()));
		getClanOp->operation = ECO_GET_MY_CLAN;
		getClanOp->data["etag_for"] = CLAN_ETAG_FOR;
		getClanOp->data["need_full_refresh"] = true;

		serverMgr->ScriptClanGet(std::move(getClanOp));

		// --- clans leaderboard
		std::unique_ptr<ClanOperation> clanLeaderboardOp(new ClanOperation(*data->operation.get()));
		clanLeaderboardOp->operation = ECO_CLANS_LEADERBOARD;
		clanLeaderboardOp->data["lb_name"] = serverMgr->GetCurrentClanLb();
		clanLeaderboardOp->data["client_lb_name"] = serverMgr->GetCurrentClientClanLb();

		serverMgr->StartGettingClansLeaderboard(std::move(clanLeaderboardOp), 0);

		// --- wall
		std::unique_ptr<ClanOperation> clanWallOp(new ClanOperation(*data->operation.get()));
		clanWallOp->operation = ECO_VIEW_WALL;

		if (clanWallOp->data["group_id"].asString().empty())
		{
			MP_LOG(DBG_WARN, "callbackScriptClanInvite launching clanWallOp with empty group id for %s and %s", clanWallOp->owner_credential.c_str(), clanWallOp->for_credential.c_str());
		}
		serverMgr->ScriptClanViewWall(std::move(clanWallOp));

		// --- post wall "user joined" messages
		data->operation->operation = ECO_POST_WALL_GAME;
		auto& postData = data->operation->data["post"];
		postData["type"] = static_cast<int>(GameWallPostType::MemberJoin);
		postData["params"]["NAME"] = client->m_seshatProfile->GetDisplayName();
		postData["params"]["ID"] = client->m_fedCredential;

		// -- Tracking clan actions
		tracking::ClanAction(client->m_fedCredential, data->operation->data["group_id"].asString(), tracking::ClanActions::Join, std::string(), tracking::PlayerRoles::Rookie);

		serverMgr->ScriptClanPostWallGame(std::move(data->operation));
	}
	else
	{
		// --- send request id (to be deleted from the list)
		if (!data->operation->data["request_id"].isNull())
		{
			request["remove_request_id"] = data->operation->data["request_id"];
		}
		// --- differentiate between invite and invite_after_accept
		if (!data->operation->data["type"].isNull())
		{
			request["type"] = data->operation->data["type"];

			// -- Tracking clan actions
			if (request["type"] == "membership_approval_accept")
			{
				tracking::ClanAction(client->m_fedCredential,
					data->operation->data["group_id"].asString(),
					tracking::ClanActions::AcceptPendingRequestToJoin,
					data->operation->for_credential);
			}
		}
		else if (request["type"] == "group_invitation")
		{
			tracking::ClanAction(client->m_fedCredential,
				data->operation->data["group_id"].asString(),
				tracking::ClanActions::Invite,
				data->operation->for_credential);
		}

		// --- request to join clan
		if (data->operation->owner_credential == data->operation->for_credential || data->operation->for_credential == "me")
		{
			tracking::ClanAction(client->m_fedCredential, data->operation->data["group_id"].asString(), tracking::ClanActions::RequestToJoin, std::string());
		}

		serverMgr->ServerSendRequestResult(client, request);

		// --- send the request to the client for anti-spam purposes
		if (!request.isNull())
		{
			Json::Value requests;
			requests.append(request);
			serverMgr->ServerSendSentRequests(client, requests);
		}
	}
}

