//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanKick(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (data->operation->data["officer"].isNull())
	{	// --- dont update token if officer impersonated clan leader
		const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
		serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);
	}
	else
	{	// --- restore request owner (was impersonating clan leader)
		data->operation->owner_credential = data->operation->data["officer"].asCString();
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanKick script op %d returned error %d - %s for %s and %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str(), data->operation->for_credential.c_str());
		// --- TODO: inform the client about the errors she should know about...
		return;
	}

	Json::Value group;
	Json::Reader().parse(response["group"].asCString(), group);

	// --- wall game post for member leave
	{
		auto group_id = data->operation->data["group_id"].asString();

		std::unique_ptr<ClanOperation> opPostWallLeave(new ClanOperation());
		opPostWallLeave->operation = ECO_POST_WALL_GAME;
		opPostWallLeave->client_id = data->operation->client_id;
		opPostWallLeave->data["group_id"] = data->operation->data["group_id"];
		auto& postData = opPostWallLeave->data["post"];
		if (data->operation->owner_credential == data->operation->for_credential || data->operation->for_credential == "me")
		{
			// --- keep ClanServerManager up-to-date with online clan members
			serverMgr->GetClanServerManager()->OnRemoveClient(group_id, serverMgr->GetClient(data->operation->owner_credential));

			postData["type"] = static_cast<int>(GameWallPostType::MemberLeave);

			auto action = group["members"].size() 
				? tracking::ClanActions::Leave
				: tracking::ClanActions::Disband;

			tracking::ClanAction(data->operation->owner_credential, group_id, action, std::string(), static_cast<tracking::PlayerRoles>(data->operation->data.isMember("role") ? data->operation->data["role"].asInt() : 0));
		}
		else
		{
			// --- keep ClanServerManager up-to-date with online clan members
			serverMgr->GetClanServerManager()->OnRemoveClient(group_id, serverMgr->GetClient(data->operation->for_credential));

			postData["type"] = static_cast<int>(GameWallPostType::MemberKick);
			postData["params"]["KICKER_NAME"] = data->operation->data["kicker_name"];
			postData["params"]["KICKER_ID"] = data->operation->data["kicker_id"];

			tracking::ClanAction(data->operation->owner_credential, group_id, tracking::ClanActions::Kick, data->operation->for_credential);
		}
		postData["params"]["NAME"] = data->operation->data["name"];
		postData["params"]["ID"] = data->operation->data["id"];

		serverMgr->ScriptClanPostWallGame(std::move(opPostWallLeave));
	}

	// --- send hermes message informing kicked member
	if (!(data->operation->owner_credential == data->operation->for_credential || data->operation->for_credential == "me"))
	{
		std::unique_ptr<ClanOperation> opHermesMessage(new ClanOperation());
		opHermesMessage->operation = ECO_SEND_HERMES_MESSAGE_TO_USER;
		opHermesMessage->client_id = data->operation->client_id;
		opHermesMessage->owner_credential = data->operation->owner_credential;
		opHermesMessage->for_credential = data->operation->for_credential;
		opHermesMessage->data["from"] = group["name"];
		opHermesMessage->data["body"] = "kick";

		serverMgr->ScriptClanSendHermesMessageToUser(std::move(opHermesMessage));
	}

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything else for clients that are no longer connected - the operation will be retried when the client connects again
		return;
	}

	// --- remove clan data from seshat profile if user left on its own
	if (data->operation->owner_credential == data->operation->for_credential || data->operation->for_credential == "me")
	{
		// --- remove from profile and send to client
		client->m_seshatProfile->StartTrackingInventoryChanges("clan:leave");
		if (data->operation->data["no_data"].isNull())
			client->m_seshatProfile->RemoveClanData();
		client->m_seshatProfile->UpdateClanTs(SESHAT_LABEL_OSIRIS_INFO_CLAN_TS_LEAVE, GameServerFedManager::Instance()->GetLocalTime());
		if (client->GetHestiaConfig())
		{
			client->GetHestiaConfig()->SetCreditBalance(client, StringHash("clan_cash"), 0);	// --- reset allied points / clan_cash when out of the clan
			client->GetHestiaConfig()->SetCreditBalance(client, StringHash("clan_insignia"), 0);	// --- reset clan_insignia / bagde when out of the clan
			client->m_seshatProfile->ResetAllClanBonus();										// --- reset any clan battlepass bonus if leaving clan
		}
		Json::Value profileData = client->m_seshatProfile->StopTrackingInventoryChanges();
		if (!profileData.empty())
			GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(profileData));

		if (data->operation->data["no_data"].isNull())
		{
			// --- send clan data update
			serverMgr->ServerSendOwnClanToClient(client, Json::Value::null);

			// --- reset client's clan data
			client->m_clanData.reset();
		}

		// --- TODO: reset any clan boss event(s) in the profile
		// --- trigger a full refresh for the client (flush seshat, get hestia, get events); this is mainly to get clan events
		client->SetNeedsFullRefresh(true);

		// --- decrement elo from old clan score
		//if (!data->operation->data["_score"].isNull())
		//{
		//	data->operation->owner_credential = group["owner"]["credential"].asCString();
		//	data->operation->for_credential = data->operation->owner_credential;

		//	data->operation->data["score"] = std::stoi(data->operation->data["_score"].asCString());
		//	data->operation->data["operation"] = "dec";
		//	data->operation->data["etag_for"] = CLAN_ETAG_FOR;

		//	data->operation->operation = ECO_UPDATE_CLAN_SCORE;

		//	serverMgr->ScriptClanUpdateScore(std::move(data->operation));
		//}
	}
	else
	{
		// --- TODO - in case of kick - update clan score (probably need to get the kicked player's profile to get the score)
		// --- decrement the score with the one sent by the kicker (the one in the clan profile, which might not be up to date, so a cron task to update the score would be necessary)
		//if (!data->operation->data["_score"].isNull() && data->operation->data["_score"].asString() != "")
		//{
		//	std::unique_ptr<ClanOperation> scoreOp(new ClanOperation(*data->operation.get()));
		//	scoreOp->data["score"] = std::stoi(data->operation->data["_score"].asCString());
		//	scoreOp->data["operation"] = "dec";
		//	scoreOp->data["etag_for"] = CLAN_ETAG_FOR;

		//	scoreOp->operation = ECO_UPDATE_CLAN_SCORE;

		//	serverMgr->ScriptClanUpdateScore(std::move(scoreOp));
		//}

		data->operation->operation = ECO_GET_MY_CLAN;
		data->operation->data["etag_for"] = CLAN_ETAG_FOR;
		serverMgr->ScriptClanGet(std::move(data->operation));
	}

	serverMgr->ParseClanDataForCache(group);

	// --- TODO: kick succesfull notification?
}

