void GameServerFedManager::ScriptTrainerClanKick(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "for_credential",	operation->for_credential },
		{ "group_id",		operation->data["group_id"].asString() },
	};

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	op_data->operation->operation = ECO_TRAINER_KICK;

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_TRAINER_CLAN_KICK)->second, op_data->operation->client_id, customParams, {}, callbackScriptTrainerClanKick, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptTrainerClanKick(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything else for clients that are no longer connected - the operation will be retried when the client connects again
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptTrainerClanKick script op %d returned error %d - %s for %s and %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str(), data->operation->for_credential.c_str());
		// --- TODO: inform the client about the errors she should know about...

		// --- send result to client
		Json::Value request;
		if (data->operation->owner_credential == data->operation->for_credential || data->operation->for_credential == "me")
		{
			request["type"] = "trainer_leave_failed";
		}
		else
		{
			request["type"] = "trainer_kick_failed";
		}
		serverMgr->ServerSendRequestResult(client, request);

		return;
	}

	Json::Value group;
	Json::Reader().parse(response["group"].asCString(), group);

	if ((data->operation->owner_credential == data->operation->for_credential || data->operation->for_credential == "me")
		&& data->operation->data["create"].asBool() && data->operation->data["trainer_id"].isString())
	{	// --- send hermes message informing the trainer(owner) of apprentice becoming a trainer - this should also trigger a refresh on the trainer side
		std::unique_ptr<ClanOperation> opHermesMessage(new ClanOperation());
		opHermesMessage->operation = ECO_SEND_HERMES_MESSAGE_TO_USER;
		opHermesMessage->client_id = data->operation->client_id;
		opHermesMessage->owner_credential = data->operation->owner_credential;
		opHermesMessage->for_credential = data->operation->data["trainer_id"].asCString();
		opHermesMessage->data["from"] = "trainer_clan";
		opHermesMessage->data["body"] = "trainered_up";

		Json::Value attachment;
		attachment["name"] = client->m_seshatProfile->GetDisplayName();
		attachment["level"] = client->GetHestiaConfig()->GetCreditBalance(client, "level");
		opHermesMessage->data["attachment"] = attachment.toCompactString();

		serverMgr->ScriptClanSendHermesMessageToUser(std::move(opHermesMessage));
	}

	// --- remove clan data from seshat profile if user left on its own
	if (data->operation->owner_credential == data->operation->for_credential || data->operation->for_credential == "me")
	{
		// --- remove from profile and send to client
		client->m_seshatProfile->StartTrackingInventoryChanges("trainer:clan:leave");
		client->m_seshatProfile->RemoveTrainerClanData();
		Json::Value profileData = client->m_seshatProfile->StopTrackingInventoryChanges();
		if (!profileData.empty())
			GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(profileData));

		// --- send clan data update
		serverMgr->ServerSendOwnTrainerClanToClient(client, Json::Value::null);

		client->m_seshatProfile->SetTrainerClanShadow();

		// ---- Tracking
		auto trainerClan = client->m_trainerClan;
		if (trainerClan)
		{
			int apprenticesCount = trainerClan->member_count() - 2;
			std::string ownerId = client->m_trainerClan->ownerId;

			auto kickedMember = trainerClan->get_member(StringHash(client->m_fedCredential.c_str()));
			if (kickedMember)
			{
				// -- for the user that left
				tracking::MentoringSystem(
					client->m_fedCredential.c_str(),
					apprenticesCount,
					(int)client->GetHestiaConfig()->GetCreditBalance(client, SESHAT_LABEL_LEVEL),
					tracking::MentoringActions::LeftApprenticeship,
					trainerClan->clan_id
				);

				// -- for the trainer
				tracking::MentoringSystem(
					ownerId.c_str(),
					apprenticesCount,
					trainerClan->get_member(StringHash(ownerId.c_str()))->level,
					apprenticesCount > 0 ? tracking::MentoringActions::AlreadyTrainer : tracking::MentoringActions::NoLongerTrainer,
					trainerClan->clan_id
				);
			}
			// --- reset client's clan data
			client->m_trainerClan.reset();
		}
		else
		{
			MP_LOG(DBG_CRIT, "callbackScriptTrainerClanKick - user left on its own - trainer clan data no longer available - %s!\n", client->m_fedCredential.c_str());
		}

		// --- trigger a full refresh for the client (flush seshat, get hestia, get events); this is mainly to get clan events
		//client->SetNeedsFullRefresh(true);

		if(data->operation->data["create"].asBool())
		{	// --- also create new trainer clan
			data->operation->operation = ECO_CREATE_TRAINER_CLAN;

			// --- initial clan score and member score and level
			data->operation->data["^level"] = std::to_string(client->GetHestiaConfig()->GetCreditBalance(client, SESHAT_LABEL_LEVEL));
			data->operation->data["^prestige"] = std::to_string(client->m_seshatProfile->GetPrestigeLevel());
			data->operation->data["^loadout"] = client->m_seshatProfile->GetAvatarModules().toCompactString();

			GameServerFedManager::Instance()->ScriptTrainerClanCreate(std::move(data->operation));
		}
		else
		{
			// --- send result to client
			Json::Value request;
			request["type"] = "trainer_leave_success";
			serverMgr->ServerSendRequestResult(client, request);
		}
	}
	else
	{
		// ---- Tracking (before group info is refreshed, and the kicked member disappears)
		if (data->operation->data["notify"].asBool())
		{
			auto trainerClan = client->m_trainerClan;
			int apprenticesCount = trainerClan->member_count() - 2;
			std::string kickedApprenticeId = data->operation->for_credential;
			auto kickedApprentice = trainerClan->get_member(StringHash(kickedApprenticeId.c_str()));
			
			if (kickedApprentice)
			{
				// -- for the user that was kicked
				tracking::MentoringSystem(
					kickedApprenticeId.c_str(),
					apprenticesCount,
					kickedApprentice->level,
					tracking::MentoringActions::Kicked,
					trainerClan->clan_id
				);

				// -- for the trainer
				tracking::MentoringSystem(
					trainerClan->ownerId.c_str(),
					apprenticesCount,
					trainerClan->get_member(StringHash(trainerClan->ownerId.c_str()))->level,
					apprenticesCount > 0 ? tracking::MentoringActions::AlreadyTrainer : tracking::MentoringActions::NoLongerTrainer,
					trainerClan->clan_id
				);
			}
		}

		// --- refresh clan for trainer
		GameServerFedManager::ProcessTrainerClanEntry(&group, client);
		
		// --- send clan data to client
		serverMgr->ServerSendOwnTrainerClanToClient(client, group);

		// --- also kick change the kicked players profile
		{
			std::unique_ptr<ProfileOperation> op(new ProfileOperation);
			op->operation = E_ProfileOperation::EPO_CHANGE_OTHER_TRAINER_CLAN;
			op->client_id = data->operation->client_id;
			op->owner_credential = data->operation->owner_credential;
			op->for_credential = data->operation->for_credential;
			op->data = std::unique_ptr<ProfileOperationData::Trainer>(new ProfileOperationData::Trainer("kick"));
			// --- this op checks that field is current clan id
			std::string etag = "_";
			etag.append(group["id"].asCString());
			GameServerFedManager::Instance()->ScriptChangeSeshatProfileFieldWithEtag("", SESHAT_LABEL_TRAINER_CLAN, "set", etag, std::move(op));
		}

		if (data->operation->data["notify"].asBool())
		{
			// --- send result to client
			Json::Value request;
			request["type"] = "trainer_kick_success";
			serverMgr->ServerSendRequestResult(client, request);
		}
	}
}

