void GameServerFedManager::ScriptClanRejectRequest(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",			GetAccessToken(operation->owner_credential) },
		{ "credential",				operation->owner_credential },
		{ "request_id",				operation->data["request_id"].asString() },
		{ "group_id",				operation->data["group_id"].asString() },
		{ "requester_credential",	operation->data["requester_credential"].asString() },
	};

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	op_data->operation->operation = ECO_REJECT_REQUEST;

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_REJECT_REQUEST)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanRejectRequest, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanRejectRequest(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (data->operation->data["officer"].isNull())
	{	// --- dont update token if officer impersonated clan leader
		const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
		serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);
	}
	else
	{	// --- restore request owner (was impersonating clan leader)
		data->operation->owner_credential = data->operation->data["officer"].asCString();
	}

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected - the operation will be retried when the client connects again
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanRejectRequest script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());

		// --- handle 404 - request not found - probably request was handled by someone else (officer/owner)
		if (response["status"] == 404)
		{
			// --- send request id (to be deleted from the list)
			if (!data->operation->data["request_id"].isNull())
			{
				Json::Value request;
				request["type"] = "reject";
				request["remove_request_id"] = data->operation->data["request_id"];
				serverMgr->ServerSendRequestResult(client, request);
			}

			// --- TODO - send a message explaining what happened
		}

		return;
	}

	if (data->operation->data["notify"].asBool())
	{
		// --- send hermes messages to other clan "officers" to refresh_clan_messages
		ClanOfficers::notify_officers_refresh_messages(client);
	}

	// -- Clan Actions Tracking
	tracking::ClanAction(
		client->m_credential,
		data->operation->data["group_id"].asString(), 
		tracking::ClanActions::DenyPendingRequestToJoin,
		data->operation->data["requester_credential"].asString());

	// --- send request id (to be deleted from the list)
	if (!data->operation->data["request_id"].isNull())
	{
		Json::Value request;
		request["type"] = "reject";
		request["remove_request_id"] = data->operation->data["request_id"];
		serverMgr->ServerSendRequestResult(client, request);
	}
}

