void GameServerFedManager::ScriptClanIgnoreRequest(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "request_id",		operation->data["request_id"].asString() },
	};

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	op_data->operation->operation = ECO_IGNORE_REQUEST;

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_IGNORE_REQUEST)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanIgnoreRequest, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanIgnoreRequest(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (data->operation->data["officer"].isNull())
	{	// --- dont update token if officer impersonated clan leader
		const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
		serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);
	}
	// --- keeping request owner as clan leader for future requests

	// --- if owner was impersonated by officer look for officer
	auto client = serverMgr->GetClient(
		data->operation->data["officer"].isNull()
		? data->operation->owner_credential
		: data->operation->data["officer"].asCString());
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected - the operation will be retried when the client connects again
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanIgnoreRequest script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());

		// --- handle 404 - request not found - probably request was handled by someone else (officer/owner)
		if (response["status"] == 404)
		{
			// --- send request id (to be deleted from the list)
			if (!data->operation->data["request_id"].isNull())
			{
				Json::Value request;
				request["type"] = "reject";
				request["remove_request_id"] = data->operation->data["request_id"];
				serverMgr->ServerSendRequestResult(client, request);
			}
		}

		return;
	}

	// --- check if we need to initiate an invite
	auto clanData = client->m_seshatProfile->GetClanData();
	if (!data->operation->data["invite_credential"].isNull() && !clanData.isNull() && !clanData[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID].isNull())
	{
		data->operation->for_credential = data->operation->data["invite_credential"].asCString();
		data->operation->data["group_id"] = clanData[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID].asCString();
		data->operation->data["type"] = "membership_approval_accept";
		data->operation->operation = ECO_INVITE;

		serverMgr->ScriptClanInvite(std::move(data->operation));

		// --- send hermes messages to other clan "officers" to refresh_clan_messages
		ClanOfficers::notify_officers_refresh_messages(client);
	}

	// --- TODO: send succes notification
}

