void GameServerFedManager::ScriptClanPostWallUser(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "object_id",		operation->data["group_id"].asString() },
		{ "text",			operation->data["text"].asString() },
	};

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(op_data->operation->operation == ECO_POST_WALL_USER);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_POST_WALL)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanPostWallUser, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanPostWallUser(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	Json::Value jReply;
	jReply["cookie"] = (int)time(nullptr);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanPostWallUser script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());

		// --- send error to client
		jReply["error"] = true; // --- TODO: error code?
		serverMgr->ServerSendClanWallPostResponse(client, jReply);
		return;
	}

	// --- get last post
	std::unique_ptr<ClanOperation> clanWallOp(new ClanOperation(*data->operation.get()));
	clanWallOp->operation = ECO_VIEW_WALL_LAST;
	serverMgr->ScriptClanViewWallLast(std::move(clanWallOp));
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptClanPostWallGame(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "credential",		"" }, // --- uses game credential
		{ "object_id",		operation->data["group_id"].asString() },
		{ "text",			Json::FastWriter().write(operation->data["post"]) },
		{ "activity_type",	"game_post" },
	};

	auto postWallRet = m_clanServerManager->PostWall("game_post", operation->data["group_id"].asString(), operation->data["post"]);
	if ((postWallRet & PostWallReturn::MessageSent) && !(postWallRet & PostWallReturn::VisibleOnClient))
	{
		// WallPost handled by clanserver, no need to make an actual wall post
		return;
	}

	if (!(postWallRet & PostWallReturn::AlertKairos))
	{
		// Don't send the kairo alert
		customParams["alert_kairos"] = "";
	}

	auto op_data = new ScriptClan_Data{ std::move(operation) };
//	GLF_ASSERT(op_data->operation->operation == ECO_POST_WALL_GAME);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_POST_WALL)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanPostWallGame, this, op_data);
}

