//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanViewWall(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanViewWall script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());
		return;
	}

	const auto& opdata_c = data->operation->data;

	// --- parse the clan wall posts data from the response
	Json::Value jPosts;
	Json::Reader().parse(response["wall_posts"].asCString(), jPosts);
	response = Json::nullValue; // --- to free the mem

	// --- send to client - TODO: only send delta
	serverMgr->ServerSendWallPosts(client, jPosts);

	// --- find the lastest game_post (the posts come newest first)
	auto it = std::find_if(jPosts.begin(), jPosts.end(), [](const Json::Value& jPost) { return StringHash(jPost["type"].asCString()) == StringHash("game_post"); });

	// --- no game posts - nothing left to do
	if (it == jPosts.end())
	{
		MP_LOG(DBG_NOTICE, "ScriptClanViewWall for %s clan %s - give up - no game wall posts", 
			client->m_credential.c_str(), opdata_c["group_id"].asString().c_str());
		return;
	}

	// --- compare it's ts with latest received
	time_t timestamp = 0;
	SemEvent::parse_time((*it)["creation"].asCString(), timestamp);
	auto latestParsedTs = client->m_seshatProfile->GetClanTs("wall_game");

	if (serverMgr->m_clanServerManager->OnClientViewWall(client, timestamp))
		return;

	// --- nothing left to do
	if (timestamp <= latestParsedTs)
	{
		MP_LOG(DBG_NOTICE, "ScriptClanViewWall for %s clan %s - give up - no new game wall posts",
			client->m_credential.c_str(), opdata_c["group_id"].asString().c_str());
		return;
	}

	// --- update profile ts
	client->m_seshatProfile->UpdateClanTs("wall_game", timestamp);

	// --- start a clan refresh if it's a clan wall refresh request
	if (!data->operation->data["refresh"].asBool())
	{
		MP_LOG(DBG_NOTICE, "ScriptClanViewWall for %s clan %s - give up - no refresh required",
			client->m_credential.c_str(), opdata_c["group_id"].asString().c_str());
		return;
	}

	// --- if the client doesn't have the clan data, she most likely left the clan in the meantime
	if (!client->m_clanData)
	{
		MP_LOG(DBG_NOTICE, "ScriptClanViewWall for %s clan %s - give up - no clan data",
			client->m_credential.c_str(), opdata_c["group_id"].asString().c_str());
		return;
	}

	// --- look at the types of the new wall posts, see what needs refreshing
	int refreshFlags = WallPostRefreshFlags::None;
	{
		// --- find the first not parsed wall post
		if (!latestParsedTs)
		{
			it = jPosts.end();
		}
		else
		{
			it = std::find_if(jPosts.begin(), jPosts.end(), [latestParsedTs](const Json::Value& jPost)
			{
				time_t timestamp = 0;
				SemEvent::parse_time(jPost["creation"].asCString(), timestamp);

				return latestParsedTs >= timestamp;
			});
		}

		// ---- see what needs to be refreshed based on the game post types
		Json::Reader reader;
		Json::Value jData;
		for (auto pit = jPosts.begin(); pit != it; ++pit)
		{
			const auto& jPost = *pit;

			if (StringHash(jPost["type"].asCString()) != StringHash("game_post"))
				continue;

			const auto& jText = jPost["text"];
			if (!jText.asCString())
				continue;

			jData.clear();
			auto ok = reader.parse(jPost["text"].asCString(), jData);
			if (!ok)
				continue;

			auto type = static_cast<GameWallPostType>(jData["type"].asInt());
			refreshFlags |= WallPostRefreshFlags::refresh_flags_for(type);

			// --- if we already have to refresh everything, no point in parsing further
			if ((refreshFlags & WallPostRefreshFlags::ClanMask) == WallPostRefreshFlags::FullClanRefresh)
				break;
		}
	}

	// don't care about Wallposts refresh at this point, we already got the wallposts
	refreshFlags = refreshFlags & ~WallPostRefreshFlags::Wallposts;

	if (refreshFlags == WallPostRefreshFlags::None)
	{
		MP_LOG(DBG_NOTICE, "ScriptClanViewWall for %s clan %s - give up - no refresh required for new posts",
			client->m_credential.c_str(), opdata_c["group_id"].asString().c_str());
		return;
	}

	if (refreshFlags == WallPostRefreshFlags::OpponentClan)
	{
		if (client->m_clanData->war.opponent_id().empty())
			return;

		data->operation->operation = ECO_GET_OPPONENT_CLAN;
		data->operation->data["brief"] = true;
		data->operation->data["get_opponent"] = false;
		data->operation->data["group_id"] = client->m_clanData->war.opponent_id();
	}
	else
	{
		data->operation->operation = ECO_GET_MY_CLAN;
		data->operation->data["brief"] = (refreshFlags & WallPostRefreshFlags::AllMembers) == 0;
		data->operation->data["get_opponent"] = (refreshFlags & WallPostRefreshFlags::OpponentClan) != 0;
	}

	MP_LOG(DBG_NOTICE, "Wall posts will trigger clan refresh op %d brief %d get_oppo %d for client %s group %s",
		data->operation->operation, opdata_c["brief"].asBool(), opdata_c["get_opponent"].asBool(),
		data->operation->for_credential.c_str(), opdata_c["group_id"].asString().c_str());

	data->operation->data["etag_for"] = CLAN_ETAG_FOR;
	client->m_clanData->schedule_clan_refresh(std::move(data->operation));
}

