void GameServerFedManager::ScriptClanViewWallLast(std::unique_ptr<ClanOperation> operation)
{
	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(operation->owner_credential) },
		{ "credential",		operation->owner_credential },
		{ "object_id",		operation->data["group_id"].asString() },
		//{ "sort_type",		"chronological" },
		{ "limit",			"1" },
	};

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(op_data->operation->operation == ECO_VIEW_WALL_LAST);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_VIEW_WALL)->second, op_data->operation->client_id, customParams, {}, callbackScriptClanViewWallLast, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptClanViewWallLast(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->operation->owner_credential, jsonAccessToken);

	auto client = serverMgr->GetClient(data->operation->owner_credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptClanViewWallLast script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());
		return;
	}

	// --- parse the clan data from the response
	Json::Value jPosts;
	Json::Reader().parse(response["wall_posts"].asCString(), jPosts);
	response = Json::nullValue; // --- to free the mem

	// --- find the lastest game_post (the posts come newest first)
	auto it = std::find_if(jPosts.begin(), jPosts.end(), [](const Json::Value& jPost) { return StringHash(jPost["type"].asCString()) == StringHash("user_post"); });

	if (it != jPosts.end())
	{
		// --- send wall post to client
		serverMgr->ServerSendClanWallPostResponse(client, *it);
	}
}

