namespace
{
	struct GlobalGroupParticipate_Data
	{
		std::string credential;
		std::string eventId;
	};
}

void GameServerFedManager::ScriptGlobalGroupParticipateEvent(const GSClient* client, const std::string& eventId)
{
	if (m_adminClan.isNull())
	{
		MP_LOG(DBG_CRIT, "ScriptGlobalGroupParticipateEvent - we don't have admin clan!  event %s client %s",
			eventId.c_str(), client->m_credential.c_str());
		return;
	}

	std::map<std::string, std::string> customParams = {
		{ "access_token",	GetAccessToken(client->m_credential) },
		{ "credential",		client->m_credential },
		{ "event_id",		eventId },
		{ "participant_id",	m_adminClan["id"].asString() },
		{ "field_id",		ClanEventFieldFromEventId(eventId.c_str()) },
	};

	auto customData = new GlobalGroupParticipate_Data {
		client->m_credential,
		eventId
	};

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_PARTICIPATE_EVENT)->second, client->m_clientId, customParams, {}, callbackScriptGlobalGroupParticipateEvent, this, customData);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptGlobalGroupParticipateEvent(const SRequest& requestData)
{
	std::unique_ptr<GlobalGroupParticipate_Data> data((GlobalGroupParticipate_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	const Json::Value& jsonAccessToken = response.isMember("access_token") ? response["access_token"] : Json::nullValue;
	serverMgr->UpdateAccessTokenFromJson(data->credential, jsonAccessToken);

	// --- 409 is "client already participated this event" -> race condition on call to participate -> add the participation and ignore the error
	if (requestData.m_errorCode || (response["status"] != 200 && response["status"] != 409))
	{
		MP_LOG(DBG_WARN, "ScriptGlobalGroupParticipateEvent script returned error %d - %s for %s", response["status"].asInt(), response["reason"].asCString(), data->credential.c_str());
		return;
	}

	auto client = serverMgr->GetClient(data->credential);
	if (!client)
	{
		// --- don't do anything else for clients that are no longer connected
		return;
	}

	// --- make sure the event is marked as "joined" in seshat as well
	Json::Value toJoinEventIDs;
	toJoinEventIDs.append(data->eventId);
	serverMgr->ClientParticipateEvents(client, toJoinEventIDs);
}

