{
	std::unique_ptr<ClanOperation> clanSendEtsRequest(new ClanOperation());
	clanSendEtsRequest->operation = ECO_SEND_ETS_EVENT;
	clanSendEtsRequest->data["data"] = Json::FastWriter().write(requestData);
	ScriptSendEtsRequest(std::move(clanSendEtsRequest));
}

