{
	std::map<std::string, std::string> customParams = {
		{ "data",			operation->data["data"].asCString() },
	};

	auto op_data = new ScriptClan_Data{ std::move(operation) };
	GLF_ASSERT(op_data->operation->operation == ECO_SEND_ETS_EVENT);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_SEND_ETS_EVENT)->second, op_data->operation->client_id, customParams, {}, callbackScriptSendEtsRequest, this, op_data);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptSendEtsRequest(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	auto client = serverMgr->GetClient(data->operation->owner_credential);

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	int status = response["status"].asInt();

	if (status == 200)
	{
		return;
	}

	MP_LOG(DBG_WARN, "ScriptSendEtsEvent script op %d returned error %d - %s for %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString(), data->operation->owner_credential.c_str());

	if (requestData.m_errorCode
		|| status == 990
		|| status == 991
		|| status == 994
		|| status == 995
		|| status == 999)
	{
		// --- Recover events from the request and try to resend them so they are not lost.
		Json::Value etsRequest;
		Json::Reader().parse(data->operation->data["data"].asCString(), etsRequest);

		for (auto& ev : etsRequest["events"])
		{
			tracking::AddEvent(client, ev["type"].asInt(), ev["data"], etsRequest["entity_type"].asCString(), etsRequest["entity_id"].asString());
		}

		return;
	}
}

