//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::InitAdminOsirisProfile(const std::string& clientId)
{
	if (!m_adminClan.isNull())
		return;

	if (m_adminClanRequestPending)
		return;

	m_adminClanRequestPending = true;

	std::map<std::string, std::string> customParams = {
		{ "access_token",	m_adminClanAccessToken },
		{ "credential",		"" },
		{ "category",		"admin" },
	};

	m_adminClanClientId = clientId;
	std::unique_ptr<ClanOperation> operation(new ClanOperation);
	operation->client_id = m_adminClanClientId;
	operation->operation = ECO_FIND_ADMIN_CLAN;
	auto op_data = new ScriptClan_Data{ std::move(operation) };

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_SEARCH_KEYWORD)->second, op_data->operation->client_id, customParams, {}, callbackInitAdminOsirisProfile, this, op_data);

}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackInitAdminOsirisProfile(const SRequest& requestData)
{
	std::unique_ptr<ScriptClan_Data> data((ScriptClan_Data*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	serverMgr->m_adminClanRequestPending = false;

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (response.isMember("access_token"))
	{
		serverMgr->m_adminClanAccessToken = response["access_token"].asString();
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "InitAdminOsirisProfile script op %d returned error %d - %s", data->operation->operation, response["status"].asInt(), response["reason"].asCString());
		return;
	}

	serverMgr->m_adminClanExpiry = serverMgr->GetLocalTime() + ADMIN_CLAN_TIMEOUT;

	// --- parse the clan data from the response
	Json::Value groups;
	Json::Reader().parse(response["groups"].asCString(), groups);
	response = Json::nullValue; // --- to free the mem

	if (groups.empty())
		serverMgr->m_adminClan = Json::Value::null;
	else
	{
		serverMgr->m_adminClan = *groups.begin();
		serverMgr->OnAdminOsirisProfileUpdated();
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UpdateAdminOsirisProfile()
{
	if (m_adminClanRequestPending)
		return;

	if (m_adminClanClientId.empty())
		return;

	auto now = GetServerTime();

	if (m_happyHourPendingTimer && m_happyHourPendingTimer <= now && m_happyHourPendingCounter && !m_adminClan.isNull())
	{
		FlushHappyHourCounter();
		return;
	}

	if (m_adminClanExpiry && m_adminClanExpiry > now)
		return;

	if (m_adminClan.isNull() || m_adminClan["id"].asString().empty())
	{
		InitAdminOsirisProfile(m_adminClanClientId);
		return;
	}

	m_adminClanRequestPending = true;

	std::map<std::string, std::string> customParams = {
		{ "access_token",	m_adminClanAccessToken },
		{ "credential",		"" },
		{ "group_id",		m_adminClan["id"].asString() },
	};

	std::unique_ptr<ClanOperation> operation(new ClanOperation);
	operation->client_id = m_adminClanClientId;
	operation->operation = ECO_GET_ADMIN_CLAN;
	auto op_data = new ScriptClan_Data{ std::move(operation) };

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_CLAN_SHOW)->second, op_data->operation->client_id, customParams, {}, callbackUpdateAdminOsirisProfile, this, op_data);

}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UpdatePendingEtsRequests()
{
	// --- Check if the tracking requests should be sent.
	auto now = OS_GetTime();

	if (m_serverSettings && (now - m_lastSentEtsEvents) > (int64_t)m_serverSettings->GetSendETSEventsInterval() && !m_etsEvents.empty())
	{
		antihackgs::tracking::FlushEtsRequests();
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UpdateIAPPendingRequests()
{
	std::vector<std::string> todel;

	for (auto& p : m_IPR_Queue)
	{
		if (p.second.req && !p.second.pending)
		{
			auto client = GetClient(p.first);
			if (client && p.second.id != -1)
			{
				ScriptRequestSeshatECommInventory(client, p.second.id, p.second.suppress_no_change_error);
			}
			else
			{
				todel.push_back(p.first);
			}
			p.second.req = false;
		}
	}

	if (!todel.empty())
	{
		m_IPR_Queue.erase(std::remove_if(m_IPR_Queue.begin(), m_IPR_Queue.end(), [&todel](const IPR_QueueMap::value_type& p)
		{
			return std::find(todel.begin(), todel.end(), p.first) != todel.end();
		}), m_IPR_Queue.end());
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::QueueIAPPendingRequests(GSClient* client, StringHash id, bool suppress_no_change_error)
{
	auto& entry = m_IPR_Queue[client->m_credential];
	entry.id = id;
	entry.suppress_no_change_error = suppress_no_change_error;

	entry.req = true;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::SetIAPPendingRequest(GSClient* client, bool pending)
{
	m_IPR_Queue[client->m_credential].pending = pending;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

auto GameServerFedManager::GetIAPPendingRequest(GSClient* client) -> IPR_Param&
{
	return m_IPR_Queue[client->m_credential];
}

