void GameServerFedManager::UpdateWarlord()
{
	for (auto it = m_gsClientsList.begin(); it != m_gsClientsList.end(); ++it)
	{
		auto client = it->second;
		if (client->GetHestiaConfig() && !client->m_seshatProfile->IsInvalid())
			client->m_seshatProfile->UpdateWarlord();
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UpdateDailyShop()
{
	auto presetChanged = DailyManager::Get()->UpdateCurrentDailyShopPreset();
	if (!presetChanged)
		return;

	for (auto it = m_gsClientsList.begin(); it != m_gsClientsList.end(); ++it)
	{
		auto client = it->second;
		if (client->GetHestiaConfig() && !client->m_seshatProfile->IsInvalid())
		{
			auto var_price_changes = client->GetHestiaConfig()->UpdateInventoryVariableOffers(client, { "daily_shop" });
			if (!var_price_changes.empty())
			{
				GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, "_variable_prices", std::move(var_price_changes));
			}
		}
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UpdateArenaModsExpiry()
{
	for (auto it = m_gsClientsList.begin(); it != m_gsClientsList.end(); ++it)
	{
		auto client = it->second;
		if (client && !client->m_seshatProfile->IsInvalid())
		{
			client->m_seshatProfile->StartTrackingInventoryChanges("arena_exp_mods"); // --- this action doesn't trigger any unwanted side-effects on client

			client->m_seshatProfile->UpdateEquippedExpiryMods();
			auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
			if (!inventory_changes.empty())
			{
				ServerSendInventoryUpdate(client, "arena_exp_mods", std::move(inventory_changes));
			}
		}
	}
}
void GameServerFedManager::UpdateClanBattlepass()
{
	auto now = GetServerTime();
	for (auto it = m_gsClientsList.begin(); it != m_gsClientsList.end(); ++it)
	{
		auto client = it->second;
		if (client->GetHestiaConfig() && !client->m_seshatProfile->IsInvalid() && client->m_clanData)
		{
			auto nextTs = client->m_seshatProfile->GetClanBattlePassStats().nextTs;
			if (nextTs && nextTs <= now)
			{
				client->m_seshatProfile->UpdateAndSendBattlepassStatus(client->m_clanData->battlepass, SeshatProfileManager::EForceSend::Yes);
			}
		}
	}
}

