//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::IncHappyHourCounter(double value)
{
	m_happyHourPendingCounter += value;
	m_happyHourPendingTimer = GetServerTime() + ADMIN_CLAN_CACHE_COUNTER;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::FlushHappyHourCounter()
{
	if (m_happyHourPendingCounter && (m_happyHourEnd == 0 || m_happyHourEnd < GetServerTime()))
		IncDecAdminClanField("_happy_hour", m_happyHourPendingCounter);

	m_happyHourPendingCounter = 0;
	m_happyHourPendingTimer = 0;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::OnAdminOsirisProfileUpdated()
{
	if (m_adminClan.isNull())
		return;

	if (m_happyHourEnd)
	{
		if (m_happyHourEnd < GetServerTime())
		{
			m_happyHourEnd = 0;
			OnActivateHappyHour();
		}
		return;
	}

	bool wasHappyHour = m_happyHourEnd && m_happyHourEnd >= GetServerTime();

	int cnt = m_adminClan["_happy_hour"].asInt();
	int max_cnt = m_adminClan.isMember("_happy_hour_max_counter") ? m_adminClan["_happy_hour_max_counter"].asInt() : GameServerFedManager::Instance()->GetServerConfigParam("Happy Hour Start Counter");
	time_t happy_end = (time_t)m_adminClan["_happy_hour_end"].asInt64();

	if (cnt >= max_cnt)	// --- happy hour started
	{
		if (happy_end < GetServerTime())	// --- it just started, compute the end
		{
			MP_LOG(DBG_WARN, "Starting Happy Hour.  Counter %d / %d\n", cnt, max_cnt);
			m_happyHourEnd = GetServerTime() + GameServerFedManager::Instance()->GetServerConfigParam("Happy Hour Duration") * 60;
			ResetAdminClanField("_happy_hour_end", (double)m_happyHourEnd);	// --- save it for others to see
			ResetAdminClanField("_happy_hour", 0);	// --- also reset the counter

			// --- Tracking - search for a valid client
			for (const auto& client : m_gsClientsList)
			{
				if (client.second->m_seshatProfile->IsInvalid() == false && client.second->GetHestiaConfig())
				{
					tracking::HappyHourTriggered(client.second);
					break;
				}
			}
			
		}
		else if (happy_end > GetServerTime())	// --- someone else already started this happy hour
		{
			m_happyHourEnd = happy_end;
		}
	}
	else if (happy_end > m_happyHourEnd)
	{
		// --- just refresh end time
		m_happyHourEnd = happy_end;
	}

	if (m_happyHourEnd < GetServerTime())
		m_happyHourEnd = 0;

	bool isHappyHour = m_happyHourEnd && m_happyHourEnd >= GetServerTime();
	if (isHappyHour != wasHappyHour)
	{
		OnActivateHappyHour();
	}
	else
	{
		Json::Value data;
		AddHappyHourData(&data);
		for (const auto& client : m_gsClientsList)
		{
			if (client.second->m_seshatProfile->IsInvalid() || !client.second->GetHestiaConfig())
				continue;

			Json::Value data2(data);
			AddClientHappyHourData(client.second, &data2);
			AddClientRedBossScoreData(client.second, &data2);
			ServerSendInventoryUpdate(client.second, "update_happy_hour", data2);
		}
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::OnActivateHappyHour()
{
	bool isHappyHour = m_happyHourEnd && m_happyHourEnd >= GetServerTime();

	auto now = GetServerTime();

	for (const auto& client : m_gsClientsList)
	{
		if (client.second->m_seshatProfile->IsInvalid() || !client.second->GetHestiaConfig())
			continue;

		GetGachaData()->CheckBM(client.second, BMType::HappyHour, isHappyHour ? EExpiryFlags::Reset : EExpiryFlags::DontReset);
		if (client.second->m_seshatProfile->ComputeHolobadgeBoost())
		{
			client.second->m_seshatProfile->MarkCurrentOpponentForResend();
			client.second->m_seshatProfile->SendCurrentOpponentToPlayer();
		}
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::AddHappyHourData(Json::Value* inventory_changes)
{
	if (!inventory_changes)
		return;

	if (m_adminClan.isNull())
	{
		MP_LOG(DBG_WARN, "AddHappyHourData - we don't have admin clan!");
		return;
	}

	bool isHappyHour = m_happyHourEnd && m_happyHourEnd >= GetServerTime();
	(*inventory_changes)["_hh"]["active"] = isHappyHour;

	double max_percent = isHappyHour ? 100.0 : 99.9;
	int max_cnt = m_adminClan.isMember("_happy_hour_max_counter") ? m_adminClan["_happy_hour_max_counter"].asInt() : GameServerFedManager::Instance()->GetServerConfigParam("Happy Hour Start Counter");
	double percent = glf::Clamp(100.0 * double(m_adminClan["_happy_hour"].asInt64() + m_happyHourPendingCounter) / max_cnt, 0.0, max_percent);

	(*inventory_changes)["_hh"]["counter"] = percent;
	(*inventory_changes)["_hh"]["end"] = Json::Value::Int64(m_happyHourEnd);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::AddClientHappyHourData(const GSClient* client, Json::Value* inventory_changes)
{
	if (!inventory_changes)
		return;

	(*inventory_changes)["_hh"]["slots"] = client->GetHestiaConfig()->GetHappyHourSlotsNo();
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::AddClientRedBossScoreData(const GSClient* client, Json::Value* inventory_changes)
{
	if (!inventory_changes)
		return;

	if (m_adminClan.isNull())
		return;

	auto bossEvent = client->GetUniqueEvent(EVENT_TYPE_RED_BOSS);
	if (bossEvent && bossEvent->IsActive() && client->m_seshatProfile->HasJoinedEvent(bossEvent->GetID()))
	{
		(*inventory_changes)["_red_boss"]["score"] = m_adminClan[ClanEventFieldFromEventId(bossEvent->GetID().c_str())].asDouble();

		client->m_seshatProfile->CheckRedOpsRewards(bossEvent->GetID(), ERedBossRewardType::None, Json::Value::null);
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

double GameServerFedManager::GetRedBossScore(const std::string& eventID) const
{
	if (m_adminClan.isNull())
		return 0;

	const auto& adminClan = m_adminClan;
	return adminClan[ClanEventFieldFromEventId(eventID.c_str())].asDouble();
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendBannedMessage(const std::string& credential, const std::string &message)
{
	NetworkMessageW banMessage;
    banMessage.addGameMessageType(TCPMSG_SERVER_SEND_BANNED);

	banMessage.addString((unsigned char*)message.c_str());

	MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendBannedMessage %s\n", credential.c_str());

	banMessage.packMessage(GetClient(credential)->m_Crypto);

	if(banMessage.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendBannedMessage packet memory overflow\n");
	}

    bool bResult = ServerSendMessage(credential, (char*) banMessage.getMessageBody(), banMessage.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendBannedMessage send message failed\n");
		return false;
	}

	return true;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendTimeToPlayer(GSClient* client)
{
	if (!client->m_isReadyForCommunication)
		return false;

	auto now = OS_GetTime();

	// --- don't send more than once per SendServerTimeInterval
	if (client->m_lastSentServerTime && now - client->m_lastSentServerTime < (int64_t)m_serverSettings->GetSendServerTimeInterval())
		return false;

	NetworkMessageW timeMessage;
	timeMessage.addGameMessageType(TCPMSG_SERVER_SEND_TIME);

	auto crtTime = GetCrtUTCTimeSeconds();
	timeMessage.addUInt((unsigned int)crtTime);
	client->m_lastSentTs = crtTime;

	timeMessage.packMessage(client->m_Crypto);

	if (timeMessage.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendTimeToPlayer packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)timeMessage.getMessageBody(), timeMessage.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendTimeToPlayer send message failed\n");
		return false;
	}

	client->m_lastSentServerTime = now;

	return true;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendProfileToPlayer(const std::string& credential, const SeshatProfileManager* profileManager)
{
	Json::Value profileToSend = profileManager->GetProfile()[SESHAT_GAME_SAVE];

	// --- subscriptions status tracking data
	{
		const auto& jActiveSubscriptions = profileManager->GetProfile()[SESHAT_LABEL_ACTIVE_SUBSCRIPTIONS];
		auto& subscriptionStatus = profileToSend["subscription_status"];
		if (jActiveSubscriptions.empty())
		{
			subscriptionStatus["status"] = "inactive";
			auto lastActiveSubscription = profileManager->LastActiveSubscription();
			if (!lastActiveSubscription.empty())
			{
				subscriptionStatus["status"] = profileManager->IsSubscriptionActive() ? "active" : "cancel";
				subscriptionStatus["content_id"] = lastActiveSubscription;
				subscriptionStatus["fake"] = true;
			}
		}
		else
		{
			auto now = GetLocalTime();
			subscriptionStatus["status"] = "cancel";
			auto it = std::max_element(jActiveSubscriptions.begin(), jActiveSubscriptions.end(), [](const Json::Value& v1, const Json::Value& v2)
			{
				auto new1 = v1["renewal_rewards"][0u].isMember("item");
				auto new2 = v2["renewal_rewards"][0u].isMember("item");
				if (new1 != new2)
					return new1 < new2;

				return v1["expiration_date"].asTimeT() < v2["expiration_date"].asTimeT();
			});
			if (it == jActiveSubscriptions.end())
			{
				subscriptionStatus["status"] = "inactive";	// --- should never happen
			}
			else
			{
				if ((*it)["expiration_date"].asTimeT() > now)
					subscriptionStatus["status"] = "active";
				subscriptionStatus["renewal_count"] = (*it)["renewal_count"];
				subscriptionStatus["content_id"] = (*it)["subscription_pack"];
			}
		}
	}

	if (profileManager->GetProfile()[SESHAT_GAME_SAVE][SESHAT_LABEL_SUBSCRIPTION_VIP][SESHAT_LABEL_SUBSCRIPTION_VIP_ACTIVE].isMember(SESHAT_LABEL_SUBSCRIPTION_VIP_EXPIRY))
	{
		profileToSend[SESHAT_LABEL_SUBSCRIPTION_VIP][SESHAT_LABEL_SUBSCRIPTION_VIP_ACTIVE][SESHAT_LABEL_SUBSCRIPTION_VIP_EXPIRY] =
			SeshatProfileManager::Day2Timestamp(profileToSend[SESHAT_LABEL_SUBSCRIPTION_VIP][SESHAT_LABEL_SUBSCRIPTION_VIP_ACTIVE][SESHAT_LABEL_SUBSCRIPTION_VIP_EXPIRY].asInt());
	}

#if POSTPONE_SQUADMATES
	Json::Value squadmates;
#endif	// POSTPONE_SQUADMATES

	if (profileToSend.isNull())
		return false;

	GSClient *client = GetClient(credential);
	profileToSend[SESHAT_LABEL_CLIENT_INVENTORY] = profileManager->GetProfile()[SESHAT_LABEL_STANDARD_INVENTORY];
	profileToSend[SESHAT_LABEL_MP_DEFENSE_SQUAD] = profileManager->GetProfile()[SESHAT_LABEL_MP_DEFENSE_SQUAD];
	profileManager->UpdateExpiryForClient(profileToSend);

	// --- count squadmates for tracking purposes
	{
		const auto& squadmates = profileToSend[SESHAT_LABEL_SQUAD_MATES][SESHAT_LABEL_SQUAD_MATES_DETAILS];
		std::vector<int> counts(GetMultiplayerData()->GetRatingsNo(), 0);
		for (const auto& sm : squadmates)
		{
			int rating = sm["rating"].asInt();
			if (rating > 0 && rating <= (int)counts.size())
				++counts[rating - 1];
		}
		auto& squadmates_count = profileToSend["_squadmates_count"] = Json::arrayValue;
		for (auto i : counts)
			squadmates_count.append(i);
	}

#if POSTPONE_SQUADMATES
	squadmates = std::move(profileToSend[SESHAT_LABEL_SQUAD_MATES]);
	profileToSend.removeMember(SESHAT_LABEL_SQUAD_MATES);
#else	// !POSTPONE_SQUADMATES
	profileManager->AddCardControlData(&profileToSend);
#endif	// !POSTPONE_SQUADMATES
	
	profileToSend[SESHAT_LABEL_XP_TABLE] = profileManager->SaveAllXPLevels();
	profileToSend[SESHAT_LABEL_CUSTOM_MATCHERS] = profileManager->GetProfile()[SESHAT_LABEL_CUSTOM_MATCHERS];
	profileToSend[SESHAT_LABEL_MP_STATS] = profileManager->GetProfile()[SESHAT_LABEL_MP_STATS];
	profileToSend[SESHAT_LABEL_MP_TLE_STATS] = profileManager->GetProfile()[SESHAT_LABEL_MP_TLE_STATS];
	profileToSend[SESHAT_LABEL_MP_HOF] = profileManager->GetProfile()[SESHAT_LABEL_MP_HOF];
	profileToSend[SESHAT_DEFENDER_LEADERBOARD] = profileManager->GetProfile()[SESHAT_DEFENDER_LEADERBOARD];
	profileToSend[SESHAT_LABEL_UPGRADE_COST_TABLE] = GameServerFedManager::Instance()->GetMultiplayerData()->SaveUpgradeCostTable();
	//profileToSend[SESHAT_LABEL_PVP_STATS] = profileManager->GetCachedPvpStatsJson();
	//if (!IsClientEloRanked(client))
	//	profileToSend[SESHAT_LABEL_PVP_STATS][SESHAT_LABEL_LEAGUE_DATA][SESHAT_LABEL_LEAGUE] = 0;	// --- send league 0 if the player is unranked

	profileToSend[SESHAT_LABEL_TRAINER_CLAN] = profileManager->GetProfile()[SESHAT_LABEL_TRAINER_CLAN];

	profileToSend[SESHAT_LABEL_REFERRAL][SESHAT_LABEL_REFERRAL_RECRUITS] = profileManager->GetProfile()[SESHAT_LABEL_RECRUITS].size();
	profileToSend[SESHAT_LABEL_REFERRAL][SESHAT_LABEL_REFERRAL_CODE] = profileManager->GetProfile()[SESHAT_GAME_SAVE][SESHAT_LABEL_ALIAS];
	profileToSend[SESHAT_LABEL_ALIAS] = RotateString(profileManager->GetProfile()[SESHAT_GAME_SAVE][SESHAT_LABEL_ALIAS].asString(), 2);
	
	profileToSend[SESHAT_FED_ID_LABEL] = client->GetFedId();

	// --- used for Helpshift
	profileToSend[SESHAT_LABEL_TOTAL_SPENT] = profileManager->GetProfile()[SESHAT_LABEL_TOTAL_SPENT].asFloat();

	auto ret = client->GetHestiaConfig()->ComputeClaimDailyRewardsPricesJson(client);
	if (!ret.empty())
		profileToSend["daily_prices"] = std::move(ret["daily_prices"]);

	auto retv2 = client->GetHestiaConfig()->ComputeClaimDailyRewardsPricesJsonV2(client);
	if (!retv2.empty())
		profileToSend["daily_v2_prices"] = std::move(retv2["daily_v2_prices"]);

	auto& subscriptions = profileToSend[SESHAT_LABEL_SUBSCRIPTION];
	for (auto it = subscriptions.begin(); it != subscriptions.end(); ++it)
	{
		int daysLeft = client->m_seshatProfile->CheckOldSubscriptionsDaysLeft(it.memberName());
		(*it)["days_left"] = daysLeft;
	}

	profileToSend["level_cap"] = client->GetHestiaConfig()->GetMaxPlayerLevel();
//	profileToSend["force_ftue"] = client->m_seshatProfile->ShouldForceFtueCoopTutorial();
	profileToSend["force_ftue"] = false;	// --- force this to false
	profileToSend["max_squad_ops_mission"] = MAX_SQUAD_OPS_MISSION;

	{
		time_t created_time = 0;
		SemEvent::parse_time(profileManager->GetProfile()[SESHAT_LABEL_CREATED].asString().c_str(), created_time);
		if (created_time == 0)
			created_time = GetLocalTime();
		const time_t GDPR_start = 1524787200; // --- 27.04.2018
		bool is_before_gdpr = created_time < GDPR_start;

		// --- even if profile created after that date, if it doesn't have the age gate country saved (which it will if it was created by a 340 build later than @70317),
		// --- consider it a profile created "before GFPR"
		// --- fixes stuff like 10034826
		if (!is_before_gdpr && 
			profileToSend.isMember(SESHAT_LABEL_AGE) && 
			!profileToSend.isMember(SESHAT_LABEL_AGE_COUNTRY))
		{
			is_before_gdpr = true;
		}

		profileToSend["before_gdpr"] = is_before_gdpr;
	}

	{
		if (profileManager->GetProfile().isMember(SESHAT_LABEL_BIRTHDATE)
			&& !profileManager->GetProfile()[SESHAT_LABEL_BIRTHDATE].isNull())
		{
			auto birthdate = profileManager->GetProfile()[SESHAT_LABEL_BIRTHDATE].asCString();
			tm birthdate_tm = {};
			strptime(birthdate, "%Y-%m-%d %H:%M:%SZ", &birthdate_tm);
			time_t now = GetLocalTime();
			tm* now_tm = gmtime(&now);

			int age = now_tm->tm_year - birthdate_tm.tm_year;
			profileToSend[SESHAT_LABEL_AGE] = age;
		}
	}
	
	std::string profile = Json::FastWriter().write(profileToSend);

	NetworkMessageW playerProfile;

	// compress the profile
	int profileSize = (int)profile.size();
	if (profileSize > (GetRecvBufferSize() - 2))
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendProfileToPlayer %s profile too large %d, resizing!!!\n", credential.c_str(), profileSize);
		ResizeBuffers(profileSize + 2);
	}

	int compressedSize = LZ4_compressHC((char*)profile.c_str(), (char*)m_tempBuffer.data(), profileSize);
	if ((compressedSize <= 0) || (compressedSize >= profileSize))
	{
		// the compression failed so we add the normal message
		playerProfile.addGameMessageType(TCPMSG_SERVER_SEND_PROFILE);
		playerProfile.addBytesAndLen((const byte*)profile.c_str(), profileSize);
		MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendProfileToPlayer %s\n", credential.c_str());
	}
	else
	{
		// the compression worked so we add the compressed message
		playerProfile.addGameMessageType(TCPMSG_SERVER_SEND_PROFILE_COMPRESSED);
		playerProfile.addInt(profileSize);
		playerProfile.addBytesAndLen(m_tempBuffer.data(), compressedSize);
		MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendProfileToPlayer (compressed) %s\n", credential.c_str());
	}

	playerProfile.packMessage(client->m_Crypto);

	if(playerProfile.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendProfileToPlayer packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(credential, (char*) playerProfile.getMessageBody(), playerProfile.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendProfileToPlayer send message failed\n");
		return false;
	}

	// --- HACK - also send an initial profile update, with the variable prices and gacha chances
	{
		client->m_seshatProfile->ClearGachaMaxChances();
		client->m_seshatProfile->StartTrackingInventoryChanges("init");
		client->m_seshatProfile->AppendInventoryChanges("init", 0);
		Json::Value data = client->m_seshatProfile->StopTrackingInventoryChanges();

		// --- send initial drone and avatar next hp
		auto& dronesData = data[SESHAT_LABEL_STANDARD_INVENTORY_DRONES2];
		auto& avatarData = data[SESHAT_LABEL_STANDARD_INVENTORY_MPAVATAR];

		dronesData = client->m_seshatProfile->GetProfile()[SESHAT_GAME_SAVE][SESHAT_LABEL_STANDARD_INVENTORY_DRONES2];
		avatarData = client->m_seshatProfile->GetProfile()[SESHAT_GAME_SAVE][SESHAT_LABEL_STANDARD_INVENTORY_MPAVATAR];

		GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(data));
	}

#if POSTPONE_SQUADMATES
	auto& squadmatesToSend = squadmates[SESHAT_LABEL_SQUAD_MATES_DETAILS];
	Json::Value data;
	data["action"] = "activate";
	auto& data_squadmates = data["squad_mates"]["details"];
	if (squadmatesToSend.size() > 1024)
	{
		int i = 0;
		for (auto it = squadmatesToSend.begin(); it != squadmatesToSend.end(); ++it)
		{
			data_squadmates[it.memberName()] = std::move(*it);
			if ((++i & 0x3ff) == 0)
			{
				GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, data);
				data_squadmates.clear();
			}
		}
	}
	else
	{
		data_squadmates = std::move(squadmatesToSend);
	}

	if (!data_squadmates.empty())
	{
		GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(data));
	}
#endif	// POSTPONE_SQUADMATES

	return true;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ProcessOtherProfileBeforeSending(const GSClient* client, Json::Value& otherProfile)
{
	// --- check / equip default holo badge for other
	{
		auto defaultHoloBadgeCredit = client->GetHestiaConfig()->FindCredit(GetMultiplayerData()->DefaultHoloBadge());
		if (defaultHoloBadgeCredit)
			SeshatProfileManager::EquipDefaultHoloBadgeForOther(otherProfile, defaultHoloBadgeCredit->name.c_str());
	}

	// --- TODO: USE MOVE!!!
	Json::Value profileToSend = otherProfile[SESHAT_GAME_SAVE];

	if (profileToSend.isNull())
		return false;

	profileToSend["credential"] = otherProfile["credential"];
	profileToSend[SESHAT_LABEL_CLIENT_INVENTORY] = otherProfile[SESHAT_LABEL_STANDARD_INVENTORY];
	profileToSend[SESHAT_LABEL_MP_DEFENSE_SQUAD] = otherProfile[SESHAT_LABEL_MP_DEFENSE_SQUAD];
	profileToSend[SESHAT_LABEL_CUSTOM_MATCHERS] = otherProfile[SESHAT_LABEL_CUSTOM_MATCHERS];
	profileToSend[SESHAT_LABEL_PVP_STATS] = otherProfile[SESHAT_LABEL_PVP_STATS];
	profileToSend[SESHAT_DEFENDER_LEADERBOARD] = otherProfile[SESHAT_DEFENDER_LEADERBOARD];
	profileToSend[SESHAT_LABEL_MP_STATS] = otherProfile[SESHAT_LABEL_MP_STATS];
	profileToSend[SESHAT_LABEL_MP_TLE_STATS] = otherProfile[SESHAT_LABEL_MP_TLE_STATS];
	profileToSend[SESHAT_LABEL_MP_HOF] = otherProfile[SESHAT_LABEL_MP_HOF];
	profileToSend[SESHAT_LABEL_TRAINER_CLAN] = otherProfile[SESHAT_LABEL_TRAINER_CLAN];
	profileToSend[SESHAT_FED_ID_LABEL] = otherProfile[SESHAT_FED_ID_LABEL];
	profileToSend[SESHAT_LABEL_TOTAL_TRANSACTIONS] = otherProfile[SESHAT_LABEL_TOTAL_TRANSACTIONS];
	SeshatProfileManager::MigrateAvatarModulesForOther(profileToSend);
	SeshatProfileManager::MigrateWeaponBulletsForOther(profileToSend);
	client->m_seshatProfile->AddCardControlData(&profileToSend); // --- safe to use for other profiles as well, at least for now
	SeshatProfileManager::UpdateSquadHp(otherProfile, profileToSend);

	otherProfile = profileToSend;

	return true;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendProfileForOtherPlayer(const GSClient* client, Json::Value&& profileToSend)
{
	auto ok = GameServerFedManager::ProcessOtherProfileBeforeSending(client, profileToSend);
	if (!ok)
		return false;

	std::string profile = Json::FastWriter().write(profileToSend);
	const auto& credential = client->m_credential;

	NetworkMessageW playerProfile;

	// compress the profile
	int profileSize = (int)profile.size();
	if (profileSize > (GetRecvBufferSize() - 8))
		ResizeBuffers(profileSize + 8);

	playerProfile.addGameMessageType(TCPMSG_SERVER_SEND_PROFILE_FOR_OTHER);

	int compressedSize = LZ4_compressHC((char*)profile.c_str(), (char*)m_tempBuffer.data(), profileSize);
	if ((compressedSize <= 0) || (compressedSize >= profileSize))
	{
		// the compression failed so we add the normal message
		playerProfile.addByte(0);
		playerProfile.addBytesAndLen((const byte*)profile.c_str(), profileSize);
		MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendProfileForOtherPlayer %s\n", credential.c_str());
	}
	else
	{
		// the compression worked so we add the compressed message
		playerProfile.addByte(1);
		playerProfile.addInt(profileSize);
		playerProfile.addBytesAndLen(m_tempBuffer.data(), compressedSize);
		MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendProfileForOtherPlayer (compressed) %s\n", credential.c_str());
	}

	playerProfile.packMessage(client->m_Crypto);

	if (playerProfile.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendProfileForOtherPlayer packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(credential, (char*)playerProfile.getMessageBody(), playerProfile.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendProfileForOtherPlayer send message failed\n");
		return false;
	}

	return true;
}

