bool GameServerFedManager::ServerSendSlotsConfigToPlayer(const std::string& credential)
{
	NetworkMessageW playerConfig;

	std::string config = GetMultiplayerData()->SerializeSlots();
	int configSize = (int)config.size() + 1;

	playerConfig.addGameMessageType(TCPMSG_SERVER_SEND_SLOTS_CONFIG);
	playerConfig.addBytesAndLen((const byte*)config.c_str(), configSize);
	MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendSlotsConfigToPlayer %s\n", credential.c_str());

	playerConfig.packMessage(GetClient(credential)->m_Crypto);

	if (playerConfig.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendSlotsConfigToPlayer packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(credential, (char*) playerConfig.getMessageBody(), playerConfig.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendSlotsConfigToPlayer send message failed\n");
		return false;
	}

	return true;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendInventoryUpdate(GSClient* client, StringHash transactionId, Json::Value result)
{
	NetworkMessageW inventoryUpdate;

	inventoryUpdate.addGameMessageType(TCPMSG_SERVER_SEND_INVENTORY_CHANGES);
	inventoryUpdate.addUInt(transactionId);
	
	// --- result is either an int, in which case it contains an error status, or a dict, in which case it's ok
	TransactionRequestStatus status = TRS_Ok;
	if (result.isInt())
	{
		status = (TransactionRequestStatus)result.asInt();
	}
	else if (result.empty())
	{
		status = TRS_NoChange;
	}
	else if (result.isMember("error"))
	{
		status = (TransactionRequestStatus)result["error"].asInt();
	}
	else if (client->GetHestiaConfig())
	{
		// --- change expiry field from time_point (seconds from epoch) to duration (seconds until expiry)
		client->m_seshatProfile->UpdateExpiryForClient(result);

		// --- add extra information for dropped cards
		client->m_seshatProfile->AddCardControlData(&result);
		client->m_seshatProfile->AddNextHPData(&result);
	}
	// Huong.DaoNgocAdd for prevent cheat on gold environment
	if (!IsBetaEnvironment() && status == TRS_Cheat_On_Gold)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendInventoryUpdate process cheat command on gold environtment, credential: %s\n", client->m_credential.c_str());
		return false;
	}
	
	if (status == TRS_Ok)
	{
		if (result.isObject())
		{
			const auto& cresult = result;
			const auto& clanUpdate = cresult[SESHAT_LABEL_INVENTORY_CHANGES_CLAN];
			// --- temp debug
			if (!clanUpdate.isNull() && !clanUpdate["id"].isNull() && clanUpdate["id"].asString().empty())
			{
				MP_LOG(DBG_NOTICE, "ServerSendInventoryUpdate with empty clan id to %s\n", client->m_credential.c_str());
			}
		}

		std::string sRawResponse = Json::FastWriter().write(result);

		std::string sCmpResponse;
		sCmpResponse.resize(LZ4_compressBound((int)sRawResponse.size()));

		unsigned int cmpSize = LZ4_compressHC(&sRawResponse[0], &sCmpResponse[0], (int)sRawResponse.size());
		if (cmpSize > 0 && cmpSize < sRawResponse.size())
		{ // add compressed data
			inventoryUpdate.addInt(TRS_Ok_Compressed);
			inventoryUpdate.addInt((int)sRawResponse.size());
			inventoryUpdate.addBytesAndLen((const byte*)sCmpResponse.c_str(), cmpSize);
		}
		else
		{ // or not
			inventoryUpdate.addInt(status);
			inventoryUpdate.addBytesAndLen((const byte*)sRawResponse.c_str(), (unsigned int)sRawResponse.size());
		}
	}
	else
	{
		inventoryUpdate.addInt(status);
		if (result.isObject())
		{
			std::string sRawResponse = Json::FastWriter().write(result);
			inventoryUpdate.addByte(1);
			inventoryUpdate.addBytesAndLen((const byte*)sRawResponse.c_str(), (unsigned int)sRawResponse.size());
		}
		else
		{
			inventoryUpdate.addByte(0);
		}
	}

	inventoryUpdate.packMessage(client->m_Crypto);

	if (inventoryUpdate.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendInventoryUpdate packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)inventoryUpdate.getMessageBody(), inventoryUpdate.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendInventoryUpdate send message failed\n");
		return false;
	}

	return true;
}

