GameServerFedManager::FindPartsData GameServerFedManager::FindPartsDataForPart(GSClient* client, hash_t partId) const
{
	FindPartsData ret;
	
	ret.weaponClass = m_weaponsData->GetFindPartsWeaponClassForPart(partId);
	ret.battlepack = m_weaponsData->BattlepackForPart(partId);

	return ret;
}

////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ActivateRaidTicket(GSClient* client, hash_t partId, bool contract)
{
	auto muid = MissionUid();
	const char* weaponClass = nullptr;
	if (partId)
	{
		// --- raid to find parts
		auto fpData = FindPartsDataForPart(client, partId);

		// --- for find parts missions, the reward is not dependent on the mission, but on the highest unlocked chapter
		muid = MissionUid(client->m_seshatProfile->HighestUnlockedAccesableChapter(), 0, 0);
		weaponClass = fpData.weaponClass;
	}
	else if (contract)
	{
		// --- raid a contract mission
		muid.chapter = client->m_seshatProfile->GetRandomMissionParamsChapter();
		muid.block = GetAHMissionsData()->GetBlockIndex("Grind");
		muid.mission = client->m_seshatProfile->GetRandomMissionParamsMission();

		weaponClass = client->m_seshatProfile->GetRandomMissionParamsWeaponClass();
		if (!weaponClass)
		{
			MP_LOG(DBG_CRIT, "ActivateRaidTicket for contracts didn't find random weapon class from %s - defaulting to Sniper class", client->m_credential.c_str());
			weaponClass = "Sniper";
		}
	}

	auto weapon = client->m_seshatProfile->GetEquippedWeapon(weaponClass);
	if (!weapon)
	{
		MP_LOG(DBG_CRIT, "ActivateRaidTicket for unequipped weapon class %s mission %d,%d,%d from %s - defaulting to Sniper class", weaponClass, muid.chapter, muid.block, muid.mission, client->m_credential.c_str());
		weaponClass = "Sniper";
		weapon = client->m_seshatProfile->GetEquippedWeapon(weaponClass);
	}

	// --- give mission rewards
	// --- both find parts missions and find keys missions should use the special find parts rewards, not the actual mission rewards
	// --- contracts on the other hand will use the normal mission rewards
	auto useFindPartsMissionReward = !contract;
	if (weapon)
	{
		int64_t xp = 0, sc = 0;
		MissionCompletedRewards(client, muid, Hash(weapon), useFindPartsMissionReward, "", nullptr, &xp, &sc);

		client->GetHestiaConfig()->ChangeCreditBalance(client, SESHAT_LABEL_XP, xp);
		client->GetHestiaConfig()->ChangeCreditBalance(client, "sc", sc);
	}
	else
	{
		MP_LOG(DBG_CRIT, "ActivateRaidTicket for unequipped weapon class %s mission %d,%d,%d from %s - default weapon missing too", weaponClass, muid.chapter, muid.block, muid.mission, client->m_credential.c_str());
	}

	if (partId)
	{
		// --- drop weapon part
		DropMissionEndStuff(client, nullptr, partId, MissionDropChancesData());
	}
	else if (contract)
	{
		// --- mission end drops
		auto dropData = MissionDropChances(client, muid);

		// --- drop weapon parts
		DropMissionEndStuff(client, m_missionsData->GetMissionDropsOverride(muid), partId, dropData);

		// --- update random mission params
		auto updateRandomMissionParamsWeaponClass = true;
		m_missionsData->RegenerateRandomMissionParams(client->m_seshatProfile, updateRandomMissionParamsWeaponClass);

		// --- contribute to play contracts challenge
		client->m_seshatProfile->AddQuestProgress("play_contracts", 1);
	}
}

////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

MissionDropChancesData GameServerFedManager::MissionDropChances(GSClient* client, MissionUid muid, const std::string& eventId) const
{
	MissionDropChancesData dropData;
	if (muid.block == m_missionsData->GetBlockIndex("Event"))
	{
		auto coopEvent = client->FindEvent(eventId);
		if (coopEvent)
		{
			int progress = client->m_seshatProfile->GetEventProgress(coopEvent->GetID());
			auto eventData = m_eventsData->GetCoopEventData(coopEvent->GetPreset());
			dropData.coopMissionDropChances = eventData.MissionDropChances(progress);
			dropData.collectorDrops = eventData.CollectorDrops(progress);
			dropData.collectorFactor = eventData.CollectorFactor(progress);

			// --- Maria's mighty hack - first time the mission 3 from chapter 1 is played in the coop event, make sure the collector parts drops drop
			auto maxProgress = client->m_seshatProfile->GetEventMaxProgress(coopEvent->GetID());
			bool ensureDrops = (progress == 2) && (maxProgress == 2);
			if (ensureDrops)
			{
				static Json::Value collectorDropsOverride;
				collectorDropsOverride = *dropData.collectorDrops;
				for (auto& drop : collectorDropsOverride)
					drop = 4; // --- Drop_highest
				dropData.collectorDrops = &collectorDropsOverride;
			}

			// --- also add the guaranteed rewards (used to be first time guaranteed rewards...)
			auto firstTime = true; // (progress == maxProgress);
			dropData.guaranteedDrops = firstTime ? eventData.MissionUnlockReward(progress) : nullptr;

			return dropData;
		}
		else
		{
			MP_LOG(DBG_CRIT, "Asking for mission drop chances for Event type mission without active coop event for client %s - defaulting to chances from Missions", client->m_credential.c_str());
		}
	}
	else if (!eventId.empty())
	{
		auto missionEvent = client->FindEvent(eventId);
		if (missionEvent && missionEvent->IsBounty())
		{
			auto bountyEvent = missionEvent;
			auto eventData = m_eventsData->GetBountyEventData(bountyEvent->GetPreset());
			auto chapterMissionCount = eventData.ChapterData(0).MissionCount();
			int progress = client->m_seshatProfile->GetEventProgress(bountyEvent->GetID());
			auto ci = progress / chapterMissionCount;
			auto mi = progress % chapterMissionCount;

			// --- bounty also add some extraData in dropData that should contain for_event, the chapter and maybe mission index
			dropData.extraData["for_event"] = bountyEvent->GetID();
			dropData.extraData["chapter"] = ci;
			dropData.extraData["mission"] = mi;

			if (muid.block == m_missionsData->GetBlockIndex("Multiplayer"))
			{
				// --- bounty - boss attack rewards - first time kill if not rewarded, otherwise secondary rewards
				dropData.guaranteedDrops = client->m_seshatProfile->GetBountyBossReward(bountyEvent->GetID(), ci);

				// --- data about the new rank - added here to it makes its way onto the rewards screen as a card :-/
				if (client->m_seshatProfile->GetBountyBossKillCount(bountyEvent->GetID(), ci) <= 0)
				{
					auto& bountyRankData = dropData.extraData["append_inv_changes"]["_bounty_rank"];
					bountyRankData["rank"] = ci + 1; // --- 0 is unranked, 1 onwards are icons
				}

				return dropData;
			}
			else
			{
				// --- bounty - regular event mission rewards
				auto eventData = m_eventsData->GetBountyEventData(bountyEvent->GetPreset());
				auto chapterMissionCount = eventData.ChapterData(0).MissionCount();
				int progress = client->m_seshatProfile->GetEventProgress(bountyEvent->GetID());
				auto ci = progress / chapterMissionCount;
				auto mi = progress % chapterMissionCount;

				const auto& bountyMissionData = eventData.ChapterData(ci).MissionData(mi);
				dropData.bountyMissionDrops = bountyMissionData.Drops();

				// --- also add the first time completed (unlock next) rewards if not marked as already rewarded
				auto addGuaranteedDrops = !client->m_seshatProfile->GetBountyMissionRewarded(bountyEvent->GetID(), ci, mi);
				if (addGuaranteedDrops)
				{
					dropData.guaranteedDrops = bountyMissionData.UnlockReward();
				}

				return dropData;
			}
		}
		else if (missionEvent && missionEvent->IsMiniops())
		{
			// --- for minops pve mission, give the rewards from highest unlocked grind missions
			if (muid.block != m_missionsData->GetBlockIndex("Multiplayer"))
			{
				muid.block = m_missionsData->GetBlockIndex("Grind"); // --- chapter will be set to highest unlocked below
			}
		}
	}

	// --- for series missions, in case we're replaying old chapters, use the rewards from the highest chapter's grind missions
	if (muid.chapter < client->m_seshatProfile->ReplayUntilChapter() && m_missionsData->BlockIsSeries(muid.block))
	{
		muid.block = m_missionsData->GetBlockIndex("Grind"); // --- chapter will be set to highest unlocked below
		muid.mission = 0;
	}

	// --- default - return drop chances from missions
	// --- for grind and exotic missions (including find parts missions) use the reward from the highest unlocked chapter
	if (muid.block == m_missionsData->GetBlockIndex("Grind") || muid.block == m_missionsData->GetBlockIndex("Exotic"))
	{
		muid.chapter = client->m_seshatProfile->HighestUnlockedAccesableChapter();
	}

	dropData.missionDropChances = m_missionsData->GetMissionDropChances(muid);

	if (eventId.empty())
		dropData.guaranteedDrops = m_missionsData->GetMissionGuaranteedDrop(muid);

	return dropData;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::DropMissionEndStuff(GSClient* client, const Json::Value* dropPartsOverride, StringHash findPartsMissionPart, const MissionDropChancesData& dropData) const
{
	auto DropStuff = [client, &dropData](const char* id, int64_t qty)
	{
		// --- TODO: maybe do this for each item if qty > 1 ?
		auto gachaData = GameServerFedManager::Instance()->GetGachaData();
		if (!gachaData->ValidateCreditForGacha(client, StringHash(), 1, id))
			return false;

		return gachaData->GiveStuff(client, id, qty, nullptr, dropData.extraData);
	};

	// --- append any inventory changes from extraData
	const auto& appendInvChanges = dropData.extraData["append_inv_changes"];
	if (appendInvChanges.type() == Json::objectValue && !appendInvChanges.empty())
	{
		for (auto it = appendInvChanges.begin(), ite = appendInvChanges.end(); it != ite; ++it)
			client->m_seshatProfile->AppendInventoryChanges(it.memberName(), *it);
	}

	// --- if I'm at the end of a find parts mission, that has priority
	if (findPartsMissionPart != 0)
	{
		auto& rng = client->m_seshatProfile->GetRandomEngine(ERandomEngine::ER_FIND_PARTS_DROP);
		double chance = GetAHWeaponsData()->FindPartsDropChance(client, findPartsMissionPart);
		std::bernoulli_distribution d(chance);
		bool drop = d(rng);
		if (!drop)
			return false;

		auto credit = client->GetHestiaConfig()->FindCredit(findPartsMissionPart);
		if (!credit)
			return false;

		return DropStuff(credit->name.c_str(), 1);
	}

	// --- otherwise the drop parts overrides have priority
	if (dropPartsOverride)
	{
		for (const auto& dropPartsEntry : *dropPartsOverride)
		{
			const char* part = dropPartsEntry["Type"].asCString();
			int count = dropPartsEntry["Count"].asInt();
			DropStuff(part, count);
		}
		return true;
	}

	// --- guaranteed drops
	auto guaranteedDrops = dropData.guaranteedDrops;
	if (guaranteedDrops && guaranteedDrops->isArray() && !guaranteedDrops->isNull())
	{
		// --- apply bonus from badges & max qty rules
		auto chapter = dropData.extraData["chapter"].asInt();
		auto forEvent = dropData.extraData["for_event"].asString();
		auto bountyEvent = client->FindEvent(forEvent);

		for (const auto& drop : *guaranteedDrops)
		{
			auto credit = drop["id"].asCString();
			auto qty = drop["qty"].asInt64();

			if (bountyEvent && bountyEvent->IsBounty())
				ApplyBountyRewardRules(client, forEvent, chapter, StringHash(credit), &qty);

			DropStuff(credit, qty);
		}
	}

	bool ret = false;

	// --- collector craft part drops
	auto collectorDrops = dropData.collectorDrops;
	if (collectorDrops && collectorDrops->isObject() && !collectorDrops->isNull())
	{
		for (auto jit = collectorDrops->begin(); jit != collectorDrops->end(); ++jit)
		{
			int dropTierIdx = (*jit).asInt();
			bool drop = client->GetHestiaConfig()->CheckCollectorDrop(client, ERandomEngine::ER_COLLECTOR_PARTS, dropTierIdx, jit.memberName(), dropData.collectorFactor);
			if (drop)
			{
				std::string part{ jit.memberName() };
				part.append("_Collector");
				ret |= DropStuff(part.c_str(), 1);
			}
		}
	}

	// --- coop mission drop chances
	auto coopMissionDropChances = dropData.coopMissionDropChances;
	if (coopMissionDropChances && coopMissionDropChances->isObject() && !coopMissionDropChances->empty())
	{
		// --- collect the rewards and their drop tier, then roll for each
		for (auto dtit = coopMissionDropChances->begin(), dtite = coopMissionDropChances->end(); dtit != dtite; ++dtit)
		{
			auto dropTierHash = StringHash(dtit.memberName());
			for (const auto& jDrop : *dtit)
			{
				auto randomTierHash = StringHash(client->GetHestiaConfig()->MissionDropRandomTier(client));
				if (randomTierHash == dropTierHash)
				{
					DropStuff(jDrop.asCString(), 1);
				}
			}
		}
	}

	// --- bounty mission drops
	auto bountyMissionDrops = dropData.bountyMissionDrops;
	if (bountyMissionDrops && bountyMissionDrops->isArray() && !bountyMissionDrops->empty())
	{
		// --- apply bonus from badges & max qty rules
		auto chapter = dropData.extraData["chapter"].asInt();
		auto forEvent = dropData.extraData["for_event"].asString();

		// --- collect of rewards and their drop tier, then roll for each
		for (const auto& bountyDropData : *bountyMissionDrops)
		{
			double chance = bountyDropData["chance"].asInt() * 0.01;
			auto& rng = client->m_seshatProfile->GetRandomEngine(ERandomEngine::ER_BOUNTY_DROPS);

			std::bernoulli_distribution d(chance);
			bool drop = d(rng);
			if (!drop)
				continue;

			auto credit = bountyDropData["id"].asCString();
			auto qty = bountyDropData["qty"].asInt64();
			
			ApplyBountyRewardRules(client, forEvent, chapter, StringHash(credit), &qty);

			DropStuff(credit, qty);
		}
	}

	// --- normal drop parts rules
	auto missionDropChances = dropData.missionDropChances;
	if (missionDropChances && missionDropChances->isObject() && !missionDropChances->isNull())
	{
		const char* tier = client->GetHestiaConfig()->MissionDropRandomTier(client);
		const auto& dropId = (*missionDropChances)[tier].asCString();
		if (dropId)
		{
			return DropStuff(dropId, 1) || ret;
		}
	}

	return ret;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::DropClanKeys(GSClient* client, const Json::Value* drops, double dropsFactor)
{
	if (!drops || !drops->isObject() || drops->isNull())
		return;

	auto credit = client->GetHestiaConfig()->FindCredit(StringHash((*drops)["id"].asString().c_str()));
	if (!credit)
		return; // --- TODO: log
	int qty = (*drops)["qty"].asInt();
	client->GetHestiaConfig()->ChangeCreditBalance(client, credit, qty);
	client->m_seshatProfile->AddQuestProgress("find_daily_key", qty);
	client->m_eventShard->IncreaseQuestProgression(SESHAT_LABEL_EVENT_SHARD_QUEST_CLAN_COLLECT_DOGTAG, qty);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::GiveEndMissionPvpPacksLogic(GSClient* client, bool doubleReward)
{
	auto bronze_pack_stock = client->GetHestiaConfig()->FindCredit("pvp_bronze_pack_stock");
	auto bp_stock = client->GetHestiaConfig()->GetCreditBalance(client, bronze_pack_stock);
	auto bpStock_max_qty = bronze_pack_stock->max_qty(client);
	if (bp_stock < bpStock_max_qty)
	{
		auto bronze_pack = client->GetHestiaConfig()->FindCredit("pvp_bronze_pack");
		auto bpQty = client->GetHestiaConfig()->GetCreditBalance(client, bronze_pack);
		
		auto offer = client->GetHestiaConfig()->FindOffer("pvp_bronze_pack_convert");
		auto variablePrice = offer ? client->GetHestiaConfig()->ComputeVariablePrice(client, offer->prices, *offer, 1, Json::Value::null) : HestiaConfig::OfferPricesT();
		// if the offer is not found consider it's a 4 to 1 conversion
		const auto qtyBronzeConvert = !variablePrice.empty() ? variablePrice.front().qty : 4;
		if (bpQty < qtyBronzeConvert)
		{
			//jackpot -qty = 2*reward -> overflow
			const auto& opponent_data = client->m_seshatProfile->GetOpponentByType(client->m_seshatProfile->GetCurrentOpponentMode());
			int64_t pvpPackNb = doubleReward ? 2 : 1;
			if (!opponent_data.isNull() && !opponent_data["pvp_bronze_pack_nb"].isNull())
				pvpPackNb = opponent_data["pvp_bronze_pack_nb"].asInt();

			GetGachaData()->GiveStuff(client, "pvp_bronze_pack", pvpPackNb); //send a pvp_bronze_pack for each pvp win
			if (bp_stock + pvpPackNb > bpStock_max_qty)
				pvpPackNb = bpStock_max_qty - bp_stock;
			client->GetHestiaConfig()->ChangeCreditBalance(client, bronze_pack_stock, pvpPackNb);

			if (bp_stock + pvpPackNb == bpStock_max_qty)
			{
				auto offerId = StringHash("pvp_bronze_pack_restock");
				Json::Value extraData;
				extraData["track_changes"] = false; // add this delayed_transaction on end_mission
				client->GetHestiaConfig()->ProcessTransaction(client, offerId, extraData);

			}
		}
	}
	else
	{

		auto offerId = StringHash("pvp_bronze_pack_restock");
		auto offer = client->GetHestiaConfig()->FindOffer(offerId);
		if (offer)
		{
			auto transactions = client->m_seshatProfile->FindDelayedTransactionsForOffer(offer->name);
			auto it2 = std::max_element(transactions.begin(), transactions.end(), [](const Json::Value& p1, const Json::Value& p2) { return p1["expiry"].asTimeT() < p2["expiry"].asTimeT(); });
			if (it2 != transactions.end())
			{
				//time_t now = GameServerFedManager::Instance()->GetLocalTime();
				//time_t expiry = (*it2)["expiry"].asTimeT();

				Json::Value bronzePackTimer = Json::objectValue;
				bronzePackTimer["credit"] = "pvp_bronze_pack";
				bronzePackTimer["category"] = "pvp_gacha";
				
				client->m_seshatProfile->AppendInventoryChanges("_pvp_bronze_pack", bronzePackTimer);
			}
		}
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::GiveEndMissionArenaTokens(GSClient* client, bool doubleReward)
{
	int64_t tokens = 0;
	if (!client->m_seshatProfile->TutorialCompleted("tutorial_ArenaGameplay"))
	{
		auto bpOffer = client->GetHestiaConfig()->FindOffer("ar_pack_alpha");
		if (bpOffer && !bpOffer->prices.empty() && bpOffer->prices.front().credit == "arena_token")
		{
			tokens = bpOffer->prices.front().qty;
		}
		else
		{
			MP_LOG(DBG_CRIT, "GameServerFedManager: GiveEndMissionArenaTokens - could not find tutorial arena token reward in ar_pack_alpha offer\n");
			tokens = 500;
		}
	}
	else
	{
		tokens = GetPvpData()->RankTokens(client->m_seshatProfile->GetMPTier(), client->m_seshatProfile->GetMPCurrentRank() - 1);
		if (doubleReward)
			tokens *= 2;
	}
	if (tokens > 0)
		client->GetHestiaConfig()->ChangeCreditBalance(client, "arena_token", tokens);
}

