void GameServerFedManager::SetClientFedId(GSClient* client, const std::string& fedid)
{
	client->SetFedId(fedid);
	m_gsClientsListByFedCredential[client->m_fedCredential] = client;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::OnRemoveClient(GSClient* client, const std::string& credential)
{
	if (!client->m_mpAnubisRoom.isNull())
	{
		// MMServer matchmaking can be canceled only if we are not in a room already
		if (client->m_mpAnubisRoom.empty())
			HandleMMDisconnect(client, mmserver::RequestDisconnectReason::MatchmakingCanceled, 11);
	}
	m_clanServerManager->OnRemoveClient(client);
	//save to seshat!
	ScriptSetSeshatProfile(credential, client);
	FlushHappyHourCounter();

	SetIAPPendingRequest(client, false);
	QueueIAPPendingRequests(client, -1, false);	// --- this will remove its entry
	
	if (client->m_trainerClan)
	{
		client->m_trainerClan->refresh_loadout(client);
	}

	if (client->mp_connection)
	{
		// --- TODO: start the flow
		SendDisconnectRequestToMP(client, mpserver::RequestDisconnectReason::PlayerLostAHConnection);
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::OnInitialDataRequestsComplete(GSClient* client)
{
	client->m_seshatProfile->NormalizeInventory();

	// --- check old subscriptions before checking IAP, to update them before buying a new one
	client->m_seshatProfile->CheckSubscriptionDaily(StringHash());

	// --- check for ecomm modifications (IAPs)
	m_hestiaConfigManager->UpdateInventoryFromIAP(client);

	client->m_seshatProfile->ProcessIncomingAttacks(true);

	// --- make sure the mission marked as unlocked by default are unlocked in the profile
	m_missionsData->ProcessDefaultUnlocks(client->m_seshatProfile);

	// --- make sure the weapons marked as owned / equipped by default are marked accordingly in the profile
	m_weaponsData->ProcessDefaultUnlocks(client);

	// --- perform any clan related operations after login
	PostLoginClanOperations(client);

	client->GetHestiaConfig()->ProcessDailySubscriptions(client);

	ServerSendProfileToPlayer(client->m_credential, client->m_seshatProfile);

	// --- log how long it took from the client sent the settings message to when we have all the mandatory data sent
	MP_LOG(DBG_WARN, "GameServerFedManager: OnInitialDataRequestsComplete time from init settings for client %s : %.2f sec\n",
		client->m_credential.c_str(), (OS_GetTime() - client->m_initSettingsReceiveTime) * 0.001f);

	client->m_seshatProfile->FindNextOpponents();
	ServerSendClanCommand(client, ClanCommand::ServerSendEnableClans, CLANS_ENABLED);
	SetIAPPendingRequest(client, false);
	ServerSendConquestCommand(client, ConquestCommand::UpdateTakeBackKey, client->m_seshatProfile->GetProfile()[SESHAT_LABEL_CONQUEST_OUTPOSTS_BASES][SESHAT_LABEL_CONQUEST_OUTPOSTS_TAKE_BACK]);

	if (client->FeatureUnlocked("outposts_unlocked"))
	{
		client->m_sendConquestUpdates = EConquestUpdatesState::Once;
		client->m_multiplayer->MarkAllOutpostsDirty();
		client->m_multiplayer->UpdateConquestStatus();
	}

	m_eloLadder->refresh_for_client(client);

	CheckComingSoonBattlepacks(client);

	ServerUpdateFirebaseFriends(client);

	DefenderLeaderboard::Get()->RefreshLeaderboardForClient(client, Defender_Request_Score_type::DEFENDER_REQUEST_SCORE_HOF);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::CheckComingSoonBattlepacks(GSClient* client)
{
	Json::Value coming_soon;
	auto& jItem = coming_soon["_coming_soon"] = Json::Value::null;

	mcfwutil::fsmap<std::string, std::vector<StringHash>> map;
	auto offers = client->GetHestiaConfig()->FindCreditsInCategory(StringHash(client->GetHestiaConfig()->GlobalParameters().get("battlepack_offer_category", "gacha_aux").asCString()));
	for (auto offerId : offers)
	{
		auto offer = client->GetHestiaConfig()->FindOffer(offerId);
		if (!offer)
			continue;

		if (offer->hidden)
			continue;

		if (offer->prices.empty())
			continue;

		auto it = std::find_if(offer->items.begin(), offer->items.end(), [client](const OfferItem& item)
		{
			if (item.qty == 0)
				return false;

			auto credit = client->GetHestiaConfig()->FindCredit(StringHash(item.credit.c_str()));
			return credit != nullptr;
		});
		if (it != offer->items.end())
			map[it->credit].push_back(offerId);
	}

	for (const auto& pack : client->GetHestiaConfig()->GetIapGachaPacks())
		map[pack];

	bool searchSm = client->m_seshatProfile->GetSquadmatesCount() < MAX_SQUADMATES_TO_REDIRECT;
	client->m_packsWithItemsInCategory.clear();
	for (const auto& item : map)
	{
		StringHash pack(item.first.c_str());
		if ((pack == StringHash("gear_pack") ||
			pack == StringHash("pandora_pack_1") ||
			pack == StringHash("pandora_pack_2") ||
			pack == StringHash("pandora_pack_3") ||
			pack == StringHash("ultra_master_pack")) &&
			!GetGachaData()->ValidateAllColumns(client, pack))
		{
			for (auto v : item.second)
				jItem.append(v.GetHash());
		}
		else if (searchSm && GetGachaData()->FindPackIf(client, pack, [client, this](const char* id, int qty) { return CheckInCategory(client, StringHash("player_card"), id, qty); }))
		{
			client->m_packsWithItemsInCategory["player_card"].push_back(item.first);
		}
	}

	client->m_packsWithItemsInCategory["commander_part"] = { "commander_premium_pack", "commander_std_pack" };

	// --- TODO: for tests only
	client->m_packsWithItemsInCategory["bullet"] = { "bronze_pack" };
	client->m_packsWithItemsInCategory["so_boost"] = { "bronze_pack" };
	client->m_packsWithItemsInCategory["pvp_boost"] = { "bronze_pack" };
	client->m_packsWithItemsInCategory["player_card_part"] = { "bronze_pack" };

	auto& packsWithItems = coming_soon["_gacha_redirect"];
	for (const auto& entry : client->m_packsWithItemsInCategory)
	{
		if (!entry.second.empty())
			packsWithItems[entry.first] = true;
	}
	ServerSendInventoryUpdate(client, "_coming_soon", std::move(coming_soon));
}

