bool GameServerFedManager::ServerSendLevelFileToClient(const std::string &credential, bool fileFound, const char* data, const int size)
{
#if defined REQUEST_LEVEL_FILE_FROM_AH_SERVER && REQUEST_LEVEL_FILE_FROM_AH_SERVER
	NetworkMessageW levelFilePacket;
    
	if (fileFound && (size > 0))
	{
		int lvlSize = size;
		if (lvlSize > (GetRecvBufferSize() - 2))
			ResizeBuffers(lvlSize + 2);

		// do not try to compress, the files are already LZMA compressed
		// keep the code though if this might be needed later
		//int compressedSize = LZ4_compressHC((char*)data, (char*)m_tempBuffer, lvlSize);	
		//if ((compressedSize <= 0) || (compressedSize >= lvlSize))
		{
			// the compression failed so we add the normal message
			levelFilePacket.addGameMessageType(TCPMSG_SERVER_SEND_LVLFILE);
			levelFilePacket.addBytesAndLen((const byte*)data, lvlSize);
			MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendLevelFileToClient found = %d, size %d\n", fileFound, size);
		}
		//else
		//{
		//	// the compression worked so we add the compressed message
		//	levelFilePacket.addGameMessageType(TCPMSG_SERVER_SEND_LVLFILE_COMPRESSED);
		//	levelFilePacket.addBytesAndLen(m_tempBuffer, compressedSize);
		//	MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendLevelFileToClient (compressed) found = %d, size %d\n", fileFound, compressedSize);
		//}
	}
	else
	{
		MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendLevelFileToClient not found.\n");
		levelFilePacket.addGameMessageType(TCPMSG_SERVER_SEND_LVLFILE);
		levelFilePacket.addUInt(0);
	}

	levelFilePacket.packMessage(GetClient(credential)->m_Crypto);

	if(levelFilePacket.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendLevelFileToClient packet memory overflow\n");
	}

    bool bResult = m_fedComms->SendMessageToCredential(credential, (char*) levelFilePacket.getMessageBody(), levelFilePacket.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendLevelFileToClient send message failed\n");
		return false;
	}

#else	// !REQUEST_LEVEL_FILE_FROM_AH_SERVER
	(void)credential;
	(void)fileFound;
	(void)data;
	(void)size;
#endif	// !REQUEST_LEVEL_FILE_FROM_AH_SERVER
	return true;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::AddServerFile(const char* fileId, const std::string& data)
{
	auto& serverFile = m_serverFiles[Hash(fileId)];

	// --- ensure enough for compression
	int maxSize = LZ4_compressBound((int)data.size());
	serverFile.data.resize(maxSize);
	serverFile.uncompressedSize = data.size();

	// --- compress
	int compressedSize = LZ4_compressHC(&data[0], &serverFile.data[0], (int)data.size());
	if (!compressedSize)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager::AddServerFile error compressing server file %s - sending uncompressed data\n", fileId);

		serverFile.data = data;
		compressedSize = (int)data.size();
	}

	// --- check we'll be able to send to client
	if (compressedSize > GetRecvBufferSize() - 2)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager::AddServerFile compressed size of %s is beyond message buffer size!\n", fileId);
		ResizeBuffers(compressedSize + 2);
	}

	// --- release unused data
	serverFile.data.resize(compressedSize);
	serverFile.data.shrink_to_fit();

	// --- compute the hash of the data
	serverFile.hash = HashData(&serverFile.data[0], serverFile.data.size());
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendServerFileToClient(const std::string &credential, hash_t serverFileId, hash_t clientDataHash)
{
	const auto& serverFile = m_serverFiles[serverFileId];

	NetworkMessageW serverFilePacket;

	if (!serverFile.data.empty() && serverFile.hash != clientDataHash)
	{
		int dataSize = (int)serverFile.data.size();
		if (dataSize > (GetRecvBufferSize() - 2))
		{
			ResizeBuffers(dataSize + 2);
			MP_LOG(DBG_CRIT, "GameServerFedManager::ServerSendServerFileToClient rresized buffer size for file %u\n", serverFileId);
		}

		bool compressed = serverFile.data.size() != serverFile.uncompressedSize;
		auto messageType = compressed ? TCPMSG_SERVER_SEND_SERVERFILE_COMPRESSED : TCPMSG_SERVER_SEND_SERVERFILE;

		serverFilePacket.addGameMessageType(messageType);
		serverFilePacket.addUInt(serverFileId);
		serverFilePacket.addUInt(serverFile.hash);
		serverFilePacket.addInt((int)serverFile.uncompressedSize);
		serverFilePacket.addBytesAndLen((const byte*)(&serverFile.data[0]), dataSize);
		MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendServerFileToClient size %d\n", dataSize);
	}
	else
	{
		MP_LOG(DBG_INFO, "GameServerFedManager::ServerSendServerFileToClient error - no serverfile for id %u.\n", serverFileId);
		serverFilePacket.addGameMessageType(TCPMSG_SERVER_SEND_SERVERFILE);
		serverFilePacket.addUInt(serverFileId);
		serverFilePacket.addUInt(clientDataHash);
		serverFilePacket.addInt(0);
	}

	serverFilePacket.packMessage(GetClient(credential)->m_Crypto);

	if (serverFilePacket.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendWeaponsFileToClient packet memory overflow\n");
	}

	bool bResult = m_fedComms->SendMessageToCredential(credential, (char*)serverFilePacket.getMessageBody(), serverFilePacket.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendWeaponsFileToClient send message failed\n");
		return false;
	}

	return true;
}


//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendArmoryFileToClient(const std::string &credential, const char* data, const int size)
{
	NetworkMessageW armoryFilePacket;

	if (data && (size > 0))
	{
		int armorySize = size;
		if (armorySize > (GetRecvBufferSize() - 2))
			ResizeBuffers(armorySize + 2);

		{
			armoryFilePacket.addGameMessageType(TCPMSG_SERVER_SEND_ARMORYFILE);
			armoryFilePacket.addBytesAndLen((const byte*)data, armorySize);
			MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendArmoryFileToClient size %d\n", size);
		}
	}
	else
	{
		MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendArmoryFileToClient - no armory sent!.\n");
		armoryFilePacket.addGameMessageType(TCPMSG_SERVER_SEND_ARMORYFILE);
		armoryFilePacket.addUInt(0);
	}

	armoryFilePacket.packMessage(GetClient(credential)->m_Crypto);

	if(armoryFilePacket.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendArmoryFileToClient packet memory overflow\n");
	}

	bool bResult = m_fedComms->SendMessageToCredential(credential, (char*) armoryFilePacket.getMessageBody(), armoryFilePacket.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendArmoryFileToClient send message failed\n");
		return false;
	}

	return true;
}

