bool GameServerFedManager::ServerSendListConnectionToPlayer(const std::string& credential, const char* listConnectionsJson)
{
	NetworkMessageW listConnectionsData;

	
	listConnectionsData.addGameMessageType(TCPMSG_SERVER_SEND_FRIENDS_LIST_GIFT);
	listConnectionsData.addString((const unsigned char*)listConnectionsJson);


	listConnectionsData.packMessage(GetClient(credential)->m_Crypto);

	if (listConnectionsData.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerRequestListConnection packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(credential, (char*)listConnectionsData.getMessageBody(), listConnectionsData.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerRequestListConnection send message failed\n");
		return false;
	}

	return true;
}

