void GameServerFedManager::ServerUpdateFirebaseFriends(GSClient* client)
{
	auto alias_list = client->m_seshatProfile->GetFriendAliasList();
	for (auto it = alias_list->begin(), ite = alias_list->end(); it != ite; ++it)
	{
		auto& entry = (*it);
		auto count = entry.asInt();
		auto alias = it.memberName();
		if (count)
		{
			if (CheckAlias(alias) && client->m_seshatProfile->SetFriendAliasInList(alias))
			{
				MP_LOG(DBG_INFO, "ServerUpdateFirebaseFriends start add_connection friend alias is %s nb_tries %d\n", alias, count);
				ScriptRequestGetCredentialFromAlias(client, alias);
			}
		}
		else
		{
			client->m_seshatProfile->DeleteFriendAliasInList(alias);//no more tries
		}
	}
}
