bool GameServerFedManager::UpdateUserStatusLineLevel(std::string &statusLine, int player_level, int player_prestige_level)
{

	char stLine[255];
	strcpy(stLine, statusLine.c_str());
	sprintf(stLine, "%c", 'y');
	sprintf(stLine + 1, "%2d", player_level);
	sprintf(stLine + 3, "%3d", player_prestige_level);
	//sprintf(stLine + 1 + HISTORY_DAY_NB * 2, "%d", player_level);
	statusLine.assign(stLine);
	return true;

}

