bool GameServerFedManager::ServerSendTimeHackDetected(const std::string& credential)
{
	NetworkMessageW timeHackDetected;
    timeHackDetected.addGameMessageType(TCPMSG_SERVER_SEND_TIME_HACK_DETECTED);

	timeHackDetected.packMessage(GetClient(credential)->m_Crypto);

	if(timeHackDetected.isPacketError())
	{
		MP_LOG(DBG_CRIT, "ServerSendTimeHackDetected packet memory overflow\n");
	}

    bool bResult = ServerSendMessage(credential, (char*) timeHackDetected.getMessageBody(), timeHackDetected.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "ServerSendTimeHackDetected send message failed\n");
		return false;
	}

	return true;
}

