bool GameServerFedManager::ServerSendFoundOpponent(const std::string& credential, const Json::Value& json)
{
	const std::string jsonStr = Json::FastWriter().write(json);

	NetworkMessageW rewardPacket;
    rewardPacket.addGameMessageType(TCPMSG_SERVER_FOUND_OPPONENT);

	rewardPacket.addString((unsigned char*)jsonStr.c_str());

	MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendFoundOpponent %s, reward %s\n", credential.c_str(), jsonStr.c_str());

	rewardPacket.packMessage(GetClient(credential)->m_Crypto);

	if(rewardPacket.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendFoundOpponent packet memory overflow\n");
	}

    bool bResult = m_fedComms->SendMessageToCredential(credential, (char*) rewardPacket.getMessageBody(), rewardPacket.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendFoundOpponent send message failed\n");
		return false;
	}

	return true;
}

