bool GameServerFedManager::LoadCompatibilityVersion()
{
	m_serverCompatibilityVersion = 0;

	glf::FileStream pFile;
	GSOpenFile(pFile, "compatibility_version.txt");

	if(!pFile.IsOpened())
	{
		return false;
	}

	int fileSize = (int)pFile.GetSize();
	char* buffer = new char[fileSize+1];
	memset(buffer, 0, fileSize+1);

	pFile.Read(buffer, fileSize );

	m_serverCompatibilityVersion = atoi(buffer);
	MP_LOG(DBG_WARN, "Compatibility version %d\n", m_serverCompatibilityVersion);

	return true;
}

