void GameServerFedManager::StartGetingEloLadders(GSClient* client)
{
	if (!IsClientEloRanked(client))
		return;

	auto op = std::unique_ptr<LadderOperation>(new LadderOperation());
	op->owner_credential = client->m_credential;
	op->for_credential = client->m_credential;
	op->client_id = client->m_clientId;
	op->tier = client->m_seshatProfile->GetCachedPvpStats().GetLeague();
	op->cookie = (int)time(0);

	// --- tiered
	if (op->tier)
	{
		op->operation = ELO_GET_TIERED;
		ScriptGetEloLadder(std::unique_ptr<LadderOperation>(new LadderOperation(*op))); // --- copy op
	}

	// --- top
	//m_topLeaderboard.get_top(client);

	// --- top & hof
	m_eloLadder->refresh_for_client(client);
}

////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::StartGetingMPLadders(GSClient* client, bool getScore, bool getWins)
{
	if (!client->m_seshatProfile->IsMPRanked())
		return;

	if (getScore)
	{
		auto op = std::unique_ptr<LadderOperation>(new LadderOperation());
		op->owner_credential = client->m_credential;
		op->for_credential = client->m_credential;
		op->client_id = client->m_clientId;
		op->tier = client->m_seshatProfile->GetMPTier();
		op->cookie = (int)time(0);

		// --- tiered
		if (op->tier)
		{
			op->operation = ELO_GET_MP_TIERED;
			ScriptGetMPLadder(std::unique_ptr<LadderOperation>(new LadderOperation(*op))); // --- copy op
		}

		// --- mp top
		m_mpTop->refresh_for_client(client);
	}

	if (getWins)
	{
		// --- mp top arena
		m_mpArena->refresh_for_client(client);

		// --- also send last lb top 3
		RefreshMPTop3(client, GetLastLadderId());
	}
}

