void GameServerFedManager::StartGettingClansLeaderboard(std::unique_ptr<ClanOperation> operation, int refreshRequiredScore)
{
	// --- check for champions before std::move
	if (UpdateClansChampions())	// --- can send data to client
	{
		auto client = GetClient(operation->owner_credential);
		ServerSendClansLeaderboard(client, m_clansChampions.Data());
	}

	// --- check for current lb refresh
	auto refreshRequired = m_clansLeaderboard.IsOld() || m_clansLeaderboard.MinScore() < refreshRequiredScore;
	if (refreshRequired)
	{
		ScriptClansLeaderboard(std::move(operation));
	}
	else
	{
		// --- can use cached data 
		auto client = GetClient(operation->owner_credential);
		ServerSendClansLeaderboard(client, m_clansLeaderboard.Data());
	}
}

