void GameServerFedManager::UpdateClansLeaderboard()
{
	if (!m_clansLeaderboard.IsOld())
		return;

	if (m_clansLeaderboard.TimeUpdateStarted())
		return;

	if (m_gsClientsList.empty())
		return;

	// --- pick one with a valid client id
	GSClient* client = nullptr;
	auto it = m_gsClientsList.cbegin();
	while ((!client || client->m_clientId.empty()) && it != m_gsClientsList.end())
	{
		client = it->second;
		++it;
	}
	
	// --- no valid client found
	if (!client || client->m_clientId.empty())
		return;

	m_clansLeaderboard.SetTimeUpdateStarted(true);

	// --- start getting the data (TODO: don't start another one while this one is in progress)
	std::unique_ptr<ClanOperation> clanLeaderboardOp(new ClanOperation());
	clanLeaderboardOp->client_id = client->m_clientId;
	clanLeaderboardOp->for_credential = client->m_credential;
	clanLeaderboardOp->owner_credential = client->m_credential;
	clanLeaderboardOp->operation = ECO_CLANS_LEADERBOARD;
	clanLeaderboardOp->data["time_update"] = true;
	clanLeaderboardOp->data["lb_name"] = GetCurrentClanLb();
	clanLeaderboardOp->data["client_lb_name"] = GetCurrentClientClanLb();

	ScriptClansLeaderboard(std::move(clanLeaderboardOp));
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::UpdateClansChampions()
{
	if (m_clansChampions.TimeUpdateStarted())
		return false;

	if (m_gsClientsList.empty())
		return false;

	auto prevLadderId = GetLadderId(GetCurrentLadderStart() - 1);
	auto prevSeasonClansLb = GetClanLb(prevLadderId);
	auto prevClientSeasonClansLb = GetClientClanLb(prevLadderId);

	// --- already have previous season lb
	if (m_clansChampions.Data()["id"].asString() == prevSeasonClansLb)
		return true;

	// --- pick one with a valid client id
	GSClient* client = nullptr;
	auto it = m_gsClientsList.cbegin();
	while ((!client || client->m_clientId.empty()) && it != m_gsClientsList.end())
	{
		client = it->second;
		++it;
	}

	// --- no valid client found
	if (!client || client->m_clientId.empty())
		return false;

	m_clansChampions.SetTimeUpdateStarted(true);

	// --- start getting the data (TODO: don't start another one while this one is in progress)
	std::unique_ptr<ClanOperation> clanLeaderboardOp(new ClanOperation());
	clanLeaderboardOp->client_id = client->m_clientId;
	clanLeaderboardOp->for_credential = client->m_credential;
	clanLeaderboardOp->owner_credential = client->m_credential;
	clanLeaderboardOp->operation = ECO_CLANS_LEADERBOARD_OLD;
	clanLeaderboardOp->data["time_update"] = true;
	clanLeaderboardOp->data["limit"] = "3";
	clanLeaderboardOp->data["lb_name"] = prevSeasonClansLb;
	clanLeaderboardOp->data["client_lb_name"] = prevClientSeasonClansLb;

	ScriptClansLeaderboard(std::move(clanLeaderboardOp));

	return false;
}

