int GameServerFedManager::CheckIncWarCashCounter(GSClient* client, int fixed_amount)
{
	if (!client->m_clanData)
		return 0;

	const auto& war = client->m_clanData->war;
	if (war.phase() == War::Phase::Invasion
		&& war.member_can_participate
		&& client->m_clanData->neutronium_data.active())
	{
		return IncWarCashCounter(client, fixed_amount);
	}

	return 0;
}

////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

int GameServerFedManager::IncWarCashCounter(GSClient * client, int fixed_amount)
{
	const auto& clanData = client->m_seshatProfile->GetClanData();
	if (!clanData.isNull())
	{
		int amount = 0;
		if (fixed_amount)
			amount = fixed_amount;
		else
		{
			auto lvl = client->GetHestiaConfig()->GetCreditBalance(client, StringHash("clan_insignia"));
			StringHash perkId("war_cash");
			const auto &perKillRewards = GetMultiplayerData()->GetClanInsigniaData()[std::to_string(lvl)]["per_kill"];
			for (auto reward : perKillRewards)
			{
				if (perkId == StringHash(reward["type"].asCString()))
				{
					amount = reward["value"].asInt();
					break;
				}
			}
		}

		if (amount)
		{
			amount = (int)_round(amount * (1.0f + client->m_seshatProfile->GetCommanderBonusModifierByBonus("cmdr_bonus_clan_war_gain") * 0.01f));
			std::unique_ptr<ClanOperation> clanOp(new ClanOperation());
			clanOp->client_id = client->m_clientId;
			clanOp->for_credential = client->m_credential;
			clanOp->owner_credential = client->m_credential;
			clanOp->clan_data = client->m_clanData;
			clanOp->operation = ECO_INC_DEC_CLAN_WAR_CASH;
			clanOp->data["group_id"] = clanData[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID];
			clanOp->data["etag_for"] = CLAN_ETAG_FOR;
			clanOp->data["score"] = amount;

			ScriptClanIncWarCash(std::move(clanOp));

			m_clanServerManager->SendCBMemberStat(client->m_clanData->clan_id, client->GetFedId(), client->m_seshatProfile->GetDisplayName(), GetCurrentLadderId(), amount, "war_cash");
		}
		return amount;
	}
	return 0;
}

