bool GameServerFedManager::EventMissionValidParams::valid(const GSClient* client, const Json::Value& params) const
{
	if (params.isNull())
		return false;

	auto muid = MissionUid(params[SESHAT_LABEL_EVENT_MISSION_PARAMS_MUID].asUInt());
	auto weaponClass = params[SESHAT_LABEL_EVENT_MISSION_PARAMS_WCLASS].asCString();

	// --- if the weapon class is no longer valid, the params aren't valid
	auto weaponClassHash = StringHash(weaponClass);
	auto it = std::find_if(weaponClasses.begin(), weaponClasses.end(), [weaponClassHash](const char* weaponClass) { return StringHash(weaponClass) == weaponClassHash; });
	if (it == weaponClasses.end()) return false;

	if (!miniopsSetup)
	{
		// --- if the chapter is no longer available, regenerate
		if (muid.chapter > client->m_seshatProfile->HighestUnlockedAccesableChapter())
			return false;
	}
	else
	{
		// --- miniops setup

		auto missionsData = GameServerFedManager::Instance()->GetAHMissionsData();
		auto weaponsData = GameServerFedManager::Instance()->GetAHWeaponsData();

		auto weapon = client->m_seshatProfile->GetEquippedWeapon(weaponClass);
		auto weaponType = weaponsData->GetWeaponType(weapon);

		// --- check the weapon type matches the randomly chosen series mission
		if ((muid.block == missionsData->GetBlockIndex("Sniper")) !=
			(weaponType == StringHash("Sniper")))
			return false;
	}

	// --- if the chapter is no longer the region of the weapon equipped for that class, the params are no longer valid
	//auto weaponsData = GameServerFedManager::Instance()->GetAHWeaponsData();
	//auto missionsData = GameServerFedManager::Instance()->GetAHMissionsData();

	//int chapter = weaponsData->GetWeaponRegion(client, StringHash(client->m_seshatProfile->GetEquippedWeapon(weaponClass))) - 1;
	//chapter = std::max(chapter, 0);
	//while (missionsData->ChapterComingSoon(chapter) || !missionsData->ChapterVisible(chapter) || !client->m_seshatProfile->IsChapterUnlocked(chapter))
	//	--chapter;

	//return chapter == muid.chapter;

	return true;
}

