bool GameServerFedManager::EventRequiresMissionParams(const GSClient* client, const SemEvent& ev) const
{
	// --- only do this for non-unique events (except miniops), non-vip events
	if ((ev.IsUnique() && !ev.IsMiniops()) || ev.IsVip() || ev.IsTopUp() || ev.IsDismiss() || ev.IsDroneOps())
		return false;

	return true;
}

////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::EventConditionsMet(GSClient* client, const SemEvent& ev) const
{
	auto condition = ev.Condition();
	switch (condition.type)
	{
	case ParticipationCondition::None:
		return true;
	case ParticipationCondition::BaseLevel:
		return client->GetHestiaConfig()->GetCreditBalance(client, SESHAT_CREDIT_BASE_LEVEL) >= condition.value;
	case ParticipationCondition::SquadDefense:
		return client->m_seshatProfile->CurrentSquadDefense() >= condition.value;
	case ParticipationCondition::PlayerLevel:
		return client->GetHestiaConfig()->GetCreditBalance(client, SESHAT_LABEL_LEVEL) >= condition.value;
	case ParticipationCondition::RegionUnlocked:
		return client->m_seshatProfile->IsChapterUnlocked(m_missionsData->ChapterFromInternalName(condition.hash));
	case ParticipationCondition::WeaponClass:
	{
		auto weaponClass = m_weaponsData->WeaponClassIdToName(condition.hash);
		auto equippedWeapon = client->m_seshatProfile->GetEquippedWeapon(weaponClass);
		if (!equippedWeapon) return false; // --- no weapon equipped for the required class - condition not met
		if (!condition.value) return true; // --- has weapon of class equipped and no damage requirement - condition met
		return m_weaponsData->GetBuffedWeaponClassDamage(client, weaponClass, equippedWeapon) >= condition.value; // --- has enough damage?
	}
	case ParticipationCondition::WeaponType:
	{
		auto weaponClasses = m_weaponsData->WeaponTypeToClass(condition.hash);
		for (std::vector<const char *>::iterator it = weaponClasses.begin(), end = weaponClasses.end(); it != end; it++)
		{
			auto equippedWeapon = client->m_seshatProfile->GetEquippedWeapon(*it);
			if (!equippedWeapon) continue; // --- no weapon equipped for the required class - condition not met
			if (m_weaponsData->GetWeaponType(equippedWeapon) != condition.hash) continue; //recheck type
			if (!condition.value) return true; // --- has weapon of type equipped and no damage requirement - condition met
			bool power_cond = m_weaponsData->GetBuffedWeaponClassDamage(client, *it, equippedWeapon) >= condition.value; // --- has enough damage?
			if (!power_cond)
			{
				continue;
			}
			else
			{
				return true;
			}
		}
		return false;
	}
	case ParticipationCondition::Weapon:
	{
		auto weaponClass = m_weaponsData->GetWeaponClass(condition.hash);
		auto equippedWeapon = client->m_seshatProfile->GetEquippedWeapon(weaponClass);
		if (!equippedWeapon) return false; // --- no weapon equipped for the required class - condition not met
		if (StringHash(equippedWeapon) != condition.hash) return false; // --- weapon not equipped - not cool
		if (!condition.value) return true; // --- weapon equipped and no damage requirement - condition met
		auto weapon = m_weaponsData->WeaponIdToName(condition.hash);
		return m_weaponsData->GetBuffedWeaponClassDamage(client, weaponClass, weapon) >= condition.value; // --- has enough damage?
	}
	case ParticipationCondition::WeaponCamo:
	{
		const auto& equippedWeapons = client->m_seshatProfile->GetEquippedWeapons();
		for (auto mit = equippedWeapons.begin(); mit != equippedWeapons.end(); ++mit)
		{
			auto weapon = (*mit).asCString();
			const auto& camo = client->m_seshatProfile->GetWeaponCamo(weapon);
			if (!camo.isString())
				continue;
			if (StringHash(camo.asCString()) == condition.hash)
			{
				if (!condition.value)
					return true; // --- at least one equipped weapon has the required camo and there's not damage requirement
				auto weaponClass = mit.memberName();
				if (m_weaponsData->GetBuffedWeaponClassDamage(client, weaponClass, weapon) >= condition.value)
					return true; // --- there's a damage requirement and at least one weapon with the camo has it
			}
		}
		return false;
	}
	case ParticipationCondition::EloEvent:
	{
		return IsClientEloRanked(client);
	}
	case ParticipationCondition::InClan:
	{
		return !client->m_seshatProfile->GetClanData()[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID].asString().empty();
	}
	case ParticipationCondition::GearSet:// --- UNTESTED
	{
		auto mpData = GameServerFedManager::Instance()->GetMultiplayerData();
		const auto& equippedModules = client->m_seshatProfile->GetAvatarModules();
		const auto& modulesData = mpData->AvatarModulesData();
		const auto& moduleSets = mpData->AvatarModuleSetData();

		int setPieces = 0;
		auto equippedModulesNames = equippedModules.getMemberNames();
		for (const auto& module : equippedModules)
		{
			auto moduleId = module.asCString();
			auto moduleSet = modulesData[moduleId]["Set"].asCString();
			if (!moduleSet)
				continue;

			if (StringHash(moduleSet) == condition.hash)
			{
				++setPieces;

				const auto& setData = moduleSets[moduleSet];
				if (setPieces >= setData["pieces"].asInt())
					return true;
			}
		}
		return false;
	}
	}
	return false;
}

////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

GameServerFedManager::EventMissionValidParams GameServerFedManager::ValidParamsForEventMission(GSClient* client, const SemEvent& ev) const
{
	EventMissionValidParams ret;

	// --- determine initial valid weapon classes
	std::vector<const char*> weaponClasses{ "Assault", "Sniper", "Exotic", "Prototype" };
	StringHash weaponType(0);

	auto condition = ev.Condition();
	switch (condition.type)
	{
	case ParticipationCondition::None:
	case ParticipationCondition::BaseLevel:
	case ParticipationCondition::SquadDefense:
	case ParticipationCondition::PlayerLevel:
	case ParticipationCondition::RegionUnlocked:
	case ParticipationCondition::GearSet:
		// --- nothing to filter out - random from everything
		break;
	case ParticipationCondition::WeaponClass:
		weaponClasses = { m_weaponsData->WeaponClassIdToName(condition.hash) };
		break;
	case ParticipationCondition::WeaponType:
		weaponClasses = { m_weaponsData->WeaponTypeToClass(condition.hash) };
		weaponType = condition.hash;
		break;
	case ParticipationCondition::Weapon:
		weaponClasses = { m_weaponsData->GetWeaponClass(condition.hash) };
		break;
	case ParticipationCondition::WeaponCamo:
	{
		// --- add only weapon classes for which the currently equipped weapon has the required camo equipped
		weaponClasses.clear();
		const auto& equippedWeapons = client->m_seshatProfile->GetEquippedWeapons();
		for (auto mit = equippedWeapons.begin(); mit != equippedWeapons.end(); ++mit)
		{
			const auto& camo = client->m_seshatProfile->GetWeaponCamo((*mit).asCString());
			if (!camo.isString())
				continue;
			if (StringHash(camo.asCString()) == condition.hash)
				weaponClasses.push_back(mit.memberName());
		}
		break;
	}
	}

	// --- filter out weapon classes for which there's no equipped weapon (basically only Exotic and Prototype can be in this situation)
	weaponClasses.erase(
		std::remove_if(weaponClasses.begin(), weaponClasses.end(),
			[this, client, weaponType](const char* weaponClass)
				{
					auto equippedWeapon = client->m_seshatProfile->GetEquippedWeapon(weaponClass);
					if (equippedWeapon == nullptr) return true;
					// --- also check weaponType if set
					if (weaponType)
					{
						return GetAHWeaponsData()->GetWeaponType(equippedWeapon) != weaponType;
					}
					return false;
				}),
		weaponClasses.end());

	// --- for events with pvp objectives if the current pvp weapon class is within the valid weapon classes, leave only the pvp weapon class
	// --- also do this for miniops events, which use the pvp weapon class
	if ((ev.HasPvpObjective() || ev.IsMiniops()) && weaponClasses.size() > 1)
	{
		auto pvpWeaponClass = client->m_seshatProfile->GetPvpWeaponClass();
		if (pvpWeaponClass)
		{
			auto pvpWeaponClassHash = StringHash(pvpWeaponClass);
			auto it = std::find_if(weaponClasses.begin(), weaponClasses.end(), [pvpWeaponClassHash](const char* entry) { return StringHash(entry) == pvpWeaponClassHash; });
			if (it != weaponClasses.end())
			{
				weaponClasses.clear();
				weaponClasses.push_back(pvpWeaponClass);
			}
		}
	}

	// --- remove exotic class from enemy type events
	if (ev.HasEnemyTypeObjective())
	{
		weaponClasses.erase(
			std::remove_if(weaponClasses.begin(), weaponClasses.end(), [](const char* entry) { return StringHash(entry) == StringHash("Exotic"); }),
			weaponClasses.end());
	}

	// --- TEMP until we use the actual weapon type RPG - exclude exotic weapon class from headshot events
	if (ev.HasHeadshotObjective() && weaponClasses.size() > 1)
	{
		weaponClasses.erase(
			std::remove_if(weaponClasses.begin(), weaponClasses.end(), [](const char* entry) { return StringHash(entry) == StringHash("Exotic"); }),
			weaponClasses.end());
	}

	// --- if we have a choice of weapon classes and prototype is one if them, remove it
	// --- since the user doesn't have a choice of weapon (we make the choice on the server)
	// --- and she might not want to consume prototype charges
	// --- however, don't do this if prototype is the only weapon choice
	if (weaponClasses.size() > 1)
	{
		weaponClasses.erase(
			std::remove_if(weaponClasses.begin(), weaponClasses.end(), [](const char* entry) { return StringHash(entry) == StringHash("Prototype"); }),
			weaponClasses.end());
	}

	ret.weaponClasses = weaponClasses;
	ret.miniopsSetup = ev.IsMiniops();

	return ret;
}

////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

// --- event doesn't require mission params -> nothing to do
// --- check if event conditions are met
// --- if not -> make sure the mission params are null in the profile -> client won't be able to start event missions
// --- if yes -> make sure the mission params in profile are valid still in profile
// ---			- if yes -> nothing to do
// ---			- if no -> generate new valid parameters

bool GameServerFedManager::UpdateMissionParamsForEvent(GSClient* client, const SemEvent& ev)
{
	if (!EventRequiresMissionParams(client, ev))
	{
		// --- there was an error that generated mission params for events that didn't need them
		// --- correct that here
		return client->m_seshatProfile->SetEventMissionParams(ev.GetID(), MissionUid(), nullptr); // --- write null in profile
	}

	const auto& eventID = ev.GetID();
	auto eventConditionsMet = EventConditionsMet(client, ev);

	if (!eventConditionsMet)
	{
		// --- event conditions not met - no mission can be started
		return client->m_seshatProfile->SetEventMissionParams(eventID, MissionUid(), nullptr); // --- write null in profile
	}

	// --- conditions met - get current mission params and validate them
	auto validParams = ValidParamsForEventMission(client, ev);
	if (!validParams.valid())
	{
		// --- considering the event conditions are met, this shouldn't happen, but...
		MP_LOG(DBG_CRIT, "UpdateMissionParamsForEvent: Could not generate valid event mission params for client %s event %s\n", client->m_credential.c_str(), eventID.c_str());
		return client->m_seshatProfile->SetEventMissionParams(eventID, MissionUid(), nullptr); // --- write null in profile
	}

	const auto& currentParams = client->m_seshatProfile->GetEventMissionParams(eventID);
	if (validParams.valid(client, currentParams))
	{
		// --- the current params are ok - nothing to do
		return false;
	}

	// --- current params no longer valid - generate new ones

	// --- choose random weapon class
	auto weaponClass = validParams.weaponClasses.front();
	if (validParams.weaponClasses.size() > 1)
	{
		std::uniform_int_distribution<size_t> rnd(0, validParams.weaponClasses.size() - 1);
		weaponClass = validParams.weaponClasses[rnd(m_rng)];
	}

	// --- chapter is highest unlocked available
	int chapter = client->m_seshatProfile->HighestUnlockedAccesableChapter();
	
	// --- for miniops, the chapter is in the event data
	if (ev.IsMiniops())
	{
		auto eventData = GetAHEventsData()->GetMiniopsEventData(ev.GetPreset());
		chapter = GetAHMissionsData()->ChapterFromInternalName(eventData.Chapter());
	}
	
	// --- TODO: what about region conditions? do we force the region if the weapon region is higher than the condition region?
	// --- later TODO: now chapter is only used for the pvp mission, which should be the highest unlocked chapter anyway... so take this out

	// --- mission types pool based on event type and weapon class:
	// --- events with pvp objectives only have pvp missions
	// --- events with exotic weapon class only have exotic missions
	// --- otherwise they have series missions and grind missions
	MissionUid muid;
	if (ev.IsMiniops())
	{
		auto missionsData = GetAHMissionsData();
		auto weapon = client->m_seshatProfile->GetEquippedWeapon(weaponClass);
		auto weaponType = GetAHWeaponsData()->GetWeaponType(weapon);

		// --- Sniper missions for Sniper weapons, Assault for all others
		auto block = weaponType == StringHash("Sniper") ?
			missionsData->GetBlockIndex("Sniper") :
			missionsData->GetBlockIndex("Assault");

		auto missions = std::vector<int>(missionsData->GetChapterBlockMissionCount(chapter, block));
		std::iota(missions.begin(), missions.end(), 0);

		missions.erase(std::remove_if(missions.begin(), missions.end(), 
			[missionsData, chapter, block](int mission)
			{
				auto missionGenType = missionsData->GetMissionGenType({ chapter, block, mission });
				return missionGenType == 3 || // --- GeneratedMissionTypes.Protect
					missionGenType == 1 || // --- GeneratedMissionTypes.Defend
					missionGenType == 4; // --- GeneratedMissionTypes.Eliminate
			}), 
			missions.end());

		std::uniform_int_distribution<int> rnd(0, (int)missions.size() - 1);
		auto mission = missions[rnd(m_rng)];

		muid = { chapter, block, mission };
	}
	else if (ev.HasPvpObjective())
	{
		muid = { chapter, m_missionsData->GetBlockIndex("Multiplayer"), 0 };
	}
	else
	{
		if (ev.HasEnemyTypeObjective())
		{
			if (weaponClass != std::string("Assault") && weaponClass != std::string("Sniper"))
			{
				MP_LOG(DBG_CRIT, "GSFM::UpdateMissionParamsForEvent: weaponClass is not valid for enemy type mission (kinda impossible?) obj=%s cred=%s tags=%s\n", ev.GetObjective().c_str(), client->m_credential.c_str(), client->GetHestiaConfig()->Tags().c_str());
				muid = MissionUid(0, m_missionsData->GetBlockIndex("Assault"), 0);
			}

			muid = m_missionsData->RandomEnemyTypeMission(client, weaponClass, ev.EnemyType().c_str());
		}
		else
		{
			// --- TODO: we'll need new markers for which series missions are eligible
			std::vector<std::pair<const char*, int>> missionTypes;
			missionTypes.push_back({ weaponClass, 1 });
			if (StringHash(weaponClass) != StringHash("Exotic"))
			{
				missionTypes.push_back({ "Grind", 2 });
			}

			// --- generate random mission using the find parts rules, except also allow unlocked series missions from completed & inprogress chapters
			auto randomMissionType = ev.HasHeadshotObjective()
				? RandomFindPartsMissionType::AllWithHeadshots
				: RandomFindPartsMissionType::All;
			muid = m_missionsData->RandomFindPartsMission(client->m_seshatProfile, missionTypes, randomMissionType);
		}
	}

	// --- write the new parameters
	return client->m_seshatProfile->SetEventMissionParams(eventID, muid, weaponClass);
}

////////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UpdateEventsMissionParams(GSClient* client)
{
	Json::Value jDirtyEvents(Json::arrayValue);

	const auto& jEvents = client->m_seshatProfile->GetEvents();
	for (const auto& jEvent : jEvents)
	{
		auto eventID = jEvent["event_id"].asString();
		auto ev = client->FindEvent(eventID);
		if (!ev)
			continue;

		// --- no data for that event yet
		if (ev->GetID().empty())
			continue;

		bool dirty = UpdateMissionParamsForEvent(client, *ev);
		if (dirty)
		{
			if (ev->IsMiniops())
			{
				jDirtyEvents.append(jEvent);
			}
			else
			{
				Json::Value toSend;
				toSend["event_id"] = jEvent["event_id"];
				toSend[SESHAT_LABEL_EVENT_MISSION_PARAMS] = jEvent[SESHAT_LABEL_EVENT_MISSION_PARAMS];
				// --- also append the score, that must always be sent
				// --- TODO: maybe move this to ServerSendEventUpdate, so that this always happens
				toSend["event_score"] = client->m_seshatProfile->GetEventScore(eventID);
				jDirtyEvents.append(std::move(toSend));
			}
		}
	}

	// --- if something changed, send the update to the client
	if (!jDirtyEvents.empty())
		ServerSendEventUpdate(client, jDirtyEvents);
}

