time_t GameServerFedManager::GetCurrentLadderStart() const
{
	auto now = GetLocalTime();
	auto it = std::lower_bound(m_eloLadderExpiryData.begin(), m_eloLadderExpiryData.end(), LeaderboardExpiryEntry(now));
	if (it == m_eloLadderExpiryData.begin())
	{
		MP_LOG(DBG_CRIT, "GetCurrentLadderStart could not deduce prev leaderboard expiry\n");
		return now - 1 * 30 * 24 * 60 * 60; // --- aprox 1 month ago
	}
	return (it - 1)->expiry;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

const GameServerFedManager::LeaderboardExpiryEntry* GameServerFedManager::GetCurrentLadderExpiryEntry() const
{
	auto now = GetLocalTime();
	auto it = std::lower_bound(m_eloLadderExpiryData.begin(), m_eloLadderExpiryData.end(), LeaderboardExpiryEntry(now));
	if (it == m_eloLadderExpiryData.end())
	{
		MP_LOG(DBG_CRIT, "GetCurrentLadderExpiry could not find next leaderboard expiry\n");
		return nullptr;
	}
	return &(*it);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

const GameServerFedManager::LeaderboardExpiryEntry* GameServerFedManager::GetLadderExpiryEntry(time_t timestamp) const
{
	auto it = std::lower_bound(m_eloLadderExpiryData.begin(), m_eloLadderExpiryData.end(), LeaderboardExpiryEntry(timestamp));
	if (it == m_eloLadderExpiryData.end())
	{
		MP_LOG(DBG_CRIT, "GetLadderExpiryEntry could not find requested leaderboard expiry\n");
		return nullptr;
	}
	return &(*it);
}

