EloSettings GameServerFedManager::GetEloSettingsForLadder(const std::string& ladderId) const
{
	auto it = std::find_if(m_eloLadderExpiryData.begin(), m_eloLadderExpiryData.end(), [&ladderId](const LeaderboardExpiryEntry& entry)
	{
		return entry.id == ladderId; // --- TODO: elo - string -> StringHash
	});
	if (it != m_eloLadderExpiryData.end())
		return it->settings;

	GLF_ASSERT(false);
	return EloSettings::_1;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

time_t GameServerFedManager::GetLadderStart(const std::string& ladderId) const
{
	auto it = std::find_if(m_eloLadderExpiryData.begin(), m_eloLadderExpiryData.end(), [&ladderId](const LeaderboardExpiryEntry& entry)
	{
		return entry.id == ladderId; // --- TODO: elo - string -> StringHash
	});
	if (it != m_eloLadderExpiryData.end())
	{
		if (it != m_eloLadderExpiryData.begin())
			return (it - 1)->expiry;
		else if ((it + 1) != m_eloLadderExpiryData.end()) // --- don't have a previous entry, but have a next one - assume same interval
			return it->expiry - ((it + 1)->expiry - it->expiry);
	}

	GLF_ASSERT(false);
	MP_LOG(DBG_CRIT, "GetLadderStart could not find start for ladder %s\n", ladderId.c_str());
	return GetLocalTime() - 1 * 30 * 24 * 60 * 60; // --- aprox 1 month ago
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

time_t GameServerFedManager::GetLadderExpiry(const std::string& ladderId) const
{
	auto it = std::find_if(m_eloLadderExpiryData.begin(), m_eloLadderExpiryData.end(), [&ladderId](const LeaderboardExpiryEntry& entry)
	{
		return entry.id == ladderId; // --- TODO: elo - string -> StringHash
	});
	if (it != m_eloLadderExpiryData.end())
	{
		return it->expiry;
	}

	GLF_ASSERT(false);
	MP_LOG(DBG_CRIT, "GetLadderExpiry could not find start for ladder %s\n", ladderId.c_str());
	return GetLocalTime() - 1 * 30 * 24 * 60 * 60; // --- aprox 1 month ago
}

