std::string GameServerFedManager::GetClanLb(const std::string& ladderId) const
{
	auto it = std::find_if(m_eloLadderExpiryData.begin(), m_eloLadderExpiryData.end(), [&ladderId](const LeaderboardExpiryEntry& entry)
	{
		return entry.id == ladderId;
	});
	if (it == m_eloLadderExpiryData.end())
	{
		GLF_ASSERT(false && "Lb not found - Falling back to global clan leaderboard");
		return CLAN_ELO_LEADERBOARD;
	}

	auto clanLb = it->clanLb;
	if (clanLb.empty())
	{
		clanLb = CLAN_ELO_LEADERBOARD;
		clanLb += "_";
		clanLb += it->id;
	}
	return clanLb;
}

