//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

std::pair<int, time_t> GameServerFedManager::GetLadderPvpWeek(const char* ladderId) const
{
	auto& cWeeksData = GetPvpData()->GetWeeksRewards(ladderId == nullptr ? GetCurrentLadderId() : ladderId);
	// --- no week data, so no check
	if (cWeeksData.isNull())
		return { -1, 0 };

	auto weekHours = ladderId == nullptr ? GetCurrentLadderPvpWeekHours() : GetLadderPvpWeekHours(ladderId);
	auto weekDuration = weekHours * 60 * 60;// --- week duration in seconds
	auto ladderStart = ladderId == nullptr ? GetCurrentLadderStart() : GetLadderStart(ladderId);
	auto now = GetLocalTime();
	auto weekIdx = int(now - ladderStart) / weekDuration; // --- week index 0 based

	if (weekIdx >= int(cWeeksData.size()))
		return { -1, 0 };

	return { weekIdx, ladderStart + (weekIdx + 1) * weekDuration };
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

const char* GameServerFedManager::GetLadderId(time_t timestamp) const
{
	auto entry = GetLadderExpiryEntry(timestamp);
	if (entry)
		return entry->id.c_str();

	GLF_ASSERT(false);
	return "invalid";
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

time_t GameServerFedManager::GetCurrentLadderExpiry() const
{
	auto currentEntry = GetCurrentLadderExpiryEntry();
	if (currentEntry)
		return currentEntry->expiry;

	GLF_ASSERTMSG(false, "Could not find valid expiry date for current elo leaderboard - please update leaderboard_expiry.json");
	auto now = GetLocalTime();
	return now + 1 * 30 * 24 * 60 * 60; // --- aprox 1 month from now
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::IsEloRanked(const Json::Value& pvp_stats) const
{
	return pvp_stats[SESHAT_LABEL_SCRATCHPAD][SESHAT_LABEL_LEAGUE_OLYMPUS_TIMESTAMP].asInt() >= GetCurrentLadderStart();
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::IsClientEloRanked(const GSClient* client) const
{
	return IsEloRanked(client->m_seshatProfile->GetCachedPvpStatsJson());
}

