bool GameServerFedManager::ServerSendOwnClanToClient(GSClient* client, Json::Value data)
{
	//tuan.transy - fix Some parts of the old clan member screen still appear after leaving the Clan.
	if (!data.isNull() && data["member_count"].asInt() >= DEFAULT_CLAN_MEMBER_LIMIT)
	{
		GameServerFedManager::Instance()->SetAchievementProgress(client, StringHash("clan.full"), 1);
	}
	//end

	if (data.isNull())
	{
		m_clanServerManager->OnRemoveClient(client);
	}
	else
	{
		m_clanServerManager->UpdateClanInfo(client, data);
	}

	if (data.isMember(OSIRIS_CLAN_BATTLEPASS_FIELD) && client->m_clanData)
	{
		if (!client->m_clanData->battlepass.data().empty())
		{
			data[OSIRIS_CLAN_BATTLEPASS_FIELD] = client->m_clanData->battlepass.to_json();
		}
		for (auto& entry : data[OSIRIS_CLAN_BATTLEPASS_FIELD]["leaderboard"])
		{
			if (entry.isMember("playerID") && entry["playerID"].isString())
				entry["playerID"] = std::string("fed_id:") + entry["playerID"].asString();

		}
	}

	return ServerSendClanCommand(client, ClanCommand::ServerSendOwnClanData, data);
}

