bool GameServerFedManager::ServerSendRequests(GSClient* client, const Json::Value& data)
{
	// --- DEBUG - apparently sometimes one of the fields is missing
	auto validateField = [client](const Json::Value& entry, const char* field)
	{
		const auto& fieldValue = entry[field];
		if (fieldValue.isNull())
		{
			MP_LOG(DBG_CRIT, "ServerSendRequests - missing id field - entry %s user %s", Json::FastWriter().write(entry).c_str(), client->m_clientId.c_str());
		}
	};
	for (const auto& entry : data)
	{
		validateField(entry, "id");
	}
	return ServerSendClanCommand(client, ClanCommand::ServerSendRequests, data);
}

