void GameServerFedManager::CheckRedBossEventParticipation(GSClient* client)
{
	auto redBossEvents = client->GetEventsOfType(EVENT_TYPE_RED_BOSS);
	if (redBossEvents.empty())
	{
		return;
	}

	time_t now = GetLocalTime();
	Json::Value toJoinEventIDs;
	for (auto redBossEvent : redBossEvents)
	{
		bool hasJoined = client->m_seshatProfile->HasJoinedEvent(redBossEvent->GetID());
		if (hasJoined)
		{
			auto op1 = std::unique_ptr<LadderOperation>(new LadderOperation());
			op1->operation = ELO_GET_RED_BOSS_GLOBAL;
			op1->owner_credential = client->m_credential;
			op1->for_credential = client->m_credential;
			op1->client_id = client->m_clientId;
			op1->cookie = GetLocalTime();
			op1->eventId = redBossEvent->GetID();
			op1->league = (int)PvpLeagueToRedBossLeague(client->m_seshatProfile->GetEventPvpLeague(redBossEvent->GetID()));
			if (redBossEvent->GetEndDate() < now)
				op1->sendToClient = false;

			ScriptGetEloLadder(std::move(op1));
		}

#ifdef RED_BOSS_CLAN_LEADERBOARD
		// Register user's clan to event if exist
		CheckRedBossClanEventParticipation(client, redBossEvent->GetID());
#endif // RED_BOSS_CLAN_LEADERBOARD

		// GetCanProgress: only events found in hestia config are allowed to progress
		// IsActive: event is running
		if (!redBossEvent->GetCanProgress() || !redBossEvent->IsActive())
		{
			continue;
		}

		client->GetHestiaConfig()->SetEventEnergyValues(client, EVENT_TYPE_RED_BOSS, "demon_energy", !hasJoined);
		if (!hasJoined)
		{
			client->m_seshatProfile->ResetDemonScores();
			ScriptGlobalGroupParticipateEvent(client, redBossEvent->GetID());
		}

		OnAdminOsirisProfileUpdated();	// --- force sending the score to client
	}

	ClientParticipateEvents(client, toJoinEventIDs);
}

