//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::CheckRedBossClanEventParticipation(GSClient* client, const std::string& eventId)
{
	//if (!client->HasClanParticipationData())
	//{
	//	return; // --- clan data not available yet
	//}

	const auto& clanData = client->m_seshatProfile->GetClanData();
	auto clanId = clanData[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID].asString();
	if (clanId.empty())
	{
		return; // ---  not in a clan atm
	}

	if (client->HasClanParticipationFor(StringHash(eventId.c_str())))
	{
		return; // ---  already join event
	}
	
	// --- call the participate API for the clan for this event
	std::unique_ptr<ClanOperation> operation(new ClanOperation());
	operation->client_id = client->m_clientId;
	operation->for_credential = client->m_credential;
	operation->owner_credential = client->m_credential;
	operation->operation = ECO_PARTICIPATE_EVENT;
	operation->data["group_id"] = clanId;
	operation->data["event_id"] = eventId;

	ScriptClanParticipateEvent(std::move(operation));
}
