//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::CheckClanEventParticipation(GSClient* client)
{
	if (!client->HasClanParticipationData())
		return; // --- clan data not available yet

	const auto& clanData = client->m_seshatProfile->GetClanData();
	auto clanId = clanData[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID].asString();
	if (clanId.empty())
		return; // ---  not in a clan atm

	auto clanEvents = client->m_EventContainer.GetEventsOfType(EVENT_TYPE_BOSS);
	if (clanEvents.empty())
		return;

	time_t now = GetLocalTime();
	Json::Value toJoinEventIDs;
	for (auto clanEvent : clanEvents)
	{
		if (!clanEvent->GetCanProgress() || !clanEvent->IsActive())
			continue;

		if (client->HasClanParticipationFor(StringHash(clanEvent->GetID().c_str())))
		{
			// --- make sure the event is marked as "joined" (ClientParticipateEvents does nothing if already joined)
			toJoinEventIDs.append(clanEvent->GetID());
			continue;
		}

		// --- call the participate API for the clan for this event
		std::unique_ptr<ClanOperation> operation(new ClanOperation());
		operation->client_id = client->m_clientId;
		operation->for_credential = client->m_credential;
		operation->owner_credential = client->m_credential;
		operation->operation = ECO_PARTICIPATE_EVENT;
		operation->data["group_id"] = clanId;
		operation->data["event_id"] = clanEvent->GetID();
		operation->data["boss_name"] = clanEvent->GetBossName();
		operation->data["end_date"] = clanEvent->GetEndDate();

		ScriptClanParticipateEvent(std::move(operation));
	}

	ClientParticipateEvents(client, toJoinEventIDs);
}

