bool  GameServerFedManager::ServerSendBPRewardVideoEnable(const std::string& credential, int bpType)
{
	NetworkMessageW bpVideoEnableMessage;
	bpVideoEnableMessage.addGameMessageType(TCPMSG_SERVER_SEND_BP_REWARD_VIDEO_ENABLE);
	bpVideoEnableMessage.addInt(bpType);
	MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendBPRewardVideoEnable %s\n", credential.c_str());

	bpVideoEnableMessage.packMessage(GetClient(credential)->m_Crypto);

	if (bpVideoEnableMessage.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendBPRewardVideoEnable packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(credential, (char*)bpVideoEnableMessage.getMessageBody(), bpVideoEnableMessage.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendBPRewardVideoEnable send message failed\n");
		return false;
	}

	return true;
}

