bool GameServerFedManager::ServerSendAddReferralEnd(const std::string& credential, const int errorCode)
{
	NetworkMessageW referralEndMessage;

	referralEndMessage.addGameMessageType(TCPMSG_REFERRAL_COMMAND_END);
	referralEndMessage.addInt(errorCode);
	MP_LOG(DBG_INFO, "GameServerFedManager: ServerSendAddReferralEnd %s\n", credential.c_str());

	referralEndMessage.packMessage(GetClient(credential)->m_Crypto);

	if (referralEndMessage.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendAddReferralEnd packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(credential, (char*)referralEndMessage.getMessageBody(), referralEndMessage.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendAddReferralEnd send message failed\n");
		return false;
	}

	return true;
}

