void GameServerFedManager::UpdateReferralUser(GSClient* client)
{
	// --- called after leveling up

	// --- 1 - check if the referral gift level was reached (MinReferralRewardLevel); if so:
	auto crtLevel = client->m_seshatProfile->GetProfile()[SESHAT_LABEL_INVENTORY][SESHAT_LABEL_LEVEL].asInt();
	auto md = GetMultiplayerData();
	if (crtLevel >= md->MinReferralRewardLevel())
	{
		if (!client->m_seshatProfile->GetReferralUser().isNull())
		{
			// --- 2 - check we haven't already increased the recruits in the referral user's profile (GetReferralUser); if so
			const char* str = client->m_seshatProfile->GetReferralUser().asCString();
			// --- 3 - check that no recruits increment operation is already started; if so:
			if (strlen(str) && !client->m_bReferralIncremenOperationStart)
			{
				client->m_bReferralIncremenOperationStart = true;
				
				static const std::string fed_id { "fed_id:" };

				// --- 4 - start a ScriptChangeSeshatProfileField to increment the number of recruits of the referral user and set a flag to know the operation is in progress
				auto op = std::unique_ptr<ProfileOperation>(new ProfileOperation());
				op->operation = E_ProfileOperation::EPO_ADD_RECRUIT;
				op->client_id = client->m_clientId;//use StartReadingProfileField(std::move(operation));;
				op->owner_credential = client->m_credential;
				op->for_credential = fed_id + client->m_seshatProfile->GetReferralUser().asCString();
				//
				Json::Value obj;
				std::string label(SESHAT_LABEL_RECRUITS ".");
				label += client->m_fedCredential.c_str() + fed_id.length();
				obj[label] = crtLevel;
				ScriptSetSeshatProfileField(obj, std::move(op));
				
			}
		}
	}
}

