void GameServerFedManager::UpdateRecruitsGifts(GSClient* client)
{
	int giftedNo = client->m_seshatProfile->GetGiftedCounter();
	//if (giftedNo == -1) //all gifts are finsihed
	//	return;
	//client->m_seshatProfile->SetGiftedCounter(0);
	auto md = GetMultiplayerData();
	int referralRecruitsNo = client->m_seshatProfile->GetReferralRecruitsCount();

	int knt = 0;
	while (referralRecruitsNo > giftedNo && (knt++ <= md->GetRefRewardsSize()))
	{
		const MultiplayerCommonData::RefMilestone* nextMilestone = md->NextLevelReferralMilestone(giftedNo + 1);
	
		if (!nextMilestone)
		{
			//client->m_seshatProfile->SetGiftedCounter(-1);
			return;
		}

		// --- see if number of elements in _recruits (GetReferralRecruitsCount) is larger than the milestone; if so:
		if (referralRecruitsNo >= nextMilestone->recruits)
		{
			// --- award the gift; construct gift notification and send it to the client; save the new "gifted" counter in the profile (SetGiftedCounter)
				// --- 2 - award gift -> AddReferralReward
				//const std::vector<MultiplayerCommonData::RefReward>* award_gift = GameServerFedManager::Instance()->GetMultiplayerData()->AddReferralReward();;
			client->m_seshatProfile->StartTrackingInventoryChanges("reward:add_referral_milestone");
			for (const auto& gi : nextMilestone->rewards)
			{
				auto qty = gi.qty;
				StringHash item = gi.id;

				client->GetHestiaConfig()->ChangeCreditBalance(client, item, qty);
			}
			// --- 3 - add ref gift notification and send it to the client
			giftedNo = nextMilestone->recruits;
			client->m_seshatProfile->SetGiftedCounter(giftedNo);
			client->m_seshatProfile->AddNotificationFromServer("add_referral", "gift_milestone", nextMilestone->recruits, ENM_CATEGORY | ENM_INFO | ENM_KEY);
			auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
			if (!inventory_changes.empty())
			{
				ServerSendInventoryUpdate(client, "add_referral_milestone", std::move(inventory_changes));
			}
		}
		else // asume we have some order
			return;
	}
}
//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void  GameServerFedManager::ReduceDelayedTransactionsTime(GSClient* client, const std::string& item_currency)
{
	client->m_seshatProfile->StartTrackingInventoryChanges("ads::sqops_time");
	auto dtid = client->m_seshatProfile->GetAdsReducedDtid();
	auto new_expiry = client->m_seshatProfile->GetDelayedTransactionExpiry(dtid.c_str());
	auto md = GameServerFedManager::Instance()->GetMultiplayerData();
	new_expiry -= md->GetOpsReduceTime();
	time_t now = GameServerFedManager::Instance()->GetLocalTime();
	if (new_expiry > now)
	{
		client->m_seshatProfile->UpdateDelayedTransactionExpiry(dtid, new_expiry);
	}
	else
	{
		const auto& delayed_transaction = client->m_seshatProfile->FindDelayedTransaction(dtid);
		if (!delayed_transaction.isNull() && delayed_transaction["id"] == "pending_gold_pack")
		{
			auto pending_pack_offer = client->GetHestiaConfig()->FindOffer("pending_gold_pack");
			if (pending_pack_offer)
			{
				client->GetHestiaConfig()->GiveTheGoodies(client, pending_pack_offer->items); // , oldest_transaction["extra"]);
				client->GetHestiaConfig()->OnItemsPurchased(client, *pending_pack_offer, pending_pack_offer->items, pending_pack_offer->prices);
			}
		}
		client->m_seshatProfile->RemoveDelayedTransaction(dtid);
	}
	Json::Value inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();

	// --- update variable prices
	auto var_price_changes = client->GetHestiaConfig()->UpdateInventoryVariableOffers(client, { });
	if (!var_price_changes.empty())
	{
		for (auto icit = var_price_changes.begin(); icit != var_price_changes.end(); ++icit)
			inventory_changes[icit.memberName()] = std::move(*icit);
	}

	if (!inventory_changes.empty())
	{
		auto transactionId = StringHash(item_currency.c_str());
		ServerSendInventoryUpdate(client, transactionId, std::move(inventory_changes));
	}
}
