//Add free_arena_token reward
void  GameServerFedManager::GiveArenaTokenFreeGifts(GSClient* client)
{
	//get inventory
	//client->m_seshatProfile->StartTrackingInventoryChanges("reward:at_free_reward");
	auto cnt = client->m_seshatProfile->GetFreeArenaToken();
	Json::Value jReward;
	Json::Value jPreset;
	std::string presetName;
	presetName = "ads_arena_token_3";
	if (cnt < 5)
	{
		presetName = "ads_arena_token_1";
	}
	else if (cnt < 15)
	{
		presetName = "ads_arena_token_2";
	}
	else if (cnt < 30)
	{
		presetName = "ads_arena_token_3";
	}
	
	Price reward(presetName, 1);
	client->GetHestiaConfig()->ResolveRelativeCurrencyPrice(client, reward);
	jReward["id"] = reward.credit;
	jReward["qty"] = reward.qty;
	jPreset = client->GetHestiaConfig()->GetGachaPreset(client, jReward["id"].asCString(), jReward["qty"].asInt());
	GetGachaData()->GiveStuff(client, reward.credit.c_str(), reward.qty);
	client->m_seshatProfile->AddNotificationFromServer("at_free_reward", jPreset["id"].asCString(), jPreset["qty"].asInt(), ENM_CATEGORY | ENM_INFO /*| ENM_UNIQUE_KEY*/);

}

void GameServerFedManager::GiveAdsReward(GSClient* client, StringHash tranzId, std::string rewardName, int amount)
{
	// --- create a json same as the json sent to profile by 3rd party ads then use the UpdateInventoryFromIAP to give rewards
	Json::Value jsonData(Json::arrayValue);
	Json::Value items;
	items[rewardName] = amount;

	Json::Value entry;
	entry["items"] = items;
	entry["source"] = "ads";
	entry["type"] = "inventory_delivery";
	jsonData.append(entry);

	auto serverMgr = GameServerFedManager::Instance();

	client->m_seshatProfile->StartTrackingInventoryChanges();

	serverMgr->m_hestiaConfigManager->UpdateInventoryFromIAP(client, jsonData);

	Json::Value inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();


	serverMgr->ServerSendInventoryUpdate(client, tranzId, std::move(inventory_changes));

}

