int GameServerFedManager::HighestSquadOpChapter(GSClient* client) const
{
	auto highestUnlockedChapter = client->m_seshatProfile->HighestUnlockedAccesableChapter();

	// --- generate squad ops missions for all chapters that have all story missions completed
	// --- since the chapters are unlocked when the story block is complete, we're interested only in the story block from the highest unlocked chapter
	auto missionsData = GetAHMissionsData();
	auto storyBlock = missionsData->GetBlockIndex("Story");
	auto highestStoryMission = MissionUid(highestUnlockedChapter, storyBlock, missionsData->GetChapterBlockMissionCount(highestUnlockedChapter, storyBlock) - 1);
	if (!missionsData->MissionCompleted(client->m_seshatProfile, highestStoryMission))
		--highestUnlockedChapter;

	return highestUnlockedChapter;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::EnsureSquadOpMissions(GSClient* client)
{
	auto highestUnlockedChapter = HighestSquadOpChapter(client);
	for (auto ci = 0; ci <= highestUnlockedChapter; ++ci)
	{
		ValidateSquadOpsMissions(client, ci);
		EnsureSquadOpsMissionsForChapter(client, ci, NewSquadOp::WithoutDelay);
	}
	// --- TODO: maybe only generate these if / when the client is in an actual clan domination?
	// --- Otherwise these will remain "blocked" forever...
	ValidateSquadOpsMissions(client, SQUAD_OPS_DOMINATION_CHAPTER_INDEX);
	EnsureSquadOpsMissionsForChapter(client, SQUAD_OPS_DOMINATION_CHAPTER_INDEX, NewSquadOp::WithoutDelay);
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ValidateSquadOpsMissions(GSClient* client, int chapter)
{
	auto missionIds = client->m_seshatProfile->SquadOpsMissions(chapter);
	for (auto missionId : missionIds)
	{
		int outcomeFlags = 0, cmdrBonus =0;
		SquadOpIdChapter squadOpIdChapter;
		mcfwutil::fsmap<StringHash, int> xpBonus;
		std::vector<RewardItem> bossReward, bossBonus;
		client->m_seshatProfile->GetSquadOpData(missionId, &outcomeFlags, &xpBonus, &squadOpIdChapter, bossReward, bossBonus, &cmdrBonus);

		// --- if we still have squad op data for this mission we're good
		auto squadOpsData = GetMultiplayerData()->FindSquadOpData(squadOpIdChapter);
		if (squadOpsData)
			continue;

		// --- if not, remove the mission and return the mates (if any)
		for (const auto& smEntry : xpBonus)
		{
			auto smid = smEntry.first;
			client->m_seshatProfile->SetSquadMateStatus(smid, ESMS_IDLE);
		}

		client->m_seshatProfile->RemoveSquadOp(missionId);
	}
}

