struct GameServerFedManager::SquadOpsRandomParams
{
	int chapterForDifficultySelection;
	SquadOpsDataFor dataFor;
};

GameServerFedManager::SquadOpsRandomParams GameServerFedManager::RandomParamsForSquadOpsChapter(GSClient* client, int chapter) const
{
	SquadOpsRandomParams ret;
	ret.dataFor = GetMultiplayerData()->SquadOpChapterIndexToType(chapter);

	switch (ret.dataFor)
	{
	// --- for clan domination squad ops, use the difficulty based on the highest unlocked chapter
	// --- for boss events use the difficulty based on the highest unlocked chapter
	case SquadOpsDataFor::ClanDomination:
	case SquadOpsDataFor::BossEvent:
		ret.chapterForDifficultySelection = client->m_seshatProfile->HighestUnlockedAccesableChapter();
		break;
	
	// --- for bounty events use difficulty of the highest completed chapter (or the current chapter if it's higher)
	case SquadOpsDataFor::BountyEvent:
		ret.chapterForDifficultySelection = std::max(chapter - SQUAD_OPS_BOUNTY_CHAPTER_INDEX, HighesteCompletedBountyChapter(client));
		break;

	case SquadOpsDataFor::MissionsMap:
		ret.chapterForDifficultySelection = chapter;
	}

	return ret;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::RefreshSquadOpsMissions(GSClient* client, int chapter)
{
	auto chapterMissionIds = client->m_seshatProfile->SquadOpsMissions(chapter);
	std::vector<StringHash> excludes = client->m_seshatProfile->AllAvailableSquadOpsMissions();
	auto randomData = RandomParamsForSquadOpsChapter(client, chapter);
	auto toReplace = std::vector<const char*>();
	for (auto missionId : chapterMissionIds)
	{
		auto edtid = client->m_seshatProfile->GetSquadOpDelayedTransactionId(missionId, SeshatProfileManager::SquadOpDelayedTransactionType::End);
		if (!edtid.empty()) // --- started (either ongoing or completed)
			continue;

		toReplace.push_back(missionId);
	}

	if (toReplace.empty())
		return;

	auto squadOpIds = GetMultiplayerData()->RandomSquadOpForChapter(randomData.chapterForDifficultySelection, randomData.dataFor, (int)toReplace.size(), excludes);
	auto squadOpIdsIt = squadOpIds.begin();

	for (auto missionId : toReplace)
	{
		client->m_seshatProfile->RemoveSquadOp(missionId);

		client->m_seshatProfile->AddSquadOpsMission(chapter, *squadOpIdsIt);

		++squadOpIdsIt;
		if (squadOpIdsIt == squadOpIds.end())
			squadOpIdsIt = squadOpIds.begin();
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::EnsureSquadOpsMissionsForChapter(GSClient* client, int chapter, NewSquadOp delay)
{
	static const int SQUAD_OPS_MISSIONS_PER_CHAPTER = 3;
	auto availableChapterMissions = client->m_seshatProfile->AvailableSquadOpsMissions(chapter);
	auto toAdd = SQUAD_OPS_MISSIONS_PER_CHAPTER - (int)availableChapterMissions.size();
	if (toAdd <= 0)
		return;

	auto randomData = RandomParamsForSquadOpsChapter(client, chapter);
	auto excludes = client->m_seshatProfile->AllAvailableSquadOpsMissions();
	auto squadOpIds = GetMultiplayerData()->RandomSquadOpForChapter(randomData.chapterForDifficultySelection, randomData.dataFor, toAdd, excludes, availableChapterMissions);
	for (auto squadOpId : squadOpIds)
	{
		auto missionId = client->m_seshatProfile->AddSquadOpsMission(chapter, squadOpId);
		if (delay == NewSquadOp::WithDelay)
		{
			Json::Value extraData;
			extraData["missionId"] = missionId;

			auto offerId = StringHash("squad_op_refresh");
			auto result = m_hestiaConfigManager->ProcessTransaction(client, offerId, extraData);

			// --- send update to the client
			ServerSendInventoryUpdate(client, offerId, std::move(result));
		}
	}
}

