void GameServerFedManager::AddSquadOpsMissionForChapter(GSClient* client, int chapter, NewSquadOp delay)
{

}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

Json::Value GameServerFedManager::ComputeSquadOpParams(GSClient* client, const Json::Value& jConfig, SquadOpParamsFor paramsFor)
{
	Json::Value params;

	auto missionId = jConfig["missionID"].asString();
	const auto& jPlayers = jConfig["players"];
	const auto& jDrones = jConfig["drones"];
	const auto& jBoosts = jConfig["boosts"];

	// --- even if it's invalid, send it back to the client the way we received it, so that it doesn't crash
	// --- it won't contain anything else anyway...
	params["missionID"] = missionId;

	// --- get squad op id from missionId
	auto squadOpIdChapter = client->m_seshatProfile->FindSquadOpsIdChapterFromMissionId(missionId.c_str());
	if (!squadOpIdChapter)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ComputeSquadOpParams - could not find squad op profile data for mission id %s for client %s\n", missionId.c_str(), client->m_credential.c_str());
		return params;
	}

	// --- get squad op data
	auto squadOpsData = GetMultiplayerData()->FindSquadOpData(squadOpIdChapter);
	if (!squadOpsData)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ComputeSquadOpParams - could not find squad op data for mission id %s chapter id %d for client %s\n", missionId.c_str(), squadOpIdChapter.chapter, client->m_credential.c_str());
		return params;
	}

	// --- check we haven't received more players than slots in the mission
	if ((int)jPlayers.size() > squadOpsData.slots())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ComputeSquadOpParams - received more players that slots - players %d slots %d mission id %s chapter id %d for client %s\n", 
			(int)jPlayers.size(), squadOpsData.slots(), missionId.c_str(), squadOpIdChapter.chapter, client->m_credential.c_str());
		return params;
	}

	// --- all player ids
	std::vector<StringHash> players(jPlayers.size());
	std::transform(jPlayers.begin(), jPlayers.end(), players.begin(), [](const Json::Value& entry) { return StringHash(entry.asCString()); });

	// --- erase all the players for which we can't find the squadmate (shouldn't happen, but due to a bug happens in 1.8.0)
	players.erase(std::remove_if(players.begin(), players.end(),
		[client](StringHash pid)
	{
		auto smCredit = client->m_seshatProfile->GetSquadMateCredit(pid);
		if (!smCredit)
		{
			MP_LOG(DBG_CRIT, "GameServerFedManager: ComputeSquadOpParams - could not find squad mate with id %u for client %s\n", pid, client->m_credential.c_str());
			return true;
		}
		return false;
	}), players.end());

	// --- gather all player ratings, all counters and all boni from perks
	std::vector<int> ratings;
	std::vector<StringHash> counters;
	std::vector<StringHash> boosts;
	mcfwutil::fsmap<StringHash, int> classes;
	mcfwutil::fsmap<StringHash, int> drones;
	std::vector<RewardItem> droneCost;
	// --- list of boni per player (or 0 if the bonus is global, not from a player)
	std::vector<std::pair<const MultiplayerCommonData::SquadOpBonus*, StringHash>> boni;
	auto duration = squadOpsData.duration();

	const int smCounterUnlock = GetMultiplayerData()->SquadmateCounterUnlockRating();
	const int smPerkUnlock = GetMultiplayerData()->SquadmatePerkUnlockRating();
	for (auto pid : players)
	{
		auto smCredit = client->m_seshatProfile->GetSquadMateCredit(pid);
		// --- checked above
		//if (!smCredit)
		//	return params;
		
		// --- TODO: check players' state (they must be available)

		auto rating = client->m_seshatProfile->GetSquadMateRating(pid);
		ratings.push_back(rating);

		const auto& smCreditName = client->GetHestiaConfig()->FindCredit(smCredit)->name;
		const auto& smData = GetMultiplayerData()->GetEntryForCard(smCreditName);

		classes[StringHash(smData["Class"].asCString())]++;

		if (rating >= smCounterUnlock)
			counters.push_back(StringHash(smData["Counter"].asCString()));
		
		if (rating >= smPerkUnlock)
		{
			auto perkId = StringHash(smData["Perk"].asCString());
			boni.emplace_back(GetMultiplayerData()->SquadOpBonusForSkill(perkId), pid);
		}

		// --- rating-specific boni
		const auto& ratingBoni = GetMultiplayerData()->SquadmateBonusForRating(rating);
		for (const auto& ratingBonus : ratingBoni)
			boni.emplace_back(&ratingBonus, pid);
	}

	// --- add boni from boosts
	for (const auto& jBoost : jBoosts)
	{
		auto boostId = StringHash(jBoost.asCString());
		auto bonus = GetMultiplayerData()->SquadOpBonusForBoost(boostId);
		if (bonus)
		{
			boni.emplace_back(bonus, StringHash());
			boosts.emplace_back(boostId);
		}
	}

	// --- add boni from drones and keep drone offers
	for (const auto& jDrone : jDrones)
	{
		auto droneId = StringHash(jDrone.asCString());
		auto droneOffer = client->GetHestiaConfig()->FindOffer(droneId);
		if (!droneOffer)
			continue;

		++drones[droneId];
		boni.emplace_back(GetMultiplayerData()->SquadOpBonusForDrone(droneId), StringHash());
	}

	mcfwutil::fsmap<StringHash, bool> bonusParams;
	bonusParams["alone"] = players.size() == 1;
	bonusParams["not_alone"] = players.size() > 1;
	bonusParams["drone"] = !jDrones.empty();
	bonusParams["longer_than"] = duration > GetMultiplayerData()->SquadOpBonusParamValue("longer_than") * 60; // --- data in minutes
	bonusParams["shorter_than"] = duration < GetMultiplayerData()->SquadOpBonusParamValue("shorter_than") * 60; // --- data in minutes

	// --- bonus id -> value
	mcfwutil::fsmap<StringHash, int> cumulatedBoni;
	// --- player id -> list of boni
	mcfwutil::fsmap<StringHash, mcfwutil::fsmap<StringHash, int>> perPlayerBoni;

	auto addBonus = [](mcfwutil::fsmap<StringHash, int>& bonusMap, const MultiplayerCommonData::SquadOpBonus* bonus)
	{
		bonusMap[bonus->type] += bonus->value;
	};

	for (const auto& bonusEntry : boni)
	{
		auto bonus = bonusEntry.first;
		if (bonus->param)
		{
			if (bonus->param == StringHash("for_me"))
			{
				// --- the bonus is only for the player
				addBonus(perPlayerBoni[bonusEntry.second], bonus);
				continue;
			}
			else if (bonus->param == StringHash("for_others"))
			{
				// --- the bonus is for all other players in the mission
				for (auto pid : players)
					if (pid != bonusEntry.second)
						addBonus(perPlayerBoni[pid], bonus);
				continue;
			}

			// --- check the param matches withe mission param
			auto it = bonusParams.find(bonus->param);
			if (it == bonusParams.end() || !it->second)
				continue;
		}

		// --- add global bonus
		addBonus(cumulatedBoni, bonus);
	}

	// --- TODO: double_trouble effect on duration

	// --- success chance based on matching requirements - assumes the mission requirements are unique
	//commander bonusses for sm
	auto reqMatchBonus = 60 / (int)squadOpsData.requirements().size(); // --- TODO: 60 in data
	//reqMatchBonus = (int)(reqMatchBonus * (1.0f + client->m_seshatProfile->GetCommanderBonusModifierByBonus("cmdr_bonus_sqops_win") * 0.01f));
	
	for (auto requirementId : squadOpsData.requirements())
	{
		if (classes.find(requirementId) != classes.end())
			cumulatedBoni["success_chance"] += reqMatchBonus;
	}

	// --- success chance based on matching mission difficulty with squad mate rating
	int diffDelta = 0;
	for (int rating : ratings)
		diffDelta += rating - squadOpsData.difficulty();
	cumulatedBoni["success_chance"] += diffDelta * 5; // --- TODO: 5 in data

	// --- success chance based on unmatched setbacks
	int diffSetbacks = 0;
	for (auto setbackId : squadOpsData.setbacks())
	{
		auto it = std::find(counters.begin(), counters.end(), setbackId);
		if (it == counters.end())
			++diffSetbacks;
	}
	cumulatedBoni["success_chance"] -= diffSetbacks * GetMultiplayerData()->SetbackChance();
	

	auto doubleTroubleIt = cumulatedBoni.find("double_trouble");
	if (doubleTroubleIt != cumulatedBoni.end())
	{
		// --- this is because we don't have support for array of boni in boosts / skills because I'm lazy
		// --- TODO: correctly implement mission_reward bonus type
		cumulatedBoni["mission_time"] -= 100;
		cumulatedBoni["mission_reward"] += 100;
	}

	auto tripleTroubleIt = cumulatedBoni.find("triple_trouble");
	if (tripleTroubleIt != cumulatedBoni.end())
	{
		// --- this is because we don't have support for array of boni in boosts / skills because I'm lazy
		// --- TODO: correctly implement mission_reward bonus type
		cumulatedBoni["mission_time"] -= 200;
		cumulatedBoni["mission_reward"] += 200;
	}
	//commander bonusses
	{
		//int commander_bonus = client->m_seshatProfile->GetCommanderBonusModifierByName("cmdr_bonus_sqops_reward");
		//cumulatedBoni["mission_reward"] += commander_bonus;
	}
	// --- for domiation squad ops, add the green zone faction bonus - drone_success_chance
	if (client->m_clanData && squadOpsData.domination())
	{
		for (const auto& droneEntry : drones)
		{
			auto droneId = droneEntry.first;
			auto qty = droneEntry.second;
			auto droneBonus = GetMultiplayerData()->SquadOpBonusForDrone(droneId);
			if (droneBonus->type == "success_chance")
			{
				auto dominationDroneBonus = *droneBonus;
				auto perkValue = client->m_clanData->domination.perk_value("drone_success_chance");
				dominationDroneBonus.value = dominationDroneBonus.value * perkValue / 100;
				cumulatedBoni["success_chance"] += qty * dominationDroneBonus.value;
			}
		}
	}

	// --- bonus chance from quartermaster
	if (client->GetHestiaConfig()->GetCreditBalance(client, "quartermaster") > 0)
	{
		cumulatedBoni["success_chance"] += GetMultiplayerData()->DeputyData()["quartermaster"]["success_chance"].asInt();
	}

	// --- bounty: for bounty squad ops missions (sabotage), apply the badge level bonus - reduce mission time
	if (squadOpsData.bounty())
	{
		// --- TODO: bounty / squadops: the squad ops missions should know the event
		auto evt = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_BOUNTY);
		if (evt)
		{
			cumulatedBoni["mission_time"] += client->m_seshatProfile->GetBountyBonus(evt->GetID(), "mission_time");
		}
		else
		{
			MP_LOG(DBG_CRIT, "GameServerFedManager: ComputeSquadOpParams - could not find bounty event for bounty mission for client %s\n", client->m_credential.c_str());
		}
	}
	{
		//commanders
		cumulatedBoni["success_chance"] += client->m_seshatProfile->GetCommanderBonusModifierByBonus("cmdr_bonus_sqops_win");
	}
	// --- clamp success chance to 1 if at least one squad mate is equipped, else make it 0 regardless of the rest of the setup
	if (players.empty())
		cumulatedBoni["success_chance"] = 0;
	else
		cumulatedBoni["success_chance"] = std::max(1, cumulatedBoni["success_chance"]);

	// --- also make sure we don't get absurd with the cost
	cumulatedBoni["mission_cost"] = std::min(cumulatedBoni["mission_cost"], 100);

	// --- compute start cost
	auto cost = squadOpsData.cost();

	// --- if the pvp is locked and the price is in gold, use the sc price
	if (!client->FeatureUnlocked("pvp_unlocked"))
	{
		auto useSc = std::any_of(cost.begin(), cost.end(), [](const RewardItem& reward) { return reward.id == "safe_dust"; });
		if (useSc)
			cost = squadOpsData.sc_cost();
		std::for_each(cost.begin(), cost.end(), [client](RewardItem& entry) { client->GetHestiaConfig()->ResolveRelativeCurrencyPrice(client, entry); });
	}

	// --- for bounty missions, the cost and duration is variable - depends on the chapter
	if (squadOpsData.bounty())
	{
		auto evt = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_BOUNTY);
		if (evt)
		{
			auto eventData = GetAHEventsData()->GetBountyEventData(evt->GetPreset());
			auto bountyChapter = squadOpIdChapter.chapter - SQUAD_OPS_BOUNTY_CHAPTER_INDEX;
			auto factorChapter = std::max(bountyChapter, HighesteCompletedBountyChapter(client));

			// --- apply bounty price factor
			auto priceFactor = eventData.ChapterData(factorChapter).SOPriceFactor();
			for (auto& price : cost)
			{
				price.qty = (int)(price.qty * priceFactor);
			}

			// --- apply bounty duration factor
			auto durationFactor = eventData.ChapterData(factorChapter).SODurationFactor();
			duration = (int)(duration * durationFactor);
		}
	}

	// --- apply cost reduction from boni
	for (auto& price : cost)
	{
		price.qty -= price.qty * cumulatedBoni["mission_cost"] / 100;
	}

	// --- helper to append a cost to the overall cost without doubling entries for the same currency
	auto appendCost = [](std::vector<RewardItem>& cost, StringHash currency, int qty)
	{
		auto it = std::find_if(cost.begin(), cost.end(), [currency](const RewardItem& entry) { return entry.id == currency; });
		if (it != cost.end())
		{
			it->qty += qty;
		}
		else
		{
			cost.emplace_back(currency, qty);
		}
	};

	// --- compute drone cost
	for (const auto& droneEntry : drones)
	{
		// --- determine how many drones of this type we have to buy
		auto droneOffer = client->GetHestiaConfig()->FindOffer(droneEntry.first);
		auto qty = droneEntry.second;
		auto droneItem = StringHash(droneOffer->items.front().credit.c_str());

		auto qtyToBuy = std::max(0, qty - (int)client->GetHestiaConfig()->GetCreditBalance(client, droneItem));
		auto qtyToTake = std::max(0, qty - qtyToBuy);

		if (qtyToTake)
		{
			// --- append drone item to the overall cost
			appendCost(droneCost, droneItem, qtyToTake);
		}

		if (qtyToBuy)
		{
			// --- append drone cost to the overall cost
			for (const auto& price : droneOffer->prices)
			{
				auto currency = StringHash(price.credit.c_str());
				appendCost(droneCost, currency, qtyToBuy * (int)price.qty);
			}
		}
	}

	//commander bonus
	cumulatedBoni["mission_time"] += client->m_seshatProfile->GetCommanderBonusModifierByBonus("cmdr_bonus_sqops_time");

	// --- apply duration bonus, round it up to minutes, clamp it to 1 min
	duration = duration - duration * cumulatedBoni["mission_time"] / 100;
	duration = std::max(60, duration + 59 / 60);

	if (paramsFor == SquadOpParamsFor::Client)
	{
		client->m_currentSquadOp_jConfigCache = jConfig;

		auto rewardToJson = [](const GSClient* client, const std::vector<RewardItem>& cost)
		{
			Json::Value jCost;
			for (const auto& price : cost)
			{
				Json::Value entry;
				entry["id"] = client->GetHestiaConfig()->FindCredit(price.id)->name;
				entry["qty"] = price.qty;
				jCost.append(std::move(entry));
			}
			return jCost;
		};

		// --- build return params that are sent to the client
		params["missionID"] = missionId;
		params["chance"] = cumulatedBoni["success_chance"];
		params["time"] = duration;
		params["cost"] = rewardToJson(client, cost);
		params["droneCost"] = rewardToJson(client, droneCost);
		params["dblRwd"] = cumulatedBoni.find("double_trouble") != cumulatedBoni.end();
		params["tplRwd"] = cumulatedBoni.find("triple_trouble") != cumulatedBoni.end();
		// --- the type is only used by the quartermaster
		params["type"] = static_cast<int>(GetMultiplayerData()->SquadOpChapterIndexToType(squadOpIdChapter.chapter));

		return params;
	}

	// --- append drone cost
	for (const auto& entry : droneCost)
	{
		appendCost(cost, entry.id, (int)entry.qty);
	}
	
	// --- add duration as time in price (minutes)
	const char* timeCredit = "time_sqops";
	if (squadOpIdChapter.chapter >= SQUAD_OPS_BOSS_CHAPTER_INDEX)
	{
		timeCredit = "time_boss_sqops";
	}
	
	
	cost.emplace_back(StringHash(timeCredit), client->m_shortSquadOpsCheat ? 10 : duration / 60);

	// --- append boost cost
	for (auto boostId : boosts)
	{
		cost.emplace_back(boostId, 1);
	}

	{
		client->m_currentSquadOp_jConfigCache.clear();

		SquadOpParams params;
		params.missionId = std::move(missionId);
		params.boni = std::move(cumulatedBoni);
		params.perPlayerboni = std::move(perPlayerBoni);
		params.squadOpId = squadOpIdChapter.id;
		params.chapter = squadOpIdChapter.chapter;
		params.players = std::move(players);
		params.duration = duration;
		params.drones = drones;
		params.boosts = boosts;

		params.cost.reserve(cost.size());
		for (const auto& price : cost)
			params.cost.emplace_back(price.id, (int)price.qty);

		client->SetCurrentSquadOpParams(std::move(params));
	}

	return params;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendSquadOpsCommand(GSClient* client, SquadOpsCommand command, const Json::Value& data)
{
	NetworkMessageW sqOpsCommandMsg;

	sqOpsCommandMsg.addGameMessageType(TCPMSG_SQUAD_OPS_COMMAND);
	sqOpsCommandMsg.addByte(static_cast<byte>(command));

	std::string sRawResponse = Json::FastWriter().write(data);

	sqOpsCommandMsg.addBytesAndLen((const byte*)sRawResponse.c_str(), (unsigned short)sRawResponse.size());

	sqOpsCommandMsg.packMessage(client->m_Crypto);

	if (sqOpsCommandMsg.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendSquadOpsCommand packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)sqOpsCommandMsg.getMessageBody(), sqOpsCommandMsg.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendSquadOpsCommand send message failed\n");
		return false;
	}

	return true;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::MergePvpSlots(GSClient* client, const char* offerName)
{
	auto offerId = StringHash(offerName);
	Json::Value extraData;
	float packCDValue = DefenderLeaderboard::Get()->GetModifierValueFromBuff(client, DefenderLeaderboard::DefenderBuffs::PVP_PACK_COOLDOWN) * 0.01f;
	extraData[PVP_PACK_COOLDOWN_REDUCE] = 1 - packCDValue;
	auto result = client->GetHestiaConfig()->ProcessTransaction(client, offerId, extraData);
	// --- send update to the client
	ServerSendInventoryUpdate(client, offerId, std::move(result));
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::OpenPvpSlot(GSClient* client, const char* offerName)
{
	auto offerId = StringHash(offerName);

	Json::Value extraData;
	extraData["activate"] = true;
	extraData["gacha_action"] = "pvp_gacha";
	auto result = client->GetHestiaConfig()->ProcessTransaction(client, offerId, extraData);

	// --- send update to the client
	ServerSendInventoryUpdate(client, offerId, std::move(result));
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::RushPvpSlots(GSClient* client, const char* offerName)
{
	auto offerId = StringHash(offerName);
	auto offer = client->GetHestiaConfig()->FindOffer(offerId);
	if (offer)
	{
		auto extraData = Json::Value(Json::objectValue);
		auto creditName = offer->items.front().credit;
		auto transactions = client->m_seshatProfile->FindDelayedTransactionsForOffer(offerName);
		GLF_ASSERT(transactions.size() == 1);	// --- more transactions for the same slot offer
		if (transactions.empty())
		{
			MP_LOG(DBG_CRIT, "GameServerFedManager: RushPvpSlots transactions delayed empty - offerName %s\n", offerName);
			return;
		}
		extraData["_delayed_transaction_id"] = transactions.front()["transactionId"];
		extraData["expediting"] = true;

		auto result = m_hestiaConfigManager->ProcessTransaction(client, offerId, extraData);

		// --- send update to the client
		ServerSendInventoryUpdate(client, offerId, std::move(result));	
	}
}
//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::StartSquadOps(GSClient* client, const Json::Value& jConfig)
{
	auto missionId = jConfig["missionID"].asString();
	if (missionId.empty())
	{
		return;
	}
	else if (missionId == TUTORIAL_SQUAD_OP_MISSION_ID)
	{
		// --- tutorial squad op needs special setup
		missionId = SetupTutorialSquadOp(client);
	}
	else
	{
		ComputeSquadOpParams(client, jConfig, SquadOpParamsFor::Server);
	}

	// --- TODO: check the computed params are ok; if not, send back transaction failed

	Json::Value extraData;
	extraData["missionId"] = missionId;

	auto offerId = StringHash("squad_op_start");
	auto result = m_hestiaConfigManager->ProcessTransaction(client, offerId, extraData);

	// --- send update to the client
	ServerSendInventoryUpdate(client, offerId, std::move(result));
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ComputeAndSetSquadOpsOutcome(GSClient* client)
{
	const auto& params = client->CurrentSquadOpParams();

	// --- roll for mission success and bonus if neccesary
	auto& rng = client->m_seshatProfile->GetRandomEngine(ERandomEngine::ER_SQUAD_OPS);
	auto success = false;
	auto bonus = false;

	auto now = GetLocalTime();

	auto successChance = params.boni.find("success_chance")->second;
	if (successChance < 100)
	{
		auto successDist = std::bernoulli_distribution((double)successChance / 100);
		success = successDist(rng);
	}
	else // if (successChance >= 100)
	{
		success = true;
		successChance -= 100;
		if (successChance > 0)
		{
			auto bonusDist = std::bernoulli_distribution((double)successChance / 100);
			bonus = bonusDist(rng);
		}
	}

	// --- get squad op data
	auto squadOpsData = GetMultiplayerData()->FindSquadOpData({ params.squadOpId, params.chapter });
	const auto& squadOpChances = GetMultiplayerData()->SquadOpsOutcomeForDifficulty(squadOpsData.difficulty());

	// --- holds final values with the xp bonus for each squadmate
	mcfwutil::fsmap<StringHash, int> xpBonus;
	// --- state to put the player in for certain bonus types
	auto bonus2state = [](StringHash bonus) -> E_SquadMateStatus
	{
		return bonus == StringHash("prevent_death") ? ESMS_MISSION_ENDED_MIA : ESMS_MISSION_ENDED_HURT;
	};
	// --- computes cumulated value for a certain bonus type for a player by adding the global value with the per-player value
	auto playerbonus = [&params](StringHash bonusType, StringHash pid) -> int
	{
		int ret = 0;
		if(bonusType == StringHash("prevent_death") || bonusType == StringHash("prevent_wounded"))
		{
			// --- add global value for death/wounded
			auto gbit = params.boni.find(StringHash("prevent_death_wounded"));
			if (gbit != params.boni.end())
				ret += gbit->second;
		}
		// --- add global value
		auto gbit = params.boni.find(bonusType);
		if (gbit != params.boni.end())
			ret += gbit->second;
		// --- add per-player value
		auto pbit = params.perPlayerboni.find(pid);
		if (pbit != params.perPlayerboni.end())
		{
			const auto& playerBoni = pbit->second;
			auto bit = playerBoni.find(bonusType);
			if (bit != playerBoni.end())
				ret += bit->second;
		}
		return ret;
	};
	// --- compute xp bonus, wounded / mia, set squadmate state & next state
	for (auto smid : params.players)
	{
		auto nextState = ESMS_MISSION_ENDED;
		if (success)
		{
			// --- give xp bonus only if not rented and upgradable
			auto giveXpBonus = 
				client->m_seshatProfile->GetSquadMateExpiry(smid) == 0 &&
				client->m_multiplayer->SquadmateUpgradable(smid);

			if (giveXpBonus)
			{
				// --- xp bonus
				auto xpBonusModifier = playerbonus("xp_bonus", smid);
				if (client->m_clanData)
					xpBonusModifier += client->m_clanData->base.perk_value("xp");
				xpBonus[smid] = squadOpsData.xp() + xpBonusModifier * squadOpsData.xp() / 100;
			}
			else
			{
				xpBonus[smid] = 0;
			}
		}
		else
		{
			// --- no xp bonus on loss
			xpBonus[smid] = 0;

			// --- ['10350655']: '[UPD33][Squadmates][GDD]: The rented squdmates are affected by the MIA and wounded status
			// --- QA driven design FTW
			//if (client->m_seshatProfile->GetSquadMateExpiry(smid))
			//	continue;

			// --- decide wounded / mia
			for (auto type : { StringHash("prevent_death"), StringHash("prevent_wounded") })
			{
				// --- base chance given by the mission properties
				auto chance = type == StringHash("prevent_death") ? squadOpChances.prevent_death : squadOpChances.prevent_wounded; // --- TODO: getter with stringhash
				
				// --- add per-player and global chances (from skills, boosts etc.)
				chance += playerbonus(type, smid);

				if (chance < 0)
				{
					nextState = bonus2state(type);
				}
				else if (chance < 100)
				{
					auto dist = std::bernoulli_distribution((double)chance / 100);
					auto prevent = dist(rng);
					if (!prevent)
					{
						nextState = bonus2state(type);
						break;
					}
				}
			}
		}

		// --- set squadmate state & next state
		client->m_seshatProfile->SetSquadMateStatus(smid, ESMS_MISSION, now + params.duration, nextState);
	}

	// --- apply double reward bonus - doesn't take into account if there are more
	auto doubleReward = params.boni.find("double_trouble") != params.boni.end();
	auto tripleReward = params.boni.find("triple_trouble") != params.boni.end();
	auto bonusRewardCommander = client->m_seshatProfile->GetCommanderBonusModifierByName("cmdr_bonus_sqops_reward");

	// --- construct mission outcome flags
	int outcomeFlags = 0;
	if (success)
		outcomeFlags |= ESOO_Success;
	if (bonus)
		outcomeFlags |= ESOO_Bonus;
	if (doubleReward)
		outcomeFlags |= ESOO_DoubleReward;
	if (tripleReward)
		outcomeFlags |= ESOO_TripleReward;
	if (bonusRewardCommander)
		outcomeFlags |= ESOO_BonusRewardCommander;

	if (client->m_clanData && 
		squadOpsData.domination() &&
		client->m_clanData->domination.perk_value("sp_influence"))
	{
		outcomeFlags |= ESOO_DoubleInfluence;
	}

	// --- write mission data to profile
	client->m_seshatProfile->SetSquadOpOutcome(params.missionId.c_str(), outcomeFlags, xpBonus, params.boni.find("success_chance")->second, bonusRewardCommander);

	// --- handle zero duration case -> process the mission result right away and send it to the client (the squad_op_start credit activation won't do anything in this case)
	// --- for now this shouldn't happen, as we clamp the duration to 1 min on start; also the client doesn't handle well this case (might not pop the current menu correctly)
	// --- but just in case, this should keep the data consistent server-side
	if (!params.duration)
	{
		// --- generate another mission in the place of the started one
		auto idChapter = client->m_seshatProfile->FindSquadOpsIdChapterFromMissionId(params.missionId.c_str());
		EnsureSquadOpsMissionsForChapter(client, idChapter.chapter, NewSquadOp::WithDelay);

		FinishSquadOp(client, params.missionId);
	}

	// --- reset cached client params
	client->SetCurrentSquadOpParams(SquadOpParams());
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ClaimSquadOps(GSClient* client, const Json::Value& jConfig)
{
	auto missionId = jConfig["missionID"].asString();
	auto delayedTransactionId = client->m_seshatProfile->GetSquadOpDelayedTransactionId(missionId.c_str(), SeshatProfileManager::SquadOpDelayedTransactionType::End);
	auto expiry = client->m_seshatProfile->GetDelayedTransactionExpiry(delayedTransactionId.c_str());

	// --- not-finished ones must go through ProcessTransaction to make sure the price is payed
	if (expiry > GetLocalTime())
	{
		if (jConfig["expectCompleted"].asBool())
		{
			// --- client saw this as completed... 
			MP_LOG(DBG_CRIT, "GameServerFedManager: ClaimSquadOps client expected squad op to be completed, but it's not: missionId %s timeDiff %d client %s\n",
				missionId.c_str(), expiry - GetLocalTime(), client->m_credential.c_str());

			return; // --- TODO: any better ideas?
		}

		auto extraData = Json::Value(Json::objectValue);
		extraData["_delayed_transaction_id"] = delayedTransactionId;
		extraData["missionId"] = missionId;
		extraData["expediting"] = true;

		auto offerId = StringHash("squad_op_start");
		auto result = m_hestiaConfigManager->ProcessTransaction(client, offerId, extraData);

		// --- send update to the client
		ServerSendInventoryUpdate(client, offerId, std::move(result));
	}
	else
	{
		client->m_seshatProfile->StartTrackingInventoryChanges();
		FinishSquadOp(client, missionId);
		auto changes = client->m_seshatProfile->StopTrackingInventoryChanges();
		ServerSendInventoryUpdate(client, "squad_op_start", std::move(changes));
	}
}

void GameServerFedManager::ClaimAllSquadOps(GSClient* client)
{
	auto allStartedSquadOpsMissions = client->m_seshatProfile->AllStartedSquadOpsMissions();

	allStartedSquadOpsMissions.erase(
		std::remove_if(allStartedSquadOpsMissions.begin(), allStartedSquadOpsMissions.end(),
			[](const SeshatProfileManager::StartedSquadOp& startedSo)
			{
				if (startedSo.data_for != SquadOpsDataFor::ClanDomination &&
					startedSo.data_for != SquadOpsDataFor::BountyEvent)
					return false;
				return true;
			}),
		allStartedSquadOpsMissions.end());

	for (auto mission : allStartedSquadOpsMissions)
	{
		auto missionId = mission.mission_id;
		auto delayedTransactionId = client->m_seshatProfile->GetSquadOpDelayedTransactionId(missionId.c_str(), SeshatProfileManager::SquadOpDelayedTransactionType::End);
		auto expiry = client->m_seshatProfile->GetDelayedTransactionExpiry(delayedTransactionId.c_str());

		// claim all finished misisons
		if (expiry < GetLocalTime())
		{
			client->m_seshatProfile->StartTrackingInventoryChanges();
			FinishSquadOp(client, missionId);
			auto changes = client->m_seshatProfile->StopTrackingInventoryChanges();
			ServerSendInventoryUpdate(client, "squad_op_start", std::move(changes));
		}
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

Json::Value GameServerFedManager::FinishSquadOp(GSClient* client, const std::string& missionId, time_t timeOffset)
{
	int outcomeFlags = 0, cmdrBonus=0;
	SquadOpIdChapter squadOpIdChapter;
	mcfwutil::fsmap<StringHash, int> xpBonus;
	std::vector<RewardItem> bossReward, bossBonus;
	int64_t totalInfluence = 0;
	client->m_seshatProfile->GetSquadOpData(missionId.c_str(), &outcomeFlags, &xpBonus, &squadOpIdChapter, bossReward, bossBonus, &cmdrBonus);

	Json::Value jResult;

	auto squadOpsData = GetMultiplayerData()->FindSquadOpData(squadOpIdChapter);
	if (!squadOpsData)
		return jResult;

	int influenceMultiplier = (outcomeFlags & ESOO_DoubleInfluence) ? 2 : 1;
	int consecutiveFails = 0;

	auto giveRewards = [this, client, influenceMultiplier, squadOpIdChapter, &squadOpsData, &totalInfluence](Json::Value& jRewards, const std::vector<RewardItem>& rewards, float fMultiplier)
	{
		for (const auto& reward : rewards)
		{
			Json::Value extraData;
			extraData["source"] = "sqops";
			extraData["chapter"] = squadOpIdChapter.chapter;
			auto qty = (int64_t)_round(reward.qty * fMultiplier);
			auto id = reward.id;

			// --- check if it's a preset
			auto id2 = client->GetHestiaConfig()->PresetHash2Name(id);
			if (id2)
			{
				const auto& preset = client->GetHestiaConfig()->GetGachaPreset(client, id2);
				if (!preset.isNull())
				{
					id = StringHash(preset["id"].asCString());
					//qty with multiplayer
					qty = _round(reward.qty * fMultiplier);
					
					qty *= preset["qty"].asInt();
					//qty = _round(qty * fMultiplier);
				}
			}

			auto rewardCredit = client->GetHestiaConfig()->FindCredit(id);
			if (!rewardCredit)
			{
				MP_LOG(DBG_CRIT, "GameServerFedManager:FinishSquadOp could not find credit with id %u name %s"
					" client %s", id.GetHash(), id2 ? id2 : "(null)", client->m_credential.c_str());
				continue;
			}

			// --- apply modifiers specific to clan influence
			if (id == "clan_influence")
			{
				qty *= influenceMultiplier;
				client->GetHestiaConfig()->ApplyGlobalModifier("sqops.clan_influence", &qty);
			}
			
			// --- apply bonus from bounty event badges - temporary?
			if (squadOpsData.bounty())
			{
				auto bountyEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_BOUNTY);
				if (bountyEvent)
				{
					auto bountyChapter = squadOpIdChapter.chapter - SQUAD_OPS_BOUNTY_CHAPTER_INDEX;

					extraData["chapter"] = bountyChapter;
					extraData["for_event"] = bountyEvent->GetID();

					ApplyBountyRewardRules(client, bountyEvent->GetID(), bountyChapter, id, &qty);
				}
				else
				{
					// --- TODO: log completing bounty squad op with no active bounty event
				}
			}

			// --- apply global modifiers
			client->GetHestiaConfig()->ApplyGlobalModifier(id, &qty);

			if (id != StringHash("clan_influence")){
				// --- give the stuff
				client->GetHestiaConfig()->ChangeCreditBalance(client, id, qty, extraData);
			}
			else
			{
				totalInfluence += qty;
			}

			// --- send it to the client for display
			Json::Value entry;
			entry["id"] = rewardCredit->name;

			// --- ugly hack to fix MCFW-3795 - reassamble the pseudocredit's name for the client to display correctly
			if (rewardCredit->categoryHash == "squadmate_tier")
			{
				entry["id"] = entry["id"].asString() + "_Tier_" + std::to_string(rewardCredit->initial_qty); // --- initial_qty holds the rating
			}

			entry["qty"] = qty;
			jRewards.append(std::move(entry));
		}
	};

	jResult["bounty"] = squadOpsData.bounty();

	// --- give reward
	if (outcomeFlags & ESOO_Success)
	{
		auto& jRewards = jResult["reward"];
		float multiplier = 1.f;
		multiplier = (outcomeFlags & ESOO_DoubleReward) ? 2.f : multiplier;
		multiplier = (outcomeFlags & ESOO_TripleReward) ? 3.f : multiplier;
		multiplier += (outcomeFlags & ESOO_BonusRewardCommander) ? /*client->m_seshatProfile->GetCommanderBonusModifierByName("cmdr_bonus_sqops_reward", true)*/cmdrBonus * 0.01f : 0;
		giveRewards(jRewards, squadOpsData.boss()? bossReward : squadOpsData.reward(), multiplier);

		jResult["success"] = true;
		jResult["chapter"] = squadOpIdChapter.chapter;
		
		if (squadOpsData.domination())
		{
			antihackgs::GameServerFedManager::Instance()->AddAchievementProgress(client, StringHash("squad_ops.domination_wins"), 1);
		}
		else if (squadOpsData.bounty())
		{
			// --- TODO: bounty - achievement for bounty squad ops? take them into account for squad_ops.wins?
		}
		else
		{
			antihackgs::GameServerFedManager::Instance()->AddAchievementProgress(client, StringHash("squad_ops.wins"), 1);
		}
		consecutiveFails = 0;
	}
	else
	{
		consecutiveFails = client->m_seshatProfile->GetCustomMatchers()[SESHAT_LABEL_SQUAD_OPS_CONSECUTIVE_FAILED].asInt() + 1;
	}
	if (outcomeFlags & ESOO_Bonus)
	{
		auto& jRewards = jResult["bonus"];
		// --- does the multiplier apply to the bonus as well?
		// --- no more TODO: yes it does
		float multiplier = 1.f;
		multiplier = (outcomeFlags & ESOO_DoubleReward) ? 2.f : multiplier;
		multiplier = (outcomeFlags & ESOO_TripleReward) ? 3.f : multiplier;
		multiplier += (outcomeFlags & ESOO_BonusRewardCommander) ? /*client->m_seshatProfile->GetCommanderBonusModifierByName("cmdr_bonus_sqops_reward", true)*/cmdrBonus * 0.01f : 0;
		giveRewards(jRewards, squadOpsData.boss() ? bossBonus : squadOpsData.bonus(), multiplier);
	}

	if (totalInfluence > 0)
	{
		Json::Value extraData;
		extraData["source"] = "sqops";
		extraData["chapter"] = squadOpIdChapter.chapter;
		client->GetHestiaConfig()->ChangeCreditBalance(client, "clan_influence", totalInfluence, extraData);
	}
	// --- update crm matcher for consecutive failed squad ops
	client->m_seshatProfile->UpdateCustomMatcher(SESHAT_LABEL_SQUAD_OPS_CONSECUTIVE_FAILED, consecutiveFails);

	// --- put squadmates in their next states and award xp if any
	// --- also separately keep track of the changes in order to present them to the client
	auto& jMates = jResult["mates"];
	for (const auto& smEntry : xpBonus)
	{
		auto smid = smEntry.first;

		auto nextState = client->m_seshatProfile->GetSquadMateStatus(smid);

		// --- ignore if the squadmate no longer exists
		//if (nextState & (ESMS_UNKNOWN | ESMS_DELETED))
		//	continue;

		// --- go to next state
		if (nextState == ESMS_MISSION)
			nextState = client->m_seshatProfile->GetSquadMateNextStatus(smid);
		time_t nextStateTs = 0;
		switch (nextState)
		{
		case ESMS_MISSION_ENDED_HURT:
			nextState = ESMS_HEALING;
			nextStateTs = GetLocalTime() + timeOffset + GetMultiplayerData()->SquadmateHealTime();
			break;

		case ESMS_MISSION_ENDED_MIA:
			nextState = ESMS_MISSING;
			break;

		default:
			nextState = ESMS_IDLE;
			break;
		}
		
		client->m_seshatProfile->SetSquadMateStatus(smid, nextState, nextStateTs); // --- TODO: put next state to healing if missing?

		// --- add xp
		auto xp = smEntry.second;
		if (xp)
			client->m_seshatProfile->ChangeSquadMateXP(smid, xp);

		jMates[client->m_seshatProfile->SquadmateHash2String(smid)] = xp;
	}

	// --- squad mate changes for client display
	client->m_seshatProfile->AppendInventoryChanges("_squad_op_result", jResult);

	// --- remove mission data
	client->m_seshatProfile->RemoveSquadOp(missionId);

	// --- notify the quartermaster in case the mission was overflowing and was manually finished
	client->HandleQuartermasterSquadOpFinish(missionId);

	// --- for bounty missions also send an event state update to the client
	if (squadOpsData.bounty())
	{
		auto bountyEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_BOUNTY);
		if (bountyEvent)
		{
			ServerSendEventUpdate(client, bountyEvent->GetID());
		}
	}

	// --- TODO: maybe only award this for non-domination, non-bounty missions?
	client->m_seshatProfile->AddQuestProgress("complete_squad_ops", 1);
	client->m_eventShard->IncreaseQuestProgression(SESHAT_LABEL_EVENT_SHARD_QUEST_SQOPS_COMPLETE_MISSION, 1);

	return jResult;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::IsPvpSelfTest(const GSClient* client) const
{
	if (!client || client->m_seshatProfile->IsInvalid())
		return false;
	auto currentMission = client->m_seshatProfile->GetCurrentMissionData();
	// --- for reasons too shamefull to explain, currentMission.muid can be different from client->m_customSettings->m_missionUid
	// --- client->m_customSettings->m_missionUid is the correct one...
	// --- TOOD: startTime has the same problem?
	currentMission.muid = client->m_customSettings->m_missionUid;

	// --- some helper locals
	StringHash currentMissionTypeHash = m_missionsData->GetMissionTypeHash(currentMission.muid);
	bool isPVPMission = (currentMissionTypeHash == StringHash("Multiplayer"));
	bool isSelfAttack = isPVPMission && (client->m_seshatProfile->GetCurrentOpponentMode() & PvpOpponentType::SELFTEST) != 0;
	if (isPVPMission && !isSelfAttack && (client->m_seshatProfile->GetCurrentOpponentMode() & PvpOpponentType::RETRY) != 0)	// --- it may be retrying a self attack
	{
		const auto& opponent_data = client->m_seshatProfile->GetOpponentByType(client->m_seshatProfile->GetCurrentOpponentMode());
		isSelfAttack = opponent_data["selftest"].asBool();
	}

	return isSelfAttack;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

std::string GameServerFedManager::SetupTutorialSquadOp(GSClient* client)
{
	// --- TODO: check tutorial not completed

	client->m_seshatProfile->StartTrackingInventoryChanges();

	// --- add the squadmate
	// --- TODO: check the user doesn't already have one
	auto smid = client->m_seshatProfile->AddSquadMate(StringHash("IRIS"), 1);
	client->GetHestiaConfig()->ChangeCreditBalance(client, StringHash("IRIS"), 1);

	// --- add the mission
	auto tutorialSquadOpId = GetMultiplayerData()->TutorialSquadOpId();
	auto squadOpsData = GetMultiplayerData()->FindSquadOpData({ tutorialSquadOpId, 0 });

	auto missionId = client->m_seshatProfile->AddSquadOpsMission(0, squadOpsData.id().c_str());

	{
		SquadOpParams params;
		params.missionId = missionId;
		params.squadOpId = tutorialSquadOpId;
		params.chapter = 0;
		params.players.emplace_back(smid);
		params.boni["success_chance"] = 100;
		params.cost.emplace_back("time_sqops", squadOpsData.duration() / 60);
		params.duration = squadOpsData.duration();

		client->SetCurrentSquadOpParams(std::move(params));
	}

	// --- send changes to client
	auto changes = client->m_seshatProfile->StopTrackingInventoryChanges();
	ServerSendInventoryUpdate(client, "squad_op_tutorial", std::move(changes));

	return missionId;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendDeletableChapters(GSClient* client)
{
	// --- for now at least, send only once for each client
	if (client->m_deletableChaptersSent)
		return false;

	client->m_deletableChaptersSent = true;

	NetworkMessageW chaptersMessage;
	chaptersMessage.addGameMessageType(TCPMSG_SERVER_SEND_DELETABLE_CHAPTERS);

	const auto& missionData = GetAHMissionsData();
	auto deletableChapters = missionData->DeletableChapters(client->m_seshatProfile);
	if (deletableChapters.empty())
	{
		deletableChapters = { 0 };
	}
	else
	{
		// --- also keep chapters used by active global hunt events
		auto bountyEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_BOUNTY);
		if (bountyEvent && bountyEvent->IsActive())
		{
			std::vector<int> bountyLocations;
			auto eventData = m_eventsData->GetBountyEventData(bountyEvent->GetPreset());
			for (auto ci = 0; ci < eventData.ChapterCount(); ++ci)
			{
				auto mci = client->m_seshatProfile->GetBountyLocation(bountyEvent->GetID(), ci);
				bountyLocations.push_back(mci);
			}
			
			// --- remove any deletetableChapters found in bountyLocations
			deletableChapters.erase(std::remove_if(deletableChapters.begin(), deletableChapters.end(), [&bountyLocations](int chapter)
				{
					return std::find(bountyLocations.begin(), bountyLocations.end(), chapter) != bountyLocations.end();
				}), deletableChapters.end());
		}

		// --- also chapter used by miniops event
		auto miniopsEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_MINIOPS);
		if (miniopsEvent && miniopsEvent->IsActive())
		{
			auto eventData = m_eventsData->GetMiniopsEventData(miniopsEvent->GetPreset());
			auto mci = m_missionsData->ChapterFromInternalName(eventData.Chapter());

			// --- remove the miniops chapter
			deletableChapters.erase(std::remove_if(deletableChapters.begin(), deletableChapters.end(), [mci](int chapter)
			{
				return chapter == mci;
			}), deletableChapters.end());
		}
	}
	chaptersMessage.addBytesAndLen((const byte*)&deletableChapters[0], (unsigned int)deletableChapters.size());

	// also add deletable standalone DLC locations
	auto deleteableStandaloneDLC = missionData->DeletableStandaloneDLC(client->m_seshatProfile);
	chaptersMessage.addByte((byte)deleteableStandaloneDLC.size());
	for (auto hash : deleteableStandaloneDLC)
		chaptersMessage.addUInt(hash);

	chaptersMessage.packMessage(client->m_Crypto);

	if (chaptersMessage.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendDeletableChapters packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)chaptersMessage.getMessageBody(), chaptersMessage.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendDeletableChapters send message failed\n");
		return false;
	}

	return true;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ProcessGenericHermesNotification(GSClient* client, const std::string& msgId, const std::string& attachment)
{
	if (attachment.empty())
	{
		// --- TODO: get the message again from hermes - because of a bug in the client, the attachment in notifications is empty until 4.3.0a
		ScriptRequestGiftMessage(client->m_credential, msgId);
		return true;
	}

	Json::Value jData;
	auto ok = Json::Reader().parse(attachment, jData);
	if (!ok)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ProcessGenericHermesNotification with invalid attachment %s for %s\n", attachment.c_str(), client->m_credential.c_str());
		ScriptRequestDeleteGiftMessage(client->m_credential, msgId);
		return false;
	}

	if (client->m_seshatProfile->IsInvalid())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ProcessGenericHermesNotification for %s with invalid seshat profile - will process next time\n", client->m_credential.c_str());
		return false;
	}

	client->m_seshatProfile->StartTrackingInventoryChanges("hermes_notification");

	auto category = jData["category"].asString();
	if (category == "selfgift")
	{
		const auto& jItems = jData["items"];
		for (auto it = jItems.begin(), ite = jItems.end(); it != ite; ++it)
		{
			client->GetHestiaConfig()->ChangeCreditBalance(client, StringHash(it.memberName()), (*it).asInt());
		}
	}
	else
	{
		auto shouldAddNotification = true;
		if (category == "clan:season_reward" &&
			jData["info"].asString() == "48" &&
			client->GetHestiaConfig()->GetCreditBalance(client, "clan_prestige") > 0)
		{
			shouldAddNotification = false;
		}

		if (shouldAddNotification)
			client->m_seshatProfile->AddNotificationFromServer(category, jData["info"].asString(), jData["key"].asUInt(), (unsigned char)jData["mask"].asUInt());
	}

	auto data = client->m_seshatProfile->StopTrackingInventoryChanges();
	ServerSendInventoryUpdate(client, "hermes_notification", std::move(data));

	ScriptRequestDeleteGiftMessage(client->m_credential, msgId);

	return true;
}

