bool GameServerFedManager::ServerSendNewEncryptionKeys(GSClient * client)
{
#if USE_DATA_ENCRYPTION
	NetworkMessageW keysMessage;
	keysMessage.addGameMessageType(TCPMSG_SERVER_SEND_ENCRYPTION_KEY);

	const int BUFF_SIZE = 1024;
	std::vector<unsigned char> buffer(BUFF_SIZE);
	int messageSize = 0;

	client->m_Crypto->SendPublicKey(&buffer[0], BUFF_SIZE, messageSize);
	keysMessage.addBytes(&buffer[0], messageSize);
	keysMessage.packMessage(client->m_Crypto);

	bool bResult = ServerSendMessage(client->m_credential, (char*)keysMessage.getMessageBody(), keysMessage.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendNewEncryptionKeys send message failed\n");
		return false;
	}
#endif

	return true;
}

