//////////////////////////////////////////////REDEEM CODE////////////////////////////////////////////////////////////////////////

namespace
{
	struct ScripCheckRedeemCodeUserData
	{
		std::string credential;
		std::string clientId;
		std::string uniqueKey;
		std::string redeem_code;
	};

}	// --- namespace

void GameServerFedManager::ScriptRequestCheckRedeemCode(const GSClient* client, const char* redeemCode)
{
	std::map<std::string, std::string> customParams;
	customParams["client_id"] = client->m_clientId;
	customParams["coupon_code"] = redeemCode;

	//auto userData = new std::string(client->m_credential);
	auto* pUserData = new ScripCheckRedeemCodeUserData;
	pUserData->credential = client->m_credential;
	pUserData->clientId = client->m_clientId;
	pUserData->uniqueKey = std::to_string(client->m_seshatProfile->GenerateUniqueKey());
	pUserData->redeem_code = std::string(redeemCode);

	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_REDEEM_COUPON)->second, client->m_clientId, customParams, {}, callbackScriptRequestCheckRedeemCode, this, (void*)pUserData);
}

void GameServerFedManager::callbackScriptRequestCheckRedeemCode(const SRequest & requestData)
{
	GameServerFedManager* callerObj = (GameServerFedManager*)(requestData.m_callerObj);
	
	std::unique_ptr<ScripCheckRedeemCodeUserData> pUserData((ScripCheckRedeemCodeUserData*)requestData.m_userData);
	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "redeem_code script returned error %d - %s - %s", response["status"].asInt(), response["reason"].asCString(), response["coupon_code"].asCString());
		
		GSClient* client = callerObj->GetClient(pUserData->credential);
		if (client)
		{
			//send notification error to client
			client->m_seshatProfile->StartTrackingInventoryChanges("redeem_fail");
			client->m_seshatProfile->AddNotificationFromServer("redeem_fail", "Fail", 0, ENM_CATEGORY | ENM_INFO);
			Json::Value data = client->m_seshatProfile->StopTrackingInventoryChanges();
			callerObj->ServerSendInventoryUpdate(client, "redeem_fail", std::move(data));
		}

		return;
	}
	
	Json::Value coupon_data;
	Json::Reader().parse(response["coupon_data"].asString(), coupon_data);
	std::string offer_id = coupon_data["id"].asString();

	Json::Value items;
	items[offer_id] = 1;
	if(pUserData->redeem_code.length())
		items["redeem"] = pUserData->redeem_code; //ceg - hack to save redeem_code in transaction

	Json::Value entry;
	//entry["created"] = GetServerTime() - TODO!
	entry["items"] = items;
	entry["source"] = "redeem_code";
	entry["type"] = "inventory_delivery";
	
	std::string raw = Json::FastWriter().write(entry).c_str();
	MP_LOG(DBG_INFO, "--AddReedemCodeInPendingTransactions %s \n", raw.c_str());

	Json::Value entryRedeem;
	entryRedeem[std::string("pending_transactions.redeem_") + pUserData->uniqueKey] = entry;// entry;

	std::unique_ptr<ProfileOperation> operation(new ProfileOperation);
	operation->client_id = pUserData->clientId;
	operation->for_credential = pUserData->credential;
	operation->owner_credential = pUserData->credential;
	operation->operation = E_ProfileOperation::EPO_SAVE_REDEEM_PENDING_TRANSACTION;
	operation->data = nullptr;

	GameServerFedManager::Instance()->ScriptSetSeshatProfileField(entryRedeem, std::move(operation));
	
	MP_LOG(DBG_INFO, "redeem_code script success %s", response["coupon_code"].asCString());
}

