bool GameServerFedManager::ServerSendSpecialAdsWon(GSClient* client, const Json::Value& data, int adsType, const Json::Value& extraData)
{
	NetworkMessageW specialAdsmessage;
	specialAdsmessage.addGameMessageType(TCPMSG_SERVER_SEND_SPECIAL_ADS_INFO);
	specialAdsmessage.addString((const unsigned char*)Json::FastWriter().write(data).c_str());
	if(adsType)
		specialAdsmessage.addInt((int)adsType);
	if((adsType == 5 || adsType == 4) && extraData != Json::nullValue) //HC_SPIN
		specialAdsmessage.addString((const unsigned char*)Json::FastWriter().write(extraData).c_str());
	specialAdsmessage.packMessage(client->m_Crypto);

	if (specialAdsmessage.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: SendGachaInfoToClient packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)specialAdsmessage.getMessageBody(), specialAdsmessage.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: SendGachaInfoToClient send message failed\n");
		return false;
	}

	return true;
}

