void GameServerFedManager::CheckComebackRewardTimestamp(const GSClient* client)
{
	//check if comeback reward must be set - before now - in game_save is set
	auto tsLastSaved = client->m_seshatProfile->GetProfile()[SESHAT_GAME_SAVE][SESHAT_LABEL_NOW].asInt();
	auto rewardIdx = client->m_seshatProfile->GetProfile()[SESHAT_GAME_SAVE].isMember(SET_COMEBACK_REWARD) ? client->m_seshatProfile->GetProfile()[SESHAT_GAME_SAVE][SET_COMEBACK_REWARD].asInt() : 0;

	if (tsLastSaved == 0 || rewardIdx == -1) //a notification is pending
		return;
	
	time_t now = GameServerFedManager::Instance()->GetLocalTime();
	tsLastSaved -= (tsLastSaved % 86400);

	auto tsNow = now - (now % 86400);
//tsNow += COMEBACK_REWARD_MISSING_DAYS;
	if (tsNow - tsLastSaved >= COMEBACK_REWARD_MISSING_DAYS)
	{
		if (tsNow - tsLastSaved >= COMEBACK_REWARD_MISSING_DAYS2)
		{
			if (tsNow - tsLastSaved >= COMEBACK_REWARD_MISSING_DAYS3)
				client->m_seshatProfile->SetComebackGiftIsAvailable(3);
			else
				client->m_seshatProfile->SetComebackGiftIsAvailable(2);
		}
		else
			client->m_seshatProfile->SetComebackGiftIsAvailable(1);
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::GiveComebackReward(GSClient* client)
{
	//comeback reward
	auto rewardIdx = client->m_seshatProfile->GetProfile()[SESHAT_GAME_SAVE].isMember(SET_COMEBACK_REWARD)?client->m_seshatProfile->GetProfile()[SESHAT_GAME_SAVE][SET_COMEBACK_REWARD].asInt():0;
	if (rewardIdx > 0)
	{
		//give reward
		std::string offerName = "comeback_gift" + std::to_string(rewardIdx);
		auto offerId = Hash(offerName);
		if (client->GetHestiaConfig())
		{
			auto offer = client->GetHestiaConfig()->FindOffer(offerId);
			if (offer)
			{
				client->m_seshatProfile->AddNotificationFromServer("comeback_reward", "comeback_gift", offerId, ENM_CATEGORY | ENM_INFO | ENM_KEY);
				client->m_seshatProfile->SetComebackGiftIsAvailable(-1); //set notification pending
			}
		}
	}
}

