bool GameServerFedManager::CheckSendMotd(GSClient* client, const Json::Value& motdData)
{
	if (motdData == Json::nullValue)
		return false;

	// --- already sent at least once before - check if it changed
	const auto& message = motdData["msg"][client->m_language].asString();
	auto type = motdData["type"].asInt();
	auto messageHash = StringHash((motdData["day"].asString() + std::to_string(type) + message).c_str());

	bool shouldSend = messageHash != client->m_lastMotdHash;

	if (!shouldSend)
		return false;

	client->m_lastMotdHash = messageHash;

	if (message.empty())
		return false;

	Json::Value motd;
	motd["msg"] = message;
	motd["type"] = type;
	motd["id"] = messageHash.GetHash();

	NetworkMessageW motdMessage;
	motdMessage.addGameMessageType(TCPMSG_MOTD);

	motdMessage.addString((const unsigned char*)Json::FastWriter().write(motd).c_str());
	motdMessage.packMessage(client->m_Crypto);

	if (motdMessage.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: SendMotd packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)motdMessage.getMessageBody(), motdMessage.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: SendMotd send message failed\n");
		return false;
	}

	return true;
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UpdateMotd()
{
	auto now = GetLocalTime();
	if (m_nextMotdCheck && now < m_nextMotdCheck)
		return;

	if (m_motdData.empty())
		return;

	auto m_currentDay = now / (24 * 60 * 60);
	std::tm today = *localtime(&now);

	const auto& jMotd = m_motdData["motd"];
	const auto& jMonthData = jMotd[today.tm_mon % jMotd.size()]["month"];
	auto day = std::to_string(today.tm_mday);
	m_dayMotd = jMonthData[day];
	if(m_dayMotd != Json::nullValue)
		m_dayMotd["day"] = day;
	m_nextMotdCheck = (m_currentDay + 1) * (24 * 60 * 60) + 1;

	if (m_dayMotd != Json::nullValue)
	{
		for (auto& client : m_gsClientsList)
		{
			if (client.second)
				CheckSendMotd(client.second, m_dayMotd);
		}
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::CheatLeaveClan(GSClient* client)
{
	if (client->m_seshatProfile->GetClanTs(SESHAT_LABEL_OSIRIS_INFO_CLAN_TS_LEAVE) + m_serverSettings->GetClanLeaveInterval() <= GetLocalTime())
	{
		std::unique_ptr<ClanOperation> operation(new ClanOperation());
		operation->client_id = client->m_clientId;
		operation->for_credential = "me";
		operation->owner_credential = client->m_credential;
		operation->operation = ECO_KICK;

		const auto& clanData = client->m_seshatProfile->GetClanData();
		if (clanData.isNull())
		{
			MP_LOG(DBG_CRIT, "Client %s wants to leave clan without being in one\n", client->m_credential.c_str());
			return;
		}

		//operation->data["_score"] = std::to_string(client->m_seshatProfile->GetCachedPvpStats().elo);
		operation->data["name"] = client->m_seshatProfile->GetDisplayName();
		operation->data["id"] = client->m_fedCredential;
		operation->data["group_id"] = client->m_seshatProfile->GetClanData()[SESHAT_LABEL_OSIRIS_INFO_CLAN_ID];
		operation->data["no_data"] = true;

		ScriptClanKick(std::move(operation));
	}
	else
	{
		// --- send error message?
		Json::Value request;
		request["type"] = "leave_limit";
		request["time"] = client->m_seshatProfile->GetClanTs(SESHAT_LABEL_OSIRIS_INFO_CLAN_TS_LEAVE) + m_serverSettings->GetClanLeaveInterval() - GetLocalTime();
		ServerSendRequestResult(client, request);
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::SetupBountyChapter(GSClient* client, const ServerEvent* evt, int chapter, BountyChapterOp ops)
{
	auto eventData = m_eventsData->GetBountyEventData(evt->GetPreset());
	const auto& eventChapterData = eventData.ChapterData(chapter);

	// --- squad op missions for sabotage
	if (ops & BountyChapterOp::EnsureSquadOps)
	{
		// --- make sure these are sent to the client
		client->m_seshatProfile->StartTrackingInventoryChanges("bounty_so");

		// --- first see if any of the missions from the previous chapters need to be updated
		auto excludes = client->m_seshatProfile->AllAvailableSquadOpsMissions();
		auto chapterForDifficulty = HighesteCompletedBountyChapter(client);
		int difficulty = GetMultiplayerData()->SquadOpsDifficultyForChapter(chapterForDifficulty, SquadOpsDataFor::BountyEvent);
		for (int ci = 0; ci < chapter; ++ci)
		{
			auto toReplace = std::vector<const char*>();
			auto sochapter = SQUAD_OPS_BOUNTY_CHAPTER_INDEX + ci;
			auto chapterMissions = client->m_seshatProfile->SquadOpsMissions(sochapter);
			for (auto missionId : chapterMissions)
			{
				auto squadOpId = client->m_seshatProfile->GetSquadOpsIdChapterFromMissionId(sochapter, missionId);
				auto squadOpsData = GetMultiplayerData()->FindSquadOpData(squadOpId);
				if (squadOpsData && squadOpsData.difficulty() == difficulty) // --- difficulty should change
					continue;

				auto edtid = client->m_seshatProfile->GetSquadOpDelayedTransactionId(missionId, SeshatProfileManager::SquadOpDelayedTransactionType::End);
				if (!edtid.empty()) // --- started (either ongoing or completed)
					continue;

				toReplace.push_back(missionId);
			}

			if (!toReplace.empty())
			{
				// --- generate new missions
				auto newSquadOpIds = GetMultiplayerData()->RandomSquadOpForChapter(chapterForDifficulty, SquadOpsDataFor::BountyEvent, 
					(int)toReplace.size(), excludes);

				// --- replace them in the profile
				auto newSquadOpIdsIt = newSquadOpIds.begin();
				for (auto missionId : toReplace)
				{
					client->m_seshatProfile->ReplaceSquadOpsMission(sochapter, missionId, *newSquadOpIdsIt);
					++newSquadOpIdsIt;
					if (newSquadOpIdsIt == newSquadOpIds.end())
						newSquadOpIdsIt = newSquadOpIds.begin();
				}

				// --- append them to the excludes
				excludes.reserve(excludes.size() + newSquadOpIds.size());
				std::transform(newSquadOpIds.begin(), newSquadOpIds.end(), std::back_inserter(excludes), [](const char* id) { return StringHash(id); });
			}
		}

		// --- then add the squad ops for the current chapter
		{
			auto sochapter = SQUAD_OPS_BOUNTY_CHAPTER_INDEX + chapter;
			EnsureSquadOpsMissionsForChapter(client, sochapter, NewSquadOp::WithoutDelay);
		}

		auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
		if (!inventory_changes.empty())
		{
			GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, 0, std::move(inventory_changes));
		}
	}

	// --- bounty - generate random "puzzle pieaces" series - first chapter only at first, generate some more / regenerate as they are unlocked / consumed
	if (ops & BountyChapterOp::GenerateRandomPuzzle)
	{
		std::vector<int> pieces(eventChapterData.TotalMapFragments());
		std::iota(pieces.begin(), pieces.end(), 0);
		std::shuffle(pieces.begin(), pieces.end(), m_rng);
		client->m_seshatProfile->SetBountyMapFragmentsOrder(evt->GetID(), chapter, pieces);
	}

	// --- bounty - generate random missions - first chapter only - generate some more when chapters and unlocked; regenerate for all chapters when the last chapter's boss is killed
	if (ops & BountyChapterOp::GenerateRandomMissions)
	{
		// --- create the mission pool - all missions from the bounty mission pool for that location
		auto mci = client->m_seshatProfile->GetBountyLocation(evt->GetID(), chapter);
		auto location = GetAHMissionsData()->GetChapterInternalName(mci);
		auto pool = GetAHEventsData()->GetBountyMissionsPool().MissionsPool(location);

		// --- remove the already used missions
		for (int ci = 0; ci < chapter; ++ci)
		{
			auto cmci = client->m_seshatProfile->GetBountyLocation(evt->GetID(), ci);
			if (cmci != mci)
				continue;

			auto usedMissions = client->m_seshatProfile->GetBountyMissions(evt->GetID(), ci);
			pool.erase(std::remove_if(pool.begin(), pool.end(), [&usedMissions](int mi)
			{
				return std::find(usedMissions.begin(), usedMissions.end(), mi) != usedMissions.end();
			}), pool.end());
		}
		if ((int)pool.size() < eventChapterData.MissionCount())
		{
			MP_LOG(DBG_CRIT, "GameServerFedManager: SetupBountyChapter can't generate unique missions for bounty event %s chapter %d client %s - using predefined\n",
				evt->GetID().c_str(), chapter, client->m_fedCredential.c_str());

			auto missionsSet = chapter / (eventData.ChapterCount() / 2);
			pool = GetAHEventsData()->GetBountyMissionsPool().MissionsPool(location, missionsSet);
		}
		else
		{
			// --- shufle and pick the first missionCount ones
			auto chapterMissionCount = eventChapterData.MissionCount();
			if ((int)pool.size() > chapterMissionCount)
			{
				std::shuffle(pool.begin(), pool.end(), client->m_seshatProfile->GetRandomEngine(ERandomEngine::ER_BOUNTY_MISSIONS));
				pool.resize(chapterMissionCount);
			}

			// --- sort by max kills (good indication of difficulty)
			std::sort(pool.begin(), pool.end(), [missionsData = GetAHMissionsData(), client, mci, mbi = eventData.MissionType()](int mi1, int mi2)
			{
				auto mk1 = missionsData->MaxKills(client->m_seshatProfile, MissionUid(mci, mbi, mi1), nullptr);
				auto mk2 = missionsData->MaxKills(client->m_seshatProfile, MissionUid(mci, mbi, mi2), nullptr);

				return mk1 < mk2;
			});
		}
		client->m_seshatProfile->SetBountyMissions(evt->GetID(), chapter, pool);
	}

	if (ops & BountyChapterOp::UsePredefinedMissions)
	{
		auto mci = client->m_seshatProfile->GetBountyLocation(evt->GetID(), chapter);
		auto location = GetAHMissionsData()->GetChapterInternalName(mci);
		auto missionsSet = chapter / (eventData.ChapterCount() / 2);
		auto pool = GetAHEventsData()->GetBountyMissionsPool().MissionsPool(location, missionsSet);
		client->m_seshatProfile->SetBountyMissions(evt->GetID(), chapter, pool);
	}

	// --- bounty - choose random boss config
	// --- bounty - not the previous one if it exists
	if (ops & BountyChapterOp::GenerateRandomBoss)
	{
		auto bossConfigCount = eventChapterData.BossConfigCount();
		if (bossConfigCount > 1) // --- at least two configs - random
		{
			// --- create the pool
			std::vector<int> pool(bossConfigCount);
			std::iota(pool.begin(), pool.end(), 0);

			// --- remove the previous config
			auto previousConfig = client->m_seshatProfile->GetBountyBossConfig(evt->GetID(), chapter);
			if (previousConfig >= 0)
				pool.erase(pool.begin() + previousConfig);

			// --- choose one
			std::uniform_int_distribution<int> rnd(0, (int)pool.size() - 1);
			auto bossConfigIndex = rnd(client->m_seshatProfile->GetRandomEngine(ERandomEngine::ER_BOUNTY_MISSIONS));
			client->m_seshatProfile->SetBountyBossConfig(evt->GetID(), chapter, pool[bossConfigIndex]);
		}
		else if (bossConfigCount == 1) // --- only one config - just set it
		{
			client->m_seshatProfile->SetBountyBossConfig(evt->GetID(), chapter, 0);
		}
	}

	if (ops & BountyChapterOp::ComputeBossRewards)
	{
		// --- bounty - compute the rewards for killing the boss in this run and save it in seshat
		auto rewarded = client->m_seshatProfile->GetBountyMissionRewarded(evt->GetID(), chapter, eventChapterData.MissionCount());
		if (rewarded)
		{
			client->m_seshatProfile->SetBountyBossReward(evt->GetID(), chapter, *eventChapterData.BossSecondaryRewards());
		}
		else
		{
			// --- https://confluence.gameloft.org/display/MCFW/Global+Hunt+2 - 
			// --- Bounty Stars: remove reward scaling depending on the run index (so they just double from the perk)
			auto chapterCount = eventData.ChapterCount();
			//auto currentRun = client->m_seshatProfile->GetBountyBossKillCount(evt->GetID(), chapterCount - 1);
			int currentRun = 0;
			auto qty = (int)std::ceil((float)(chapter + 1) * (currentRun + 1) / chapterCount);

			Json::Value reward(Json::objectValue);
			reward["id"] = "bounty_star";
			reward["qty"] = qty;
			Json::Value rewards(Json::arrayValue);
			rewards.append(std::move(reward));

			client->m_seshatProfile->SetBountyBossReward(evt->GetID(), chapter, rewards);
		}
	}
}

