void GameServerFedManager::ResetBountyEvent(GSClient* client, const ServerEvent* evt)
{
	auto eventData = m_eventsData->GetBountyEventData(evt->GetPreset());
	auto chapterCount = eventData.ChapterCount();
	auto missionCount = eventData.ChapterData(0).MissionCount();

	// --- reset event

	// --- for each chapter:
	for (auto ci = 0; ci < chapterCount; ++ci)
	{
		// --- reset bomb tokens
		client->m_seshatProfile->ResetBountyBombs(evt->GetID(), ci);

		// --- reset map fragments
		client->m_seshatProfile->ResetBountyMapFragments(evt->GetID(), ci);

		// --- reset mission rewarded flag for the boss - the ones for the mission remain the same
		client->m_seshatProfile->ResetBountyMissionRewarded(evt->GetID(), ci, missionCount);

		// --- regenerate missions, using random ones, the puzzle pieces and the boss, recompute the boss rewards
		SetupBountyChapter(client, evt, ci, 
			BountyChapterOp::GenerateRandomPuzzle | 
			BountyChapterOp::GenerateRandomMissions | BountyChapterOp::GenerateRandomBoss | BountyChapterOp::ComputeBossRewards);
	}

	client->m_seshatProfile->ResetEvent(evt->GetID());

	// --- add a notification for the client
	client->m_seshatProfile->StartTrackingInventoryChanges("notice:bounty");
	client->m_seshatProfile->AddNotificationFromServer("bounty:reset", evt->GetID(), 0, ENM_CATEGORY | ENM_INFO);
	auto inventory_changes = client->m_seshatProfile->StopTrackingInventoryChanges();
	if (!inventory_changes.empty())
	{
		ServerSendInventoryUpdate(client, 0, std::move(inventory_changes));
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ApplyBountyRewardRules(GSClient* client, const std::string& eventId, int chapter, StringHash id, int64_t* qty) const
{
	// --- apply event badge bonus
	auto rewardFactor = client->m_seshatProfile->GetBountyBonus(eventId, "reward_factor");
	if (id == StringHash("bounty_token"))
	{
		rewardFactor += client->m_seshatProfile->GetBountyBonus(eventId, "bounty_token_factor");
	}

	*qty = *qty + *qty * rewardFactor / 100;

	// --- apply max qty for per-chapter currencies
	auto bountyEvent = client->FindEvent(eventId);
	auto eventData = GameServerFedManager::Instance()->GetAHEventsData()->GetBountyEventData(bountyEvent->GetPreset());

	if (id == StringHash("bomb_token"))
	{
		auto ownedQty = client->m_seshatProfile->GetBountyBombs(eventId, chapter);
		auto maxQty = eventData.BombTokens();
		if (ownedQty + *qty > maxQty)
			*qty = maxQty - ownedQty;
	}
	else
	{
		auto mapFragmentType = AHEventsData::BountyMapFragmentCreditToType(id);
		if (mapFragmentType >= 0)
		{
			auto ownedQty = client->m_seshatProfile->GetBountyMapFragments(eventId, chapter, mapFragmentType);
			auto maxQty = eventData.ChapterData(chapter).MapFragments(mapFragmentType);
			if (ownedQty + *qty > maxQty)
				*qty = maxQty - ownedQty;
		}
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

int GameServerFedManager::HighesteCompletedBountyChapter(GSClient* client) const
{
	auto bountyEvent = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_BOUNTY);
	if (!bountyEvent)
		return 0;
	return client->m_seshatProfile->HighesteCompletedBountyChapter(bountyEvent->GetID());
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UpdateMiniopsPveRewards(GSClient* client, const ServerEvent* evt)
{
	auto shouldSendEventUpdate = false;

	if (!evt)
	{
		evt = client->m_EventContainer.GetUniqueEvent(EVENT_TYPE_MINIOPS);

		// --- this happens when the highest unlocked chapter changes, so we should send an event update
		shouldSendEventUpdate = true;
	}

	if (!evt)
		return;

	auto muid = MissionUid();
	muid.chapter = client->m_seshatProfile->HighestUnlockedAccesableChapter();
	muid.block = m_missionsData->GetBlockIndex("Grind");
	muid.mission = 0;

	int64_t SC = 0, XP = 0;
	m_missionsData->GetMissionCompletedRewards(muid, false, &XP, &SC);

	Json::Value rewards;

	Json::Value scReward;
	scReward["id"] = "sc";
	scReward["qty"] = SC;
	rewards.append(std::move(scReward));

	Json::Value xpReward;
	xpReward["id"] = "xp";
	xpReward["qty"] = XP;
	rewards.append(std::move(xpReward));

	client->m_seshatProfile->SetMiniopsPveRewards(evt->GetID(), rewards);

	if (shouldSendEventUpdate)
		ServerSendEventUpdate(client, evt->GetID());
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ChatCommand(GSClient* client, const Json::Value& data)
{
	auto command = data["command"].asString();
	if (command == "help")
	{
		Json::Value resp;
		resp["data"]["_timestamp"] = GetServerTime();
		resp["id"] = std::to_string(resp["data"]["_timestamp"].asUInt64());

		// --- help
		{
			Json::Value entry;
			entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_HELP_COMMAND}";
			resp["entries"].append(entry);
		}
		// --- clan roster
		{
			Json::Value entry;
			entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_ROSTER_COMMAND}";
			resp["entries"].append(entry);
		}
		// --- clan top
		{
			Json::Value entry;
			entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_COMMAND}";
			resp["entries"].append(entry);
		}
		// --- clan war
		{
			Json::Value entry;
			entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_WAR_COMMAND}";
			resp["entries"].append(entry);
		}
		// --- clan domination
		{
			Json::Value entry;
			entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_DOMINATION_COMMAND}";
			resp["entries"].append(entry);
		}
		// --- clan top attackers
		{
			Json::Value entry;
			entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_ATTACKERS_COMMAND}";
			resp["entries"].append(entry);
		}
		// --- clan top squad
		{
			Json::Value entry;
			entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_SQUAD_COMMAND}";
			resp["entries"].append(entry);
		}
		// --- clan top donate
		{
			Json::Value entry;
			entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_DONATE_COMMAND}";
			resp["entries"].append(entry);
		}
		// --- clan join
		{
			Json::Value entry;
			entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_JOIN_COMMAND_HELP}";
			resp["entries"].append(entry);
		}
		// --- clan top domiantion
		{
			Json::Value entry;
			entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_TOP_DOMINATION_COMMAND_HELP}";
			resp["entries"].append(entry);
		}

		ServerSendChatCommand(client, resp);
	}
	else if (command == "roster")
	{
		if (client->m_clanData)
		{
			Json::Value resp;
			resp["data"]["_timestamp"] = GetServerTime();
			resp["id"] = std::to_string(resp["data"]["_timestamp"].asUInt64());

			// --- header
			resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_ROSTER_DOTS}";

			// --- entries
			int cnt = 0;
			for (const auto& member : client->m_clanData->members)
			{
				++cnt;
				Json::Value entry;
				entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_ROSTER_POSITION_NAME}";//[${NO}] ${NAME}
				entry["params"]["NAME"] = member.name;
				entry["params"]["NO"] = std::to_string(cnt);
				resp["entries"].append(entry);
			}

			ServerSendChatCommand(client, resp);
		}
	}
	else if (command == "top")
	{
		if (client->m_clanData)
		{
			Json::Value resp;
			resp["data"]["_timestamp"] = GetServerTime();
			resp["id"] = std::to_string(resp["data"]["_timestamp"].asUInt64());

			// --- header
			resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_DOTS}";

			// --- entries
			auto members = client->m_clanData->members;
			std::sort(members.begin(), members.end(), [](const ClanMember& l, const ClanMember& r) {return l.score > r.score; });
			int cnt = 0;
			StringHash fedIdHash(client->m_fedCredential.c_str());
			for (const auto& member : members)
			{
				++cnt;
				Json::Value entry;
				entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_POSITION_NAME_SCORE}";//"[${NO}] ${NAME} - ${SCORE}"
				entry["params"]["NAME"] = member.name;
				entry["params"]["NO"] = std::to_string(cnt);

				if (member.fed_id_hash == fedIdHash)
					entry["params"]["SCORE"] = std::to_string(client->m_seshatProfile->GetCachedPvpStats().elo);
				else
					entry["params"]["SCORE"] = std::to_string(member.score);

				resp["entries"].append(entry);
			}

			ServerSendChatCommand(client, resp);
		}
	}
	else if (command == "war")
	{
		//("Not at war", "At war with clan X - Invasion Phase/Attack Phase remaining time - Invasion status/Core HP status) 
		if (client->m_clanData)
		{
			Json::Value resp;
			resp["data"]["_timestamp"] = GetServerTime();
			resp["id"] = std::to_string(resp["data"]["_timestamp"].asUInt64());

			auto now = GameServerFedManager::GetCrtUTCTimeSeconds();
			auto phase = client->m_clanData->war.phase();
			if (phase == War::Phase::Invasion
				|| phase == War::Phase::InvasionResolving)
			{
				resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_AT_WAR_INVASION_PHASE}";//At war with clan ${NAME} – Invasion Phase
				// --- op name
				resp["header"]["params"]["NAME"] = client->m_clanData->war.opponent_name();
				// --- time remaining (min)
				auto time = client->m_clanData->war.time_battle_start() - now;
				if (time > 0)
					time /= 60;
				else
					time = 0;
				resp["header"]["params"]["MINUTES"] = time;
			}
			else if (phase == War::Phase::Battle
				|| phase == War::Phase::BattleResolving)
			{
				resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_AT_WAR_ATTACK_PHASE}";//At war with clan ${NAME} – Attack Phase
				// --- op name
				resp["header"]["params"]["NAME"] = client->m_clanData->war.opponent_name();
				// --- time remaining (min)
				auto time = client->m_clanData->war.time_war_end() - now;
				if (time > 0)
					time /= 60;
				else
					time = 0;
				resp["header"]["params"]["MINUTES"] = time;
				// --- my core hp
				{
					auto max = client->m_clanData->war.core_max_hp();
					auto damage = client->m_clanData->war.opponent_core_damage();
					resp["header"]["params"]["HP"] = War::format_core_damage_percent(max - damage, max);
				}
				// --- op core hp
				{
					auto max = client->m_clanData->war.opponent_core_max_hp();
					auto damage = client->m_clanData->war.core_damage();
					resp["header"]["params"]["OP_HP"] = War::format_core_damage_percent(max - damage, max);
				}
			}
			else
			{
				resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_NOT_AT_WAR}";
			}

			ServerSendChatCommand(client, resp);
		}
	}
	else if (command == "domination")
	{
		//("Zone not chosen", "Fighting for zone X - currently #x", "Controlling zone X")
		if (client->m_clanData)
		{
			Json::Value resp;
			resp["data"]["_timestamp"] = GetServerTime();
			resp["id"] = std::to_string(resp["data"]["_timestamp"].asUInt64());

			auto phase = client->m_clanData->domination.phase();
			if (phase == ClanDomination::Phase::Control
				&& client->m_clanData->domination.selected_zone() != StringHash())
			{
				resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_CONTROLLING_ZONE}";//"Controlling ${ZONE}";
				resp["header"]["params"]["ZONE"] = client->m_clanData->domination.selected_zone().GetHash();
			}
			else if (phase == ClanDomination::Phase::Domination
				&& client->m_clanData->domination.selected_zone() != StringHash())
			{
				auto rank = client->m_clanData->domination.get_rank();
				if (rank > 0)
				{
					resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_FIGHTING_FOR_ZONE_AND_PLACE}";//"Fighting for ${ZONE} - currently #${PLACE}";
					resp["header"]["params"]["PLACE"] = std::to_string(rank);
				}
				else
				{
					resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_FIGHTING_FOR_ZONE_AND_PLACE_UNRANKED}";//"Fighting for ${ZONE} - currently unranked";
				}
				resp["header"]["params"]["ZONE"] = client->m_clanData->domination.selected_zone().GetHash();
			}
			else
			{
				resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_ZONE_NOT_CHOSEN}";//"Zone not chosen";
			}

			ServerSendChatCommand(client, resp);
		}
	}
	else if (command == "topattackers")
	{
		if (client->m_clanData)
		{
			Json::Value resp;
			resp["data"]["_timestamp"] = GetServerTime();
			resp["id"] = std::to_string(resp["data"]["_timestamp"].asUInt64());

			// --- entries
			auto members = client->m_clanData->members;

			// --- get war id
			clan_ts_t warId = 0;
			auto phase = client->m_clanData->war.phase();
			if (phase == War::Phase::Invasion
				|| phase == War::Phase::InvasionResolving
				|| phase == War::Phase::Battle
				|| phase == War::Phase::BattleResolving)
			{	// --- get current war
				warId = client->m_clanData->war.id();
			}
			else
			{	// --- get last war anyone entered in
				std::for_each(members.begin(), members.end(), [&warId](const ClanMember& e) {
					auto war = e.contributions["war"].asInt64();
					if (warId < war)
						warId = war;
				});
			}

			if (warId == 0)
			{
				// --- header
				resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_NO_CLAN_WAR_DATA}";//No recent data available.
			}
			else
			{
				// --- header
				resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_ATTACKERS_LISTING}";//Top attackers:

				// --- remove invalid entries
				members.erase(std::remove_if(members.begin(), members.end(), [warId](const ClanMember& e) {return e.contributions["war"].asInt64() != warId; }), members.end());

				// --- sort
				std::sort(members.begin(), members.end(), [](const ClanMember& l, const ClanMember& r) {return l.contributions["Damage"].asInt64() > r.contributions["Damage"].asInt64(); });
				int cnt = 0;
				for (const auto& member : members)
				{
					++cnt;
					Json::Value entry;
					entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_POSITION_NAME_SCORE}";//"[${NO}] ${NAME} - ${SCORE}"
					entry["params"]["NAME"] = member.name;
					entry["params"]["SCORE"] = std::to_string(member.contributions["Damage"].asInt64());
					entry["params"]["NO"] = std::to_string(cnt);
					resp["entries"].append(entry);
				}
			}

			ServerSendChatCommand(client, resp);
		}
	}
	else if (command == "topsquad")
	{
		if (client->m_clanData)
		{
			Json::Value resp;
			resp["data"]["_timestamp"] = GetServerTime();
			resp["id"] = std::to_string(resp["data"]["_timestamp"].asUInt64());

			// --- entries
			auto members = client->m_clanData->members;

			// --- get war id
			clan_ts_t warId = 0;
			auto phase = client->m_clanData->war.phase();
			if (phase == War::Phase::Invasion
				|| phase == War::Phase::InvasionResolving
				|| phase == War::Phase::Battle
				|| phase == War::Phase::BattleResolving)
			{	// --- get current war
				warId = client->m_clanData->war.id();
			}
			else
			{	// --- get last war anyone entered in
				std::for_each(members.begin(), members.end(), [&warId](const ClanMember& e) {
					auto war = e.contributions["war"].asInt64();
					if (warId < war)
						warId = war;
				});
			}

			if (warId == 0)
			{
				// --- header
				resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_NO_CLAN_WAR_DATA}";//No recent data available.
			}
			else
			{
				// --- header
				resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_SQUAD_POWER_LISTING}";//Top squad power sent:

				// --- remove invalid entries
				members.erase(std::remove_if(members.begin(), members.end(), [warId](const ClanMember& e) {return e.contributions["war"].asInt64() != warId; }), members.end());

				// --- sort
				std::sort(members.begin(), members.end(), [](const ClanMember& l, const ClanMember& r) {
					return l.contributions["Offense"].asInt64() + l.contributions["Defense"].asInt64() > r.contributions["Offense"].asInt64() + r.contributions["Defense"].asInt64();
				});
				int cnt = 0;
				for (const auto& member : members)
				{
					++cnt;
					Json::Value entry;
					entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_POSITION_NAME_SCORE}";//"[${NO}] ${NAME} - ${SCORE}"
					entry["params"]["NAME"] = member.name;
					entry["params"]["SCORE"] = std::to_string(member.contributions["Offense"].asInt64() + member.contributions["Defense"].asInt64());
					entry["params"]["NO"] = std::to_string(cnt);
					resp["entries"].append(entry);
				}
			}

			ServerSendChatCommand(client, resp);
		}
	}
	else if (command == "topdonate")
	{
		if (client->m_clanData)
		{
			Json::Value resp;
			resp["data"]["_timestamp"] = GetServerTime();
			resp["id"] = std::to_string(resp["data"]["_timestamp"].asUInt64());

			// --- header
			resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_DONATIONS_LISTING}";//Top donations:

			// --- entries
			auto members = client->m_clanData->members;
			auto& history = client->m_clanData->base.get_history();
			std::for_each(members.begin(), members.end(), [&history](ClanMember& e) {
				auto& d = history[e.fed_id];
				e.last_online = d["safe_dust"].asInt64();
				e.officer_ts = d["clan_cash"].asInt64();
				e.joined_at = e.last_online / 1000 + e.officer_ts;
			});
			std::sort(members.begin(), members.end(), [&history](const ClanMember& l, const ClanMember& r) {return l.joined_at > r.joined_at; });
			int cnt = 0;
			for (const auto& member : members)
			{
				++cnt;
				Json::Value entry;
				entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_CLAN_TOP_DONATION_NAME_AMOUNTS}";//"[${NO}] ${NAME} – Gold: ${VAL1}  Allied Points: ${VAL2}"
				entry["params"]["NO"] = std::to_string(cnt);
				entry["params"]["NAME"] = member.name;
				entry["params"]["VAL1"] = std::to_string(member.last_online);
				entry["params"]["VAL2"] = std::to_string(member.officer_ts);
				resp["entries"].append(entry);
			}

			ServerSendChatCommand(client, resp);
		}
	}
	else if (command == "topdomination")
	{
		if (client->m_clanData)
		{
			Json::Value resp;
			resp["data"]["_timestamp"] = GetServerTime();
			resp["id"] = std::to_string(resp["data"]["_timestamp"].asUInt64());

			// --- header
			resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_TOP_DOMINATION_HEADER}";//Top influence contributions:

			// --- entries
			auto members = client->m_clanData->members;
			auto& history = client->m_clanData->domination.data()["history"];
			std::for_each(members.begin(), members.end(), [&history](ClanMember& e) {
				e.last_online = history[e.fed_id].asInt64();
			});
			std::sort(members.begin(), members.end(), [&history](const ClanMember& l, const ClanMember& r) {return l.last_online > r.last_online; });
			int cnt = 0;
			for (const auto& member : members)
			{
				++cnt;
				Json::Value entry;
				entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_TOP_DOMINATION_COMMAND}";//"[${NO}] ${NAME} – Influence: ${VAL1}"
				entry["params"]["NO"] = std::to_string(cnt);
				entry["params"]["NAME"] = member.name;
				entry["params"]["VAL1"] = std::to_string(member.last_online);
				resp["entries"].append(entry);
			}

			ServerSendChatCommand(client, resp);
		}
	}
	else if (command == "clanjoin")
	{
		if (client->m_clanData)
		{
			Json::Value resp;
			resp["data"]["_timestamp"] = GetServerTime();
			resp["id"] = std::to_string(resp["data"]["_timestamp"].asUInt64());

			auto now = GameServerFedManager::GetCrtUTCTimeSeconds();
			if (ClanData::is_owner(client) || ClanOfficers::is_officer(client))
			{
				// --- header
				resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_MEMBERS_DAYS_JOINED_HEADER}";//Members joined:

				// --- entries
				auto members = client->m_clanData->members;
				std::sort(members.begin(), members.end(), [](const ClanMember& l, const ClanMember& r) {return l.joined_at > r.joined_at; });
				int cnt = 0;
				for (const auto& member : members)
				{
					++cnt;
					Json::Value entry;
					entry["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_MEMBERS_DAYS_JOINED_COMMAND}";//"[${NO}] ${NAME} – Joined ${VAL1} days ago"
					entry["params"]["NO"] = std::to_string(cnt);
					entry["params"]["NAME"] = member.name;

					if (member.joined_at <= 0)
						break;

					auto time = now - member.joined_at;
					time /= 60 * 60 * 24; // --- get days

					entry["params"]["VAL1"] = std::to_string(time);
					resp["entries"].append(entry);
				}
			}
			else
			{
				// --- header
				resp["header"]["msg"] = "${STR_FPS_MENU_FLASH_CLAN_CHAT_QUERIES_DAYS_JOINED_COMMAND}";//You joined the clan ${DAYS} day(s) ago
				// --- time remaining (min)
				auto member = client->m_clanData->get_member(StringHash(client->m_fedCredential.c_str()));
				if (!member)
					return;
				auto time = now - member->joined_at;
				time /= 60 * 60 * 24; // --- get days
				resp["header"]["params"]["DAYS"] = std::to_string(time);
			}

			ServerSendChatCommand(client, resp);
		}
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::SetEloLadderProps(StringHash ladderId, EloSettings eloSettings)
{
	if (m_eloLadder &&
		m_eloLadder->current_ladder_id() == ladderId &&
		m_eloLadder->current_elo_settings() == eloSettings)
	{
		return;
	}

	auto md = GetMultiplayerData();
	auto hofSeasonData = md->HofDataForSeason(ladderId);
	if (hofSeasonData && hofSeasonData->hof_places > 0)
	{
		m_eloLadder = std::make_unique<LimitedHofEloLadder>(*this, ladderId, eloSettings, hofSeasonData->hof_places);
	}
	else
	{
		m_eloLadder = std::make_unique<UnlimitedHofEloLadder>(*this, ladderId, eloSettings);
	}

	m_mpTop = std::make_unique<MPTopLeaderboard>(*this);
	m_mpArena = std::make_unique<MPArenaLeaderboard>(*this);
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

GameServerFedManager::EloLadder::EloLadder(GameServerFedManager& mgr, StringHash ladderId, EloSettings eloSettings)
	: mgr_(mgr)
	, current_ladder_id_(ladderId)
	, current_elo_settings_(eloSettings)
{
	auto md = mgr_.GetMultiplayerData();
	auto hofSeasonData = md->HofDataForSeason(current_ladder_id_);
	min_hof_elo_ = hofSeasonData ? hofSeasonData->min_elo : 3400;
	// --- TODO: elo - CRIT log id no hof season data, refreh this when the file data is available
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UnlimitedHofEloLadder::refresh_for_client(GSClient* client)
{
	// --- client non-null

	if (!mgr_.IsClientEloRanked(client))
		return;

	if (client->m_lastTopRefresh == 0) // --- client just connected
	{
		// --- if we have no top data, get it now
		if (ts_top_ == 0)
		{
			auto op = std::unique_ptr<LadderOperation>(new LadderOperation());
			op->operation = ELO_GET_TOP_PLAYERS;
			op->owner_credential = client->m_credential;
			op->for_credential = client->m_credential;
			op->client_id = client->m_clientId;
			op->cookie = mgr_.GetLocalTime();

			op->offset = 0;
			op->limit = TOP_ENTRIES;

			mgr_.ScriptGetEloLadder(std::move(op));
		}

		// --- if we have no hof data, get it now
		if (ts_hof_ == 0)
		{
			auto op = std::unique_ptr<LadderOperation>(new LadderOperation());
			op->operation = ELO_GET_TOP;
			op->owner_credential = client->m_credential;
			op->for_credential = client->m_credential;
			op->client_id = client->m_clientId;
			op->cookie = mgr_.GetLocalTime();

			op->offset = 0;
			op->limit = HOF_ENTRIES;

			mgr_.ScriptGetEloLadder(std::move(op));
		}
	}

	if (ts_top_ != 0 && ts_hof_ != 0)
	{
		send_data_to_client(client);
	}

	client->m_lastTopRefresh = mgr_.GetLocalTime();
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UnlimitedHofEloLadder::on_get_error(std::unique_ptr<LadderOperation> operation)
{

}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UnlimitedHofEloLadder::on_data(std::unique_ptr<LadderOperation> operation, Json::Value&& jReply)
{
	auto md = mgr_.GetMultiplayerData();
	
	if (operation->operation == ELO_GET_TOP_PLAYERS)
	{
		// --- for now we only get replies from requests with limit TOP_ENTRIES
		auto is_initial_data = ts_top_ == 0;

		// --- ignore if older than what we have
		if (operation->cookie < ts_top_)
			return;
		ts_top_ = operation->cookie;

		auto& jLadderEntries = jReply["data"];

		// --- go through all entries to add league
		for (auto& entry : jLadderEntries)
		{
			auto elo = entry["score"].asInt();
			entry["league"] = md->FindLeague(current_elo_settings_, elo);
		}

		// --- update the lowest_top_score_
		lowest_top_score_ = jLadderEntries.empty() ? 0 : jLadderEntries[jLadderEntries.size() - 1]["score"].asInt();

		// --- store the data
		top_players_ = std::move(jLadderEntries);

		// --- assemble and send it to client(s)
		if (is_initial_data)
		{
			send_data_to_all_clients();
		}
		else
		{
			auto for_client = mgr_.GetClient(operation->for_credential);
			if (!for_client)
				return;

			send_data_to_client(for_client);
		}
	}
	else if (operation->operation == ELO_GET_TOP)
	{
		if (operation->limit == 1)
		{
			// --- if for_credential client no longer connected, return
			auto for_client = mgr_.GetClient(operation->for_credential);
			if (!for_client)
				return;

			// --- ignore if older than what the client has
			if (operation->cookie < for_client->GetHofEntryTs())
				return;

			auto client_entry = std::move(jReply["my_entry"]);

			auto hofSeasonData = md->HofDataForSeason(current_ladder_id_);
			const auto& hofSeasonIcon = hofSeasonData ? hofSeasonData->icon : "22";

			// --- add league to my entry
			client_entry["league"] = hofSeasonIcon;

			// --- add the fed id, since it's missing from my entry
			client_entry["id"] = for_client->m_fedCredential.substr(7, for_client->m_fedCredential.length() - 7);

			// --- store the data in the client
			for_client->SetHofEntry(std::move(client_entry), operation->cookie);

			// --- assemble and send it to the client
			send_data_to_client(for_client);
		}
		else
		{
			auto is_initial_data = ts_hof_ == 0;

			// --- ignore if older than what we have
			if (operation->cookie < ts_hof_)
				return;
			ts_hof_ = operation->cookie;

			auto& jLadderEntries = jReply["data"];

			auto hofSeasonData = md->HofDataForSeason(current_ladder_id_);
			const auto& hofSeasonIcon = hofSeasonData ? hofSeasonData->icon : "22";

			// --- go through all entries to add league and store the data
			hof_players_.clear();
			for (auto& entry : jLadderEntries)
			{
				auto elo = entry["score"].asInt();
				if (elo > min_hof_elo_)
				{
					entry["league"] = hofSeasonIcon;
					hof_players_.append(std::move(entry));
				}
				else
				{
					break;
				}
			}

			// --- get the lowest_hof_score_
			lowest_hof_score_ = hof_players_.empty() ? 3400 : hof_players_[hof_players_.size() - 1]["score"].asInt();

			// --- assemble and send it to clients
			if (is_initial_data)
			{
				send_data_to_all_clients();
			}
			else
			{
				auto for_client = mgr_.GetClient(operation->for_credential);
				if (!for_client)
					return;

				send_data_to_client(for_client);
			}
		}
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UnlimitedHofEloLadder::on_post(GSClient* client, std::unique_ptr<LadderOperation> operation)
{
	// --- client may be null
	
	// --- if the posted score is lower than the lowest top lb score, nothing to do
	// --- TODO: elo - maybe if the request was for a connected client, 
	// --- do a get in global_top with limit 1 to get the new overall rank, attach it to the existing top_lb data and send it to the client
	if (operation->score < lowest_top_score_)
	{
		return;
	}

	// --- if the posted score is lower than the hof entry score, start top refresh with limit TOP_ENTRIES
	if (operation->score <= min_hof_elo_ &&
		operation->operation == ELO_POST_TOP_PLAYERS)
	{
		auto op = std::unique_ptr<LadderOperation>(new LadderOperation(*operation));
		op->operation = ELO_GET_TOP_PLAYERS;
		op->owner_credential = operation->owner_credential;
		op->for_credential = operation->for_credential;
		op->client_id = operation->client_id;
		op->cookie = mgr_.GetLocalTime();

		op->offset = 0;
		op->limit = TOP_ENTRIES;

		mgr_.ScriptGetEloLadder(std::move(op));

		return;
	}

	if (operation->operation != ELO_POST_GLOBAL)
		return;

	// --- else the post is in global:

	// --- in hof even - quite the achievement :-/
	if (client && operation->score > min_hof_elo_)
	{
		GameServerFedManager::Instance()->SetAchievementProgress(client, StringHash("hof.enter"), 1);
	}

	// --- if the posted score is lower than the lowest hof score within HOF_ENTRIES, 
	// --- and the post was for a connected client, 
	// --- start a get in global_top with limit 1
	// --- and attach it to existing HOF data and send it to the client
	if (operation->score < lowest_hof_score_ &&
		operation->score > min_hof_elo_)
	{
		auto for_client = mgr_.GetClient(operation->for_credential);
		if (!for_client)
			return;

		auto op = std::unique_ptr<LadderOperation>(new LadderOperation(*operation));
		op->operation = ELO_GET_TOP;
		op->owner_credential = operation->owner_credential;
		op->for_credential = operation->for_credential;
		op->client_id = operation->client_id;
		op->cookie = mgr_.GetLocalTime();

		op->offset = 0;
		op->limit = 1;

		mgr_.ScriptGetEloLadder(std::move(op));

		return;
	}

	// --- else (if the posted score is higher than the lowest hof score within HOF_ENTRIES)
	// --- start a global_top get with HOF_ENTRIES limit
	if (operation->score > min_hof_elo_ ||
		lowest_hof_score_ == 0)
	{
		auto op = std::unique_ptr<LadderOperation>(new LadderOperation(*operation));
		op->operation = ELO_GET_TOP;
		op->owner_credential = operation->owner_credential;
		op->for_credential = operation->for_credential;
		op->client_id = operation->client_id;
		op->cookie = mgr_.GetLocalTime();

		op->offset = 0;
		op->limit = HOF_ENTRIES;

		mgr_.ScriptGetEloLadder(std::move(op));

		return;
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UnlimitedHofEloLadder::on_delete_from_top(std::unique_ptr<LadderOperation> operation)
{
	// --- the delete from top players was succesful - need to get the top again since the player is no longer there
	auto op = std::unique_ptr<LadderOperation>(new LadderOperation(*operation));
	op->operation = ELO_GET_TOP_PLAYERS;
	op->owner_credential = operation->owner_credential;
	op->for_credential = operation->for_credential;
	op->client_id = operation->client_id;
	op->cookie = mgr_.GetLocalTime();

	op->offset = 0;
	op->limit = TOP_ENTRIES;

	mgr_.ScriptGetEloLadder(std::move(op));
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UnlimitedHofEloLadder::additional_post_op(std::unique_ptr<LadderOperation> operation, std::map<std::string, std::string>&& customParams)
{
	// --- either post to or delete from top players leaderboard
	auto postScore = operation->score;

	if (postScore > min_hof_elo_)
	{
		auto op = std::unique_ptr<LadderOperation>(new LadderOperation(*operation));
		op->operation = ELO_DELETE_FROM_TOP_PLAYERS;
		op->owner_credential = operation->owner_credential;
		op->for_credential = operation->for_credential;
		op->client_id = operation->client_id;
		op->cookie = mgr_.GetLocalTime();

		op->offset = 0;
		op->limit = 0;

		mgr_.ScriptDeleteFromLadder(std::move(op));
	}
	else
	{
		// --- invalidate client m_hofEntry if any
		auto for_client = mgr_.GetClient(operation->for_credential);
		if (for_client)
		{
			for_client->ResetHofEntry();
		}

		customParams["type"] = "top_players";

		mgr_.ScriptPostEloTopPlayersLadder(std::move(operation), std::move(customParams));
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UnlimitedHofEloLadder::send_data_to_client(GSClient* client) const
{
	if (client->m_seshatProfile->IsInvalid())
		return;

	if (!mgr_.IsClientEloRanked(client))
		return;

	// --- if the client has a higher hof score than the lowest_hof_score_, invalidate it's entry
	if (!client->GetHofEntry().isNull() && client->GetHofEntry()["score"].asInt() > lowest_hof_score_)
	{
		client->ResetHofEntry();
	}
	else if (client->GetHofEntry().isNull() &&
		client->m_seshatProfile->GetCachedPvpStats().elo > min_hof_elo_ &&
		lowest_hof_score_ != 0 && 
		client->m_seshatProfile->GetCachedPvpStats().elo < lowest_hof_score_)
	{
		// --- if the client has no hof entry, but should have one, start a request for it now and don't send her the data until we have her entry
		auto op = std::unique_ptr<LadderOperation>(new LadderOperation());
		op->operation = ELO_GET_TOP;
		op->owner_credential = client->m_credential;
		op->for_credential = client->m_credential;
		op->client_id = client->m_clientId;
		op->cookie = mgr_.GetLocalTime();

		op->offset = 0;
		op->limit = 1;

		mgr_.ScriptGetEloLadder(std::move(op));

		return;
	}

	int clientEntryOffset = 500;
	time_t cookie = std::max(ts_top_, ts_hof_);
	Json::Value jLadder = hof_players_;

	if (!client->GetHofEntry().isNull())
	{
		jLadder.append(client->GetHofEntry());

		clientEntryOffset = client->GetHofEntry()["rank"].asInt();

		cookie = std::max(cookie, client->GetHofEntryTs());
	}

	for (const auto& tpEntry : top_players_)
	{
		auto topEntry = tpEntry;
		auto& topEntryRank = topEntry["rank"];
		topEntryRank = topEntryRank.asInt() + clientEntryOffset;
		jLadder.append(std::move(topEntry));
	}

	Json::Value jData;
	jData["data"] = std::move(jLadder);
	jData["cookie"] = cookie;

	mgr_.ServerSendEloLadder(client, StringHash("top"), Json::FastWriter().write(jData).c_str());
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::UnlimitedHofEloLadder::send_data_to_all_clients() const
{
	// --- don't send incomplete data
	if (ts_top_ == 0 || ts_hof_ == 0)
		return;

	const auto& clients = mgr_.m_gsClientsList;
	for (const auto& clientEntry : clients)
	{
		auto client = clientEntry.second;
		send_data_to_client(client);
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////
///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::LimitedHofEloLadder::refresh_for_client(GSClient* client)
{
	// --- client non-null

	if (!mgr_.IsClientEloRanked(client))
		return;

	if (client->m_lastTopRefresh == 0) // --- client just connected
	{
		// --- if we have no data, get it now
		if (ts_ == 0)
		{
			auto op = std::unique_ptr<LadderOperation>(new LadderOperation());
			op->operation = ELO_GET_TOP;
			op->owner_credential = client->m_credential;
			op->for_credential = client->m_credential;
			op->client_id = client->m_clientId;
			op->cookie = mgr_.GetLocalTime();

			op->offset = 0;
			op->limit = max_hof_entries_ + TOP_ENTRIES;

			mgr_.ScriptGetEloLadder(std::move(op));
		}
	}

	if (ts_ != 0)
	{
		send_data_to_client(client);
	}

	client->m_lastTopRefresh = mgr_.GetLocalTime();
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::LimitedHofEloLadder::on_get_error(std::unique_ptr<LadderOperation> operation)
{

}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::LimitedHofEloLadder::on_data(std::unique_ptr<LadderOperation> operation, Json::Value&& jReply)
{
	auto md = mgr_.GetMultiplayerData();

	if (operation->operation != ELO_GET_TOP)
		return;

	auto is_initial_data = ts_ == 0;

	// --- ignore if older than what we have
	if (operation->cookie < ts_)
		return;
	ts_ = operation->cookie;

	auto& jLadderEntries = jReply["data"];

	auto hofSeasonData = md->HofDataForSeason(current_ladder_id_);
	const auto& hofSeasonIcon = hofSeasonData ? hofSeasonData->icon : "23";

	// --- go through all entries to add league and store the data
	players_.clear();
	highest_top_score_ = 0;
	lowest_top_score_ = 0;
	int top_entries = 0;
	int lowest_hof_elo = std::numeric_limits<int>::max();
	for (auto& entry : jLadderEntries)
	{
		auto elo = entry["score"].asInt();
		auto rank = entry["rank"].asInt();

		auto in_hof = (elo > min_hof_elo_ && rank <= max_hof_entries_);
		if (in_hof && elo < lowest_hof_elo)
			lowest_hof_elo = elo;
		if (!in_hof && elo == lowest_hof_elo)
			in_hof = true;

		if (in_hof)
		{
			// --- check if we have a local client for this entry; if so, give the achivement
			auto fedId = std::string("fed_id:") + entry["id"].asString();
			auto client = mgr_.GetClient(fedId);
			if (client && !client->m_seshatProfile->IsInvalid())
			{
				GameServerFedManager::Instance()->SetAchievementProgress(client, StringHash("hof.enter"), 1);
			}

			// --- player in hof - put the hof icon
			entry["league"] = hofSeasonIcon;
			players_.append(std::move(entry));
		}
		else
		{
			if (!highest_top_score_)
				highest_top_score_ = elo;

			entry["league"] = md->FindLeague(current_elo_settings_, elo);
			players_.append(std::move(entry));
			++top_entries;
		}

		if (top_entries >= TOP_ENTRIES)
		{
			// --- have enough entries to populate both hof and top - stop
			lowest_top_score_ = elo;
			break;
		}
	}

	if (!highest_top_score_)
	{
		// --- no players -> the score limit is the default hof entry score
		highest_top_score_ = min_hof_elo_;
	}

	// --- assemble and send it to clients
	if (is_initial_data)
	{
		send_data_to_all_clients();
	}
	else
	{
		auto for_client = mgr_.GetClient(operation->for_credential);
		if (!for_client)
			return;

		send_data_to_client(for_client);
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::LimitedHofEloLadder::on_post(GSClient* client, std::unique_ptr<LadderOperation> operation)
{
	// --- client may be null

	// --- if the posted score is lower than the lowest top lb score, nothing to do
	// --- TODO: elo - maybe if the request was for a connected client, 
	// --- do a get in global_top with limit 1 to get the new overall rank, attach it to the existing top_lb data and send it to the client
	if (operation->score < lowest_top_score_)
		return;

	if (operation->operation != ELO_POST_GLOBAL)
		return;

	// --- the post is in global with a score higher than what we know to be the lowest score in top -> start a get
	auto op = std::unique_ptr<LadderOperation>(new LadderOperation(*operation));
	op->operation = ELO_GET_TOP;
	op->owner_credential = operation->owner_credential;
	op->for_credential = operation->for_credential;
	op->client_id = operation->client_id;
	op->cookie = mgr_.GetLocalTime();

	op->offset = 0;
	op->limit = max_hof_entries_ + TOP_ENTRIES;

	mgr_.ScriptGetEloLadder(std::move(op));
}

