void GameServerFedManager::OutpostsTopLeaderboard::refresh_for_client(GSClient* client, bool sendDataToClient)
{
	// --- client non-null
	if (!client)
		return;

	std::string currLb = mgr_.GetCurrentLadderId();

	if (lbId_ != currLb || client->m_lastOutpostsTopRefresh == 0) // --- client just connected
	{
		// --- if we have no data, get it now
		if (players_.empty() && !getting_)
		{
			getting_ = true;

			auto op = std::unique_ptr<LadderOperation>(new LadderOperation());
			op->operation = ELO_GET_OUTPOSTS_TOP;
			op->owner_credential = client->m_credential;
			op->for_credential = client->m_credential;
			op->client_id = client->m_clientId;
			op->cookie = mgr_.GetLocalTime();
			op->ladderId = lbId_;

			op->offset = 0;
			op->limit = TOP_ENTRIES;

			mgr_.ScriptGetMPLadder(std::move(op));

			clients_.insert(client->m_fedCredential);
		}
	}

	if (!players_.empty())
	{
		send_data_to_client(client, sendDataToClient);
	}
	else
	{
		clients_.insert(client->m_fedCredential);
	}

	if (lbId_ == currLb)
		client->m_lastOutpostsTopRefresh = mgr_.GetLocalTime();
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::OutpostsTopLeaderboard::on_get_error(std::unique_ptr<LadderOperation> operation)
{

}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::OutpostsTopLeaderboard::on_data(std::unique_ptr<LadderOperation> operation, Json::Value&& jReply)
{
	auto md = mgr_.GetMultiplayerData();

	if (operation->operation != ELO_GET_OUTPOSTS_TOP)
		return;

	// --- ignore if older than what we have
	if (operation->cookie < ts_)
		return;
	ts_ = operation->cookie;

	auto& jLadderEntries = jReply["data"];

	// --- go through all entries to get lowest and highest scores
	players_.clear();
	jPlayers_.clear();
	highest_top_score_ = 0;
	lowest_top_score_ = 0;
	int top_entries = 0;
	for (auto& entry : jLadderEntries)
	{
		auto elo = entry["score"].asInt();
		auto rank = entry["rank"].asInt();

		Json::Value rankData;
		rankData["rank"] = rank;
		rankData["score"] = elo;
		jPlayers_[StringHash(entry["id"].asCString())] = rankData;

		if (!highest_top_score_)
			highest_top_score_ = elo;

		//entry["league"] = md->FindLeague(current_elo_settings_, elo);
		players_.append(std::move(entry));
		++top_entries;

		if (top_entries >= TOP_ENTRIES)
		{
			lowest_top_score_ = elo;
			break;
		}
	}

	// --- assemble and send it to clients
	send_data_to_all_clients();
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::OutpostsTopLeaderboard::on_post(GSClient* client, std::unique_ptr<LadderOperation> operation)
{
	// --- client may be null

	// --- if the posted score is lower than the lowest top lb score, nothing to do
	// --- TODO - maybe if the request was for a connected client, 
	// --- do a get in global_top with limit 1 to get the new overall rank, attach it to the existing top_lb data and send it to the client
	if (operation->score < lowest_top_score_)
		return;

	if (operation->operation != ELO_POST_OUTPOSTS_TOP)
		return;

	// --- the post is in global with a score higher than what we know to be the lowest score in top -> start a get
	auto op = std::unique_ptr<LadderOperation>(new LadderOperation(*operation));
	op->operation = ELO_GET_OUTPOSTS_TOP;
	op->owner_credential = operation->owner_credential;
	op->for_credential = operation->for_credential;
	op->client_id = operation->client_id;
	op->cookie = mgr_.GetLocalTime();

	op->offset = 0;
	op->limit = TOP_ENTRIES;

	if (client)
		client->m_seshatProfile->SetOutpostsLb(op->ladderId);

	mgr_.ScriptGetMPLadder(std::move(op));

}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

Json::Value GameServerFedManager::OutpostsTopLeaderboard::get_data(const GSClient* client) const
{
	auto it = jPlayers_.find(StringHash(client->GetFedId().c_str()));
	if (it == jPlayers_.end())
		return Json::nullValue;
	return it->second;
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::OutpostsTopLeaderboard::send_data_to_client(GSClient* client, bool sendDataToClient) const
{
	if (client->m_seshatProfile->IsInvalid())
		return;

	// --- send data for client to display (if current season)
	if (lbId_ == mgr_.GetCurrentLadderId())
	{
		Json::Value jData;
		jData["data"] = players_;
		jData["cookie"] = ts_;

		mgr_.ServerSendEloLadder(client, StringHash("top_outposts"), Json::FastWriter().write(jData).c_str());
	}
	else // --- it's not the current season, so send rewards?
	{
		auto data = get_data(client);
		client->m_seshatProfile->CheckOutpostsRewardsForSeasonImpl(sendDataToClient, data["rank"].asInt(), data["score"].asInt(), lbId_);
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::OutpostsTopLeaderboard::send_data_to_all_clients() const
{
	// --- don't send incomplete data
	if (players_.empty())
		return;

	for (const auto& clientEntry : clients_)
	{
		auto for_client = mgr_.GetClient(clientEntry);
		if (!for_client)
			return;

		send_data_to_client(for_client, true);
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

GameServerFedManager::OutpostsTopLeaderboard& GameServerFedManager::GetOutpostsTop(const std::string& lbId)
{
	return m_outpostsTops.emplace(std::make_pair(StringHash(lbId.c_str()), GameServerFedManager::OutpostsTopLeaderboard(*this, lbId))).first->second;
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::RefreshOutpostsTop(GSClient* client, const std::string& lbId)
{
	auto& top = GetOutpostsTop(lbId);
	top.refresh_for_client(client);
}

