///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptSendEcommChinaRegistrationID(const SRequest& requestData)
{
	std::unique_ptr<std::string> credential((std::string*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	auto client = serverMgr->GetClient(*credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		//send error to client
		Json::Value jData;
		Json::Reader().parse(response["response"].asCString(), jData);
		std::string details = jData["details"].asString();
		GameServerFedManager::Instance()->ServerSendEcommResponseChinaRegistration(client, EcommChOp::OP_SEND_SMS, response["status"].asInt(), jData["description"].asCString(), details.c_str());
		//erase data from player profile?

		MP_LOG(DBG_WARN, "ScriptSendEcommChinaRegistrationID script returned error %d - %s %s for %s", response["status"].asInt(), jData["description"].asCString(), details.c_str(), credential->c_str());
		return;
		
	}
	if (client->GetHestiaConfig()->IsChinaPhoneValidationRequired())
	{
		//sms was sent ok - save to seshat
		client->m_seshatProfile->SaveEcommRegistrationSMSSent(true);
	}
	//else
	//{
	//	//accept offer
	//	auto offerId = StringHash("china_registration_gift");
	//	const auto result = GameServerFedManager::Instance()->GetHestiaConfigManager()->ProcessTransaction(client, offerId, Json::Value::null);
	//	GameServerFedManager::Instance()->ServerSendInventoryUpdate(client, offerId, std::move(result));
	//}
	//send success to client
	GameServerFedManager::Instance()->ServerSendEcommResponseChinaRegistration(client, EcommChOp::OP_SEND_SMS, response["status"].asInt());

}

bool  GameServerFedManager::ServerSendEcommResponseChinaRegistration(GSClient* client, int operationType, int status, std::string errorType, std::string errorMessage)
{
	NetworkMessageW ecommCHResponseMessage;
	ecommCHResponseMessage.addGameMessageType(TCPMSG_SERVER_SEND_ECOMM_RESPONSE_CHINA_REGISTRATION);
	ecommCHResponseMessage.addInt(operationType);
	if (operationType == EcommChOp::OP_SEND_PREGS)
	{
		ecommCHResponseMessage.addString((const unsigned char*)ECOMM_CHINA_REGISTRATION_MOBILE_PREG);
		ecommCHResponseMessage.addString((const unsigned char*)ECOMM_CHINA_REGISTRATION_NATIONAL_ID_PREG);
		ecommCHResponseMessage.addString((const unsigned char*)ECOMM_CHINA_REGISTRATION_NAME_PREG);
		ecommCHResponseMessage.addString((const unsigned char*)ECOMM_CHINA_REGISTRATION_PIN_PREG);
		ecommCHResponseMessage.addInt(ECOMM_CHINA_REGISTRATION_NO_IAP_DAYS);
	}
	else
	{
		ecommCHResponseMessage.addInt(status);
		ecommCHResponseMessage.addString((const unsigned char*)errorType.c_str());
		ecommCHResponseMessage.addString((const unsigned char*)errorMessage.c_str());
	}
	ecommCHResponseMessage.packMessage(client->m_Crypto);

	if (ecommCHResponseMessage.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendEcommResponseChinaRegistration packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)ecommCHResponseMessage.getMessageBody(), ecommCHResponseMessage.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendEcommResponseChinaRegistration send message failed\n");
		return false;
	}

	return true;
}

