///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

struct ConnectToMMServerCustomData
{
	std::string credential;
	std::string fed_id;
	std::string client_id;
};

void GameServerFedManager::ConnectToMMServer(GSClient* client, bool allow_local)
{
	if (!m_commsManager || !m_commsManager->alive())
	{
		m_commsManager.reset(new comms::manager(getTime));
	}

	client->m_mpStartAutomatch = time(nullptr);
	client->m_mpAnubisRoom = Json::Value( Json::ValueType::objectValue );

	if (m_MMServerConnection.connection() && !m_MMServerConnection.connection()->valid())
		HandleMMDisconnect(comms::Connection_error::DISCONNECTED);

	// --- if connection to MMServer is established, use it
	if (m_MMServerConnection.isDone())
	{
		Json::Value room;
		room["pandora_url"] = m_RequestsManager->GetPandoraUrl();
		room["ets_gs_url"] = m_RequestsManager->GetEtsGSUrl();

		// --- add client to pending list
		if (std::find(m_MMServerConnection.pendingClients.begin(), m_MMServerConnection.pendingClients.end(), client->m_credential) == m_MMServerConnection.pendingClients.end())
			m_MMServerConnection.pendingClients.push_back(client->m_credential);

		// --- add the pending clients to the room
		for (const auto &pendingClientCredential : m_MMServerConnection.pendingClients)
		{
			auto pendingClient = GetClient(pendingClientCredential);
			if (pendingClient && !pendingClient->mp_cancel_automatch)
			{
				Json::Value profile;
				if (pendingClient->mm_is_Arena_TLE)
					AddMPTLEDataToProfile(pendingClient, &profile);
				else
					AddMPDataToProfile(pendingClient, &profile);
				profile["credential"] = pendingClient->m_credential;
				profile["fed_id"] = pendingClient->GetFedId();
				profile["matchmake_id"] = "1";
				if (pendingClient->mm_is_Arena_TLE)
					profile["matchmake_id"] = "2";
				profile["client_id"] = pendingClient->m_clientId;
				profile["access_token"] = pendingClient->GetAccessToken();
				room["members"].append(std::move(profile));
			}
		}
		m_MMServerConnection.pendingClients.clear();

		// --- inform MM about a new client wanting to match
		{
			auto msg = m_MMServerConnection.connection()->new_message();

			bool b = msg.add_small_int(mmserver::MMAHMessageId::Init);
			room["msg"] = (int)mmserver::MMAHMessageId::Init;
			b |= msg.add_string(Json::FastWriter().write(room));
			msg.send();
			MP_LOG(DBG_INFO, "Send MM INIT b %s\n", (b ? "true" : "false"));
		}
		return;
	}

	// --- when the connection finishes we need to also send this client
	if (std::find(m_MMServerConnection.pendingClients.begin(), m_MMServerConnection.pendingClients.end(), client->m_credential) == m_MMServerConnection.pendingClients.end())
		m_MMServerConnection.pendingClients.push_back(client->m_credential);

	// --- start AH <-> MM connection if it's not in progress
	if (m_MMServerConnection.isInProgress())
		return;
	m_MMServerConnection.setInProgress();

#if defined WIN32
	if (allow_local)
	{
		auto cred = m_MMServerConnection.pendingClients[0];
		auto connect_cb = [cred, this](comms::Connection_error status, int error, comms::connection q)
		{
			auto client = GetClient(cred);

			if (status == comms::Connection_error::OK)
			{
				m_MMServerConnection.connection(new comms::connection(q));
				m_MMServerConnection.setDone();
				if (client)
					ConnectToMMServer(client, false);
			}
			else if (status == comms::Connection_error::CONNECTERROR)
			{
				MP_LOG(DBG_WARN, "Connection to localhost refused\n");
				HandleMMDisconnect(q, comms::Connection_error::DISCONNECTED);
				// try again with allow_local set to false
				if (client)
					ConnectToMMServer(client, false);
			}
			else
			{
				MP_LOG(DBG_WARN, "Connection to localhost failed for other reason\n");
				HandleMMDisconnect(q, status, error);
			}
		};

		auto disconnect_cb = [this](comms::Connection_error status, int error, comms::connection q)
		{
			MP_LOG(DBG_INFO, "MM disconnected from local AH reason %s error %d socket %d\n", comms::to_string(status), error, q.socket());
			// send a harmless DISCONNECTED status to allow client to wait for Anubis connection
			if (status == comms::Connection_error::CONNECTERROR)
				status = comms::Connection_error::DISCONNECTED;
			HandleMMDisconnect(q, status, error);
		};

		// --- baobab -> 10.58.12.85
		// --- viorel -> 10.58.11.145
		m_commsManager->connect(comms::address("127.0.0.1", 35353), comms::Connection_type::STREAM, 0, connect_cb, disconnect_cb, nullptr);
		return;
	}
#endif

	//Json::Value profile;
	//AddMPDataToProfile(client, &profile);

	std::map<std::string, std::string> customParams = {
		{ "credential",				client->m_credential },
		{ "room_id",				GetUUID("mm_id") },
		//{ "user",					Json::FastWriter().write(profile) },
		//{ "timeout",				"10" },
		//{ "room_search_timeout",	"5" },
	};

	auto customData = new ConnectToMMServerCustomData{ client->m_credential, client->GetFedId(), client->m_clientId };
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_MMSERVER)->second, client->m_clientId, customParams, {}, callbackConnectToMMServer, this, customData);
	return;
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void SendMMDisconnectMessage(comms::connection *connection, GSClient *client, int reason, int error)
{
	if (connection->status() == comms::Connection_status::CONNECTED)
	{
		// if mm server connection is valid, send request to remove player from queue
		Json::Value json;
		json["msg"] = int(mmserver::MMAHMessageId::RequestDisconnect);
		json["reason"] = reason;
		json["error"] = error;
		if (client)
		{
			json["credential"] = client->m_credential;
			json["fed_id"] = client->GetFedId();
		}
		auto wmsg = connection->new_message();
		wmsg.add_small_int(mmserver::MMAHMessageId::RequestDisconnect);
		wmsg.add_string(std::move(json.toCompactString()));
		wmsg.send();
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::HandleMMDisconnect(GSClient *client, mmserver::RequestDisconnectReason reason, int error)
{
	// remove client if he was pending a connection with mm server
	m_MMServerConnection.pendingClients.erase(std::remove(m_MMServerConnection.pendingClients.begin(), m_MMServerConnection.pendingClients.end(), client->m_credential), m_MMServerConnection.pendingClients.end());
	if (m_MMServerConnection.isDone())
		SendMMDisconnectMessage(m_MMServerConnection.connection(), client, (int)reason, error);
}

void GameServerFedManager::HandleMMDisconnect(comms::connection q, comms::Connection_error reason, int error)
{
	if (!m_MMServerConnection.connection() || *m_MMServerConnection.connection() == q)
	{
		HandleMMDisconnect(reason, error);
	}
}

void GameServerFedManager::HandleMMDisconnect(comms::Connection_error reason, int error)
{
	if (m_MMServerConnection.isDone())
		SendMMDisconnectMessage(m_MMServerConnection.connection(), nullptr, (int)reason, error);
	if (m_MMServerConnection.connection())
	{
		m_MMServerConnection.connection()->close(reason, error);
		delete m_MMServerConnection.connection();
	}
	m_MMServerConnection.connection(nullptr);

	if (reason != comms::Connection_error::DISCONNECTED)
	{
		// --- notify the pending clients that MM connection closed
		for (const auto& pendingClientCredential : m_MMServerConnection.pendingClients)
		{
			auto pendingClient = GetClient(pendingClientCredential);
			if (pendingClient && !pendingClient->mp_cancel_automatch)
			{
				// --- send message to client to exit the waiting screen
				ServerSendAutomatchCommand(pendingClient, AutomatchCommand::ServerAutomatchError);
			}
		}
		m_MMServerConnection.pendingClients.clear();
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

struct EncryptTokenCustomData
{
	std::string credential;
	std::string fed_id;
	Json::Value room;
};

void GameServerFedManager::callbackConnectToMMServer(const SRequest& requestData)
{
	std::unique_ptr<ConnectToMMServerCustomData> customData((ConnectToMMServerCustomData*)requestData.m_userData);
	auto serverMgr = (GameServerFedManager*)(requestData.m_callerObj);

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (requestData.m_errorCode || response["status"].asInt() != 200)
	{
		MP_LOG(DBG_WARN, "ConnectToMMServer returned error %d for %s\n", response["status"].asInt(), customData->credential.c_str());
		//TODO: if status is 409 retry the connection
		serverMgr->HandleMMDisconnect(comms::Connection_error::RECVERROR, requestData.m_errorCode);
		return;
	}

	Json::Value room;
	Json::Reader().parse(response["room"].asCString(), room);

	comms::address address(room["controller_public_ip"].asString(), room["controller_port"].asInt());
	serverMgr->m_MMServerConnection.public_ips.clear();
	serverMgr->m_MMServerConnection.public_ips.push_back(room["controller_public_ip"].asString());
	for (const auto& ip : room["controller_public_ips"])
	{
		auto str_ip = ip.asString();
		if (std::find(serverMgr->m_MMServerConnection.public_ips.begin(), serverMgr->m_MMServerConnection.public_ips.end(), str_ip) == serverMgr->m_MMServerConnection.public_ips.end())
		{
			serverMgr->m_MMServerConnection.public_ips.push_back(std::move(str_ip));
		}
	}

	auto cred = customData->credential;
	auto fed = customData->fed_id;
	auto client_id = customData->client_id;

	auto connect_cb = [serverMgr](comms::Connection_error status, int error, comms::connection q)
	{
		if (status == comms::Connection_error::OK)
		{
			serverMgr->m_MMServerConnection.connection(new comms::connection(q));
			serverMgr->m_MMServerConnection.setInProgress();
		}
		else
		{
			//wait for disconnect_cb
		}
	};

	auto disconnect_cb = [serverMgr](comms::Connection_error status, int error, comms::connection q)
	{
		MP_LOG(DBG_INFO, "[callbackConnectToMMServer] disconnected reason %s error %d socket %d\n", comms::to_string(status), error, q.socket());
		serverMgr->HandleMMDisconnect(q, status, error);
	};

	std::string buff;
	auto data_cb = [cred, fed, client_id, serverMgr, buff, room](comms::connection q) mutable -> int
	{
		size_t n = buff.length();
		buff.resize(n + 1024);
		int i = ::recv(q.socket(), &buff[n], 1024, 0);
		if (i < 0)
		{
			int error = comms::manager::get_errno();
			MP_LOG(DBG_WARN, "data_cb read error %d %s\n", error, comms::manager::strerror(errno));
			return -1;
		}

		buff.resize(n + i);

		auto bn = buff.find('\n');
		if (bn != std::string::npos)
		{
			Json::Value root;
			auto ok = Json::Reader().parse(&*buff.begin(), &*(buff.begin() + bn), root);
			if (ok)
			{
				auto nonce = root["nonce"].asString();
				//serverMgr->ScriptEncryptToken(client, root["nonce"].asString(), std::move(room));
				std::map<std::string, std::string> customParams = {
					{ "credential",		cred },
					{ "nonce",			nonce },
				};

				auto customData = new EncryptTokenCustomData{ cred, fed, std::move(room) };
				serverMgr->m_RequestsManager->StartNewRequest(serverMgr->m_scriptTaskNames.find(FED_TASK_ENCRYPT_TOKEN)->second, client_id, customParams, {}, callbackMMServerToken, serverMgr, customData);
				return 1;
			}

			MP_LOG(DBG_WARN, "Invalid JSON from Anubis\n");
			return 1;
		}

		return 1;
	};

	// --- if the manager has managed to quit to this point, create a new one
	if (!serverMgr->m_commsManager)
	{
		serverMgr->m_commsManager.reset(new comms::manager(getTime));
	}

	serverMgr->m_commsManager->connect(address, comms::Connection_type::STREAM, 0, connect_cb, disconnect_cb, data_cb);
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackMMServerToken(const SRequest& requestData)
{
	std::shared_ptr<EncryptTokenCustomData> customData((EncryptTokenCustomData*)requestData.m_userData);
	auto serverMgr = (GameServerFedManager*)(requestData.m_callerObj);

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (requestData.m_errorCode || response["status"].asInt() != 200)
	{
		MP_LOG(DBG_WARN, "ScriptEncryptToken script returned error %d for %s\n", response["status"].asInt(), customData->credential.c_str());
		serverMgr->HandleMMDisconnect(comms::Connection_error::RECVERROR, requestData.m_errorCode);
		return;
	}

	std::string buff;
	auto data_cb = [serverMgr, buff, customData](comms::connection q) mutable -> int
	{
		size_t n = buff.length();
		buff.resize(n + 1024);
		int i = ::recv(q.socket(), &buff[n], 1024, 0);
		if (i < 0)
		{
			int error = comms::manager::get_errno();
			MP_LOG(DBG_WARN, "data_cb 2 read error %d %s\n", error, comms::manager::strerror(errno));
			return -1;
		}

		buff.resize(n + i);

		auto bn = buff.find('\n');
		if (bn != std::string::npos)
		{
			Json::Value root;
			auto ok = Json::Reader().parse(&*buff.begin(), &*(buff.begin() + bn), root);
			if (ok)
			{
				serverMgr->m_MMServerConnection.setDone();
				auto client = serverMgr->GetClient(customData->credential);
				if (client)
					serverMgr->ConnectToMMServer(client, false);
				return 0;
			}

			MP_LOG(DBG_WARN, "Invalid JSON from Anubis 2\n");
			return 1;
		}

		return 1;
	};

	auto connection = serverMgr->m_MMServerConnection.connection();
	if (!connection)
	{
		MP_LOG(DBG_INFO, "callbackMMServerToken connection null client %s\n", customData->credential.c_str());
		return;
	}
	connection->set_new_data_available_callback(data_cb);

	Json::Value json;
	json["access_token"] = response["encrypted_token"];
	json["action"] = "connect game";
	json["room_id"] = customData->room["id"];
	auto jsonStr = Json::FastWriter().write(json) + "\n";
	auto i = ::send(connection->socket(), jsonStr.data(), (int)jsonStr.length(), 0);
	if (i < (int)jsonStr.length())
	{
		MP_LOG(DBG_WARN, "Sent only %d instead of %d bytes to Anubis controller for client %s\n", i, jsonStr.length(), customData->credential.c_str());
	}
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

struct AutomatchCustomData
{
	std::string credential;
	int cookie;
};

void GameServerFedManager::ScriptAutomatch(GSClient* client, bool force_anubis)
{
	if (!m_commsManager)
	{
		m_commsManager.reset(new comms::manager(getTime));
	}

	client->m_anubisCookie = m_rng();

#if defined WIN32
	if (!force_anubis)
	{
		client->mp_public_ips.clear();
		auto cred = client->m_credential;
		auto fed = client->m_fedCredential.substr(client->m_fedCredential.find(':') + 1);
		client->m_mpStartAutomatch = time(nullptr);
		client->m_mpAnubisRoom.clear();	// --- fake room
		client->m_mpAnubisRoom["id"] = "local";
		client->m_mpAnubisRoom["member_count"] = 0;
		Json::Value profile;
		profile["credential"] = client->m_credential;
		profile["fed_id"] = client->m_fedCredential.substr(client->m_fedCredential.find(':') + 1);
		if (client->mm_is_Arena_TLE)
			AddMPTLEDataToProfile(client, &profile);
		else
			AddMPDataToProfile(client, &profile);
		profile["tier"] = client->m_seshatProfile->GetMPTier();
		client->m_mpAnubisRoom["members"].append(std::move(profile));
		auto& bots = client->m_mpAnubisRoom["bots"];
		for (int i = 0; i != 19; ++i)
		{
			bots.append(CreateFakeBotProfile(client));
		}
		auto connect_cb = [cred, fed, this, room = client->m_mpAnubisRoom, cookie = client->m_anubisCookie](comms::Connection_error status, int error, comms::connection q)
		{
			auto client = GetClient(cred);

			if (status == comms::Connection_error::OK)
			{
				if (client)
				{
					if (cookie != client->m_anubisCookie)
					{
						MP_LOG(DBG_WARN, "Old Anubis request ignored for client %s\n", cred.c_str());
					}
					else
					{
						client->mp_connection.reset(new comms::connection(q));

						MP_LOG(DBG_INFO, "All went well for client %s test\n", cred.c_str());
						auto msg = client->mp_connection->new_message();
						msg.add_small_int(mpserver::MPAHMessageId::Init);
						msg.add_string(cred);
						msg.add_string(fed);
						msg.add_string(Json::FastWriter().write(room));
						msg.send();
					}
				}
				else
				{
					MP_LOG(DBG_WARN, "Client %s left during mpconnecting test\n", cred.c_str());
				}
			}
			else
			{
				MP_LOG(DBG_WARN, "Connection to localhost failed\n");
				if (client && !client->mp_cancel_automatch)
				{
					MP_LOG(DBG_INFO, "Trying Anubis...\n");
					ScriptAutomatch(client, true);
				}
			}
		};

		auto disconnect_cb = [this](comms::Connection_error status, int error, comms::connection q)
		{
			HandleMPDisconnect(q, status, error);
		};

		// --- baobab -> 10.58.12.85
		// --- viorel -> 10.58.11.145
		m_commsManager->connect(comms::address("127.0.0.1", 34343), comms::Connection_type::STREAM, 0, connect_cb, disconnect_cb, nullptr);
		return;
	}
#endif	// OS_WINDOWS

	Json::Value profile;
	if (client->mm_is_Arena_TLE)
		AddMPTLEDataToProfile(client, &profile);
	else
		AddMPDataToProfile(client, &profile);
	
	auto isInFirstTier = client->m_seshatProfile->GetMPTier() == GetPvpData()->DefaultTier(GetCurrentLadderId());
	auto matcher = isInFirstTier ? "alpha_join_mp" : "quick_join_mp";
	std::map<std::string, std::string> customParams = {
		{ "credential",				client->m_credential },
		{ "automatcher",			matcher },
		{ "server_type",			"mp_server" },
		{ "user",					Json::FastWriter().write(profile) },
		//{ "filter",				GetMPMatcherFilter(client) },
		//{ "timeout",				"10" },
		//{ "room_search_timeout",	"5" },
	};
	if (isInFirstTier)
		customParams["filter"] = GetMPMatcherFilter(client);

	client->m_mpStartAutomatch = time(nullptr);
	auto customData = new AutomatchCustomData { client->m_credential, client->m_anubisCookie };
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_AUTOMATCH)->second, client->m_clientId, customParams, {}, callbackScriptAutomatch, this, customData);
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptAutomatch(const SRequest& requestData)
{
	std::unique_ptr<AutomatchCustomData> customData((AutomatchCustomData*)requestData.m_userData);
	auto serverMgr = (GameServerFedManager*)(requestData.m_callerObj);

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	auto client = serverMgr->GetClient(customData->credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	if (client->m_anubisCookie != customData->cookie)
	{
		MP_LOG(DBG_WARN, "Ignore old automatch callback for %s\n", customData->credential.c_str());
		return;
	}

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptAutomatch script returned error %d for %s\n", response["status"].asInt(), customData->credential.c_str());
		
		// --- send message to client to exit the waiting screen
		serverMgr->ServerSendAutomatchCommand(client, AutomatchCommand::ServerAutomatchError);
		
		return;
	}

	if (client->mp_cancel_automatch)
	{	// --- client canceled
		MP_LOG(DBG_WARN, "ScriptAutomatch canceled for %s\n", customData->credential.c_str());
		return;
	}

	client->m_mpAnubisRoom.clear();
	Json::Reader().parse(response["room"].asCString(), client->m_mpAnubisRoom);

	{	// --- check if members in room are same tier
		int tier = -1;
		for (const auto& member : client->m_mpAnubisRoom["members"])
		{
			auto mtier = member["tier"].asInt();
			if (tier == -1)
				tier = mtier;
			else if (mtier != tier)
				MP_LOG(DBG_CRIT, "ScriptAutomatch got room (%s) with multiple tier members %d and %d\n", client->m_mpAnubisRoom["id"].asCString(), tier, mtier);
		}
	}

	ConnectClientToRoom(serverMgr, client, client->m_mpAnubisRoom, true);
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ConnectClientToRoom(GameServerFedManager *serverMgr, GSClient *client, const Json::Value& anubisRoom, bool force_anubis)
{
	if (client->mp_cancel_automatch)
	{	// --- client canceled
		MP_LOG(DBG_WARN, "ScriptAutomatch canceled for %s\n", client->m_credential.c_str());
		return;
	}
	client->m_mpAnubisRoom = anubisRoom;

	comms::address address(client->m_mpAnubisRoom["controller_public_ip"].asString(), client->m_mpAnubisRoom["controller_port"].asInt());
	client->mp_room_id = client->m_mpAnubisRoom["id"].asString();
	client->mp_public_ips.clear();
	client->mp_public_ips.push_back(client->m_mpAnubisRoom["controller_public_ip"].asString());
	for (const auto& ip : client->m_mpAnubisRoom["controller_public_ips"])
	{
		auto str_ip = ip.asString();
		if (std::find(client->mp_public_ips.begin(), client->mp_public_ips.end(), str_ip) == client->mp_public_ips.end())
		{
			client->mp_public_ips.push_back(std::move(str_ip));
		}
	}

	auto cred = client->m_credential;
	auto connect_cb = [cred, serverMgr](comms::Connection_error status, int error, comms::connection q)
	{
		if (status == comms::Connection_error::OK)
		{
			auto client = serverMgr->GetClient(cred);
			if (client)
			{
				client->mp_connection.reset(new comms::connection(q));
			}
			else
			{
				MP_LOG(DBG_WARN, "Client %s left during mpconnecting\n", cred.c_str());
			}
		}
	};

	auto disconnect_cb = [serverMgr](comms::Connection_error status, int error, comms::connection q)
	{
		serverMgr->HandleMPDisconnect(q, status, error);
	};

	std::string buff;
	auto data_cb = [cred, serverMgr, buff, room = client->m_mpAnubisRoom, cookie = client->m_anubisCookie](comms::connection q) mutable -> int
	{
		auto client = serverMgr->GetClient(cred);
		if (!client)
		{	// --- client disconnected
			MP_LOG(DBG_WARN, "Client %s left during mpconnecting 2\n", cred.c_str());
			return -4;
		}

		if (cookie != client->m_anubisCookie)
		{
			MP_LOG(DBG_WARN, "Client %s received data from an old automatch, ignoring\n", client->m_credential.c_str());
			return -5;
		}

		if (client->mp_cancel_automatch)
		{	// --- client canceled
			MP_LOG(DBG_INFO, "Client %s canceled during mpconnecting 2\n", cred.c_str());
			return -2;
		}

		size_t n = buff.length();
		buff.resize(n + 1024);
		int i = ::recv(q.socket(), &buff[n], 1024, 0);
		if (i < 0)
		{
			int error = comms::manager::get_errno();
			MP_LOG(DBG_WARN, "data_cb read error %d %s\n", error, comms::manager::strerror(errno));
			return -1;
		}

		buff.resize(n + i);

		auto bn = buff.find('\n');
		if (bn != std::string::npos)
		{
			Json::Value root;
			auto ok = Json::Reader().parse(&*buff.begin(), &*(buff.begin() + bn), root);
			if (ok)
			{
				serverMgr->ScriptEncryptToken(client, root["nonce"].asString(), std::move(room));
				return 1;
			}

			MP_LOG(DBG_WARN, "Invalid JSON from Anubis\n");
			return 1;
		}

		return 1;
	};

	// --- if the manager has managed to quit to this point, create a new one
	if (!serverMgr->m_commsManager)
	{
		serverMgr->m_commsManager.reset(new comms::manager(getTime));	// -- should never happen on new flow
	}

#if defined WIN32
	if (!force_anubis)
	{
		auto connect_cb_local = [cred, serverMgr, connect_cb](comms::Connection_error status, int error, comms::connection q)
		{
			auto client = serverMgr->GetClient(cred);
			if (status == comms::Connection_error::OK)
			{
				MP_LOG(DBG_WARN, "Connection to localhost succeeded\n");
				connect_cb(status, error, q);
				if (client && !client->mp_cancel_automatch)
				{
					client->mp_public_ips.clear();
					int n = client->m_mpAnubisRoom["available_slots"].asInt();
					auto& bots = client->m_mpAnubisRoom["bots"];
					for (int i = 0; i < n; i += 1)
					{
						bots.append(serverMgr->CreateFakeBotProfile(client));
					}

					auto msg = client->mp_connection->new_message();
					msg.add_small_int(mpserver::MPAHMessageId::Init);
					msg.add_string(cred);
					msg.add_string(client->GetFedId());
					msg.add_string(client->m_mpAnubisRoom.toCompactString());
					msg.send();
				}
			}
			else
			{
				MP_LOG(DBG_WARN, "Connection to localhost failed\n");
				if (client && !client->mp_cancel_automatch)
				{
					MP_LOG(DBG_INFO, "Trying Anubis...\n");
					ConnectClientToRoom(serverMgr, client, client->m_mpAnubisRoom, true);
				}
			}
		};
		serverMgr->m_commsManager->connect(comms::address("127.0.0.1", 34343), comms::Connection_type::STREAM, 0, connect_cb_local, disconnect_cb, nullptr);

		return;
	}
#endif

	serverMgr->m_commsManager->connect(address, comms::Connection_type::STREAM, 0, connect_cb, disconnect_cb, data_cb);
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::ScriptEncryptToken(const GSClient* client, std::string nonce, Json::Value room)
{
	std::map<std::string, std::string> customParams = {
		{ "credential",		client->m_credential },
		{ "nonce",			nonce },
	};

	auto customData = new EncryptTokenCustomData { client->m_credential, client->m_fedCredential.substr(client->m_fedCredential.find(':') + 1), std::move(room) };
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_ENCRYPT_TOKEN)->second, client->m_clientId, customParams, {}, callbackScriptEncryptToken, this, customData);
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

void GameServerFedManager::callbackScriptEncryptToken(const SRequest& requestData)
{
	std::shared_ptr<EncryptTokenCustomData> customData((EncryptTokenCustomData*)requestData.m_userData);
	auto serverMgr = (GameServerFedManager*)(requestData.m_callerObj);

	auto client = serverMgr->GetClient(customData->credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}

	Json::Value response;
	Json::Reader().parse(requestData.m_requestResponse, response);

	if (requestData.m_errorCode || response["status"] != 200)
	{
		MP_LOG(DBG_WARN, "ScriptEncryptToken script returned error %d for %s\n", response["status"].asInt(), customData->credential.c_str());
		return;
	}
	
	if (client->mp_cancel_automatch || !client->mp_connection)
	{	// --- client canceled
		if (client->mp_connection)
			// --- close connection
			client->mp_connection->close(comms::Connection_error::DISCONNECTED, 0);

		MP_LOG(DBG_INFO, "ScriptEncryptToken canceled for %s\n", customData->credential.c_str());
		return;
	}

	std::string buff;
	auto data_cb = [serverMgr, buff, customData](comms::connection q) mutable -> int
	{
		auto client = serverMgr->GetClient(customData->credential);
		if (!client)
		{	// --- client disconnected
			MP_LOG(DBG_WARN, "Client %s left during mpconnecting 3\n", customData->credential.c_str());
			return -3;
		}
		if (client->mp_cancel_automatch)
		{	// --- client canceled
			MP_LOG(DBG_INFO, "Client %s canceled during mpconnecting 3\n", customData->credential.c_str());
			return -2;
		}

		size_t n = buff.length();
		buff.resize(n + 1024);
		int i = ::recv(q.socket(), &buff[n], 1024, 0);
		if (i < 0)
		{
			int error = comms::manager::get_errno();
			MP_LOG(DBG_WARN, "data_cb 2 read error %d %s\n", error, comms::manager::strerror(errno));
			return -1;
		}

		buff.resize(n + i);

		auto bn = buff.find('\n');
		if (bn != std::string::npos)
		{
			Json::Value root;
			auto ok = Json::Reader().parse(&*buff.begin(), &*(buff.begin() + bn), root);
			if (ok)
			{
				int n = customData->room["available_slots"].asInt();
				auto& bots = customData->room["bots"];
				for (int i = 0; i != n; ++i)
				{
					bots.append(serverMgr->CreateFakeBotProfile(client));
				}

				MP_LOG(DBG_INFO, "All went well for client %s\n", customData->credential.c_str());
				auto msg = client->mp_connection->new_message();
				bool b = msg.add_small_int(mpserver::MPAHMessageId::Init);
				b |= msg.add_string(customData->credential);
				b |= msg.add_string(customData->fed_id);
				b |= msg.add_string(Json::FastWriter().write(customData->room));
				msg.send();
				MP_LOG(DBG_INFO, "Send MP INIT b %s\n", (b ? "true" : "false"));
				return 0;
			}

			MP_LOG(DBG_WARN, "Invalid MP JSON from Anubis 2\n");
			return 1;
		}

		return 1;
	};

	client->mp_connection->set_new_data_available_callback(data_cb);

	Json::Value json;
	json["access_token"] = response["encrypted_token"];
	json["action"] = "connect game";
	json["room_id"] = client->mp_room_id;
	auto jsonStr = Json::FastWriter().write(json) + "\n";
	auto i = ::send(client->mp_connection->socket(), jsonStr.data(), (int)jsonStr.length(), 0);
	if (i < (int)jsonStr.length())
	{
		MP_LOG(DBG_WARN, "Sent only %d instead of %d bytes to Anubis controller for client %s\n", i, jsonStr.length(), customData->credential.c_str());
	}
}

void GameServerFedManager::ScriptSendUserPersonalInfoData(const GSClient* client, int ggi, const std::string& firstName, const std::string& lastName, const std::string& email, const std::string& birthDate, const std::string& country)
{
	std::map<std::string, std::string> customParams = {
		{ "staging",	"1" },
		{ "firstname",	firstName.c_str()},
		{ "lastname",	lastName.c_str()},
		{ "email",		email.c_str()},
		{ "birthday",	birthDate.c_str()},
		{ "country",	country.c_str()},
		{ "platform",	std::to_string(ggi).c_str()},
		{ "language",		client->m_language.c_str()},
		{ "fed_id",		client->m_fedCredential.c_str()},
		{ "datacenter",		GetDatacenter().c_str()},
	};

	auto userData = new std::string(client->m_credential);
	m_RequestsManager->StartNewRequest(m_scriptTaskNames.find(FED_TASK_USER_PERSONAL_INFO)->second, client->m_clientId, customParams, {}, callbackScriptSendUserPersonalInfoData, this, userData);
}

void GameServerFedManager::callbackScriptSendUserPersonalInfoData(const SRequest& requestData)
{
	std::unique_ptr<std::string> credential((std::string*)requestData.m_userData);
	auto serverMgr = GameServerFedManager::Instance();

	Json::Value response;
	Json::Reader reader = Json::Reader();;

	if (!reader.parse(requestData.m_requestResponse, response))
	{
		MP_LOG(DBG_WARN, "ScriptSendUserPersonalInfoData script response parse error: %s\n",
			   reader.getFormatedErrorMessages().c_str());
	}

	auto client = serverMgr->GetClient(*credential);
	if (!client)
	{
		// --- don't do anything for clients that are no longer connected
		return;
	}
	int status = 0;
	std::string reason = "none";
	std::string description = "";
	if (response.isObject())
	{
		// status
		status = response.get("status", 0).asInt();
		
		// reason
		Json::Value reasonJson = response.get("reason", Json::nullValue);
		std::string reason = reasonJson.isNull() ? "" : reasonJson.toCompactString();

		// description
		Json::Value descJson = response.get("description", Json::nullValue);
		std::string description = descJson.isNull() ? "" : descJson.toCompactString();
	}

	if (requestData.m_errorCode || status != 200)
	{
		// send error to client
		GameServerFedManager::Instance()->ServerSendResponsePersonalInfo(client, status, reason, description);
		MP_LOG(DBG_WARN, "ScriptSendUserPersonalInfoData script returned error %d - %s %s for %s", status, reason.c_str(), description.c_str(), credential->c_str());
		return;
	}
	// send succes to client
	MP_LOG(DBG_INFO, "ScriptSendUserPersonalInfoData script returned OK: %d reason: %s\n", status, reason.c_str());
	GameServerFedManager::Instance()->ServerSendResponsePersonalInfo(client, status);
}

///////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool  GameServerFedManager::ServerSendResponsePersonalInfo(GSClient* client, int status, std::string errorType, std::string errorMessage)
{
	NetworkMessageW userInfoResponseMessage;
	userInfoResponseMessage.addGameMessageType(TCPMSG_GENERIC);
	userInfoResponseMessage.addByte(TCPMSG_GENERIC_PERSONAL_INFO);
	userInfoResponseMessage.addInt(status);
	if (status != 200)
	{
		userInfoResponseMessage.addString((const unsigned char*)errorType.c_str());
		userInfoResponseMessage.addString((const unsigned char*)errorMessage.c_str());
	}
	userInfoResponseMessage.packMessage(client->m_Crypto);

	if (userInfoResponseMessage.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendResponsePersonalInfo packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)userInfoResponseMessage.getMessageBody(), userInfoResponseMessage.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendResponsePersonalInfo send message failed\n");
		return false;
	}
	return true;
}

