void GameServerFedManager::BroadcastRequiredDlcVersion()
{
	for (const auto& entry : m_gsClientsList)
	{
		auto client = entry.second;
		if (!client->m_isReadyForCommunication)
			continue;

		ServerSendRequiredDlcVersion(entry.second);
	}
}

//////////////////////////////////////////////////////////////////////////////////////////////////////////////////////

bool GameServerFedManager::ServerSendRequiredDlcVersion(GSClient* client)
{
	// --- match the required dlc version keys agains the client id
	// --- choose the longest matching one
	int version = 0;
	size_t largestMatchingLen = 0;

	const auto& requiredVersions = m_requiredDlcVersion["required_dlc_version"];
	for (auto it = requiredVersions.begin(), ite = requiredVersions.end(); it != ite; ++it)
	{
		if (client->m_clientId.find(it.memberName()) == std::string::npos)
			continue;

		auto matchingLen = glf::Strlen(it.memberName());
		if (matchingLen < largestMatchingLen)
			continue;

		version = (*it).asInt();
		largestMatchingLen = matchingLen;
	}

	// --- send the message
	NetworkMessageW reqDlcVersionMsg;

	reqDlcVersionMsg.addGameMessageType(TCPMSG_SEND_DLC_DETAILS);
	reqDlcVersionMsg.addInt(version);

	reqDlcVersionMsg.packMessage(client->m_Crypto);

	if (reqDlcVersionMsg.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendRequiredDlcVersion packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)reqDlcVersionMsg.getMessageBody(), reqDlcVersionMsg.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendRequiredDlcVersion send message failed\n");
		return false;
	}

	return true;
}
/////////////////////////////////////////FORGE message
void GameServerFedManager::CreateForgeSquadmatesPacks(GSClient* client)
{
	m_ForgeSquadsToSend.clear();
	const auto & forgeSMConfig = GetMultiplayerData()->ForgeSquadPacksDataConfig();
	auto& squadmates = client->m_seshatProfile->GetProfile()[SESHAT_GAME_SAVE][SESHAT_LABEL_SQUAD_MATES][SESHAT_LABEL_SQUAD_MATES_DETAILS];
	
	std::vector<MultiplayerCommonData::ForgeSquadPacksConfig> tempConfig;
	for (const auto item : forgeSMConfig)
	{
		tempConfig.push_back(item);
	}
	for (auto it = squadmates.begin(); it != squadmates.end(); ++it)
	{
		const auto& card = *it;
		auto sm_id = StringHash(it.memberName());

		auto status = card[SESHAT_LABEL_SQUAD_MATES_STATUS].asInt();
		if (status != ESMS_IDLE)
			continue;
		//rented sm
		if (client->m_seshatProfile->GetSquadMateExpiry(sm_id) != 0)
			continue;

		auto sm_rating = card[SESHAT_LABEL_SQUAD_MATES_RATING].asInt();
		auto creditName = card[SESHAT_LABEL_SQUAD_MATES_CREDIT].asString();
		const auto& smData = GetMultiplayerData()->GetEntryForCard(creditName);
		auto smClass = StringHash(smData["Class"].asCString());
		
		bool added = false;
		for(int i=0; i< (int)tempConfig.size(); i++)
		{
			auto id = tempConfig[i].squad_pack_id;
			auto mit = std::find_if(m_ForgeSquadsToSend.begin(), m_ForgeSquadsToSend.end(), [id](const Forge_Squadmates_Packs& entry) { return entry.pack_id == id; });
			Forge_Squadmates_Packs temp;
			bool notFound = false;
			if (mit == m_ForgeSquadsToSend.end())
			{
				temp.pack_id = id;
				notFound = true;
			}

			for(int j=0; j< (int)tempConfig[i].packs.size(); j++)
			{
				auto className = tempConfig[i].packs[j].squad_class;
				auto rating = tempConfig[i].packs[j].squad_rating;
				int qty = tempConfig[i].packs[j].squad_qty;
				if (qty == 0)
					continue;

				if (smClass == className && sm_rating == rating)
				{
					if (notFound)
					{
						temp.squads.push_back(sm_id);
						tempConfig[i].packs[j].squad_qty--;
						added = true;
						m_ForgeSquadsToSend.push_back(temp);
						break;
					}
					else
					{
						auto& elem = *mit;
						int size = (int)elem.squads.size();
						if (qty)
						{
							tempConfig[i].packs[j].squad_qty--;
							elem.squads.push_back(sm_id);
							added = true;
							break;

						}
					}
				}
			}
			if (added)
			{
				break;
			}
		}	
	}
}

bool GameServerFedManager::ServerSendForgeSquadmatesPacks(GSClient* client)
{
	NetworkMessageW reqForgeSquadpacksMsg;

	reqForgeSquadpacksMsg.addGameMessageType(TCPMSG_HANDLE_FORGE_DATA);
	
	reqForgeSquadpacksMsg.addByte(static_cast<byte>(ForgeCommand::ForgeServerSendSquadMates));
	CreateForgeSquadmatesPacks(client);
	
	reqForgeSquadpacksMsg.addInt((int)m_ForgeSquadsToSend.size());
	for (auto pack : m_ForgeSquadsToSend)
	{
		reqForgeSquadpacksMsg.addUInt(pack.pack_id);
		reqForgeSquadpacksMsg.addInt((int)pack.squads.size());
		int size = (int)pack.squads.size();
		for (int i = 0; i < size; i++)
		{
			auto id = pack.squads[i];
			reqForgeSquadpacksMsg.addUInt(id);
		}
	}

	reqForgeSquadpacksMsg.packMessage(client->m_Crypto);

	if (reqForgeSquadpacksMsg.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendforgeSquadmatesPacks packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)reqForgeSquadpacksMsg.getMessageBody(), reqForgeSquadpacksMsg.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendforgeSquadmatesPacks send message failed\n");
		return false;
	}

	return true;
}
void GameServerFedManager::ActivateForgeRewardList(GSClient* client, byte activate)
{
	ServerSendForgeRewardActivated(client, activate);
	if(activate == 1)
		client->m_seshatProfile->SetForgeIgnite(true);
	else
		client->m_seshatProfile->SetForgeIgnite(false);
}

bool GameServerFedManager::ServerSendForgeRewardActivated(GSClient* client, byte state)
{
	NetworkMessageW reqForgeSquadpacksMsg;

	reqForgeSquadpacksMsg.addGameMessageType(TCPMSG_HANDLE_FORGE_DATA);
	reqForgeSquadpacksMsg.addByte(static_cast<byte>(ForgeCommand::ForgeServerReset));
	reqForgeSquadpacksMsg.addByte(state);

	
	reqForgeSquadpacksMsg.packMessage(client->m_Crypto);

	if (reqForgeSquadpacksMsg.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendForgeRewardActivated packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)reqForgeSquadpacksMsg.getMessageBody(), reqForgeSquadpacksMsg.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendForgeRewardActivated send message failed\n");
		return false;
	}

	return true;
}


bool GameServerFedManager::ServerSendForgeFuelsWeapons(GSClient* client)
{
	NetworkMessageW reqForgeFuelWeaponsMsg;

	reqForgeFuelWeaponsMsg.addGameMessageType(TCPMSG_HANDLE_FORGE_DATA);

	reqForgeFuelWeaponsMsg.addByte(static_cast<byte>(ForgeCommand::ForgeServerSendFuelWeapons));
	const auto& allCredits = client->GetHestiaConfig()->GetCredits();
	std::vector<StringHash> weapons;
	
	for (const auto& weaponCredit : allCredits)
	{
		if (weapons.size() >= FORGE_MAX_WEAPONS)
			break;
		auto amount = client->GetHestiaConfig()->GetCreditBalance(client, weaponCredit.hash);
		if (weaponCredit.categoryHash != StringHash("weapon"))
			continue;
		if(amount <= 0)
			continue;
		auto isAvailable = GetAHWeaponsData()->CanUseWeaponAsForgeFuel(client, weaponCredit.hash);
		if (isAvailable)
			weapons.push_back(weaponCredit.hash);	
	}
	reqForgeFuelWeaponsMsg.addInt((int)weapons.size());
	for (auto id : weapons)
	{
		reqForgeFuelWeaponsMsg.addUInt(id);
	}


	reqForgeFuelWeaponsMsg.packMessage(client->m_Crypto);

	if (reqForgeFuelWeaponsMsg.isPacketError())
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendforgeSquadmatesPacks packet memory overflow\n");
	}

	bool bResult = ServerSendMessage(client->m_credential, (char*)reqForgeFuelWeaponsMsg.getMessageBody(), reqForgeFuelWeaponsMsg.getMessageLen());
	if (!bResult)
	{
		MP_LOG(DBG_CRIT, "GameServerFedManager: ServerSendforgeSquadmatesPacks send message failed\n");
		return false;
	}

	return true;
}

