double GameServerFedManager::GetSurvivalProgressByLBTypeFromStatistic(GSClient* client, E_SurvivalLeaderboardType lbType, const Json::Value& jStatistics, const std::string& eventID) const
{
	double progress = 0.0;


	if (lbType == E_SurvivalLeaderboardType::CleanShot)
	{
		progress = jStatistics[EVOBJ_HEADSHOTS].asDouble();
	}
	else if (lbType == E_SurvivalLeaderboardType::MostWanted)
	{
		auto event = client->FindEvent(eventID);
		auto bountyHunterPoints = event->GetSquadmateBountyPoint();

		for (auto& key : bountyHunterPoints.getMemberNames())
		{
			std::string statisticKey = EVOBJ_ENEMYTYPES + key.substr(1);

			if (jStatistics.isMember(statisticKey)) {
				double point = bountyHunterPoints[key].asDouble();
				double killed = jStatistics[statisticKey].asDouble();
				progress += point * killed;
			}
		}

		progress += jStatistics[EVOBJ_HEADSHOTS].asDouble();

	}
	else
	{
		progress = jStatistics[EVOBJ_SURVIVAL ".score"].asDouble();
	}

	return progress;
}

double GameServerFedManager::ComputeSurvivalScore(E_SurvivalLeaderboardType lbType, double newScore, double currentScore) const
{
	switch (lbType)
	{
	case E_SurvivalLeaderboardType::CriticalMass:
	case E_SurvivalLeaderboardType::CleanShot:
	case E_SurvivalLeaderboardType::MostWanted:
		return newScore;

	default:
		return (newScore > currentScore) ? (newScore - currentScore) : 0.0;
	}
}
